function intFromEnv(name, fallback, { min = 0, max = 60000 } = {}) {
	const parsed = parseInt(process.env[name] || "", 10);
	const value = Number.isFinite(parsed) ? parsed : fallback;
	return Math.min(max, Math.max(min, value));
}

function boolFromEnv(name, fallback = false) {
	const raw = String(process.env[name] ?? "").trim().toLowerCase();
	if (!raw) return Boolean(fallback);
	return ["1", "true", "yes", "on", "enabled"].includes(raw);
}

function shouldUseBrainFirstOrchestrator() {
	return boolFromEnv("AI_BRAIN_FIRST_ORCHESTRATOR", true);
}

function shouldUseLegacyPreBrainOrchestrator() {
	return boolFromEnv("AI_LEGACY_PRE_BRAIN_ORCHESTRATOR", false);
}

function shouldUseOpenAiResponseThread() {
	return boolFromEnv("AI_OPENAI_RESPONSE_THREAD", true);
}

function shouldContinueOpenAiResponseThread() {
	// The full authoritative transcript is replayed on each planner call. Sending
	// it together with previous_response_id duplicates the same history and grows
	// context quadratically, so continuation is opt-in rather than the default.
	return boolFromEnv("AI_OPENAI_RESPONSE_CONTINUATION", false);
}

function shouldUsePreBrainHotelFactRouter() {
	return boolFromEnv("AI_PRE_BRAIN_HOTEL_FACT_ROUTER", false);
}

function shouldUseHotelFactReplyGuards() {
	// These guards are deterministic/local and enforce authoritative hotel facts;
	// they do not add another OpenAI request or material latency.
	return true;
}

function shouldUseOpeningReplyGuard() {
	return boolFromEnv("AI_OPENING_REPLY_GUARD", false);
}

