function normalizeReplySimilarityToken(value = "") {
	return String(value || "")
		.normalize("NFKD")
		.toLowerCase()
		.replace(/[\u0300-\u036f\u064b-\u065f\u0670]/g, "")
		.replace(/[\u0622\u0623\u0625]/g, "\u0627")
		.replace(/\u0649/g, "\u064a")
		.replace(/\u0629/g, "\u0647")
		.trim();
}

