const REQUIRED_REPLY_SIMILARITY_TRANSITIONS = new Set([
	"quote_ready->review_reservation",
	"split_stay_quote_ready->review_reservation",
	"review_reservation->reservation_confirmed",
	"reservation_lookup_not_found->reservation_lookup_found",
]);
const FACTUAL_UPDATE_REPEAT_ACTIONS = new Set([
	"quote_ready",
	"split_stay_quote_ready",
	"review_reservation",
	"reservation_update_success",
	"reservation_lookup_found",
]);

function replySimilarityTokens(value = "") {
	const withoutFacts = String(value || "")
		.replace(/https?:\/\/\S+/gi, " ")
		.replace(/[\w.+-]+@[\w.-]+\.[a-z]{2,}/gi, " ")
		.replace(/<[^>]+>/g, " ")
		.replace(/[\p{N}\u0660-\u0669\u06f0-\u06f9]+(?:[.,:/-][\p{N}\u0660-\u0669\u06f0-\u06f9]+)*/gu, " ");
	const words = withoutFacts.match(/\p{L}[\p{L}\p{M}]*/gu) || [];
	return [
		...new Set(
			words
				.map(normalizeReplySimilarityToken)
				.filter(
					(token) =>
						token.length > 2 &&
						!REPLY_SIMILARITY_STOPWORDS.has(token) &&
						!REPLY_SIMILARITY_FACT_LABELS.has(token)
				)
		),
	];
}

function replySimilarityComparison(left = "", right = "") {
	const a = new Set(replySimilarityTokens(left));
	const b = new Set(replySimilarityTokens(right));
	let intersection = 0;
	for (const token of a) {
		if (b.has(token)) intersection += 1;
	}
	const union = a.size + b.size - intersection;
	const smaller = Math.min(a.size, b.size);
	return {
		leftSize: a.size,
		rightSize: b.size,
		intersection,
		jaccard: union ? intersection / union : 0,
		containment: smaller ? intersection / smaller : 0,
	};
}

function replySimilarityScore(left = "", right = "") {
	return replySimilarityComparison(left, right).jaccard;
}

function replyRequiredFactSignature(value = "") {
	const text = String(value || "");
	return [
		...(text.match(/https?:\/\/\S+/gi) || []).map((item) =>
			item.replace(/[),.;!?]+$/g, "").toLowerCase()
		),
		...(text.match(/[\w.+-]+@[\w.-]+\.[a-z]{2,}/gi) || []).map((item) =>
			item.toLowerCase()
		),
		...(text.match(/[\p{N}\u0660-\u0669\u06f0-\u06f9]+(?:[.,:/-][\p{N}\u0660-\u0669\u06f0-\u06f9]+)*/gu) || []),
	]
		.filter(Boolean)
		.sort()
		.join("|");
}

function repliesSubstantiallyRepeatForGuard(previous = {}, current = {}) {
	const previousText = String(previous?.message || "").trim();
	const currentText = String(current?.message || "").trim();
	if (!previousText || !currentText) return false;
	const exact = (value) =>
		normalizeReplySimilarityToken(
			String(value || "")
				.replace(/<[^>]+>/g, " ")
				.replace(/&(?:nbsp|amp|lt|gt|quot|#39);/gi, " ")
				.replace(/[^\p{L}\p{N}]+/gu, " ")
				.replace(/\s+/g, " ")
		);
	if (exact(previousText) === exact(currentText)) return true;
	const previousAction = String(previous?.clientAction || "").trim().toLowerCase();
	const currentAction = String(current?.clientAction || "").trim().toLowerCase();
	const previousFactSignature = replyRequiredFactSignature(previousText);
	const currentFactSignature = replyRequiredFactSignature(currentText);
	if (
		previousFactSignature &&
		currentFactSignature &&
		previousFactSignature !== currentFactSignature &&
		(FACTUAL_UPDATE_REPEAT_ACTIONS.has(previousAction) ||
			FACTUAL_UPDATE_REPEAT_ACTIONS.has(currentAction))
	) {
		return false;
	}
	const comparison = replySimilarityComparison(previousText, currentText);
	const sameMeaningfulTokenSet =
		comparison.leftSize >= 2 &&
		comparison.leftSize === comparison.rightSize &&
		comparison.intersection === comparison.leftSize;
	const enoughMeaningfulOverlap =
		sameMeaningfulTokenSet ||
		(comparison.intersection >= 3 && comparison.jaccard >= 0.7) ||
		(comparison.intersection >= 5 && comparison.jaccard >= 0.65);
	if (!enoughMeaningfulOverlap) return false;
	if (
		REQUIRED_REPLY_SIMILARITY_TRANSITIONS.has(`${previousAction}->${currentAction}`) &&
		replyRequiredFactSignature(previousText) &&
		replyRequiredFactSignature(currentText)
	) {
		return false;
	}
	return true;
}

function recentAiReplyEntries(sc = {}, latestGuest = null, limit = 4) {
	const conversation = Array.isArray(sc.conversation) ? sc.conversation : [];
	let endIndex = latestGuest ? conversationIndexOfEntry(sc, latestGuest) : conversation.length;
	if (endIndex < 0) endIndex = conversation.length;
	const replies = [];
	for (let index = endIndex - 1; index >= 0 && replies.length < limit; index -= 1) {
		const entry = conversation[index] || {};
		if (!isAiSupportEntry(entry) || entry.isSystem) continue;
		if (String(entry.message || "").trim()) replies.push(entry);
	}
	return replies;
}

function replyTooSimilarToRecentAi(
	sc = {},
	candidate = "",
	latestGuest = null,
	candidateAction = ""
) {
	if (String(candidate || "").trim().length < 40) return false;
	return recentAiReplyEntries(sc, latestGuest).some((previous) =>
		repliesSubstantiallyRepeatForGuard(previous, {
			message: candidate,
			clientAction: candidateAction,
		})
	);
}

function entryFingerprint(entry = {}) {
	return [
		String(entry?.date || ""),
		String(entry?.clientTag || ""),
		String(entry?.message || "").trim(),
	].join("|");
}

function latestGuestStillCurrent(sc = {}, expected = null) {
	if (!expected) return false;
	const latest = latestGuestEntry(sc);
	return Boolean(latest && entryFingerprint(latest) === entryFingerprint(expected));
}

function guestAcknowledgesReservationProcessing(value = "") {
	let text = normalizeIntentSearchText(value)
		.replace(/[.!?؟،,;:]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!text || text.length > 100) return false;
	text = text
		.replace(/\b(?:please|my friend|friend)\b/gi, " ")
		.replace(/(?:يا\s+صديقي|يا\s+صديقتي|من\s+فضلك|لو\s+سمحت)/giu, " ")
		.replace(/\s+/g, " ")
		.trim();
	return (
		/^(?:ok(?:ay)?|alright|sure|got it|understood|no problem|no worries|that(?:'|’)?s fine|that is fine|take your time|take all the time you need|no rush|go ahead|continue|proceed|i(?:'|’)?m here|i am here|i(?:'|’)?ll wait|i will wait|i(?:'|’)?m waiting|i am waiting|waiting|whenever you(?:'|’)?re ready|thank you|thanks)(?:\s+(?:and\s+)?(?:ok(?:ay)?|alright|sure|no problem|no worries|that(?:'|’)?s fine|that is fine|take your time|take all the time you need|no rush|go ahead|continue|proceed|i(?:'|’)?m here|i am here|i(?:'|’)?ll wait|i will wait|i(?:'|’)?m waiting|i am waiting|waiting|whenever you(?:'|’)?re ready|thank you|thanks))*$/i.test(
			text
		) ||
		/^(?:تمام|طيب|حاضر|ماشي|اوكي|أوكي|لا\s+مشكلة|ما\s+في\s+مشكلة|كله\s+تمام|تفضل|تابع|كمل|اكمل|أكمل|انا\s+موجود|أنا\s+موجود|خذ\s+وقتك|خدي\s+وقتك|خذوا\s+وقتكم|براحتك|على\s+راحتك|لا\s+تستعجل|لا\s+تستعجلوا|بانتظارك|سأنتظر|سوف\s+أنتظر|شكرا|شكرًا|شكراً)(?:\s+(?:و\s*)?(?:تمام|طيب|حاضر|ماشي|اوكي|أوكي|لا\s+مشكلة|ما\s+في\s+مشكلة|كله\s+تمام|تفضل|تابع|كمل|اكمل|أكمل|انا\s+موجود|أنا\s+موجود|خذ\s+وقتك|براحتك|على\s+راحتك|لا\s+تستعجل|بانتظارك|سأنتظر|شكرا|شكرًا|شكراً))*$/iu.test(
			text
		)
	);
}

function onlyReservationProcessingAcknowledgementsAfter(sc = {}, expected = null) {
	if (!expected || !Array.isArray(sc.conversation)) return false;
	const expectedFingerprint = entryFingerprint(expected);
	let expectedIndex = -1;
	for (let index = sc.conversation.length - 1; index >= 0; index -= 1) {
		if (entryFingerprint(sc.conversation[index]) === expectedFingerprint) {
			expectedIndex = index;
			break;
		}
	}
	if (expectedIndex < 0) return false;
	const after = sc.conversation.slice(expectedIndex + 1);
	const guestRows = after.filter((entry) => isGuestEntry(entry));
	if (!guestRows.length) return false;
	if (after.some((entry) => entry?.isAi === true && entry?.isSystem !== true)) return false;
	return guestRows.every((entry) =>
		guestAcknowledgesReservationProcessing(entry?.message || "")
	);
}

function latestNonSystemAiAfterGuest(sc = {}, guest = null) {
	if (!guest || !Array.isArray(sc.conversation)) return null;
	const fingerprint = entryFingerprint(guest);
	let guestIndex = -1;
	for (let index = sc.conversation.length - 1; index >= 0; index -= 1) {
		if (entryFingerprint(sc.conversation[index]) === fingerprint) {
			guestIndex = index;
			break;
		}
	}
	if (guestIndex < 0) return null;
	for (let index = sc.conversation.length - 1; index > guestIndex; index -= 1) {
		const entry = sc.conversation[index] || {};
		if (entry.isAi === true && entry.isSystem !== true) return entry;
	}
	return null;
}

function entryTime(entry = {}) {
	const timestamp = entry?.date || entry?.createdAt || entry?.timestamp || 0;
	const value =
		timestamp instanceof Date ? timestamp.getTime() : new Date(timestamp).getTime();
	return Number.isFinite(value) ? value : 0;
}

function roomTypeLabel(roomTypeKey = "", languageCode = "en") {
	const ar = /^ar\b/i.test(languageCode || "");
	const labels = {
		individualBed: ar ? "\u0633\u0631\u064a\u0631 \u0641\u0631\u062f\u064a" : "Individual Bed",
		singleRooms: ar ? "غرفة فردية" : "Single Room",
		doubleRooms: ar ? "غرفة مزدوجة" : "Double Room",
		tripleRooms: ar ? "غرفة ثلاثية" : "Triple Room",
		quadRooms: ar ? "غرفة رباعية" : "Quadruple Room",
		familyRooms: ar ? "غرفة عائلية" : "Family Room",
		suite: ar ? "جناح" : "Suite",
		other: ar ? "غرفة" : "Room",
	};
	return labels[roomTypeKey] || roomTypeKey || (ar ? "غرفة" : "Room");
}

function roomCapacityForKey(roomTypeKey = "") {
	const capacities = {
		singleRooms: 1,
		doubleRooms: 2,
		tripleRooms: 3,
		quadRooms: 4,
		familyRooms: 5,
		suite: 6,
		individualBed: 1,
	};
	return capacities[roomTypeKey] || 0;
}

function activeRoomTypeKeySet(hotel = {}) {
	return new Set(
		(Array.isArray(hotel.roomCountDetails) ? hotel.roomCountDetails : [])
			.filter((room) => room?.activeRoom !== false)
			.map((room) => canonicalRoomTypeKey(room))
			.filter(Boolean)
	);
}

function activeSelectionsFromKnownForHotel(hotel = {}, known = {}) {
	return normalizeRoomSelections(selectionsFromKnown(known))
		.map((selection) => {
			const room = resolveRoomForStay(hotel, {
				...selection,
				requestedCapacity: roomSelectionCapacity(selection),
			});
			if (!room) return null;
			return roomSelectionFromHotelRoom(room, selection.count);
		})
		.filter(Boolean);
}

function filterInactiveRoomSelectionsForHotel(hotel = {}, known = {}, options = {}) {
	const activeRoomKeys = activeRoomTypeKeySet(hotel);
	if (!activeRoomKeys.size) return { known, changed: false };
	const currentSelections = normalizeRoomSelections(selectionsFromKnown(known));
	if (!currentSelections.length) return { known, changed: false };
	let activeSelections = activeSelectionsFromKnownForHotel(hotel, {
		...known,
		roomSelections: currentSelections,
	});
	if (!activeSelections.length && options.fallbackKnown) {
		activeSelections = activeSelectionsFromKnownForHotel(hotel, options.fallbackKnown);
	}
	if (!activeSelections.length) return { known, changed: false };
	const beforeKey = roomSelectionKey(currentSelections);
	const afterKey = roomSelectionKey(activeSelections);
	const currentRoomType = String(known.roomTypeKey || "");
	const roomTypeStillActive = !currentRoomType || activeRoomKeys.has(currentRoomType);
	if (beforeKey === afterKey && roomTypeStillActive) return { known, changed: false };
	const next = { ...asObject(known) };
	next.roomSelections = activeSelections;
	next.rooms = roomSelectionsTotal(activeSelections);
	if (activeSelections.length === 1) {
		next.roomTypeKey = activeSelections[0].roomTypeKey;
	} else if (next.roomTypeKey && !activeRoomKeys.has(next.roomTypeKey)) {
		delete next.roomTypeKey;
	}
	if (quoteHasContent(next.quote) && !quoteCanBePreservedForKnown(next.quote, next)) {
		delete next.quote;
	}
	if (next.reviewSentAt && beforeKey !== afterKey) delete next.reviewSentAt;
	return { known: next, changed: true };
}

function totalGuestsFromKnown(known = {}) {
	const adults = Number(known.adults || known.guests || 0);
	const children = Number(known.children || 0);
	const total =
		(Number.isFinite(adults) ? adults : 0) +
		Math.max(0, Number.isFinite(children) ? children : 0);
	return total > 0 ? Math.floor(total) : 0;
}

function requestedBedsFromKnown(known = {}) {
	const beds = Number(known.requestedBeds || known.bedCount || known.beds || 0);
	return Number.isFinite(beds) && beds > 0 ? Math.floor(beds) : 0;
}

function capacityTargetFromKnown(known = {}) {
	if (known.childrenCountUnclear) return 0;
	return Math.max(totalGuestsFromKnown(known), requestedBedsFromKnown(known));
}

function roomPhysicalInventory(room = {}) {
	return roomSellableInventory(room);
}

function roomSelectionFromHotelRoom(room = {}, count = 1) {
	const roomTypeKey = canonicalRoomTypeKey(room);
	return {
		roomId: cleanString(room?._id, 80),
		roomTypeKey,
		roomDisplayName: cleanDisplayString(
			room?.displayName || room?.displayName_OtherLanguage || roomTypeLabel(roomTypeKey),
			160
		),
		capacityGuests: roomCapacity(room) || roomCapacityForKey(roomTypeKey) || 0,
		totalRooms: roomPhysicalInventory(room),
		pricingUnit:
			roomTypeKey === "individualBed" ? "per_bed_per_night" : "per_room_per_night",
		count: normalizeRoomCount(count, 1),
	};
}

function roomSelectionCapacity(selection = {}) {
	const explicit = Number(selection?.capacityGuests || 0);
	return explicit > 0 ? explicit : roomCapacityForKey(selection?.roomTypeKey);
}

function activeRoomCapacityCandidates(hotel = {}) {
	return (Array.isArray(hotel?.roomCountDetails) ? hotel.roomCountDetails : [])
		.filter(roomIsSellable)
		.map((room) => {
			const selection = roomSelectionFromHotelRoom(room, 1);
			return {
				...selection,
				key: selection.roomTypeKey,
				capacity: roomSelectionCapacity(selection),
			};
		})
		.filter((item) => item.roomId && item.capacity > 0 && ROOM_TYPE_KEYS.includes(item.key));
}

function roomSelectionsGuestCapacity(selections = []) {
	return normalizeRoomSelections(selections).reduce(
		(total, selection) =>
			total +
			normalizeRoomCount(selection.count, 1) * roomSelectionCapacity(selection),
		0
	);
}

function sortedRoomPlanSelections(selections = []) {
	return normalizeRoomSelections(selections).sort((a, b) => {
		const capacityDelta =
			roomSelectionCapacity(b) - roomSelectionCapacity(a);
		return capacityDelta || roomTypeSortIndex(a.roomTypeKey) - roomTypeSortIndex(b.roomTypeKey);
	});
}

function roomPlanScore(selections = [], totalGuests = 0) {
	const normalized = normalizeRoomSelections(selections);
	const roomCount = roomSelectionsTotal(normalized);
	const capacity = roomSelectionsGuestCapacity(normalized);
	const unused = Math.max(0, capacity - totalGuests);
	const highestCapacity = normalized.reduce(
		(max, selection) => Math.max(max, roomSelectionCapacity(selection)),
		0
	);
	const typeCount = normalized.length;
	const typeOrder = normalized
		.map((selection) => roomTypeSortIndex(selection.roomTypeKey))
		.reduce((sum, index) => sum + index, 0);
	return {
		roomCount,
		unused,
		highestCapacity,
		typeCount,
		typeOrder,
	};
}

function compareRoomPlanScores(a = {}, b = {}) {
	return (
		a.roomCount - b.roomCount ||
		a.unused - b.unused ||
		b.highestCapacity - a.highestCapacity ||
		a.typeCount - b.typeCount ||
		a.typeOrder - b.typeOrder
	);
}

function bestRoomSelectionsForGuests(hotel = {}, totalGuests = 0) {
	const guests = Math.max(0, Math.floor(Number(totalGuests || 0) || 0));
	if (!guests) return [];
	const candidates = activeRoomCapacityCandidates(hotel).sort(
		(a, b) =>
			b.capacity - a.capacity ||
			roomTypeSortIndex(a.key) - roomTypeSortIndex(b.key) ||
			String(a.roomDisplayName || "").localeCompare(String(b.roomDisplayName || ""))
	);
	if (!candidates.length) return [];
	// Bounded 0/1 dynamic programming respects exact physical counts. Capacity
	// states stop once they fit the party, so runtime scales with the guest target
	// instead of the combinatorial number of room arrangements.
	const maxCapacity = Math.max(...candidates.map((item) => item.capacity));
	const capacityLimit = guests + maxCapacity - 1;
	const states = Array(capacityLimit + 1).fill(null);
	states[0] = {
		selections: [],
		roomCount: 0,
		capacity: 0,
		score: {
			roomCount: 0,
			unused: 0,
			highestCapacity: 0,
			typeCount: 0,
			typeOrder: 0,
		},
	};
	for (const candidate of candidates) {
		const units = Math.min(
			MAX_AI_ROOM_COUNT,
			Math.max(0, Math.floor(Number(candidate.totalRooms || 0) || 0))
		);
		for (let unit = 0; unit < units; unit += 1) {
			for (
				let capacity = capacityLimit - candidate.capacity;
				capacity >= 0;
				capacity -= 1
			) {
				const state = states[capacity];
				if (!state || state.capacity >= guests || state.roomCount >= MAX_AI_ROOM_COUNT) {
					continue;
				}
				const nextCapacity = capacity + candidate.capacity;
				const existingSelectionIndex = state.selections.findIndex(
					(selection) => selection.roomId === candidate.roomId
				);
				const nextSelections = state.selections.map((selection) => ({ ...selection }));
				if (existingSelectionIndex >= 0) {
					nextSelections[existingSelectionIndex].count += 1;
				} else {
					nextSelections.push({
						roomId: candidate.roomId,
						roomTypeKey: candidate.key,
						roomDisplayName: candidate.roomDisplayName,
						capacityGuests: candidate.capacity,
						totalRooms: candidate.totalRooms,
						pricingUnit: candidate.pricingUnit,
						count: 1,
					});
				}
				const roomCount = state.roomCount + 1;
				const highestCapacity = Math.max(
					state.score.highestCapacity,
					candidate.capacity
				);
				const typeCount =
					state.score.typeCount + (existingSelectionIndex >= 0 ? 0 : 1);
				const typeOrder =
					state.score.typeOrder +
					(existingSelectionIndex >= 0 ? 0 : roomTypeSortIndex(candidate.key));
				const nextState = {
					selections: nextSelections,
					roomCount,
					capacity: nextCapacity,
					score: {
						roomCount,
						unused: Math.max(0, nextCapacity - guests),
						highestCapacity,
						typeCount,
						typeOrder,
					},
				};
				const existing = states[nextCapacity];
				if (!existing || compareRoomPlanScores(nextState.score, existing.score) < 0) {
					states[nextCapacity] = nextState;
				}
			}
		}
	}
	let best = null;
	for (const state of states) {
		if (!state) continue;
		if (state.capacity < guests || state.roomCount < 1) continue;
		if (!best || compareRoomPlanScores(state.score, best.score) < 0) best = state;
	}
	return best ? sortedRoomPlanSelections(best.selections) : [];
}

function physicalRoomPlanWasAdjusted(
	requestedSelections = [],
	allocatedSelections = [],
	singleMappedToDouble = false
) {
	if (singleMappedToDouble) return true;
	const requested = normalizeRoomSelections(requestedSelections);
	const allocated = normalizeRoomSelections(allocatedSelections);
	if (roomSelectionsTotal(requested) !== roomSelectionsTotal(allocated)) return true;
	const claimed = new Set();
	for (const selection of requested) {
		const requestedId = cleanString(selection.roomId, 80);
		const requestedDisplay = cleanDisplayString(selection.roomDisplayName, 160).toLowerCase();
		const matches = allocated
			.map((item, index) => ({ item, index }))
			.filter(({ item, index }) => {
				if (claimed.has(index)) return false;
				if (requestedId) return cleanString(item.roomId, 80) === requestedId;
				if (requestedDisplay) {
					return cleanDisplayString(item.roomDisplayName, 160).toLowerCase() === requestedDisplay;
				}
				return item.roomTypeKey === selection.roomTypeKey;
			});
		const matchedCount = matches.reduce(
			(total, match) => total + normalizeRoomCount(match.item.count, 1),
			0
		);
		if (matchedCount !== normalizeRoomCount(selection.count, 1)) return true;
		// A broad request that had to be split across multiple exact room
		// configurations is still a proposed replacement mix and needs approval.
		if (!requestedId && !requestedDisplay && matches.length > 1) return true;
		matches.forEach(({ index }) => claimed.add(index));
	}
	return claimed.size !== allocated.length;
}

function fitRoomSelectionsToPhysicalInventory(hotel = {}, requestedSelections = [], known = {}) {
	const requested = normalizeRoomSelections(requestedSelections);
	const hasStayDates = Boolean(
		validISODate(known.checkinISO) && validISODate(known.checkoutISO)
	);
	const candidates = activeRoomCapacityCandidates(hotel)
		.map((candidate) => ({
			...candidate,
			openForStay: hasStayDates
				? Boolean(
						priceRoomForStay(
							hotel,
							{ roomId: candidate.roomId, roomType: candidate.roomTypeKey },
							known.checkinISO,
							known.checkoutISO
						)?.available
				  )
				: true,
		}))
		.sort(
		(left, right) =>
			roomTypeSortIndex(left.roomTypeKey) - roomTypeSortIndex(right.roomTypeKey) ||
			left.capacity - right.capacity ||
			String(left.roomDisplayName || "").localeCompare(String(right.roomDisplayName || ""))
		);
	if (!requested.length) {
		return {
			requestedRoomSelections: requested,
			roomSelections: [],
			adjusted: false,
			unfilledRooms: 0,
		};
	}
	if (!candidates.length) {
		return {
			requestedRoomSelections: requested,
			roomSelections: [],
			adjusted: true,
			unfilledRooms: roomSelectionsTotal(requested),
		};
	}
	const usedByRoomId = new Map();
	const allocated = [];
	let unfilledRooms = 0;
	let singleMappedToDouble = false;
	const allocateFrom = (pool = [], wanted = 0) => {
		let remaining = wanted;
		for (const candidate of pool) {
			if (remaining <= 0) break;
			const alreadyUsed = Number(usedByRoomId.get(candidate.roomId) || 0);
			const available = Math.max(0, Number(candidate.totalRooms || 0) - alreadyUsed);
			if (!available) continue;
			const take = Math.min(remaining, available);
			allocated.push({ ...candidate, count: take });
			usedByRoomId.set(candidate.roomId, alreadyUsed + take);
			remaining -= take;
		}
		return remaining;
	};

	for (const selection of requested) {
		const requestedCount = normalizeRoomCount(selection.count, 1);
		const requestedType = selection.roomTypeKey;
		let requestedCapacity = Math.max(
			roomSelectionCapacity(selection),
			requestedCount === 1 ? capacityTargetFromKnown(known) : 0
		);
		const preferredRoom = resolveRoomForStay(hotel, {
			...selection,
			requestedCapacity,
		});
		const resolvedType = preferredRoom
			? canonicalRoomTypeKey(preferredRoom)
			: requestedType;
		requestedCapacity = Math.max(
			requestedCapacity,
			preferredRoom ? roomCapacity(preferredRoom) : 0
		);
		if (requestedType === "singleRooms" && resolvedType === "doubleRooms") {
			singleMappedToDouble = true;
		}
		const sameType = candidates.filter((candidate) => {
			if (hasStayDates && !candidate.openForStay) return false;
			return (
				candidate.roomTypeKey === resolvedType &&
				candidate.capacity >= requestedCapacity
			);
		});
		const preferredId = cleanString(preferredRoom?._id, 80);
		const orderedSameType = [...sameType].sort((left, right) => {
			if (left.openForStay !== right.openForStay) return left.openForStay ? -1 : 1;
			if (preferredId && left.roomId === preferredId) return -1;
			if (preferredId && right.roomId === preferredId) return 1;
			const leftFits = left.capacity >= requestedCapacity;
			const rightFits = right.capacity >= requestedCapacity;
			if (leftFits !== rightFits) return leftFits ? -1 : 1;
			return left.capacity - right.capacity;
		});
		let remaining = allocateFrom(orderedSameType, requestedCount);
		if (remaining > 0) {
			const startIndex = roomTypeSortIndex(resolvedType || requestedType);
			const nextTypes = candidates.filter(
				(candidate) =>
					candidate.openForStay &&
					candidate.roomTypeKey !== "individualBed" &&
					candidate.capacity >= requestedCapacity &&
					roomTypeSortIndex(candidate.roomTypeKey) > startIndex
			);
			remaining = allocateFrom(nextTypes, remaining);
		}
		unfilledRooms += remaining;
	}

	const roomSelections = normalizeRoomSelections(allocated);
	const adjusted = physicalRoomPlanWasAdjusted(
		requested,
		roomSelections,
		singleMappedToDouble
	);
	return {
		requestedRoomSelections: requested,
		roomSelections,
		adjusted,
		singleMappedToDouble,
		unfilledRooms,
	};
}

function ensureRoomPlanForGuestCapacity(hotel = {}, known = {}) {
	const capacityTarget = capacityTargetFromKnown(known);
	if (!capacityTarget) return { known, changed: false };
	const currentSelections = normalizeRoomSelections(selectionsFromKnown(known));
	const currentCapacity = roomSelectionsGuestCapacity(currentSelections);
	if (currentSelections.length && currentCapacity >= capacityTarget) {
		return { known, changed: false };
	}
	const plannedSelections = bestRoomSelectionsForGuests(hotel, capacityTarget);
	if (!plannedSelections.length) return { known, changed: false };
	const plannedCapacity = roomSelectionsGuestCapacity(plannedSelections);
	if (plannedCapacity < capacityTarget) return { known, changed: false };
	if (
		currentSelections.length &&
		roomSelectionKey(currentSelections) === roomSelectionKey(plannedSelections)
	) {
		return { known, changed: false };
	}
	const next = { ...asObject(known) };
	next.roomSelections = plannedSelections;
	next.rooms = roomSelectionsTotal(plannedSelections);
	if (plannedSelections.length === 1) {
		next.roomTypeKey = plannedSelections[0].roomTypeKey;
	} else {
		delete next.roomTypeKey;
	}
	delete next.quote;
	delete next.reviewSentAt;
	return { known: next, changed: true };
}

function inferRoomTypeFromGuests(hotel = {}, known = {}) {
	if (known.roomTypeKey) return "";
	const capacityTarget = capacityTargetFromKnown(known);
	if (!Number.isFinite(capacityTarget) || capacityTarget < 1) return "";
	const candidates = activeRoomCapacityCandidates(hotel)
		.filter((item) => item.capacity >= capacityTarget)
		.sort((a, b) => a.capacity - b.capacity);
	return candidates[0]?.key || "";
}

function inferRoomSelectionsFromGuests(hotel = {}, known = {}) {
	if (selectionsFromKnown(known).length) return [];
	const capacityTarget = capacityTargetFromKnown(known);
	if (!Number.isFinite(capacityTarget) || capacityTarget < 1) return [];
	return bestRoomSelectionsForGuests(hotel, capacityTarget);
}

function localizedAgentName(sc = {}) {
	const name = String(sc.aiResponderName || "Jannat Booking").trim();
	const languageCode = String(sc.preferredLanguageCode || "").toLowerCase();
	if (!languageCode.startsWith("ar")) return name;
	const map = {
		mona: "\u0645\u0646\u0649",
		amira: "أميرة",
		huda: "هدى",
		khadija: "خديجة",
		nadia: "نادية",
		noor: "نور",
		iman: "إيمان",
		safiya: "صفية",
		sara: "سارة",
		aisha: "\u0639\u0627\u0626\u0634\u0629",
		hana: "\u0647\u0646\u0627",
		yasmin: "\u064a\u0627\u0633\u0645\u064a\u0646",
		fatima: "\u0641\u0627\u0637\u0645\u0629",
		maryam: "\u0645\u0631\u064a\u0645",
		mariam: "مريم",
		zainab: "\u0632\u064a\u0646\u0628",
		layla: "\u0644\u064a\u0644\u0649",
		leila: "\u0644\u064a\u0644\u0649",
		aya: "\u0622\u064a\u0629",
		salma: "\u0633\u0644\u0645\u0649",
		lina: "\u0644\u064a\u0646\u0627",
		samira: "\u0633\u0645\u064a\u0631\u0629",
		samera: "\u0633\u0645\u064a\u0631\u0629",
		rania: "\u0631\u0627\u0646\u064a\u0627",
		nour: "\u0646\u0648\u0631",
	};
	return map[name.toLowerCase()] || name;
}

function activeLanguageCode(sc = {}, known = {}) {
	return (
		String(known.languageCode || "").trim() ||
		String(sc.preferredLanguageCode || "").trim() ||
		"en"
	);
}

function languageFactsFromGuestText(value = "") {
	const text = String(value || "").toLowerCase();
	if (!text.trim() || /[\u0600-\u06FF]/.test(text)) return {};
	if (
		/[çğıöşü]/i.test(text) ||
		/\b(?:merhaba|selam|oda|odasi|odas\u0131|gece|g\u00fcn|fiyat|kahvalt|ekonomik|ucuz|uygun|yak\u0131n|yakin|temmuz|a\u011fustos|agustos|m\u0131|mi|var\s*m\u0131|var\s*mi|rezervasyon)\b/i.test(
			text
		)
	) {
		return { languageCode: "tr", languageName: "Turkish" };
	}
	return {};
}

function looksLikeOrganizationName(value = "") {
	const text = String(value || "").replace(/\s+/g, " ").trim();
	if (!text) return false;
	const lower = text.toLowerCase();
	if (
		/\b(?:agency|travel|tourism|company|corp|corporation|office|group|llc|ltd|inc|co\.)\b/i.test(
			lower
		)
	) {
		return true;
	}
	return /(?:\u0648\u0643\u0627\u0644\u0629|\u0634\u0631\u0643\u0629|\u0634\u0631\u0643\u0647|\u0645\u0643\u062a\u0628|\u0645\u0624\u0633\u0633\u0629|\u0645\u0624\u0633\u0633\u0647|\u0644\u0644\u0633\u064a\u0627\u062d\u0629|\u0627\u0644\u0633\u064a\u0627\u062d\u0629|\u0627\u0644\u0633\u0641\u0631)/i.test(
		text
	);
}

function addressableNameFromClientName(value = "") {
	const text = String(value || "").replace(/\s+/g, " ").trim();
	if (!text) return "";
	const agencyMatch = text.match(
		/^(?:\u0627\u0644)?(?:\u0648\u0643\u0627\u0644\u0629|\u0645\u0643\u062a\u0628|\u0634\u0631\u0643\u0629|\u0634\u0631\u0643\u0647|\u0645\u0624\u0633\u0633\u0629|\u0645\u0624\u0633\u0633\u0647)\s+(.+)$/i
	);
	if (agencyMatch?.[1]) {
		const withoutBusinessTail = agencyMatch[1]
			.replace(
				/(?:\s+|\b)(?:\u0644\u0644\u0633\u064a\u0627\u062d\u0629|\u0648\u0627\u0644\u0633\u0641\u0631|\u0627\u0644\u0633\u064a\u0627\u062d\u0629|\u0627\u0644\u0633\u0641\u0631|\u0627\u0644\u062c\u0632\u0627\u0626\u0631).*$/i,
				""
			)
			.trim();
		const firstToken = withoutBusinessTail.split(/\s+/).find((token) =>
			/^[A-Za-z\u0600-\u06FF]{2,}$/.test(token)
		);
		if (firstToken) return firstToken;
	}
	if (looksLikeOrganizationName(text)) {
		const personish = text.split(/\s+/).find((token) =>
			/^[A-Z][a-z]{2,}$|^[\u0621-\u064A]{2,}$/u.test(token)
		);
		return personish || "";
	}
	return text;
}

function profileNameForBooking(sc = {}) {
	const name = cleanDisplayString(sc.clientName || sc.displayName1, 120);
	if (!name || /^(guest|customer|client|visitor|unknown)$/i.test(name)) return "";
	if (/^(?:codex|qa|test)(?:\s+|$)|\b(?:codex\s*qa|qa\s*case|test\s*guest|live\s*qa)\b/i.test(name)) return "";
	if (looksLikeOrganizationName(name)) return "";
	return name;
}

function guestDisplayName(sc = {}) {
	const raw =
		String(sc.clientName || "").trim() ||
		String(sc.displayName1 || "").trim() ||
		"";
	return addressableNameFromClientName(raw) || raw || "Guest";
}

function normalizeDigits(value = "") {
	return digitsToEnglish(String(value || ""));
}

function normalizeIntentSearchText(value = "") {
	return normalizeDigits(value)
		.normalize("NFD")
		.replace(/[\u0300-\u036f\u064b-\u065f\u0670]/g, "")
		.toLowerCase();
}

function repairMojibakeText(value = "") {
	const raw = String(value || "");
	if (!/[ÃØÙ]/.test(raw)) return raw;
	try {
		const repaired = Buffer.from(raw, "latin1").toString("utf8");
		if (/[\u0600-\u06FF]/.test(repaired)) return repaired;
	} catch {
		// Keep the original when the text was not Latin-1 mojibake.
	}
	return raw;
}

function normalizeIntentSearchTextRepaired(value = "") {
	return normalizeIntentSearchText(repairMojibakeText(value));
}

function compactNameForCompare(value = "") {
	return normalizeIntentSearchText(value)
		.replace(/[^\p{L}\d]+/gu, "")
		.trim();
}

function sameBookingName(left = "", right = "") {
	const a = compactNameForCompare(left);
	const b = compactNameForCompare(right);
	return Boolean(a && b && a === b);
}

function cleanString(value = "", max = 240) {
	return normalizeDigits(value).replace(/\s+/g, " ").trim().slice(0, max);
}

function cleanDisplayString(value = "", max = 240) {
	return String(value || "").replace(/\s+/g, " ").trim().slice(0, max);
}

function cleanMultilineDisplayString(value = "", max = 1200) {
	const text = String(value || "")
		.replace(/[ \t\f\v]+/g, " ")
		.replace(/\s*\r?\n\s*/g, "\n")
		.replace(/\n{3,}/g, "\n\n")
		.trim();
	return text.slice(0, Math.max(1, Number(max) || 1200)).trim();
}

function cleanPhone(value = "") {
	return normalizeDigits(value).replace(/[^\d+]/g, "").slice(0, 32);
}

function looksLikeDatePhoneCandidate(value = "") {
	const digits = cleanPhone(value).replace(/[^\d]/g, "");
	if (!/^20\d{6}$/.test(digits)) return false;
	const iso = `${digits.slice(0, 4)}-${digits.slice(4, 6)}-${digits.slice(6, 8)}`;
	return validISODate(iso) === iso;
}

function profilePhoneForBooking(sc = {}) {
	const contactType = String(sc.clientContactType || "").toLowerCase();
	const contact = String(sc.clientContact || "");
	if (contactType === "email" || contact.includes("@")) return "";
	const phone = cleanPhone(contact);
	return phone && phone.replace(/[^\d]/g, "").length >= 7 && !looksLikeDatePhoneCandidate(phone) ? phone : "";
}

function isShortAffirmativeToken(value = "") {
	const compact = normalizeIntentSearchText(value)
		.replace(/[^\p{L}\d]+/gu, "")
		.trim();
	if (!compact) return false;
	return new Set([
		"yes",
		"y",
		"ok",
		"okay",
		"sure",
		"correct",
		"confirm",
		"confirmed",
		"\u0646\u0639\u0645",
		"\u062a\u0645\u0627\u0645",
		"\u0627\u0643\u064a\u062f",
		"\u0627\u064a",
		"\u0623\u064a",
		"\u0627\u064a\u0648\u0646",
		"\u0623\u064a\u0648\u0646",
		"\u0627\u064a\u0648\u0647",
		"\u0623\u064a\u0648\u0647",
		"\u0627\u064a\u0648\u0627",
		"\u0623\u064a\u0648\u0627",
		"\u0627\u064a\u0648\u0629",
		"\u0623\u064a\u0648\u0629",
		"\u0627\u0647",
		"\u0623\u0647",
		"\u0622\u0647",
	]).has(compact);
}

function looksLikeActionOrConfirmationPhrase(value = "") {
	if (isShortAffirmativeToken(value)) return true;
	const text = cleanDisplayString(value, 160)
		.replace(/^[\s"'`*_]+|[\s"'`*_.!,;:؟،-]+$/g, "")
		.toLowerCase();
	if (!text) return true;
	if (
		/^(?:yes|yeah|yep|ok|okay|sure|correct|right|continue|proceed|go ahead|complete|book it|finalize|skip|no email)(?:\b|[\s,.!;:-])/i.test(
			text
		)
	) {
		return true;
	}
	return /^(?:\u0646\u0639\u0645|\u062a\u0645\u0627\u0645|\u062d\u0633\u0646\u0627|\u062d\u0633\u0646\u064b\u0627|\u0627\u0648\u0643|\u0623\u0648\u0643|\u062a\u0627\u0628\u0639|\u0627\u0643\u0645\u0644|\u0623\u0643\u0645\u0644|\u0627\u0633\u062a\u0645\u0631|\u0625\u062a\u0645\u0627\u0645|\u0627\u062a\u0645\u0627\u0645|\u0628\u062f\u0648\u0646 \u0628\u0631\u064a\u062f|\u0644\u0627 \u0628\u0631\u064a\u062f)(?:$|\b|[\s\u060C,.!;:-])/iu.test(
		text
	);
}

function normalizedSemanticPhrase(value = "") {
	return normalizeIntentSearchText(value)
		.replace(/[.!?\u061f\u060c,;:()[\]{}"'`*_+=/\\|-]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
}

function looksLikeClarificationOrConfusionPhrase(value = "") {
	const text = normalizedSemanticPhrase(value);
	if (!text) return false;
	const compact = text.replace(/\s+/g, "");
	const negation =
		/\b(?:not|no|dont|do not|can't|cant|cannot|never|pas|non|ne|nicht|kein|no entiendo|no comprendo)\b/i.test(
			text
		) ||
		/(?:^|\s)(?:\u0645\u0634|\u0645\u0648|\u0645\u0627|\u0644\u0627|\u0644\u0645|\u0645\u0628)(?:\s|$)/iu.test(
			text
		);
	const understanding =
		/\b(?:understand\w*|comprehend\w*|follow|clear|meaning|mean|confused|confusing|unclear|compren\w*|comprend\w*|compris|entiend\w*|entender|comprendo|capisc\w*|versteh\w*)\b/i.test(
			text
		) ||
		/(?:\u0641\u0647\u0645|\u0641\u0627\u0647\u0645|\u0641\u0627\u0647\u0645\u0629|\u0648\u0627\u0636\u062d|\u0642\u0635\u062f|\u0645\u0639\u0646\u0649|\u064a\u0639\u0646\u064a)/iu.test(
			text
		);
	if (negation && understanding) return true;
	return (
		/\b(?:what do you mean|what does that mean|meaning please|please clarify|can you clarify|i am confused|im confused|unclear)\b/i.test(
			text
		) ||
		/(?:\u0645\u0627\u0630\u0627\s+\u062a\u0639\u0646\u064a|\u0648\u0634\s+\u062a\u0642\u0635\u062f|\u0627\u064a\u0634\s+\u062a\u0642\u0635\u062f|\u064a\u0639\u0646\u064a\s+\u0627\u064a\u0647|\u0642\u0635\u062f\u0643\s+\u0627\u064a\u0647|\u0648\u0636\u062d|\u0627\u0644\u0645\u0642\u0635\u0648\u062f)/iu.test(
			compact
		)
	);
}

function looksLikeGuestCountClosurePhrase(value = "") {
	const text = normalizeNumberWordsForParsing(normalizedSemanticPhrase(value));
	if (!text) return false;
	const compact = text.replace(/\s+/g, "");
	const hasClosure =
		/\b(?:that|this|those|these|total|altogether|all|makes|equals|complete|done)\b/i.test(
			text
		) ||
		/(?:^|\s)(?:\u0643\u062f\u0647|\u0643\u0630\u0627|\u0628\u0643\u062f\u0647|\u0628\u0643\u0630\u0627|\u0647\u0643\u0630\u0627)(?:\s|$)/iu.test(
			text
		);
	const hasNumericValue =
		/(?:^|[^0-9])\d{1,3}(?:$|[^0-9])/.test(text) ||
		/(?:\u0627\u0644)?(?:\u0648\u0627\u062d\u062f|\u0627\u062b\u0646\u064a\u0646|\u0627\u062a\u0646\u064a\u0646|\u062b\u0644\u0627\u062b|\u0627\u0631\u0628\u0639|\u0623\u0631\u0628\u0639|\u062e\u0645\u0633|\u0633\u062a|\u0633\u0628\u0639|\u062b\u0645\u0627\u0646|\u062a\u0633\u0639|\u0639\u0634\u0631)/iu.test(
			compact
		);
	const hasGuestMeaning =
		/\b(?:guest|guests|person|people|adult|adults|child|children|kid|kids)\b/i.test(
			text
		) ||
		/(?:\u0636\u064a\u0648\u0641|\u0636\u064a\u0641|\u0627\u0634\u062e\u0627\u0635|\u0623\u0634\u062e\u0627\u0635|\u0627\u0641\u0631\u0627\u062f|\u0623\u0641\u0631\u0627\u062f|\u0628\u0627\u0644\u063a|\u0628\u0627\u0644\u063a\u064a\u0646|\u0637\u0641\u0644|\u0627\u0637\u0641\u0627\u0644|\u0623\u0637\u0641\u0627\u0644|\u0646\u0632\u0644\u0627\u0621)/iu.test(
			text
		);
	return hasClosure && (hasGuestMeaning || hasNumericValue);
}

function looksLikeNonBookingNamePhrase(value = "") {
	const text = cleanDisplayString(value, 160).replace(/^[\s:,-]+|[\s.,;:!-]+$/g, "");
	if (!text) return true;
	if (isShortAffirmativeToken(text)) return true;
	if (looksLikeClarificationOrConfusionPhrase(text)) return true;
	if (looksLikeGuestCountClosurePhrase(text)) return true;
	const normalized = normalizeIntentSearchText(text);
	const compact = normalized.replace(/\s+/g, "");
	if (
		/(?:\?|هل|يوجد|عندكم|فيه|فندق|الحرم|اتوبيس|أتوبيس|باص|حافلة|مواصلات|موقف|مواقف|مطعم|مطاعم|خدمة|خدمات|موقع|خريطة|عنوان|مسافة|مشيا|مشي|سيارة|غرفة|غرف|سعر|اسعار|الإجمالي|الاجمالي|\b(?:bus|shuttle|transport|haram|parking|restaurant|service|map|location|address|distance|walk|walking|car|room|hotel|price|total)\b)/iu.test(
			normalized
		) &&
		/(?:\?|هل|يوجد|عندكم|فيه|\b(?:do|does|is|are|can|where|how|what)\b)/iu.test(
			normalized
		)
	) {
		return true;
	}
	const nationality = normalizeNationalityHint(text) || nationalityFromText(text);
	if (
		nationality &&
		compact === normalizeIntentSearchText(nationality).replace(/\s+/g, "")
	) {
		return true;
	}
	if (guestDeclinesOptionalEmail(text, "")) return true;
	if (
		guestConfirms(text, "") ||
		guestWantsToContinueBooking(text, "") ||
		guestRequestsBookingReviewStep(text, "")
	) {
		return true;
	}
	if (/^(?:wrong|incorrect|mistake|bad|invalid|not correct)$/i.test(normalized)) {
		return true;
	}
	if (
		/(?:\b(?:you|u)\s+(?:know|already\s+know)\b|(?:\u0639\u0627\u0631\u0641|\u0639\u0627\u0631\u0641\u0629|\u0639\u0627\u0631\u0641\u0627\u0647|\u0639\u0627\u0631\u0641\u0627\u0647\u0627)|\u064a\u0627\s+(?:\u0639\u064a\u0634\u0629|\u0639\u0627\u0626\u0634\u0629|\u0627\u064a\u0645\u0627\u0646|\u0625\u064a\u0645\u0627\u0646|\u0631\u0627\u0646\u064a\u0627|\u0635\u0641\u064a\u0629|\u0635\u0641\u064a\u0647|\u0632\u064a\u0646\u0628|\u0644\u064a\u0646\u0627))/iu.test(
			normalized
		)
	) {
		return true;
	}
	if (/^(?:\u0627\u0646\u062a|\u0627\u0646\u062a\u064a|\u0627\u0646\u062a\u0649|\u062d\u0636\u0631\u062a\u0643|\u0645\u0646\u062a\u064a|\u0645\u0646\u062a\u0649|\u0645\u0627\u0646\u062a\u064a|\u0645\u0627\u0646\u062a\u0649)(?:\s|$)/iu.test(normalized)) {
		return true;
	}
	if (/^(?:\u062e\u0627\u0637\u0626|\u062e\u0627\u0637\u0649|\u062e\u0637\u0623|\u062e\u0637\u0627|\u063a\u0644\u0637|\u063a\u0644\u0637\u0627\u0646|\u063a\u064a\u0631\u0635\u062d\u064a\u062d|\u0645\u0634\u0635\u062d\u064a\u062d)$/iu.test(compact)) {
		return true;
	}
	if (
		/(?:^|\s)(?:\u0645\u0634|\u0645\u0648|\u0644\u064a\u0633|\u0644\u064a\u0633\u062a|not)(?:\s|$)/iu.test(
			normalized
		) &&
		/(?:\u0627\u0633\u0645|\u0627\u0633\u0645\u064a|\u0627\u0633\u0645\u0649|\u0627\u0644\u0627\u0633\u0645|\u0627\u0628\u0646|\u0627\u0628\u0646\u064a|\u0627\u0628\u0646\u0649|\u0628\u0646\u062a|\u0632\u0648\u062c|\u0627\u062e|\u0623\u062e|\u0627\u062e\u062a|\u0623\u062e\u062a)/iu.test(
			normalized
		)
	) {
		return true;
	}
	if (/\d/.test(normalizeDigits(text))) return true;
	if (
		new Set([
			"\u0643\u0627\u0646",
			"\u0643\u062f\u0627",
			"\u0643\u062f\u0647",
			"\u0643\u0630\u0627",
			"\u0645\u0627",
			"\u0645\u0627\u0639\u0644\u064a\u0646\u0627",
			"\u0645\u0627\u0634\u064a",
			"\u0645\u0627\u0634\u0649",
			"\u0627\u0644\u062d\u062c\u0632",
			"\u0627\u0628\u0646",
			"\u0627\u0628\u0646\u064a",
			"\u0627\u0628\u0646\u0649",
			"\u0627\u0628\u0646\u0643",
			"\u0628\u0646\u062a",
			"\u0628\u0646\u062a\u064a",
			"\u0628\u0646\u062a\u0649",
			"\u0645\u0634\u0627\u0628\u0646\u064a",
			"\u0645\u0634\u0627\u0628\u0646\u0649",
			"\u0627\u062a\u0645\u0627\u0645\u0627\u0644\u062d\u062c\u0632",
			"\u0625\u062a\u0645\u0627\u0645\u0627\u0644\u062d\u062c\u0632",
			"\u0627\u0631\u064a\u062f\u062a\u0639\u062f\u064a\u0644\u0634\u064a\u0621",
			"\u0623\u0631\u064a\u062f\u062a\u0639\u062f\u064a\u0644\u0634\u064a\u0621",
			"\u0647\u0646\u0627\u0643\u0634\u064a\u0621\u063a\u064a\u0631\u0635\u062d\u064a\u062d",
		]).has(compact)
	) {
		return true;
	}
	if (
		/^(?:\u0646\u062d\u0646|\u0627\u062d\u0646\u0627|\u0625\u062d\u0646\u0627|\u0627\u0646\u0627|\u0623\u0646\u0627|\u0645\u0639\u0627\u0643|\u0645\u0639\u0627\u0643\u064a|\u0645\u0639\u0627\u0643\u0649|\u0645\u0639\u0643)$/iu.test(
			compact
		)
	) {
		return true;
	}
	if (
		/^(?:ok|okay|sure|yes|yeah|yep|no|not|same|profile|visible|shown|displayed|name|one|haha+|lol)$/i.test(
			normalized
		)
	) {
		return true;
	}
	if (
		/^(?:\u0637\u0628|\u0637\u064a\u0628|\u062a\u0645\u0627\u0645|\u0627\u0643\u064a\u062f|\u0623\u0643\u064a\u062f|\u0627\u064a\u0648\u0647|\u0627\u064a\u0648\u0627|\u0646\u0639\u0645|\u0644\u0627|\u0645\u0634|\u0647\u0648|\u0647\u064a|\u0647\u0649|\u0646\u0641\u0633|\u0627\u0644\u0627\u0633\u0645|\u0627\u0633\u0645|\u0627\u0644\u0644\u064a|\u0627\u0644\u0644\u0649|\u0627\u0644\u064a|\u0627\u0644\u0649|\u0627\u0644\u0630\u064a|\u0634\u0627\u064a\u0641|\u0634\u0627\u064a\u0641\u0647|\u0634\u0627\u064a\u0641\u0627\u0647|\u0638\u0627\u0647\u0631|\u0628\u0627\u064a\u0646|\u0639\u0646\u062f\u0643|\u0639\u0646\u062f\u064a|\u0627\u0646\u062a|\u0627\u0646\u062a\u064a|\u0647+|\u0647\u0627+|هههه+)$/iu.test(
			compact
		)
	) {
		return true;
	}
	if (sameAsDisplayedNameIntent(text)) return true;
	if (
		/(?:\u0627\u0646\u0627|\u0623\u0646\u0627|\bme\b|\bmyself\b).{0,40}(?:\u0627\u0628\u0646\u064a|\u0627\u0628\u0646\u0649|\u0628\u0646\u062a\u064a|\u0628\u0646\u062a\u0649|\u0637\u0641\u0644\u064a|\u0637\u0641\u0644\u0649|\bson\b|\bdaughter\b|\bchild\b|\bkid\b)/iu.test(
			normalized
		) ||
		/(?:\u064a\u0627\s+(?:\u0627\u064a\u0645\u0627\u0646|\u0625\u064a\u0645\u0627\u0646|\u0646\u0648\u0631|\u0635\u0641\u064a\u0629|\u0635\u0641\u064a\u0647|\u0632\u064a\u0646\u0628)|\bdear\s+(?:eman|iman|zainab|noor|safiya)\b)/iu.test(
			normalized
		)
	) {
		return true;
	}
	if (/\d{1,2}\s*(?:\u0633\u0646\u0629|\u0633\u0646\u064a\u0646|\u0633\u0646\u0648\u0627\u062a|\u0639\u0627\u0645|\u0639\u0627\u0645\u0627|years?|yrs?|y\/?o)(?:$|[\s.,;:!?])/iu.test(normalized)) {
		return true;
	}
	return false;
}

function isPlausibleBookingName(value = "") {
	const text = cleanDisplayString(value, 120).replace(/^[\s:,-]+|[\s.,;:!-]+$/g, "");
	if (!text || text.length < 2 || text.length > 120) return false;
	if (looksLikeActionOrConfirmationPhrase(text)) return false;
	if (looksLikeNonBookingNamePhrase(text)) return false;
	if (looksLikeOrganizationName(text)) return false;
	if (text.includes("@")) return false;
	if (cleanPhone(text).replace(/[^\d]/g, "").length >= 7) return false;
	if (/(?:check.?in|checkout|arriv|depart|booking|reservation|confirmation|email|phone|nationality|room|hotel|price|total|\d{4}-\d{2}-\d{2})/i.test(text)) {
		return false;
	}
	if (!/[\p{L}]/u.test(text)) return false;
	if (text.split(/\s+/).length > 6) return false;
	return true;
}

function cleanEmail(value = "") {
	const email = String(value || "").trim().toLowerCase().slice(0, 160);
	return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) ? email : "";
}

function emailFromText(value = "") {
	const match = String(value || "").match(/[^\s<>()@]+@[^\s<>()@]+\.[^\s<>()@.,;:!?]+/i);
	return cleanEmail(match?.[0] || "");
}

function numberOrNull(value) {
	if (value === null || value === undefined || value === "") return null;
	const normalized = normalizeDigits(String(value)).replace(/[^\d.-]/g, "");
	const number = Number(normalized);
	return Number.isFinite(number) ? number : null;
}

function normalizeRoomCount(value, fallback = 1) {
	const n = numberOrNull(value);
	if (n === null) return Math.max(1, Math.min(MAX_AI_ROOM_COUNT, fallback || 1));
	return Math.max(1, Math.min(MAX_AI_ROOM_COUNT, Math.floor(n)));
}

function normalizeRoomSelections(value = []) {
	const source = Array.isArray(value) ? value : [];
	const merged = new Map();
	for (const item of source) {
		const key =
			mapRoomToKey(item?.roomTypeKey || item?.roomType || item?.type || item?.label || "") ||
			(ROOM_TYPE_KEYS.includes(String(item?.roomTypeKey || "")) ? item.roomTypeKey : "");
		if (!key || !ROOM_TYPE_KEYS.includes(key)) continue;
		const count = normalizeRoomCount(item?.count ?? item?.rooms ?? item?.quantity, 1);
		const roomId = cleanString(item?.roomId || item?._id || item?.id, 80);
		const mergeKey = roomId ? `id:${roomId}` : `type:${key}`;
		const existing = merged.get(mergeKey) || {};
		merged.set(mergeKey, {
			roomTypeKey: key,
			count: normalizeRoomCount((existing.count || 0) + count, count),
			...(roomId ? { roomId } : {}),
			...(cleanDisplayString(
				item?.roomDisplayName || item?.displayName || item?.display_name || existing.roomDisplayName,
				160
			)
				? {
						roomDisplayName: cleanDisplayString(
							item?.roomDisplayName ||
								item?.displayName ||
								item?.display_name ||
								existing.roomDisplayName,
							160
						),
				  }
				: {}),
			...(Number(item?.capacityGuests || existing.capacityGuests) > 0
				? { capacityGuests: Number(item?.capacityGuests || existing.capacityGuests) }
				: {}),
			...(Number(item?.totalRooms || existing.totalRooms) >= 0 &&
			Number.isFinite(Number(item?.totalRooms ?? existing.totalRooms))
				? { totalRooms: Number(item?.totalRooms ?? existing.totalRooms) }
				: {}),
			...(cleanString(item?.pricingUnit || existing.pricingUnit, 40)
				? { pricingUnit: cleanString(item?.pricingUnit || existing.pricingUnit, 40) }
				: {}),
		});
	}
	return Array.from(merged.values());
}

function roomSelectionsTotal(selections = []) {
	return normalizeRoomSelections(selections).reduce(
		(total, item) => total + normalizeRoomCount(item.count, 1),
		0
	);
}

function roomSelectionKey(selections = []) {
	return normalizeRoomSelections(selections)
		.map(
			(item) =>
				`${item.roomId ? `id:${item.roomId}` : `type:${item.roomTypeKey}`}:${normalizeRoomCount(
					item.count,
					1
				)}`
		)
		.sort()
		.join("+");
}

function normalizeRoomCountMarkers(value = "") {
	return String(value || "").replace(/[×✕✖]/g, "x");
}

function stripDateTokensForRoomParsing(value = "") {
	return String(value || "")
		.replace(/\b\d{4}\s*[-/]\s*\d{1,2}\s*[-/]\s*\d{1,2}\b/g, " ")
		.replace(/\b\d{1,2}\s*[-/]\s*\d{1,2}\s*[-/]\s*\d{2,4}\b/g, " ");
}

function quoteRoomCount(quote = {}) {
	if (Array.isArray(quote.rooms)) {
		return roomSelectionsTotal(quote.rooms);
	}
	return normalizeRoomCount(quote.totalRooms ?? quote.roomCount ?? quote.rooms, 1);
}

function selectionsFromKnown(known = {}) {
	const explicit = normalizeRoomSelections(known.roomSelections);
	if (explicit.length) return explicit;
	if (!known.roomTypeKey) return [];
	return [
		{
			roomTypeKey: known.roomTypeKey,
			count: normalizeRoomCount(known.rooms, 1),
		},
	];
}

const ROOM_SELECTION_PATTERNS = [
	{
		key: "singleRooms",
		pattern:
			/(?:single|standard\s+single|\u0641\u0631\u062f\u064a\u0629|\u0641\u0631\u062f\u064a|\u0633\u0646\u062c\u0644)/i,
	},
	{
		key: "doubleRooms",
		pattern:
			/(?:double|twin|standard|two\s+beds?|2\s*beds?|\u0645\u0632\u062f\u0648\u062c\u0629|\u0645\u0632\u062f\u0648\u062c|\u0645\u0632\u0648\u062c\u0629|\u0645\u0632\u0648\u062c\u0647|\u0645\u0632\u0648\u062c|\u062f\u0628\u0644|\u062f\u0627\u0628\u0644|\u062b\u0646\u0627\u0626\u064a\u0629|\u062b\u0646\u0627\u0626\u064a|2\s*(?:\u0633\u0631\u064a\u0631|\u0633\u0631\u0627\u064a\u0631|\u0627\u0633\u0631\u0629|\u0627\u0633\u0631\u0647|\u0627\u0633\u0631))/i,
	},
	{
		key: "tripleRooms",
		pattern:
			/(?:triple|three\s+beds?|3\s*beds?|\u062b\u0644\u0627\u062b\u064a\u0629|\u062b\u0644\u0627\u062b\u064a|\u062b\u0644\u0627\u062b\u0649|\u062a\u0644\u0627\u062a\u064a|\u062a\u0644\u0627\u062a\u0649|3\s*(?:\u0633\u0631\u064a\u0631|\u0633\u0631\u0627\u064a\u0631|\u0627\u0633\u0631\u0629|\u0627\u0633\u0631\u0647|\u0627\u0633\u0631))/i,
	},
	{
		key: "quadRooms",
		pattern:
			/(?:quadruple|quad|four\s+beds?|4\s*beds?|\u0631\u0628\u0627\u0639\u064a\u0629|\u0631\u0628\u0627\u0639\u064a|\u0631\u0628\u0627\u0639\u0649|4\s*(?:\u0633\u0631\u064a\u0631|\u0633\u0631\u0627\u064a\u0631|\u0627\u0633\u0631\u0629|\u0627\u0633\u0631\u0647|\u0627\u0633\u0631))/i,
	},
	{
		key: "familyRooms",
		pattern:
			/(?:family|quintuple|sextuple|five\s+beds?|six\s+beds?|[56]\s*beds?|\u0639\u0627\u0626\u0644\u064a\u0629|\u0639\u0627\u0626\u0644\u064a|\u062e\u0645\u0627\u0633\u064a\u0629|\u062e\u0645\u0627\u0633\u064a|\u0633\u062f\u0627\u0633\u064a\u0629|\u0633\u062f\u0627\u0633\u064a|[56]\s*(?:\u0633\u0631\u064a\u0631|\u0633\u0631\u0627\u064a\u0631|\u0627\u0633\u0631\u0629|\u0627\u0633\u0631\u0647|\u0627\u0633\u0631))/i,
	},
	{ key: "suite", pattern: /(?:suite|\u062c\u0646\u0627\u062d)/i },
];

function explicitNamedRoomSelectionsFromText(value = "") {
	const source = normalizeNumberWordsForParsing(normalizeDigits(String(value || "")))
		.replace(/[.!?\u061f\u060c,;:]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	const rawSource = normalizeDigits(String(value || ""))
		.replace(/[.!?\u061f\u060c,;:]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	const sources = Array.from(new Set([source, rawSource].filter(Boolean)));
	if (!sources.length) return [];
	const roomNoun =
		"(?:rooms?|room|units?|unit|\\u063a\\u0631\\u0641|\\u063a\\u0631\\u0641\\u0629|\\u063a\\u0631\\u0641\\u0647|\\u0627\\u0648\\u0636|\\u0627\\u0648\\u0636\\u0629|\\u0627\\u0648\\u0636\\u0647)";
	const typePatterns = {
		singleRooms: "(?:single|standard\\s+single|\\u0641\\u0631\\u062f\\u064a\\u0629|\\u0641\\u0631\\u062f\\u064a|\\u0633\\u0646\\u062c\\u0644)",
		doubleRooms: "(?:double|twin|standard|\\u0645\\u0632\\u062f\\u0648\\u062c\\u0629|\\u0645\\u0632\\u062f\\u0648\\u062c|\\u0645\\u0632\\u0648\\u062c\\u0629|\\u0645\\u0632\\u0648\\u062c\\u0647|\\u0645\\u0632\\u0648\\u062c|\\u062f\\u0628\\u0644|\\u062f\\u0627\\u0628\\u0644|\\u062b\\u0646\\u0627\\u0626\\u064a\\u0629|\\u062b\\u0646\\u0627\\u0626\\u064a)",
		tripleRooms: "(?:triple|\\u062b\\u0644\\u0627\\u062b\\u064a\\u0629|\\u062b\\u0644\\u0627\\u062b\\u064a|\\u062b\\u0644\\u0627\\u062b\\u0649|\\u062a\\u0644\\u0627\\u062a\\u064a|\\u062a\\u0644\\u0627\\u062a\\u0649)",
		quadRooms: "(?:quadruple|quad|\\u0631\\u0628\\u0627\\u0639\\u064a\\u0629|\\u0631\\u0628\\u0627\\u0639\\u064a|\\u0631\\u0628\\u0627\\u0639\\u0649)",
		familyRooms: "(?:family|quintuple|sextuple|\\u0639\\u0627\\u0626\\u0644\\u064a\\u0629|\\u0639\\u0627\\u0626\\u0644\\u064a|\\u062e\\u0645\\u0627\\u0633\\u064a\\u0629|\\u062e\\u0645\\u0627\\u0633\\u064a|\\u0633\\u062f\\u0627\\u0633\\u064a\\u0629|\\u0633\\u062f\\u0627\\u0633\\u064a)",
	};
	const selections = [];
	for (const [roomTypeKey, typePattern] of Object.entries(typePatterns)) {
		const patterns = [
			new RegExp(`(?:^|[^0-9/\\-])(\\d{1,3})(?![0-9/\\-])\\s*(?:x\\s*)?${roomNoun}\\s+(?:.{0,12}\\s+)?${typePattern}(?=$|\\s|[^\\p{L}0-9])`, "iu"),
			new RegExp(`(?:^|[^0-9/\\-])(\\d{1,3})(?![0-9/\\-])\\s*(?:x\\s*)?${typePattern}\\s+(?:.{0,12}\\s+)?${roomNoun}(?=$|\\s|[^\\p{L}0-9])`, "iu"),
		];
		for (const pattern of patterns) {
			let matched = false;
			for (const candidate of sources) {
				const match = candidate.match(pattern);
				const count = Number(match?.[1] || 0);
				if (Number.isFinite(count) && count >= 1 && count <= MAX_AI_ROOM_COUNT) {
					selections.push({ roomTypeKey, count: normalizeRoomCount(count, 1) });
					matched = true;
					break;
				}
			}
			if (matched) break;
		}
	}
	return normalizeRoomSelections(selections);
}

function roomCountNearMatch(text = "", matcher) {
	const rawDualRoomCount = arabicDualRoomCountFromText(text);
	if (rawDualRoomCount && !suiteCompositionText(text)) return rawDualRoomCount;
	const normalized = stripDateTokensForRoomParsing(
		normalizeNumberWordsForParsing(normalizeDigits(text))
	);
	const source = normalizeRoomCountMarkers(normalized).replace(/\s+/g, " ").trim();
	if (!source || !matcher?.pattern) return 1;
	const dualRoomCount = arabicDualRoomCountFromText(source);
	if (dualRoomCount && !suiteCompositionText(source)) return dualRoomCount;
	const roomNoun =
		"(?:rooms?|room|units?|unit|\\u063a\\u0631\\u0641|\\u063a\\u0631\\u0641\\u0629|\\u063a\\u0631\\u0641\\u0647|\\u0627\\u0648\\u0636|\\u0627\\u0648\\u0636\\u0629|\\u0627\\u0648\\u0636\\u0647)";
	const patternSource = matcher.pattern.source;
	const before = source.match(
		new RegExp(`(?:^|[^0-9])(\\d{1,3})\\s*(?:x\\s*)?(?:${roomNoun}\\s+)?${patternSource}`, "i")
	);
	if (before?.[1]) return normalizeRoomCount(before[1], 1);
	const beforeNoun = source.match(
		new RegExp(`(?:^|[^0-9])(\\d{1,3})\\s*${roomNoun}.{0,32}${patternSource}`, "i")
	);
	if (beforeNoun?.[1]) return normalizeRoomCount(beforeNoun[1], 1);
	const after = source.match(
		new RegExp(`${patternSource}.{0,32}(?:^|[^0-9])(\\d{1,3})\\s*${roomNoun}`, "i")
	);
	if (after?.[1]) return normalizeRoomCount(after[1], 1);
	return 1;
}

function arabicDualRoomCountFromText(value = "") {
	const compact = normalizeIntentSearchText(value).replace(/\s+/g, "");
	return /(?:\u063a\u0631\u0641(?:\u062a\u064a\u0646|\u062a\u0627\u0646)|\u0627\u0648\u0636(?:\u062a\u064a\u0646|\u062a\u0627\u0646)|\u062d\u062c\u0631(?:\u062a\u064a\u0646|\u062a\u0627\u0646))/.test(
		compact
	)
		? 2
		: null;
}

function suiteCompositionText(value = "") {
	const text = normalizeIntentSearchTextRepaired(value)
		.replace(/[.!?\u061f\u060c,;:()]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!text) return false;
	const compact = text.replace(/\s+/g, "");
	const hasSuite =
		/\bsuites?\b/i.test(text) ||
		/(?:\u0627?\u0644?\u062c\u0646\u0627\u062d|\u0627?\u062c\u0646\u062d\u0629|\u0623\u062c\u0646\u062d\u0629|\u0633\u0648\u064a\u062a|\u0627\u0633\u0648\u064a\u062a)/iu.test(
			compact
		);
	if (!hasSuite) return false;
	return (
		/\b(?:contains?|includes?|consists?|with)\b/i.test(text) ||
		/(?:\u064a\u062d\u062a\u0648\u064a|\u064a\u062d\u062a\u0648\u0649|\u062a\u062d\u062a\u0648\u064a|\u062a\u062d\u062a\u0648\u0649|\u064a\u062a\u0643\u0648\u0646|\u062a\u062a\u0643\u0648\u0646|\u0645\u0643\u0648\u0646|\u0645\u0643\u0648\u0646\u0629|\u0639\u0628\u0627\u0631\u0629|\+|\u062d\u0645\u0627\u0645|\u062d\u0645\u0627\u0645\u064a\u0646)/iu.test(
			text
		)
	);
}

function roomCountOnlyFromText(value = "") {
	if (roomCapacityStatementOnly(value)) return null;
	const rawDualRoomCount = arabicDualRoomCountFromText(value);
	if (rawDualRoomCount && !suiteCompositionText(value)) return rawDualRoomCount;
	const source = normalizeRoomCountMarkers(
		stripDateTokensForRoomParsing(
			normalizeNumberWordsForParsing(normalizeDigits(String(value || "")))
		)
	)
		.replace(/\s+/g, " ")
		.trim();
	if (!source) return null;
	const dualRoomCount = arabicDualRoomCountFromText(source);
	if (dualRoomCount && !suiteCompositionText(source)) return dualRoomCount;
	const roomNoun =
		"(?:rooms?|room|units?|unit|\\u063a\\u0631\\u0641|\\u063a\\u0631\\u0641\\u0629|\\u063a\\u0631\\u0641\\u0647|\\u0627\\u0648\\u0636|\\u0627\\u0648\\u0636\\u0629|\\u0627\\u0648\\u0636\\u0647)";
	const guestNoun =
		"(?:guests?|persons?|people|adults?|pax|individuals?|pilgrims?|\\u0627\\u0634\\u062e\\u0627\\u0635|\\u0623\\u0634\\u062e\\u0627\\u0635|\\u0627\\u0641\\u0631\\u0627\\u062f|\\u0623\\u0641\\u0631\\u0627\\u062f|\\u0646\\u0632\\u0644\\u0627\\u0621|\\u0636\\u064a\\u0648\\u0641|\\u0628\\u0627\\u0644\\u063a\\u064a\\u0646|\\u0628\\u0627\\u0644\\u063a|\\u0643\\u0628\\u0627\\u0631|\\u0645\\u0639\\u062a\\u0645\\u0631\\u064a\\u0646|\\u0645\\u0639\\u062a\\u0645\\u0631|\\u0632\\u0648\\u0627\\u0631)";
	if (
		new RegExp(
			`${roomNoun}.{0,24}(?:fit|fits|sleep|sleeps|accommodate|accommodates|capacity|hold|holds|\\u062a\\u0633\\u0639|\\u064a\\u0633\\u0639|\\u062a\\u062a\\u0633\\u0639|\\u062a\\u0643\\u0641\\u064a|\\u062a\\u0633\\u062a\\u0648\\u0639\\u0628).{0,16}\\d{1,3}\\s*${guestNoun}(?:$|\\s|[^\\p{L}0-9])`,
			"iu"
		).test(source)
	) {
		return null;
	}
	if (
		new RegExp(`${roomNoun}\\s*\\d{1,3}\\s*${guestNoun}(?:$|\\s|[^\\p{L}0-9])`, "iu").test(
			source
		)
	) {
		return null;
	}
	const explicitCountBeforeRoom = new RegExp(
		`(?:^|[^0-9])(\\d{1,3})\\s*(?:x\\s*)?${roomNoun}(?:$|\\s|[^\\p{L}0-9])`,
		"iu"
	).test(source);
	const rawForPeople = normalizeIntentSearchText(value).replace(/\s+/g, " ").trim();
	const roomForPeopleOnly =
		/(?:room|unit|\u063a\u0631\u0641\u0629|\u063a\u0631\u0641\u0647|\u0627\u0648\u0636\u0629|\u0627\u0648\u0636\u0647).{0,32}(?:for|pour|para|\u0644\s*)\s*(?:\d{1,2}\s*)?(?:people|persons|guests|adults|\u0634\u062e\u0635|\u0634\u062e\u0635\u064a\u0646|\u0634\u062e\u0635\u0627\u0646|\u0627\u0634\u062e\u0627\u0635|\u0623\u0634\u062e\u0627\u0635|\u0636\u064a\u0648\u0641|\u0646\u0632\u0644\u0627\u0621|\u0628\u0627\u0644\u063a|\u0628\u0627\u0644\u063a\u064a\u0646|\u0641\u0631\u062f|\u0641\u0631\u062f\u064a\u0646|\u0646\u0632\u064a\u0644|\u0646\u0632\u064a\u0644\u064a\u0646|\u0636\u064a\u0641|\u0636\u064a\u0641\u064a\u0646)/iu.test(rawForPeople);
	if (!explicitCountBeforeRoom && roomForPeopleOnly) return null;
	const match =
		source.match(new RegExp(`(?:^|[^0-9])(\\d{1,3})\\s*(?:x\\s*)?${roomNoun}(?:$|\\s|[^\\p{L}0-9])`, "iu")) ||
		source.match(new RegExp(`${roomNoun}\\s*(\\d{1,3})(?:$|\\s|[^\\p{L}0-9])`, "iu"));
	const count = Number(match?.[1] || 0);
	if (!Number.isFinite(count) || count < 1 || count > MAX_AI_ROOM_COUNT) return null;
	return normalizeRoomCount(count, 1);
}

function roomCountRequestLimitExceeded(value = "") {
	const source = normalizeRoomCountMarkers(
		stripDateTokensForRoomParsing(
			normalizeNumberWordsForParsing(normalizeDigits(String(value || "")))
		)
	)
		.replace(/[.!?\u061f\u060c,;:]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!source) return false;
	if (/^\d{1,3}$/.test(source) && Number(source) > MAX_AI_ROOM_COUNT) return true;
	const roomNoun =
		"(?:rooms?|room|units?|unit|\\u063a\\u0631\\u0641|\\u063a\\u0631\\u0641\\u0629|\\u063a\\u0631\\u0641\\u0647|\\u0627\\u0648\\u0636|\\u0627\\u0648\\u0636\\u0629|\\u0627\\u0648\\u0636\\u0647)";
	const typeLabel =
		"(?:single|double|twin|triple|quad|quadruple|family|quintuple|sextuple|suite|\\u0641\\u0631\\u062f\\u064a(?:\\u0629)?|\\u0645\\u0632\\u062f\\u0648\\u062c(?:\\u0629)?|\\u062b\\u0644\\u0627\\u062b\\u064a(?:\\u0629)?|\\u0631\\u0628\\u0627\\u0639\\u064a(?:\\u0629)?|\\u0639\\u0627\\u0626\\u0644\\u064a(?:\\u0629)?|\\u062e\\u0645\\u0627\\u0633\\u064a(?:\\u0629)?|\\u0633\\u062f\\u0627\\u0633\\u064a(?:\\u0629)?)";
	const pattern = new RegExp(
		`(?:^|[^0-9/\\-])(\\d{1,4})(?![0-9/\\-])\\s*(?:x\\s*)?(?:${typeLabel}\\s+)?${roomNoun}|(?:${typeLabel}\\s+)?${roomNoun}\\s*(?:[:x-]\\s*)?(\\d{1,4})(?![0-9/\\-])`,
		"giu"
	);
	const counts = Array.from(source.matchAll(pattern))
		.map((match) => Number(match[1] || match[2] || 0))
		.filter((count) => Number.isFinite(count) && count > 0);
	if (counts.some((count) => count > MAX_AI_ROOM_COUNT)) return true;
	const explicitSelections = explicitNamedRoomSelectionsFromText(source);
	const explicitTotal = roomSelectionsTotal(explicitSelections);
	if (explicitTotal > MAX_AI_ROOM_COUNT) return true;
	return counts.length > 1 && counts.reduce((total, count) => total + count, 0) > MAX_AI_ROOM_COUNT;
}

function knownRoomCountRequestLimitExceeded(known = {}) {
	const selections = Array.isArray(known?.roomSelections) ? known.roomSelections : [];
	const rawCounts = selections
		.map((selection) => Number(selection?.count ?? selection?.rooms ?? selection?.quantity ?? 0))
		.filter((count) => Number.isFinite(count) && count > 0);
	if (rawCounts.some((count) => count > MAX_AI_ROOM_COUNT)) return true;
	if (rawCounts.reduce((total, count) => total + Math.floor(count), 0) > MAX_AI_ROOM_COUNT) {
		return true;
	}
	const rooms = Number(known?.rooms || 0);
	return Number.isFinite(rooms) && rooms > MAX_AI_ROOM_COUNT;
}

function requestedBedCountFromText(value = "") {
	const source = normalizeRoomCountMarkers(
		stripDateTokensForRoomParsing(
			normalizeNumberWordsForParsing(normalizeDigits(String(value || "")))
		)
	)
		.replace(/[.!?\u061f\u060c,;:]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!source) return 0;
	const bedNoun =
		"(?:beds?|single\\s+beds?|\\u0633\\u0631\\u064a\\u0631|\\u0633\\u0631\\u0627\\u064a\\u0631|\\u0627\\u0633\\u0631\\u0629|\\u0623\\u0633\\u0631\\u0629|\\u0627\\u0633\\u0631\\u0647|\\u0623\\u0633\\u0631\\u0647)";
	const patterns = [
		new RegExp(`(?:^|[^0-9])(\\d{1,2})\\s*${bedNoun}(?=$|\\s|[^\\p{L}0-9])`, "iu"),
		new RegExp(`${bedNoun}\\s*(\\d{1,2})(?=$|\\s|[^\\p{L}0-9])`, "iu"),
	];
	for (const pattern of patterns) {
		const match = source.match(pattern);
		const count = Number(match?.[1] || 0);
		if (Number.isFinite(count) && count >= 1 && count <= 30) {
			return Math.floor(count);
		}
	}
	return 0;
}

function roomCountCorrectionFromText(value = "") {
	if (roomCapacityStatementOnly(value)) return null;
	const rawDualRoomCount = arabicDualRoomCountFromText(value);
	if (rawDualRoomCount && !suiteCompositionText(value)) return rawDualRoomCount;
	const source = normalizeRoomCountMarkers(
		normalizeNumberWordsForParsing(normalizeDigits(String(value || "")))
	)
		.replace(/[.!?\u061f\u060c,]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!source) return null;
	const dualRoomCount = arabicDualRoomCountFromText(source);
	if (dualRoomCount && !suiteCompositionText(source)) return dualRoomCount;
	const roomNoun =
		"(?:rooms?|room|units?|unit|\\u063a\\u0631\\u0641|\\u063a\\u0631\\u0641\\u0629|\\u063a\\u0631\\u0641\\u0647|\\u0627\\u0648\\u0636|\\u0627\\u0648\\u0636\\u0629|\\u0627\\u0648\\u0636\\u0647)";
	const roomCountContext = new RegExp(
		`(?:number\\s+of\\s+${roomNoun}|${roomNoun}\\s+count|\\u0639\\u062f\\u062f\\s+(?:\\u0627\\u0644)?${roomNoun}|${roomNoun}\\s+(?:\\u0646\\u0641\\u0633\\u0647|\\u0646\\u0641\\u0633\\u0647\\u0627|same))`,
		"iu"
	);
	const explicitSingleRoomCorrection = [
		new RegExp(
			`(?:^|\\s)1\\s+(?:[\\p{L}-]+\\s+){0,3}${roomNoun}(?=$|\\s|[^\\p{L}0-9])`,
			"iu"
		),
		new RegExp(
			`${roomNoun}(?:\\s+[\\p{L}-]+){0,3}\\s+1(?=$|\\s|[^\\p{L}0-9])`,
			"iu"
		),
	];
	if (explicitSingleRoomCorrection.some((pattern) => pattern.test(source))) {
		return 1;
	}
	if (!roomCountContext.test(source)) return null;
	const numberPatterns = [
		/(?:want|need|make|change|update|become|set|عايز|عاوز|اريد|أريد|نريد|نبغى|ابغى|خليها|خلّيها|غيرها|غيّرها|عدل|عدّل)\s*(?:الى|إلى|to)?\s*(\d{1,3})/iu,
		/(\d{1,3})\s*(?:rooms?|room|units?|unit|\u063a\u0631\u0641|\u063a\u0631\u0641\u0629|\u063a\u0631\u0641\u0647|\u0627\u0648\u0636|\u0627\u0648\u0636\u0629|\u0627\u0648\u0636\u0647)/iu,
		/(?:rooms?|room|units?|unit|\u063a\u0631\u0641|\u063a\u0631\u0641\u0629|\u063a\u0631\u0641\u0647|\u0627\u0648\u0636|\u0627\u0648\u0636\u0629|\u0627\u0648\u0636\u0647)\s*(\d{1,3})/iu,
		/(\d{1,3})(?:\s|$)/u,
	];
	for (const pattern of numberPatterns) {
		const match = source.match(pattern);
		const count = Number(match?.[1] || 0);
		if (Number.isFinite(count) && count >= 1 && count <= MAX_AI_ROOM_COUNT) {
			return normalizeRoomCount(count, 1);
		}
	}
	return null;
}

function preserveImplicitRoomCount(roomSelections = [], known = {}, latestText = "") {
	const selections = normalizeRoomSelections(roomSelections);
	if (!selections.length) return selections;
	if (roomCountOnlyFromText(latestText)) return selections;
	if (selections.length !== 1 || normalizeRoomCount(selections[0].count, 1) !== 1) {
		return selections;
	}
	const previousRooms = Math.max(
		normalizeRoomCount(known.rooms, 1),
		roomSelectionsTotal(known.roomSelections)
	);
	if (previousRooms <= 1) return selections;
	return [{ ...selections[0], count: previousRooms }];
}

function textMentionsRoomSelection(value = "") {
	const text = normalizeNumberWordsForParsing(normalizeIntentSearchText(value))
		.replace(/[.!?\u061f\u060c,]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!text) return false;
	if (
		/\b(?:rooms?|units?|suite|suites?|single|double|twin|triple|quad|quadruple|family|quintuple|beds?|chambres?|personnes?|adultes?|hommes?|voyageurs?)\b/i.test(
			text
		)
	) {
		return true;
	}
	const compact = text.replace(/\s+/g, "");
	return [
		"\u063a\u0631\u0641",
		"\u063a\u0631\u0641\u0629",
		"\u063a\u0631\u0641\u0647",
		"\u0627\u0648\u0636",
		"\u0627\u0648\u0636\u0629",
		"\u0627\u0648\u0636\u0647",
		"\u062d\u062c\u0631\u0629",
		"\u062d\u062c\u0631\u0647",
		"\u0633\u0631\u064a\u0631",
		"\u0627\u0633\u0631\u0629",
		"\u0627\u0633\u0631\u0647",
		"\u0641\u0631\u062f\u064a",
		"\u0633\u0646\u062c\u0644",
		"\u0645\u0632\u062f\u0648\u062c",
		"\u062b\u0646\u0627\u0626\u064a",
		"\u062f\u0628\u0644",
		"\u062f\u0627\u0628\u0644",
		"\u062b\u0644\u0627\u062b\u064a",
		"\u062b\u0644\u0627\u062b\u0649",
		"\u062a\u0644\u0627\u062a\u064a",
		"\u062a\u0644\u0627\u062a\u0649",
		"\u0631\u0628\u0627\u0639\u064a",
		"\u0631\u0628\u0627\u0639\u0649",
		"\u0639\u0627\u0626\u0644\u064a",
		"\u062e\u0645\u0627\u0633\u064a",
		"\u062c\u0646\u0627\u062d",
	].some((needle) => compact.includes(needle));
}

function roomCapacityStatementOnly(value = "") {
	const text = normalizeDigits(String(value || ""))
		.replace(/[.!?\u061f\u060c,;:]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!text) return false;
	const roomNoun =
		"(?:rooms?|room|units?|unit|\\u063a\\u0631\\u0641|\\u063a\\u0631\\u0641\\u0629|\\u063a\\u0631\\u0641\\u0647|\\u0627\\u0648\\u0636|\\u0627\\u0648\\u0636\\u0629|\\u0627\\u0648\\u0636\\u0647)";
	const capacityVerb =
		"(?:fit|fits|sleep|sleeps|accommodate|accommodates|capacity|hold|holds|enough|\\u062a\\u0633\\u0639|\\u064a\\u0633\\u0639|\\u062a\\u062a\\u0633\\u0639|\\u062a\\u0643\\u0641\\u064a|\\u064a\\u0643\\u0641\\u064a|\\u062a\\u0633\\u062a\\u0648\\u0639\\u0628)";
	const guestNoun =
		"(?:guests?|persons?|people|adults?|pax|individuals?|pilgrims?|\\u0627\\u0634\\u062e\\u0627\\u0635|\\u0623\\u0634\\u062e\\u0627\\u0635|\\u0627\\u0641\\u0631\\u0627\\u062f|\\u0623\\u0641\\u0631\\u0627\\u062f|\\u0646\\u0632\\u0644\\u0627\\u0621|\\u0636\\u064a\\u0648\\u0641|\\u0628\\u0627\\u0644\\u063a\\u064a\\u0646|\\u0628\\u0627\\u0644\\u063a|\\u0643\\u0628\\u0627\\u0631|\\u0645\\u0639\\u062a\\u0645\\u0631\\u064a\\u0646|\\u0645\\u0639\\u062a\\u0645\\u0631|\\u0632\\u0648\\u0627\\u0631)";
	const guestCount =
		"(?:\\d{1,3}|one|two|three|four|five|six|\\u0648\\u0627\\u062d\\u062f|\\u0648\\u0627\\u062d\\u062f\\u0629|\\u0627\\u062b\\u0646\\u064a\\u0646|\\u0627\\u062b\\u0646\\u0627\\u0646|\\u062b\\u0644\\u0627\\u062b|\\u062b\\u0644\\u0627\\u062b\\u0629|\\u062b\\u0644\\u0627\\u062b\\u0647|\\u0623\\u0631\\u0628\\u0639|\\u0627\\u0631\\u0628\\u0639|\\u0623\\u0631\\u0628\\u0639\\u0629|\\u0627\\u0631\\u0628\\u0639\\u0629|\\u062e\\u0645\\u0633|\\u062e\\u0645\\u0633\\u0629|\\u062e\\u0645\\u0633\\u0647|\\u0633\\u062a|\\u0633\\u062a\\u0629|\\u0633\\u062a\\u0647)";
	const roomBeforeCapacity = new RegExp(
		`${roomNoun}.{0,24}${capacityVerb}.{0,16}${guestCount}\\s*${guestNoun}(?:$|\\s|[^\\p{L}0-9])`,
		"iu"
	).test(text);
	const capacityBeforeRoom = new RegExp(
		`${capacityVerb}.{0,28}${roomNoun}.{0,28}${guestCount}\\s*${guestNoun}(?:$|\\s|[^\\p{L}0-9])`,
		"iu"
	).test(text);
	const guestBeforeRoom = new RegExp(
		`(?:can|could|may|would|is\\s+it\\s+possible|\\u0647\\u0644|\\u0645\\u0645\\u0643\\u0646).{0,16}${guestCount}\\s*${guestNoun}.{0,20}(?:stay|sleep|fit|\\u064a\\u0642\\u064a\\u0645|\\u064a\\u0646\\u0627\\u0645|\\u064a\\u0633\\u0643\\u0646).{0,24}${roomNoun}`,
		"iu"
	).test(text);
	return roomBeforeCapacity || capacityBeforeRoom || guestBeforeRoom;
}

function textMentionsSpecificRoomType(value = "") {
	if (roomCapacityStatementOnly(value)) return false;
	const text = normalizeNumberWordsForParsing(normalizeIntentSearchText(value))
		.replace(/[.!?\u061f\u060c,]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!text) return false;
	if (ROOM_SELECTION_PATTERNS.some((matcher) => matcher.pattern.test(text))) return true;
	if (/\b(?:room\s+for\s+0?[2-5]|rooms\s+for\s+0?[2-5]|chambres?\s+(?:pour|de)\s+0?[2-5]|0?[2-5]\s+(?:beds?|people|persons?|guests?|adults?|personnes?|adultes?|hommes?|voyageurs?))\b/i.test(text)) {
		return true;
	}
	const compact = text.replace(/\s+/g, "");
	return /(?:\u0634\u062e\u0635\u064a\u0646|\u0641\u0631\u062f\u064a\u0646|\u0636\u064a\u0641\u064a\u0646|\u0633\u0631\u064a\u0631\u064a\u0646|\u0627\u0633\u0631\u062a\u064a\u0646|\u062b\u0644\u0627\u062b(?:\u0629|\u0647)?(?:\u0633\u0631\u064a\u0631|\u0627\u0633\u0631)|\u062a\u0644\u0627\u062a(?:\u0629|\u0647)?(?:\u0633\u0631\u064a\u0631|\u0627\u0633\u0631)|\u0627?\u0631\u0628\u0639(?:\u0629|\u0647)?(?:\u0633\u0631\u064a\u0631|\u0627\u0633\u0631)|\u062e\u0645\u0633(?:\u0629|\u0647)?(?:\u0633\u0631\u064a\u0631|\u0627\u0633\u0631)|[2-5](?:\u0633\u0631\u064a\u0631|\u0627\u0633\u0631|\u0627\u0634\u062e\u0627\u0635|\u0627\u0641\u0631\u0627\u062f|\u0636\u064a\u0648\u0641|\u0628\u0627\u0644\u063a\u064a\u0646))/.test(
		compact
	);
}

function textMentionsNamedRoomType(value = "") {
	const text = normalizeNumberWordsForParsing(normalizeIntentSearchText(value))
		.replace(/[.!?\u061f\u060c,]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!text) return false;
	if (/\b(?:single|standard\s+single|double|twin|triple|quad|quadruple|family|quintuple|suite)\b/i.test(text)) {
		return true;
	}
	const compact = text.replace(/\s+/g, "");
	return [
		"\u0641\u0631\u062f\u064a",
		"\u0633\u0646\u062c\u0644",
		"\u0645\u0632\u062f\u0648\u062c",
		"\u0645\u0632\u0648\u062c",
		"\u062b\u0646\u0627\u0626\u064a",
		"\u062f\u0628\u0644",
		"\u062f\u0627\u0628\u0644",
		"\u062b\u0644\u0627\u062b\u064a",
		"\u062b\u0644\u0627\u062b\u0649",
		"\u062a\u0644\u0627\u062a\u064a",
		"\u062a\u0644\u0627\u062a\u0649",
		"\u0631\u0628\u0627\u0639\u064a",
		"\u0631\u0628\u0627\u0639\u0649",
		"\u0639\u0627\u0626\u0644\u064a",
		"\u062e\u0645\u0627\u0633\u064a",
		"\u062c\u0646\u0627\u062d",
	].some((needle) => compact.includes(needle));
}

function explicitGuestCountTotalFromText(value = "") {
	const facts = explicitGuestCountFactsFromText(value);
	const adults = Number(facts.adults || 0) || 0;
	const children = Number.isFinite(Number(facts.children)) ? Number(facts.children) : 0;
	const total = adults + Math.max(0, children);
	if (total > 0) return total;
	const people = peopleCountFromLine(value);
	return Number.isFinite(Number(people)) && Number(people) > 0 ? Number(people) : 0;
}

function singularCapacityRoomShorthand(value = "", roomTypeKey = "", count = 0) {
	const capacity = roomCapacityForKey(roomTypeKey);
	if (!capacity || Number(count || 0) !== capacity) return false;
	const typePatterns = {
		singleRooms: "(?:single|فردي|فردية|سنجل)",
		doubleRooms: "(?:double|twin|مزدوج|مزدوجة|دبل|دابل|ثنائي|ثنائية)",
		tripleRooms: "(?:triple|ثلاثي|ثلاثية|ثلاثى|تلاتي|تلاتية|تلاتى)",
		quadRooms: "(?:quad|quadruple|رباعي|رباعية|رباعى)",
		familyRooms: "(?:family|quintuple|عائلي|عائلية|خماسي|خماسية)",
	};
	const typePattern = typePatterns[roomTypeKey];
	if (!typePattern) return false;
	const text = normalizeRoomCountMarkers(
		normalizeNumberWordsForParsing(normalizeDigits(String(value || "")))
	)
		.replace(/\s+/g, " ")
		.trim();
	const number = `0?${capacity}`;
	const singularRoom = "(?:\\broom\\b|\\bunit\\b|غرفة|غرفه|اوضة|اوضه)";
	return new RegExp(
		`(?:^|[^0-9])${number}\\s*(?:x\\s*)?${singularRoom}\\s+(?:.{0,24})?${typePattern}`,
		"iu"
	).test(text);
}

function extractRoomSelectionsFromText(value = "") {
	const explicitNamedSelections = explicitNamedRoomSelectionsFromText(value);
	if (roomCapacityStatementOnly(value) && !explicitNamedSelections.length) return [];
	const text = normalizeRoomCountMarkers(
		normalizeNumberWordsForParsing(normalizeDigits(String(value || "")))
	);
	if (!text.trim()) return [];
	const selections = [...explicitNamedSelections];
	for (const matcher of ROOM_SELECTION_PATTERNS) {
		if (!matcher.pattern.test(text)) continue;
		if (selections.some((item) => item.roomTypeKey === matcher.key)) continue;
		selections.push({
			roomTypeKey: matcher.key,
			count: roomCountNearMatch(text, matcher),
		});
	}
	const capacityKey = textMentionsSpecificRoomType(text) ? mapRoomToKey(text) : "";
	if (capacityKey && !selections.some((item) => item.roomTypeKey === capacityKey)) {
		selections.push({ roomTypeKey: capacityKey, count: 1 });
	}
	if (!selections.length) {
		const key = mapRoomToKey(text);
		if (key && textMentionsSpecificRoomType(text)) {
			selections.push({ roomTypeKey: key, count: roomCountNearMatch(text, { pattern: /room|rooms|\u063a\u0631\u0641|\u063a\u0631\u0641\u0629/i }) });
		}
	}
	const explicitGuests = explicitGuestCountTotalFromText(text);
	return normalizeRoomSelections(selections).map((selection) => {
		const capacity = roomCapacityForKey(selection.roomTypeKey);
		if (
			explicitGuests === capacity &&
			singularCapacityRoomShorthand(text, selection.roomTypeKey, selection.count)
		) {
			return { ...selection, count: 1 };
		}
		return selection;
	});
}

function validISODate(value = "") {
	if (value instanceof Date && !Number.isNaN(value.getTime())) {
		return value.toISOString().slice(0, 10);
	}
	const text = String(value || "").slice(0, 10);
	if (!/^\d{4}-\d{2}-\d{2}$/.test(text)) return "";
	const date = new Date(`${text}T00:00:00.000Z`);
	if (Number.isNaN(date.getTime())) return "";
	return date.toISOString().slice(0, 10);
}

function addDaysISO(iso = "", days = 0) {
	const date = new Date(`${iso}T00:00:00.000Z`);
	if (Number.isNaN(date.getTime())) return "";
	date.setUTCDate(date.getUTCDate() + Number(days || 0));
	return date.toISOString().slice(0, 10);
}

function hotelBusinessTimezone(hotel = {}) {
	const value = cleanString(
		hotel.timezone || hotel.timeZone || hotel.hotelTimezone || process.env.HOTEL_BOOKING_TIMEZONE,
		80
	);
	return value || "Asia/Riyadh";
}

function businessTodayISO(hotel = {}) {
	const timeZone = hotelBusinessTimezone(hotel);
	try {
		const parts = new Intl.DateTimeFormat("en-CA", {
			timeZone,
			year: "numeric",
			month: "2-digit",
			day: "2-digit",
		}).formatToParts(new Date());
		const get = (type) => parts.find((part) => part.type === type)?.value || "";
		const year = get("year");
		const month = get("month");
		const day = get("day");
		if (year && month && day) return `${year}-${month}-${day}`;
	} catch {
		// Fall through to UTC if the configured timezone is invalid.
	}
	return new Date().toISOString().slice(0, 10);
}

function isoDateParts(iso = "") {
	const valid = validISODate(iso);
	if (!valid) return null;
	const [year, month, day] = valid.split("-").map((part) => Number(part));
	if (!year || !month || !day) return null;
	return { year, month, day };
}

function isoFromGregorianParts(year, month, day) {
	const y = Number(year);
	const m = Number(month);
	const d = Number(day);
	if (!Number.isInteger(y) || !Number.isInteger(m) || !Number.isInteger(d)) return "";
	if (y < 2000 || y > 2100 || m < 1 || m > 12 || d < 1 || d > 31) return "";
	const date = new Date(Date.UTC(y, m - 1, d));
	if (
		date.getUTCFullYear() !== y ||
		date.getUTCMonth() + 1 !== m ||
		date.getUTCDate() !== d
	) {
		return "";
	}
	return date.toISOString().slice(0, 10);
}

function normalizeTwoDigitYear(year = "") {
	const value = String(year || "").trim();
	if (!value) return 0;
	const numeric = Number(value);
	if (!Number.isInteger(numeric)) return 0;
	if (numeric >= 2000 && numeric <= 2100) return numeric;
	if (numeric >= 0 && numeric <= 99) return 2000 + numeric;
	return 0;
}

function numericSlashDateTokens(value = "") {
	const raw = digitsToEnglish(String(value || ""));
	return Array.from(
		raw.matchAll(/\b(\d{1,2})\s*[\/.-]\s*(\d{1,2})(?:\s*[\/.-]\s*((?:20\d{2})|\d{2}))?\b/g)
	);
}

function containsDateLikeSlashToken(value = "") {
	return numericSlashDateTokens(value).some((match) => {
		const a = Number(match[1]);
		const b = Number(match[2]);
		if (!Number.isInteger(a) || !Number.isInteger(b)) return false;
		return (
			(a >= 1 && a <= 31 && b >= 1 && b <= 12) ||
			(a >= 1 && a <= 12 && b >= 1 && b <= 31)
		);
	});
}

function futureYearForMonthDay(month, day, baseISO = businessTodayISO()) {
	const baseParts = isoDateParts(baseISO) || isoDateParts(new Date().toISOString().slice(0, 10));
	const todayISO = validISODate(baseISO) || new Date().toISOString().slice(0, 10);
	let year = baseParts?.year || new Date().getUTCFullYear();
	let iso = isoFromGregorianParts(year, month, day);
	if (iso && iso < todayISO) {
		year += 1;
		iso = isoFromGregorianParts(year, month, day);
	}
	return iso;
}

function slashDateMatchToISO(match = [], known = {}) {
	const a = Number(match[1]);
	const b = Number(match[2]);
	const explicitYear = normalizeTwoDigitYear(match[3]);
	if (!a || !b) return "";
	let day = 0;
	let month = 0;
	const knownCheckinParts = isoDateParts(known.checkinISO);
	const knownCheckoutParts = isoDateParts(known.checkoutISO);
	const knownMonth = knownCheckinParts?.month || knownCheckoutParts?.month || 0;
	if (a > 12 && b <= 12) {
		day = a;
		month = b;
	} else if (b > 12 && a <= 12) {
		month = a;
		day = b;
	} else if (knownMonth && b === knownMonth) {
		day = a;
		month = b;
	} else if (knownMonth && a === knownMonth) {
		month = a;
		day = b;
	} else {
		return "";
	}
	const baseYear = explicitYear || knownCheckinParts?.year || knownCheckoutParts?.year || 0;
	return baseYear
		? isoFromGregorianParts(baseYear, month, day)
		: futureYearForMonthDay(month, day);
}

function sameHotelSplitStayPeriodsFromText(value = "", known = {}) {
	const raw = digitsToEnglish(String(value || ""));
	const matches = numericSlashDateTokens(raw);
	if (matches.length < 4) return [];
	const preferDayMonth = /[\u0600-\u06FF]/.test(raw);
	const periods = [];
	for (let index = 0; index + 1 < matches.length; index += 2) {
		const startMatch = matches[index];
		const endMatch = matches[index + 1];
		const between = raw.slice(startMatch.index + startMatch[0].length, endMatch.index);
		if (
			!/(?:-|to|until|through|thru|till|حتى|حتي|الى|إلى|الي|\bto\b)/iu.test(
				between
			)
		) {
			return [];
		}
		const checkinISO = slashDateMatchToISOWithPreference(startMatch, known, {
			preferDayMonth,
			hintMonth: slashDateMatchMonthHint(endMatch),
		});
		const checkinParts = isoDateParts(checkinISO);
		const checkoutISO = slashDateMatchToISOWithPreference(
			endMatch,
			{
				...known,
				checkinISO: checkinISO || known.checkinISO,
			},
			{
				preferDayMonth,
				hintMonth: checkinParts?.month || slashDateMatchMonthHint(startMatch),
				baseYear: checkinParts?.year || 0,
			}
		);
		if (!validISODate(checkinISO) || !validISODate(checkoutISO)) return [];
		if (checkoutISO <= checkinISO) return [];
		periods.push({ checkinISO, checkoutISO });
	}
	if (periods.length < 2) return [];
	const hasGap = periods.some((period, index) => {
		const previous = periods[index - 1];
		return previous && period.checkinISO > previous.checkoutISO;
	});
	return hasGap ? periods : [];
}

function normalizeSplitStayPeriods(periods = []) {
	return (Array.isArray(periods) ? periods : [])
		.map((period) => ({
			checkinISO: validISODate(period?.checkinISO || period?.checkin),
			checkoutISO: validISODate(period?.checkoutISO || period?.checkout),
			nights: Number(period?.nights || 0) || 0,
			total: Number(period?.total || 0) || 0,
			currency: cleanString(period?.currency || "SAR", 12) || "SAR",
			selectionKey: cleanString(period?.selectionKey, 500),
			roomSelections: normalizeRoomSelections(period?.roomSelections),
			quoteFingerprint: cleanString(period?.quoteFingerprint, 80),
		}))
		.filter((period) => period.checkinISO && period.checkoutISO && period.checkoutISO > period.checkinISO);
}

function splitStayPeriodQuoteFingerprint(quoteValue = {}, period = {}) {
	const quote = asObject(quoteValue);
	const roomLines = (Array.isArray(quote.roomLines) ? quote.roomLines : []).map(
		(line) => ({
			roomId: cleanString(line.roomId, 80),
			roomTypeKey: cleanString(line.roomTypeKey, 40),
			count: normalizeRoomCount(line.count, 1),
			perRoomStayTotal: Number(line.perRoomStayTotal || 0) || 0,
			lineTotal: Number(line.lineTotal || 0) || 0,
			perNightPerRoom: Array.isArray(line.perNightPerRoom)
				? line.perNightPerRoom.map((value) => Number(value || 0))
				: [],
		})
	);
	return stableHash({
		checkinISO: validISODate(quote.checkinISO || period.checkinISO),
		checkoutISO: validISODate(quote.checkoutISO || period.checkoutISO),
		nights: Number(quote.nights || 0) || 0,
		total: Number(quote.total || quote.totals?.totalPriceWithCommission || 0) || 0,
		currency: cleanString(quote.currency || period.currency || "SAR", 12),
		selectionKey:
			cleanString(quote.selectionKey, 500) || roomSelectionKey(quote.roomSelections),
		roomSelections: normalizeRoomSelections(quote.roomSelections),
		roomLines,
		perNight: Array.isArray(quote.perNight)
			? quote.perNight.map((value) => Number(value || 0))
			: [],
	});
}

function latestTextHasMultipleStayPeriodSignal(value = "") {
	const raw = digitsToEnglish(String(value || ""));
	const isoDates = new Set(raw.match(/\b20\d{2}-\d{2}-\d{2}\b/g) || []);
	if (isoDates.size >= 4) return true;
	if (numericSlashDateTokens(raw).length >= 4) return true;
	const text = normalizeIntentSearchText(raw).toLowerCase();
	const separateStayLanguage =
		/(?:\btwo\b|\b2\b).{0,40}(?:separate|split|period|reservation|booking)|(?:separate|split).{0,40}(?:stay|period|reservation|booking)|\u062d\u062c\u0632\u064a\u0646|\u062d\u062c\u0632\u064a\u0646|\u0645\u0646\u0641\u0635\u0644|\u0641\u062a\u0631\u062a\u064a\u0646|\u0641\u062a\u0631\u0627\u062a/u.test(
			text
		);
	if (!separateStayLanguage) return false;
	const fromSignals = (text.match(/\bfrom\b|\u0645\u0646/gu) || []).length;
	const toSignals = (text.match(/\bto\b|\buntil\b|\btill\b|\u0627\u0644\u0649|\u0627\u0644\u064a|\u062d\u062a\u0649|\u062d\u062a\u064a/gu) || []).length;
	return fromSignals >= 2 || toSignals >= 2;
}

function brainSplitStayPeriodsGroundedInLatestText(latestText = "", periods = []) {
	const normalizedPeriods = normalizeSplitStayPeriods(periods);
	if (normalizedPeriods.length < 2) return false;
	const raw = digitsToEnglish(String(latestText || ""));
	const isoDates = new Set(raw.match(/\b20\d{2}-\d{2}-\d{2}\b/g) || []);
	if (
		isoDates.size &&
		normalizedPeriods.every(
			(period) => isoDates.has(period.checkinISO) && isoDates.has(period.checkoutISO)
		)
	) {
		return true;
	}
	return latestTextHasMultipleStayPeriodSignal(raw);
}

function latestTextExplicitlyRequestsMultipleRooms(value = "") {
	const text = normalizeNumberWordsForParsing(normalizeIntentSearchText(value));
	return (
		/\b(?:2|3|4|5|6|7|8|9|10)\s+(?:single|double|triple|quad(?:ruple)?|family)?\s*rooms?\b/i.test(
			text
		) ||
		/(?:\u063a\u0631\u0641\u062a\u064a\u0646|\u063a\u0631\u0641\u062a\u0627\u0646|[2-9]\s*\u063a\u0631\u0641|\u063a\u0631\u0641\s*[2-9])/.test(
			text
		)
	);
}

function latestTextSuggestsOneRoomPerSplitPeriod(value = "") {
	const text = normalizeNumberWordsForParsing(normalizeIntentSearchText(value));
	if (!latestTextHasMultipleStayPeriodSignal(text)) return false;
	if (latestTextExplicitlyRequestsMultipleRooms(text)) return false;
	return (
		/\b(?:1|one|a)\s+(?:single|double|triple|quad(?:ruple)?|family)?\s*room\b/i.test(
			text
		) ||
		/\broom\s+for\s+(?:1|one|2|two|3|three|4|four|5|five|6|six)\b/i.test(text) ||
		/(?:\u063a\u0631\u0641\u0629|\u063a\u0631\u0641\u0647)\s+(?:\u0648\u0627\u062d\u062f\u0629|\u0648\u0627\u062d\u062f\u0647\s+)?\u0644(?:\u0634\u062e\u0635|\u0634\u062e\u0635\u064a\u0646|[1-9])/.test(
			text
		) ||
		/(?:\u063a\u0631\u0641\u0629|\u063a\u0631\u0641\u0647)\s+[1-9]\s+(?:\u0645\u0646|\u0627\u0644\u0649|\u0627\u0644\u064a|\bfrom\b|\bto\b)/.test(
			text
		)
	);
}

function normalizeSplitStayPerPeriodRoomFacts(facts = {}, latestText = "") {
	const periods = normalizeSplitStayPeriods(facts.splitStayPeriods);
	if (periods.length < 2 || !latestTextSuggestsOneRoomPerSplitPeriod(latestText)) {
		return facts;
	}
	const next = { ...asObject(facts) };
	const selections = normalizeRoomSelections(next.roomSelections);
	const totalRooms = selections.length
		? roomSelectionsTotal(selections)
		: Number.isFinite(Number(next.rooms))
		? Number(next.rooms)
		: 0;
	if (totalRooms !== periods.length) return facts;
	if (selections.length === 1) {
		next.roomSelections = [{ ...selections[0], count: 1 }];
		next.roomTypeKey = selections[0].roomTypeKey;
	} else if (next.roomTypeKey) {
		next.roomSelections = [{ roomTypeKey: next.roomTypeKey, count: 1 }];
	}
	next.rooms = 1;
	return next;
}

function mergeSplitStayPeriodsPreservingQuote(existingPeriods = [], sourcePeriods = []) {
	const previousByRange = new Map(
		normalizeSplitStayPeriods(existingPeriods).map((period) => [
			`${period.checkinISO}|${period.checkoutISO}`,
			period,
		])
	);
	return normalizeSplitStayPeriods(sourcePeriods).map((period) => {
		const previous = previousByRange.get(`${period.checkinISO}|${period.checkoutISO}`) || {};
		const total = Number(period.total || 0) > 0 ? Number(period.total) : Number(previous.total || 0) || 0;
		const nights =
			Number(period.nights || 0) ||
			Number(previous.nights || 0) ||
			nightsBetween(period.checkinISO, period.checkoutISO);
		return {
			...period,
			nights,
			total,
			currency: period.currency || previous.currency || "SAR",
		};
	});
}

function singleGregorianDateFromText(value = "", known = {}) {
	const raw = digitsToEnglish(String(value || ""));
	const isoMatches = raw.match(/\b20\d{2}-\d{2}-\d{2}\b/g) || [];
	if (isoMatches.length === 1) return validISODate(isoMatches[0]);
	const monthDate =
		quickSingleGregorianMonthDate(raw, known) ||
		(/[\u0600-\u06FF]/.test(raw)
			? quickSingleGregorianMonthDate(normalizeArabicSingleGregorianDateText(raw), known)
			: null);
	if (monthDate?.iso) return validISODate(monthDate.iso);
	const matches = numericSlashDateTokens(raw);
	if (matches.length !== 1) return "";
	const explicitYear = normalizeTwoDigitYear(matches[0][3]);
	let iso = slashDateMatchToISO(matches[0], known);
	if (!iso && /[\u0600-\u06FF]/.test(raw)) {
		iso = slashDateMatchToISOWithPreference(matches[0], known, {
			preferDayMonth: true,
		});
	}
	if (!iso) return "";
	const knownCheckin = validISODate(known.checkinISO);
	if (!explicitYear && knownCheckin && iso <= knownCheckin) {
		const parts = isoDateParts(iso);
		const nextYearIso = parts
			? isoFromGregorianParts(parts.year + 1, parts.month, parts.day)
			: "";
		if (nextYearIso) iso = nextYearIso;
	}
	return iso;
}

function normalizeArabicSingleGregorianDateText(value = "") {
	return digitsToEnglish(normalizeNumberWordsForParsing(String(value || "")))
		.toLowerCase()
		.normalize("NFD")
		.replace(/[\u0300-\u036f\u064b-\u065f\u0670]/g, "")
		.replace(/[\u0622\u0623\u0625\u0671]/g, "\u0627")
		.replace(/\u0649/g, "\u064a")
		.replace(/\u0629/g, "\u0647")
		.replace(/[_,.;:()[\]{}]/g, " ")
		.replace(/\s+/g, " ")
		.trim();
}

function slashDateMatchToISOWithPreference(
	match = [],
	known = {},
	{ preferDayMonth = false, hintMonth = 0, baseYear = 0 } = {}
) {
	const a = Number(match[1]);
	const b = Number(match[2]);
	const explicitYear = normalizeTwoDigitYear(match[3]);
	if (!a || !b) return "";
	let day = 0;
	let month = 0;
	if (a > 12 && b <= 12) {
		day = a;
		month = b;
	} else if (b > 12 && a <= 12) {
		month = a;
		day = b;
	} else if (hintMonth && b === hintMonth) {
		day = a;
		month = b;
	} else if (hintMonth && a === hintMonth) {
		month = a;
		day = b;
	} else if (preferDayMonth) {
		day = a;
		month = b;
	} else {
		month = a;
		day = b;
	}
	if (!day || !month) return "";
	const knownParts = isoDateParts(known.checkinISO) || isoDateParts(known.checkoutISO);
	const year = explicitYear || baseYear || knownParts?.year || 0;
	return year
		? isoFromGregorianParts(year, month, day)
		: futureYearForMonthDay(month, day);
}

function slashDateMatchMonthHint(match = []) {
	const a = Number(match[1]);
	const b = Number(match[2]);
	if (a > 12 && b <= 12) return b;
	if (b > 12 && a <= 12) return a;
	return 0;
}

function dateOnlyRangeFactsFromText(value = "", known = {}, sc = {}) {
	const raw = digitsToEnglish(String(value || ""));
	const matches = numericSlashDateTokens(raw);
	if (matches.length !== 2) return null;
	const withoutDates = raw
		.replace(/\b\d{1,2}\s*[\/.-]\s*\d{1,2}(?:\s*[\/.-]\s*(?:(?:20\d{2})|\d{2}))?\b/g, " ")
		.replace(/[\s,،;؛|\\\/.\-–—]+/g, "")
		.trim();
	if (withoutDates) return null;
	const languageCode = activeLanguageCode(sc, known);
	const preferDayMonth = /^ar\b/i.test(languageCode) || /[\u0600-\u06FF]/.test(raw);
	const checkinISO = slashDateMatchToISOWithPreference(matches[0], known, {
		preferDayMonth,
		hintMonth: slashDateMatchMonthHint(matches[1]),
	});
	if (!validISODate(checkinISO)) return null;
	const checkinParts = isoDateParts(checkinISO);
	let checkoutISO = slashDateMatchToISOWithPreference(
		matches[1],
		{ ...known, checkinISO },
		{
			preferDayMonth,
			hintMonth: checkinParts?.month || 0,
			baseYear: checkinParts?.year || 0,
		}
	);
	if (!validISODate(checkoutISO)) return null;
	if (checkoutISO <= checkinISO && !matches[1][3]) {
		const checkoutParts = isoDateParts(checkoutISO);
		checkoutISO = checkoutParts
			? isoFromGregorianParts(checkoutParts.year + 1, checkoutParts.month, checkoutParts.day)
			: checkoutISO;
	}
	if (!validISODate(checkoutISO) || checkoutISO <= checkinISO) return null;
	return { checkinISO, checkoutISO, dateCalendar: "gregorian" };
}

function isoDateRangeFactsFromText(value = "") {
	const matches = String(value || "").match(/\b20\d{2}-\d{2}-\d{2}\b/g) || [];
	const dates = [];
	for (const item of matches) {
		const iso = validISODate(item);
		if (iso && !dates.includes(iso)) dates.push(iso);
	}
	if (dates.length < 2 || dates[1] <= dates[0]) return null;
	return { checkinISO: dates[0], checkoutISO: dates[1], dateCalendar: "gregorian" };
}

function previousAiLooksLikePriceCollection(entry = {}) {
	const action = String(entry?.clientAction || "").toLowerCase();
	if (
		[
			"quote_ready",
			"quote_unavailable",
			"get_quote",
			"available_quote",
			"same_date_room_options_ready",
		].includes(action)
	) {
		return true;
	}
	if (aiMessageLooksLikeDisplayedQuote(entry)) return true;
	const text = normalizeIntentSearchText(entry?.message || "").toLowerCase();
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:price|rate|quote|total|discount|availability|available)\b/i.test(text) ||
		/(?:\u0633\u0639\u0631|\u0627\u0644\u0633\u0639\u0631|\u062e\u0635\u0645|\u0645\u062a\u0627\u062d|\u0627\u0644\u062a\u0648\u0641\u0631|\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a|\u0627\u0644\u0627\u062c\u0645\u0627\u0644\u064a)/u.test(
			compact
		)
	);
}

function latestGuestSuppliesCheckoutBoundary(value = "", known = {}, previousAi = {}) {
	if (!latestGuestMentionsDateish(value)) return false;
	if (quickDateFactsFromText(value)?.checkoutISO) return true;
	if (dateOnlyRangeFactsFromText(value, known)?.checkoutISO) return true;
	if (labeledDateBoundaryFactsFromText(value, known)?.checkoutISO) return true;
	const priorCustomerFacingAi =
		previousAi && isAiSupportEntry(previousAi) && !previousAi.isSystem ? previousAi : {};
	if (dateBoundaryFactsFromAskedAnswer(value, known, priorCustomerFacingAi)?.checkoutISO) {
		return true;
	}
	const text = normalizeIntentSearchText(value).toLowerCase();
	return /(?:\b(?:to|until|till|through|thru|checkout|check\s*out|departure|depart|leave|leaving)\b|\u0627\u0644\u0649|\u0625\u0644\u0649|\u0627\u0644\u064a|\u062d\u062a\u0649|\u0644\u063a\u0627\u064a\u0629|\u0644\u063a\u0627\u064a\u0647|\u0627\u0644\u062e\u0631\u0648\u062c|\u062e\u0631\u0648\u062c|\u0627\u0644\u0645\u063a\u0627\u062f\u0631\u0629|\u0627\u0644\u0645\u063a\u0627\u062f\u0631\u0647|\u0645\u063a\u0627\u062f\u0631\u0629|\u0645\u063a\u0627\u062f\u0631\u0647)/i.test(text);
}

function dateFactsFromBrainAcknowledgedReply(
	reply = "",
	latestText = "",
	previousAi = {},
	known = {}
) {
	if (!String(reply || "").trim() || !latestGuestMentionsDateish(latestText)) return null;
	const priorCustomerFacingAi =
		previousAi && isAiSupportEntry(previousAi) && !previousAi.isSystem ? previousAi : null;
	if (!priorCustomerFacingAi) return null;
	if (
		!previousAiLooksLikePriceCollection(priorCustomerFacingAi) &&
		!previousAiAskedForCheckinDate(priorCustomerFacingAi) &&
		!previousAiAskedForCheckoutDate(priorCustomerFacingAi)
	) {
		return null;
	}
	if (!latestGuestSuppliesCheckoutBoundary(latestText, known, priorCustomerFacingAi)) return null;
	const isoFacts = isoDateRangeFactsFromText(reply);
	if (isoFacts?.checkinISO && isoFacts?.checkoutISO) return isoFacts;
	const quickFacts = quickDateRange(reply);
	if (quickFacts?.checkinISO && quickFacts?.checkoutISO) {
		return {
			checkinISO: quickFacts.checkinISO,
			checkoutISO: quickFacts.checkoutISO,
			dateCalendar: quickFacts.raw?.calendar || "gregorian",
		};
	}
	return null;
}

function latestStayDateFactsFromConversation(sc = {}, known = {}) {
	const conversation = Array.isArray(sc.conversation) ? sc.conversation : [];
	for (let index = conversation.length - 1; index >= 0; index -= 1) {
		const entry = conversation[index] || {};
		if (!isGuestEntry(entry)) continue;
		const text = String(entry.message || "");
		const quickFacts = quickDateFactsFromText(text);
		if (quickFacts?.checkinISO && quickFacts?.checkoutISO) return quickFacts;
		const dateOnlyFacts = dateOnlyRangeFactsFromText(text, known, sc);
		if (dateOnlyFacts?.checkinISO && dateOnlyFacts?.checkoutISO) return dateOnlyFacts;
		const isoFacts = isoDateRangeFactsFromText(text);
		if (isoFacts?.checkinISO && isoFacts?.checkoutISO) return isoFacts;
	}
	return null;
}

function latestSplitStayPeriodsFromConversation(sc = {}, known = {}) {
	const conversation = Array.isArray(sc.conversation) ? sc.conversation : [];
	for (let index = conversation.length - 1; index >= 0; index -= 1) {
		const entry = conversation[index] || {};
		if (!isGuestEntry(entry)) continue;
		const periods = sameHotelSplitStayPeriodsFromText(entry.message || "", known);
		if (periods.length >= 2) return periods;
	}
	return [];
}

function eachNight(checkinISO = "", checkoutISO = "") {
	const start = validISODate(checkinISO);
	const end = validISODate(checkoutISO);
	if (!start || !end || start >= end) return [];
	const dates = [];
	let cursor = start;
	while (cursor < end && dates.length < 60) {
		dates.push(cursor);
		cursor = addDaysISO(cursor, 1);
	}
	return cursor === end ? dates : [];
}

function nightsBetween(checkinISO = "", checkoutISO = "") {
	return eachNight(checkinISO, checkoutISO).length;
}

function nightsCountFromText(value = "") {
	const text = normalizeNumberWordsForParsing(normalizeDigits(String(value || "")))
		.toLowerCase()
		.replace(/\s+/g, " ")
		.trim();
	const match = text.match(
		/(?:^|[^0-9])(\d{1,2})\s*(?:nights?|ليالي|ليالى|ليال|ليلة|ليله)(?:$|\s|[^\p{L}0-9])/iu
	);
	const nights = Number(match?.[1] || 0);
	if (!Number.isFinite(nights) || nights < 1 || nights > 60) return null;
	return Math.floor(nights);
}

function asObject(value) {
	return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function cloneKnownFacts(value = {}) {
	try {
		return JSON.parse(JSON.stringify(asObject(value)));
	} catch {
		return { ...asObject(value) };
	}
}

function quoteHasContent(value = {}) {
	const quote = asObject(value);
	return Boolean(
		Object.prototype.hasOwnProperty.call(quote, "available") ||
			quote.roomTypeKey ||
			quote.checkinISO ||
			quote.checkoutISO ||
			quote.total ||
			quote.totals?.totalPriceWithCommission
	);
}

function initialKnownFacts(sc = {}) {
	const snapshot = asObject(sc.aiStateSnapshot);
	const known = asObject(snapshot.known);
	return applySelectedSameDateRoomOptionLock({
		...known,
		quote: asObject(known.quote),
	});
}

function usefulProfileName(sc = {}) {
	return profileNameForBooking(sc);
}

function stripChatMarkup(value = "") {
	return cleanDisplayString(value, 240)
		.replace(/[*_`]/g, "")
		.replace(/\s+/g, " ")
		.trim();
}

function normalizeNationalityHint(value = "") {
	const raw = stripChatMarkup(value).replace(/^[\s:,-]+|[\s.,;:!-]+$/g, "");
	const rawWithoutLabel = raw
		.replace(
			/^(?:nationality|my nationality is|guest nationality|citizenship|الجنسية|جنسيتي|جنسيتى)\s*[:：,\-]?\s*/i,
			""
		)
		.trim();
	const unicodeLabelCleaned = rawWithoutLabel
		.replace(/^(?:\u0648\s*)?(?:\u0627\u0644\u062c\u0646\u0633\u064a\u0629|\u062c\u0646\u0633\u064a\u0629|\u062c\u0646\u0633\u064a\u062a\u064a|\u062c\u0646\u0633\u064a\u062a\u0649)\s*[:\uFF1A,\-]?\s*/iu, "")
		.trim();
	const key = raw.toLowerCase().replace(/\./g, "");
	const sentenceMatches = [
		{ pattern: /\b(?:us|u\s*s\s*a|usa|united states|american)\b/i, value: "US" },
		{ pattern: /\b(?:uk|united kingdom|british)\b/i, value: "UK" },
		{ pattern: /\b(?:ksa|saudi arabia|saudi)\b/i, value: "Saudi" },
		{ pattern: /\b(?:uae|united arab emirates|emirati)\b/i, value: "UAE" },
		{ pattern: /\b(?:egypt|egyptian)\b/i, value: "Egyptian" },
		{ pattern: /\b(?:algeria|algerian|alg[e\u00e9]rie|alg[e\u00e9]rien|alg[e\u00e9]rienne)\b/i, value: "Algerian" },
		{ pattern: /\b(?:canada|canadian)\b/i, value: "Canadian" },
		{ pattern: /\b(?:pakistan|pakistani)\b/i, value: "Pakistani" },
		{ pattern: /\b(?:india|indian)\b/i, value: "Indian" },
		{ pattern: /\b(?:afghanistan|afghan|afghani)\b/i, value: "Afghan" },
	];
	const arabicNationalityMatches = [
		{ pattern: /^(?:\u0645\u0635\u0631\u064a|\u0645\u0635\u0631\u064a\u0629|\u0645\u0635\u0631\u0649|\u0645\u0635\u0631\u064a\u0647|\u0645\u0635\u0631)$/, value: "\u0645\u0635\u0631\u064a" },
		{ pattern: /^(?:\u0633\u0639\u0648\u062f\u064a|\u0633\u0639\u0648\u062f\u064a\u0629|\u0633\u0639\u0648\u062f\u0649|\u0627\u0644\u0633\u0639\u0648\u062f\u064a\u0629)$/, value: "\u0633\u0639\u0648\u062f\u064a" },
		{ pattern: /^(?:\u0625\u0645\u0627\u0631\u0627\u062a\u064a|\u0627\u0645\u0627\u0631\u0627\u062a\u064a|\u0625\u0645\u0627\u0631\u0627\u062a\u064a\u0629|\u0627\u0645\u0627\u0631\u0627\u062a\u064a\u0629|\u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a|\u0627\u0644\u0627\u0645\u0627\u0631\u0627\u062a)$/, value: "\u0625\u0645\u0627\u0631\u0627\u062a\u064a" },
		{ pattern: /^(?:\u0643\u0648\u064a\u062a\u064a|\u0643\u0648\u064a\u062a\u064a\u0629|\u0627\u0644\u0643\u0648\u064a\u062a)$/, value: "\u0643\u0648\u064a\u062a\u064a" },
		{ pattern: /^(?:\u0642\u0637\u0631\u064a|\u0642\u0637\u0631\u064a\u0629|\u0642\u0637\u0631)$/, value: "\u0642\u0637\u0631\u064a" },
		{ pattern: /^(?:\u0628\u062d\u0631\u064a\u0646\u064a|\u0628\u062d\u0631\u064a\u0646\u064a\u0629|\u0627\u0644\u0628\u062d\u0631\u064a\u0646)$/, value: "\u0628\u062d\u0631\u064a\u0646\u064a" },
		{ pattern: /^(?:\u0639\u0645\u0627\u0646\u064a|\u0639\u0645\u0627\u0646\u064a\u0629|\u0639\u0645\u0627\u0646)$/, value: "\u0639\u0645\u0627\u0646\u064a" },
		{ pattern: /^(?:\u0623\u0631\u062f\u0646\u064a|\u0627\u0631\u062f\u0646\u064a|\u0623\u0631\u062f\u0646\u064a\u0629|\u0627\u0631\u062f\u0646\u064a\u0629|\u0627\u0644\u0623\u0631\u062f\u0646|\u0627\u0644\u0627\u0631\u062f\u0646)$/, value: "\u0623\u0631\u062f\u0646\u064a" },
		{ pattern: /^(?:\u0641\u0644\u0633\u0637\u064a\u0646\u064a|\u0641\u0644\u0633\u0637\u064a\u0646\u064a\u0629|\u0641\u0644\u0633\u0637\u064a\u0646)$/, value: "\u0641\u0644\u0633\u0637\u064a\u0646\u064a" },
		{ pattern: /^(?:\u0633\u0648\u0631\u064a|\u0633\u0648\u0631\u064a\u0629|\u0633\u0648\u0631\u064a\u0627)$/, value: "\u0633\u0648\u0631\u064a" },
		{ pattern: /^(?:\u0644\u0628\u0646\u0627\u0646\u064a|\u0644\u0628\u0646\u0627\u0646\u064a\u0629|\u0644\u0628\u0646\u0627\u0646)$/, value: "\u0644\u0628\u0646\u0627\u0646\u064a" },
		{ pattern: /^(?:\u0639\u0631\u0627\u0642\u064a|\u0639\u0631\u0627\u0642\u064a\u0629|\u0627\u0644\u0639\u0631\u0627\u0642)$/, value: "\u0639\u0631\u0627\u0642\u064a" },
		{ pattern: /^(?:\u0633\u0648\u062f\u0627\u0646\u064a|\u0633\u0648\u062f\u0627\u0646\u064a\u0629|\u0627\u0644\u0633\u0648\u062f\u0627\u0646)$/, value: "\u0633\u0648\u062f\u0627\u0646\u064a" },
		{ pattern: /^(?:\u064a\u0645\u0646\u064a|\u064a\u0645\u0646\u064a\u0629|\u0627\u0644\u064a\u0645\u0646)$/, value: "\u064a\u0645\u0646\u064a" },
		{ pattern: /^(?:\u0645\u063a\u0631\u0628\u064a|\u0645\u063a\u0631\u0628\u064a\u0629|\u0627\u0644\u0645\u063a\u0631\u0628)$/, value: "\u0645\u063a\u0631\u0628\u064a" },
		{ pattern: /^(?:\u062c\u0632\u0627\u0626\u0631\u064a|\u062c\u0632\u0627\u0626\u0631\u064a\u0629|\u0627\u0644\u062c\u0632\u0627\u0626\u0631)$/, value: "\u062c\u0632\u0627\u0626\u0631\u064a" },
		{ pattern: /^(?:\u062a\u0648\u0646\u0633\u064a|\u062a\u0648\u0646\u0633\u064a\u0629|\u062a\u0648\u0646\u0633)$/, value: "\u062a\u0648\u0646\u0633\u064a" },
		{ pattern: /^(?:\u0623\u0641\u063a\u0627\u0646\u064a|\u0627\u0641\u063a\u0627\u0646\u064a|\u0627\u0641\u063a\u0627\u0646\u0649|\u0623\u0641\u063a\u0627\u0646\u0649|\u0623\u0641\u063a\u0627\u0646\u064a\u0629|\u0627\u0641\u063a\u0627\u0646\u064a\u0629|\u0627\u0641\u063a\u0627\u0646\u064a\u0647|\u0623\u0641\u063a\u0627\u0646\u064a\u0647|\u0623\u0641\u063a\u0627\u0646\u0633\u062a\u0627\u0646|\u0627\u0641\u063a\u0627\u0646\u0633\u062a\u0627\u0646)$/, value: "\u0623\u0641\u063a\u0627\u0646\u064a" },
	];
	for (const candidate of [unicodeLabelCleaned, rawWithoutLabel, raw]) {
		const exactArabic = arabicNationalityMatches.find((item) => item.pattern.test(candidate));
		if (exactArabic) return exactArabic.value;
	}
	const nationalityContext =
		/\b(?:citizen|national|nationality|passport|from|i am|i'm|im|my nationality)\b/i.test(raw) ||
		/\b(?:je\s+suis|nationalit[e\u00e9])\b/i.test(raw) ||
		/(?:\u0627\u0644\u062c\u0646\u0633\u064a\u0629|\u062c\u0646\u0633\u064a\u062a\u064a|\u062c\u0646\u0633\u064a\u062a\u0649)/.test(raw);
	if (nationalityContext) {
		const match = sentenceMatches.find((item) => item.pattern.test(raw));
		if (match) return match.value;
		const arabicMatch = arabicNationalityMatches.find((item) =>
			item.pattern.test(unicodeLabelCleaned) || item.pattern.test(rawWithoutLabel)
		);
		if (arabicMatch) return arabicMatch.value;
	}
	const mapped = {
		us: "US",
		usa: "US",
		"u s": "US",
		"u.s": "US",
		"u.s.a": "US",
		uk: "UK",
		uae: "UAE",
		ksa: "Saudi",
	};
	if (mapped[key]) return mapped[key];
	if (/^alg[e\u00e9]rien(?:ne)?$/i.test(raw)) return "Algerian";
	if (/^marocain(?:e)?$/i.test(raw)) return "Moroccan";
	if (/^tunisien(?:ne)?$/i.test(raw)) return "Tunisian";
	if (/^(?:egyptien(?:ne)?|[\u00e9e]gyptien(?:ne)?)$/i.test(raw)) return "Egyptian";
	if (/^(american|egyptian|saudi|emirati|kuwaiti|qatari|bahraini|omani|jordanian|pakistani|indian|british|canadian|moroccan|algerian|tunisian|iraqi|syrian|lebanese|palestinian|sudanese|yemeni|turkish|indonesian|malaysian|afghan|afghani)$/i.test(raw)) {
		return raw;
	}
	if (/^(united states|united kingdom|saudi arabia|united arab emirates|egypt|pakistan|india|canada|morocco|algeria|tunisia|jordan|kuwait|qatar|bahrain|oman|iraq|syria|lebanon|palestine|sudan|yemen|turkey|indonesia|malaysia|afghanistan)$/i.test(raw)) {
		return raw;
	}
	return "";
}

function nationalityFromText(value = "") {
	const text = stripChatMarkup(value);
	const patterns = [
		/(?:nationality|citizenship)\s*(?:is|:|-)?\s*([A-Za-z][A-Za-z\s-]{1,40}?)(?=\s*(?:,|;|\.|\band\b|\bphone\b|\bmobile\b|$))/i,
		/(?:nationalit[e\u00e9])\s*(?:est|is|:|-)?\s*([A-Za-z\u00c0-\u017F][A-Za-z\u00c0-\u017F\s-]{1,40}?)(?=\s*(?:,|;|\.|\bet\b|\band\b|\bt[ée]l\b|\bphone\b|\bmobile\b|$))/i,
		/(?:^|\s)(?:\u0648\s*)?(?:\u0627\u0644\u062c\u0646\u0633\u064a\u0629|\u062c\u0646\u0633\u064a\u062a\u064a|\u062c\u0646\u0633\u064a\u062a\u0649|\u062c\u0646\u0633\u064a\u0629)\s*(?:[:\-\u060C,]|\u0647\u064a)?\s*([\u0600-\u06FF][\u0600-\u06FF\s-]{1,40}?)(?=\s*(?:\u060C|,|;|\.|\u0648?\u0631\u0642\u0645|\u0648?\u0627\u0644\u0647\u0627\u062a\u0641|\u0648?\u0627\u0644\u062c\u0648\u0627\u0644|\u0647\u0627\u062a\u0641|\u062c\u0648\u0627\u0644|$))/iu,
	];
	for (const pattern of patterns) {
		const match = text.match(pattern);
		const nationality = normalizeNationalityHint(match?.[1] || "");
		if (nationality) return nationality;
	}
	return "";
}

function simplePhoneFromLine(value = "") {
	let raw = normalizeDigits(cleanDisplayString(value, 80)).replace(
		/^(?:phone|phone number|mobile|mobile number|whatsapp|whats\s*app|\u0627\u0644\u0647\u0627\u062a\u0641|\u0631\u0642\u0645 \u0627\u0644\u0647\u0627\u062a\u0641|\u0627\u0644\u062c\u0648\u0627\u0644|\u0631\u0642\u0645 \u0627\u0644\u062c\u0648\u0627\u0644|\u0631\u0642\u0645\u064a|\u0631\u0642\u0645\u0649|\u0627\u0644\u0631\u0642\u0645|\u0648\u0627\u062a\u0633|\u0648\u0627\u062a\u0633\u0627\u0628)\s*[:\uFF1A,\-]?\s*/i,
		""
	);
	const phone = cleanPhone(raw);
	if (!phone || phone.replace(/[^\d]/g, "").length < 7) return "";
	if (looksLikeDatePhoneCandidate(phone)) return "";
	const nonPhone = raw.replace(/[+\d\s().-]/g, "").trim();
	return nonPhone ? "" : phone;
}

function phoneFromText(value = "") {
	const text = normalizeDigits(cleanDisplayString(value, 240));
	const labeled = text.match(
		/(?:phone|phone\s+number|mobile|mobile\s+number|whatsapp|whats\s*app|telephone|tel|\u0631\u0642\u0645\s+\u0627\u0644\u0647\u0627\u062a\u0641|\u0627\u0644\u0647\u0627\u062a\u0641|\u0647\u0627\u062a\u0641|\u0631\u0642\u0645\s+\u0627\u0644\u062c\u0648\u0627\u0644|\u0627\u0644\u062c\u0648\u0627\u0644|\u062c\u0648\u0627\u0644|\u0631\u0642\u0645\u064a|\u0631\u0642\u0645\u0649|\u0627\u0644\u0631\u0642\u0645|\u0645\u0648\u0628\u0627\u064a\u0644|\u0648\u0627\u062a\u0633|\u0648\u0627\u062a\u0633\u0627\u0628)\s*(?:[:\-\u060C,]|\u0647\u0648)?\s*(\+?\d[\d\s().-]{6,24})/i
	);
	const loosePlus = !labeled ? text.match(/\+\d[\d\s().-]{6,24}/) : null;
	let raw = labeled?.[1] || loosePlus?.[0] || "";
	raw = raw.replace(/^(?:\u0631\u0642\u0645\u064a|\u0631\u0642\u0645\u0649|\u0627\u0644\u0631\u0642\u0645)\s*[:\uFF1A,\-]?\s*/i, "");
	const phone = cleanPhone(raw);
	return phone && phone.replace(/[^\d]/g, "").length >= 7 && !looksLikeDatePhoneCandidate(phone) ? phone : "";
}

function phoneFromIdentityText(value = "") {
	const labeled = phoneFromText(value) || simplePhoneFromLine(value);
	if (labeled) return labeled;
	const text = normalizeDigits(cleanDisplayString(value, 240));
	const compact = normalizeIntentSearchText(text).replace(/\s+/g, "");
	if (mentionsExplicitReservationIdentifier(text)) return "";
	if (
		/(?:\u062a\u0623\u0643\u064a\u062f|\u062a\u0627\u0643\u064a\u062f)(?:\u0627\u0644)?\u062d\u062c\u0632|\b(?:booking|reservation|confirmation|reference)\b/i.test(
			compact
		)
	) {
		return "";
	}
	const match = text.match(/(?:^|[^\d+])(\+?\d[\d\s().-]{6,24})(?=$|[^\d])/);
	const phone = cleanPhone(match?.[1] || "");
	return phone && phone.replace(/[^\d]/g, "").length >= 7 && !looksLikeDatePhoneCandidate(phone) ? phone : "";
}

function nameHintFromLine(value = "") {
	let text = stripChatMarkup(value);
	text = text
		.replace(/^(ok|okay|sure|yes|yep|yeah|name is|my name is|i am|i'm)\b[\s,:-]*/i, "")
		.trim();
	if (simplePhoneFromLine(text) || normalizeNationalityHint(text)) return "";
	if (!isPlausibleBookingName(text)) return "";
	return cleanDisplayString(text, 80);
}

function nationalityFromIdentityText(value = "") {
	const direct = nationalityFromText(value) || normalizeNationalityHint(value);
	if (direct) return direct;
	const tokens = stripChatMarkup(value)
		.split(/[\s,;\u060C|]+/)
		.map((token) => token.trim())
		.filter(Boolean);
	for (const token of tokens) {
		const nationality = normalizeNationalityHint(token);
		if (nationality) return nationality;
	}
	return "";
}

function bookingNameFromIdentityText(value = "") {
	let text = normalizeDigits(stripChatMarkup(value));
	const original = cleanDisplayString(value, 240);
	const hasNameCue =
		/\b(?:name|booking name|guest name|full name)\b/i.test(original) ||
		/(?:\u0627\u0633\u0645\s+\u0627\u0644\u062d\u062c\u0632|\u0627\u0633\u0645\s+\u0627\u0644\u0636\u064a\u0641|\u0627\u0644\u0627\u0633\u0645|\u0627\u0633\u0645\u064a|\u0627\u0633\u0645\u0649)/iu.test(
			original
		);
	const hasOtherIdentityCue =
		phoneFromIdentityText(original) ||
		phoneFromText(original) ||
		simplePhoneFromLine(original) ||
		nationalityFromIdentityText(original) ||
		nationalityFromText(original) ||
		normalizeNationalityHint(original) ||
		/\b(?:phone|mobile|whatsapp|nationality|citizenship)\b/i.test(original) ||
		/(?:\u0631\u0642\u0645\s+\u0627\u0644\u0647\u0627\u062a\u0641|\u0627\u0644\u0647\u0627\u062a\u0641|\u0647\u0627\u062a\u0641|\u0631\u0642\u0645\u064a|\u0631\u0642\u0645\u0649|\u0627\u0644\u0631\u0642\u0645|\u0627\u0644\u062c\u0648\u0627\u0644|\u062c\u0648\u0627\u0644|\u0627\u0644\u062c\u0646\u0633\u064a\u0629|\u062c\u0646\u0633\u064a\u0629)/iu.test(
			original
		);
	text = text
		.replace(/\+?\d[\d\s().-]{6,24}/g, " ")
		.replace(/\b(?:phone|mobile|whatsapp|nationality|citizenship|name|booking name|guest name|full name)\b/gi, " ")
		.replace(/(?:\u0648?\u0631\u0642\u0645\s+\u0627\u0644\u0647\u0627\u062a\u0641|\u0648?\u0627\u0644\u0647\u0627\u062a\u0641|\u0648?\u0647\u0627\u062a\u0641|\u0648?\u0631\u0642\u0645\u064a|\u0648?\u0631\u0642\u0645\u0649|\u0648?\u0627\u0644\u0631\u0642\u0645|\u0648?\u0627\u0644\u062c\u0648\u0627\u0644|\u0648?\u062c\u0648\u0627\u0644|\u0648?\u0627\u0644\u062c\u0646\u0633\u064a\u0629|\u0648?\u062c\u0646\u0633\u064a\u0629|\u0627\u0633\u0645\s+\u0627\u0644\u062d\u062c\u0632|\u0627\u0644\u0627\u0633\u0645|\u0627\u0633\u0645\u064a|\u0627\u0633\u0645\u0649)/giu, " ");
	const tokens = text
		.split(/[\s,;\u060C|]+/)
		.map((token) => token.trim())
		.filter((token) => token && !normalizeNationalityHint(token));
	const candidate = cleanDisplayString(tokens.join(" "), 80).replace(/^[\s:,-]+|[\s.,;:!-]+$/g, "");
	if (!hasNameCue && hasOtherIdentityCue) return "";
	const nationality =
		nationalityFromIdentityText(original) ||
		nationalityFromText(original) ||
		normalizeNationalityHint(original);
	if (
		nationality &&
		normalizeIntentSearchText(candidate).replace(/\s+/g, "") ===
			normalizeIntentSearchText(nationality).replace(/\s+/g, "")
	) {
		return "";
	}
	return isPlausibleBookingName(candidate) ? candidate : "";
}

function identityCorrectionOnly(value = "") {
	const text = normalizeDigits(stripChatMarkup(value));
	const normalized = normalizeIntentSearchText(text)
		.replace(/[.!?\u061f\u060c,]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!normalized) return false;
	const compact = normalized.replace(/\s+/g, "");
	const hasNameCue =
		/\b(?:name|booking name|guest name|full name)\b/i.test(normalized) ||
		/(?:\u0627\u0633\u0645\u0627\u0644\u062d\u062c\u0632|\u0627\u0633\u0645\u062d\u062c\u0632|\u0627\u0633\u0645\u0627\u0644\u0636\u064a\u0641|\u0627\u0644\u0627\u0633\u0645|\u0627\u0633\u0645\u064a|\u0627\u0633\u0645\u0649|\u0627\u0633\u0645)/iu.test(
			compact
		);
	const hasCorrectionCue =
		/\b(?:wrong|incorrect|mistake|typo|invalid|not correct|needs? changing|change it|fix it)\b/i.test(
			normalized
		) ||
		/(?:\u062e\u0627\u0637\u0626|\u062e\u0627\u0637\u0649|\u062e\u0637\u0623|\u062e\u0637\u0627|\u063a\u0644\u0637|\u063a\u0644\u0637\u0627\u0646|\u063a\u064a\u0631\u0635\u062d\u064a\u062d|\u0645\u0634\u0635\u062d\u064a\u062d|\u0645\u0634|\u0645\u0648|\u0644\u064a\u0633|\u0644\u064a\u0633\u062a|\u062a\u0639\u062f\u064a\u0644|\u0639\u062f\u0644)/iu.test(
			compact
		);
	const hasValueConnector =
		/[:=]|\b(?:is|as|to)\b/i.test(text) ||
		/(?:\u0647\u0648|\u0647\u064a|\u0647\u0649|:|\u060c|,|-)/iu.test(text);
	return hasNameCue && hasCorrectionCue && !hasValueConnector;
}

function cleanBookingNameCandidate(value = "") {
	return cleanDisplayString(value, 80)
		.replace(/\s+(?:\u0639\u0644\u0649\s+\u0641\u0643\u0631\u0629|\u0639\u0644\u064a\s+\u0641\u0643\u0631\u0629|\u0628\u0627\u0644\u0645\u0646\u0627\u0633\u0628\u0629|by\s+the\s+way).*$/iu, "")
		.replace(/(?:\s+|\u060C|,)+(?:\u0648|and)$/iu, "")
		.replace(/^[\s:,-]+|[\s.,;:!-]+$/g, "")
		.trim();
}

function bookingNameFromLine(value = "") {
	const text = stripChatMarkup(value);
	if (identityCorrectionOnly(text)) return "";
	const patterns = [
		/(?:use|put)\s+([A-Za-z][A-Za-z\s'.-]{1,80}?)\s+as\s+(?:the\s+)?(?:booking|guest|full)\s+name\b/i,
		/(?:booking\s+name|guest\s+name|full\s+name|name)\s*(?:is|:|-)?\s*([A-Za-z][A-Za-z\s'.-]{1,80}?)(?=\s*(?:,|;|\.|\band\b|\bphone\b|\bmobile\b|\bnationality\b|$))/i,
		/(?:\u0627\u0633\u0645\s+(?:\u0635\u0627\u062d\u0628\s+)?\u0627\u0644\u062d\u062c\u0632|\u0627\u0633\u0645\s+\u0627\u0644\u0636\u064a\u0641|\u0627\u0644\u0627\u0633\u0645\s+\u0627\u0644\u0643\u0627\u0645\u0644|\u0627\u0644\u0627\u0633\u0645|\u0627\u0633\u0645\u064a|\u0627\u0633\u0645\u0649)\s*(?:[:\-\u060C,]|\u0647\u0648)?\s*([\u0600-\u06FF][\u0600-\u06FF\s'.-]{1,80}?)(?=\s*(?:\u060C|,|;|\.|\u0648?\u0627\u0644\u062c\u0646\u0633\u064a\u0629|\u0648?\u062c\u0646\u0633\u064a\u062a|\u0648?\u0631\u0642\u0645|\u0648?\u0631\u0642\u0645\u064a|\u0648?\u0631\u0642\u0645\u0649|\u0648?\u0627\u0644\u0631\u0642\u0645|\u0648?\u0627\u0644\u0647\u0627\u062a\u0641|\u0648?\u0647\u0627\u062a\u0641|\u0648?\u0627\u0644\u062c\u0648\u0627\u0644|\u0648?\u062c\u0648\u0627\u0644|$))/iu,
	];
	for (const pattern of patterns) {
		const match = text.match(pattern);
		const name = cleanBookingNameCandidate(match?.[1] || "");
		if (isPlausibleBookingName(name)) return name;
	}
	return "";
}

function bookingIdentityFactsFromText(
	value = "",
	{ allowName = false, allowUnlabeledName = false } = {}
) {
	const facts = {};
	const lines = String(value || "")
		.split(/\r?\n|\\n|[|]/)
		.map((line) => cleanDisplayString(line, 500))
		.filter(Boolean);
	const source = lines.length ? lines : [cleanDisplayString(value, 500)].filter(Boolean);
	for (const line of source) {
		if (guestDeclinesOptionalEmail(line, "")) continue;
		const hasExplicitReservationIdentifier = mentionsExplicitReservationIdentifier(line);
		if (!facts.phone && !hasExplicitReservationIdentifier) {
			const phone = phoneFromIdentityText(line) || phoneFromText(line) || simplePhoneFromLine(line);
			if (phone) facts.phone = phone;
		}
		if (!facts.nationality) {
			const nationality =
				nationalityFromIdentityText(line) ||
				nationalityFromText(line) ||
				normalizeNationalityHint(line);
			if (nationality) facts.nationality = nationality;
		}
		if (allowName && !facts.fullName && !hasExplicitReservationIdentifier) {
			const name = sameAsDisplayedNameIntent(line)
				? ""
				: bookingNameFromLine(line) ||
				  (allowUnlabeledName ? bookingNameFromIdentityText(line) : "");
			if (name) facts.fullName = name;
		}
	}
	if (facts.phone) facts.phoneConfirmed = true;
	if (facts.nationality) facts.nationalityConfirmed = true;
	if (facts.fullName) facts.fullNameConfirmed = true;
	return facts;
}

function latestGuestProvidesBookingIdentityDetails(value = "") {
	const text = stripChatMarkup(value);
	if (!text.trim()) return false;
	if (guestDeclinesOptionalEmail(text, "")) return false;
	return Boolean(
		bookingNameFromLine(text) ||
			phoneFromIdentityText(text) ||
			phoneFromText(text) ||
			nationalityFromIdentityText(text) ||
			nationalityFromText(text) ||
			/(?:booking\s+name|guest\s+name|full\s+name|phone|mobile|nationality|\u0627\u0633\u0645\s+(?:\u0635\u0627\u062d\u0628\s+)?\u0627\u0644\u062d\u062c\u0632|\u0627\u0644\u0627\u0633\u0645|\u0631\u0642\u0645\s+\u0627\u0644\u0647\u0627\u062a\u0641|\u0631\u0642\u0645\u064a|\u0631\u0642\u0645\u0649|\u0627\u0644\u0631\u0642\u0645|\u0627\u0644\u0647\u0627\u062a\u0641|\u0627\u0644\u062c\u0648\u0627\u0644|\u0627\u0644\u062c\u0646\u0633\u064a\u0629|\u062c\u0646\u0633\u064a\u062a)/i.test(
				text
			)
	);
}

