function formatDate(iso = "", languageCode = "en") {
	const date = new Date(`${validISODate(iso)}T00:00:00.000Z`);
	if (Number.isNaN(date.getTime())) return iso;
	const locale = /^ar\b/i.test(languageCode) ? "ar-EG" : "en-US";
	return new Intl.DateTimeFormat(locale, {
		day: "numeric",
		month: "long",
		year: "numeric",
		timeZone: "UTC",
	}).format(date);
}

function formatNumber(value, languageCode = "en") {
	const locale = /^ar\b/i.test(languageCode) ? "ar-EG" : "en-US";
	return new Intl.NumberFormat(locale, { maximumFractionDigits: 2 }).format(
		Number(value || 0)
	);
}

function localizedDurationMinutes(value = "", fallback = "", languageCode = "en") {
	const raw = cleanDisplayString(value || fallback, 80);
	const normalized = normalizeDigits(raw).toLowerCase();
	const numeric = Number(normalized.replace(/[^\d.]/g, ""));
	if (
		Number.isFinite(numeric) &&
		numeric > 0 &&
		/^\s*[\d.,]+\s*(?:m|min|mins|minutes?|\u062f\u0642\u064a\u0642\u0629|\u062f\u0642\u0627\u0626\u0642)?\s*$/.test(normalized)
	) {
		return /^ar\b/i.test(languageCode)
			? `${formatNumber(numeric, languageCode)} \u062f\u0642\u064a\u0642\u0629`
			: `${formatNumber(numeric, languageCode)} minute${numeric === 1 ? "" : "s"}`;
	}
	return raw || (/^ar\b/i.test(languageCode) ? "\u062f\u0642\u0627\u0626\u0642" : "minutes");
}

function arabicQuantityLabel(count = 1, one = "", two = "", plural = "") {
	const normalized = Number(count || 0);
	if (normalized === 1) return one;
	if (normalized === 2) return two || plural || one;
	return plural || one;
}

function arabicGuestCountText(adults = 1, children = 0, languageCode = "ar") {
	const adultCount = Math.max(1, Number(adults || 1) || 1);
	const childCount = Math.max(0, Number(children || 0) || 0);
	const parts = [
		`${formatNumber(adultCount, languageCode)} ${arabicQuantityLabel(
			adultCount,
			"\u0628\u0627\u0644\u063a",
			"\u0628\u0627\u0644\u063a\u0627\u0646",
			"\u0628\u0627\u0644\u063a\u064a\u0646"
		)}`,
	];
	if (childCount > 0) {
		parts.push(
			`${formatNumber(childCount, languageCode)} ${arabicQuantityLabel(
				childCount,
				"\u0637\u0641\u0644",
				"\u0637\u0641\u0644\u0627\u0646",
				"\u0623\u0637\u0641\u0627\u0644"
			)}`
		);
	}
	return parts.join("\u060c ");
}

function englishGuestCountText(adults = 1, children = 0) {
	const adultCount = Math.max(1, Number(adults || 1) || 1);
	const childCount = Math.max(0, Number(children || 0) || 0);
	const parts = [`${adultCount} adult${adultCount === 1 ? "" : "s"}`];
	if (childCount > 0) {
		parts.push(`${childCount} child${childCount === 1 ? "" : "ren"}`);
	}
	return parts.join(", ");
}

function arabicReviewAddress(sc = {}, known = {}) {
	return (
		guestAddressForPrompt(sc, { ...asObject(known), languageCode: "ar" }) ||
		"\u0636\u064a\u0641\u0646\u0627 \u0627\u0644\u0639\u0632\u064a\u0632"
	);
}

function formatMoney(value, currency = "SAR", languageCode = "en") {
	const amount = formatNumber(value, languageCode);
	return /^ar\b/i.test(languageCode)
		? `${amount} ريال سعودي`
		: `${amount} ${currency || "SAR"}`;
}

function escapePriceMarkup(value = "") {
	return String(value || "")
		.replace(/&/g, "&amp;")
		.replace(/</g, "&lt;")
		.replace(/>/g, "&gt;")
		.replace(/"/g, "&quot;");
}

function originalAmountBeforeDirectDiscount(discountedValue = 0) {
	const discounted = Number(discountedValue || 0);
	if (!Number.isFinite(discounted) || discounted <= 0) return 0;
	return Number((discounted / DIRECT_BOOKING_DISCOUNT_FACTOR).toFixed(2));
}

function directBookingDiscountText(languageCode = "en") {
	const percent = formatNumber(DIRECT_BOOKING_DISCOUNT_RATE * 100, languageCode);
	if (/^ar\b/i.test(languageCode)) {
		return `\u062e\u0635\u0645 ${percent}\u066a \u0644\u0644\u062d\u062c\u0632 \u0627\u0644\u0645\u0628\u0627\u0634\u0631`;
	}
	return /^ar\b/i.test(languageCode)
		? `خصم ${percent}٪ للحجز المباشر`
		: `${percent}% direct-booking discount`;
}

function directBookingDiscountReason(languageCode = "en") {
	if (/^ar\b/i.test(languageCode)) {
		return "\u0644\u0623\u0646 \u0627\u0644\u062d\u062c\u0632 \u0645\u0628\u0627\u0634\u0631 \u0645\u0639 \u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644 \u0628\u062f\u0648\u0646 \u0639\u0645\u0648\u0644\u0629 \u0648\u0633\u064a\u0637.";
	}
	return /^ar\b/i.test(languageCode)
		? "لأن الحجز مباشر مع الاستقبال بدون عمولة وسيط."
		: "Because the booking is direct with reception, with no middleman commission.";
}

function discountedPriceInline(value = 0, currency = "SAR", languageCode = "en") {
	const discounted = Number(value || 0);
	if (!Number.isFinite(discounted) || discounted <= 0) {
		return formatMoney(value, currency, languageCode);
	}
	const original = originalAmountBeforeDirectDiscount(discounted);
	return [
		`<s class="message-price-old">${escapePriceMarkup(
			formatMoney(original, currency, languageCode)
		)}</s>`,
		`<strong class="message-price-new">${escapePriceMarkup(
			formatMoney(discounted, currency, languageCode)
		)}</strong>`,
		`<span class="message-price-badge">${escapePriceMarkup(
			directBookingDiscountText(languageCode)
		)}</span>`,
	].join(" ");
}

function discountedPriceLine(label = "", value = 0, currency = "SAR", languageCode = "en") {
	return `${label}: ${discountedPriceInline(value, currency, languageCode)}`;
}

function quoteDiscountDisplay(quote = {}, languageCode = "en") {
	const source = asObject(quote);
	const total = Number(source.total || source.totals?.totalPriceWithCommission || 0) || 0;
	const averagePerNight = Number(source.averagePerNight || 0) || 0;
	const currency = source.currency || "SAR";
	if (!total) return null;
	const ar = /^ar\b/i.test(languageCode);
	return {
		ratePercent: DIRECT_BOOKING_DISCOUNT_RATE * 100,
		factor: DIRECT_BOOKING_DISCOUNT_FACTOR,
		originalTotal: originalAmountBeforeDirectDiscount(total),
		originalAveragePerNight: averagePerNight
			? originalAmountBeforeDirectDiscount(averagePerNight)
			: 0,
		finalTotal: total,
		finalAveragePerNight: averagePerNight,
		currency,
		reason: directBookingDiscountReason(languageCode),
		displayTotalLine: discountedPriceLine(
			ar ? "الإجمالي" : "Total",
			total,
			currency,
			languageCode
		),
		displayAveragePerNightLine: averagePerNight
			? discountedPriceLine(
					ar ? "السعر لليلة" : "Rate per night",
					averagePerNight,
					currency,
					languageCode
			  )
			: "",
		formatInstruction:
			"Use the display lines exactly when showing quote prices. Keep the original price inside the <s class=\"message-price-old\"> tag and the discounted price inside <strong class=\"message-price-new\"> on the same row.",
	};
}

function quoteReplyMissingDiscountFormat(reply = "", toolResult = {}) {
	const discount = asObject(toolResult?.discount);
	if (
		toolResult?.tool !== "get_quote" ||
		toolResult?.available !== true ||
		!discount.displayTotalLine
	) {
		return false;
	}
	const text = String(reply || "");
	return (
		!/<s\b[^>]*class=["'][^"']*\bmessage-price-old\b/i.test(text) ||
		!/<strong\b[^>]*class=["'][^"']*\bmessage-price-new\b/i.test(text) ||
		!replyPreservesVisibleNumbers(discount.displayTotalLine, text)
	);
}

function quoteReplyMissingToolDates(reply = "", toolResult = {}) {
	if (toolResult?.tool !== "get_quote" || toolResult?.available !== true) return false;
	const checkinISO = validISODate(toolResult?.checkinISO || toolResult?.quote?.checkinISO);
	const checkoutISO = validISODate(toolResult?.checkoutISO || toolResult?.quote?.checkoutISO);
	if (!checkinISO || !checkoutISO) return false;
	const text = String(reply || "");
	return !text.includes(checkinISO) || !text.includes(checkoutISO);
}

function moneyTokenToNumber(value = "") {
	const raw = normalizeDigits(String(value || "")).trim();
	if (!raw) return null;
	const normalized = /^\d{1,3}(?:,\d{3})+(?:\.\d{1,2})?$/.test(raw)
		? raw.replace(/,/g, "")
		: raw.replace(",", ".");
	const number = Number(normalized.replace(/[^\d.-]/g, ""));
	return Number.isFinite(number) && number >= 0 ? Number(number.toFixed(2)) : null;
}

function moneyAmountKey(value = 0) {
	const number = Number(value);
	if (!Number.isFinite(number)) return "";
	return Number(number.toFixed(2)).toString();
}

function moneyAmountsFromText(value = "") {
	const text = normalizeDigits(String(value || "").replace(/<[^>]*>/g, " "));
	const amount =
		"(\\d{1,3}(?:,\\d{3})+(?:\\.\\d{1,2})?|\\d{1,7}(?:[.,]\\d{1,2})?)";
	const currency = "(?:SAR|S\\.?R\\.?|ر\\.س|ريال(?:\\s+سعودي)?)";
	const matches = [
		...text.matchAll(new RegExp(`${amount}\\s*${currency}`, "giu")),
		...text.matchAll(new RegExp(`${currency}\\s*${amount}`, "giu")),
	];
	return matches
		.map((match) => moneyTokenToNumber(match[1]))
		.filter((number) => Number.isFinite(number));
}

function collectStructuredMoneyAmounts(value, allowed = new Set(), keyPath = "") {
	if (value === null || value === undefined) return allowed;
	if (typeof value === "number") {
		if (/(?:total|price|amount|average|rate|nightly|deposit|araboon|fee|cost)/i.test(keyPath)) {
			const key = moneyAmountKey(value);
			if (key) allowed.add(key);
		}
		return allowed;
	}
	if (typeof value === "string") {
		moneyAmountsFromText(value).forEach((amount) => {
			const key = moneyAmountKey(amount);
			if (key) allowed.add(key);
		});
		return allowed;
	}
	if (Array.isArray(value)) {
		value.forEach((item, index) => collectStructuredMoneyAmounts(item, allowed, `${keyPath}.${index}`));
		return allowed;
	}
	if (typeof value === "object") {
		for (const [key, item] of Object.entries(value)) {
			collectStructuredMoneyAmounts(item, allowed, keyPath ? `${keyPath}.${key}` : key);
		}
	}
	return allowed;
}

function allowedQuoteMoneyAmountKeys(toolResult = {}, fallback = "") {
	const allowed = new Set();
	moneyAmountsFromText(fallback).forEach((amount) => {
		const key = moneyAmountKey(amount);
		if (key) allowed.add(key);
	});
	collectStructuredMoneyAmounts(toolResult, allowed);
	const quote = asObject(toolResult?.quote || toolResult?.review?.quote);
	const discount = asObject(toolResult?.discount || quote.discount);
	[discount.finalTotal, discount.finalAveragePerNight, discount.originalTotal, discount.originalAveragePerNight]
		.filter((value) => Number.isFinite(Number(value)))
		.forEach((value) => {
			const key = moneyAmountKey(value);
			if (key) allowed.add(key);
		});
	return allowed;
}

function quoteReplyHasExtraneousMoneyAmount(reply = "", toolResult = {}, fallback = "") {
	const tool = String(toolResult?.tool || "");
	const isQuote = tool === "get_quote" && toolResult?.available === true;
	const isReview = tool === "send_review" && String(toolResult?.code || "") === "review_ready";
	if (!isQuote && !isReview) return false;
	const seen = moneyAmountsFromText(reply).map(moneyAmountKey).filter(Boolean);
	if (!seen.length) return false;
	const allowed = allowedQuoteMoneyAmountKeys(toolResult, fallback);
	if (!allowed.size) return false;
	return seen.some((amount) => !allowed.has(amount));
}

function quoteReplyMentionsUnbackedDeposit(reply = "", toolResult = {}) {
	if (toolResult?.tool !== "get_quote" || toolResult?.available !== true) return false;
	const hasDepositAmount = [
		toolResult.deposit,
		toolResult.depositAmount,
		toolResult.araboon,
		toolResult.araboonAmount,
		toolResult.quote?.deposit,
		toolResult.quote?.depositAmount,
		toolResult.quote?.araboon,
		toolResult.quote?.araboonAmount,
	].some((value) => Number(value || 0) > 0);
	if (hasDepositAmount) return false;
	const text = normalizeIntentSearchText(reply);
	return /\b(?:deposit|down\s*payment|advance\s*payment|araboon|earnest)\b|(?:عربون|عربونها|دفعة\s*مقدمة|مقدم|دفعة\s*أولى)/iu.test(
		text
	);
}

function quoteReplyUsesPrematureReviewLanguage(reply = "", toolResult = {}) {
	if (toolResult?.tool !== "get_quote" || toolResult?.available !== true) return false;
	const text = normalizeDigits(String(reply || ""))
		.replace(/[.!?\u061f\u060c,]+/g, " ")
		.replace(/\s+/g, " ")
		.trim()
		.toLowerCase();
	if (!text) return false;
	return (
		/\b(?:final|official)\s+(?:booking\s+)?(?:review|summary)\b/i.test(text) ||
		/\b(?:raise|send|move|submit).{0,50}(?:final|official).{0,30}(?:review|booking review)\b/i.test(
			text
		) ||
		/(?:\u0645\u0644\u062e\u0635\s+\u0627\u0644\u062d\u062c\u0632\s+\u0627\u0644\u0646\u0647\u0627\u0626\u064a|\u0627\u0644\u0645\u0631\u0627\u062c\u0639\u0629\s+\u0627\u0644\u0646\u0647\u0627\u0626\u064a\u0629|\u0627\u0644\u0645\u0631\u0627\u062c\u0639\u0629\s+\u0627\u0644\u0631\u0633\u0645\u064a\u0629)/iu.test(
			text
		) ||
		/(?:\u0627\u0631\u0641\u0639|\u0623\u0631\u0641\u0639|\u0633\u0623\u0631\u0641\u0639|\u0647\u0631\u0641\u0639).{0,40}(?:\u0627\u0644\u062d\u062c\u0632|\u0644\u0644\u0645\u0631\u0627\u062c\u0639\u0629)/iu.test(
			text
		)
	);
}

function quoteReplyRoomCountConflictsWithTool(reply = "", toolResult = {}) {
	if (toolResult?.tool !== "get_quote" || toolResult?.available !== true) return false;
	const expected = Number(toolResult.totalRooms || quoteRoomCount(toolResult.quote) || 0) || 0;
	if (!expected) return false;
	const expectedSelections = normalizeRoomSelections(
		toolResult.roomSelections || toolResult.quote?.roomSelections
	);
	if (expectedSelections.length) {
		const roomishReply = String(reply || "")
			.split(/\r?\n|[.;]+/)
			.map((line) => line.trim())
			.filter((line) =>
				/(?:rooms?|room\s*\(s\)|suite|suites?|single|double|twin|triple|quad|quadruple|family|quintuple|\u063a\u0631\u0641|\u063a\u0631\u0641\u0629|\u063a\u0631\u0641\u0647|\u0627\u0648\u0636|\u0627\u0648\u0636\u0629|\u0627\u0648\u0636\u0647|\u062c\u0646\u0627\u062d)/iu.test(
					line
				)
			)
			.join("\n");
		const replySelections = normalizeRoomSelections(
			extractRoomSelectionsFromText(roomishReply)
		);
		if (
			replySelections.length &&
			roomSelectionKey(replySelections) !== roomSelectionKey(expectedSelections)
		) {
			return true;
		}
	}
	const text = normalizeDigits(String(reply || ""))
		.replace(/[^\p{L}\p{N}\s:×x\-]/gu, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!text) return false;
	const roomCountMatches = Array.from(
		text.matchAll(
			/(?:^|[\s:])0?(\d{1,3})\s*(?:[x×]\s*)?(?:rooms?|units?|\u063a\u0631\u0641|\u063a\u0631\u0641\u0629|\u063a\u0631\u0641\u0647|\u0627\u0648\u0636\u0629|\u0627\u0648\u0636\u0647)(?=$|[\s:])/giu
		)
	);
	return roomCountMatches.some((match) => {
		const count = Number(match[1] || 0) || 0;
		return count > 0 && count !== expected;
	});
}

function reviewReplyMissingDiscountFormat(reply = "", toolResult = {}) {
	if (toolResult?.tool !== "send_review" || toolResult?.code !== "review_ready") return false;
	const review = asObject(toolResult?.review);
	const quote = asObject(review.quote);
	const discounts = [
		asObject(toolResult?.discount),
		asObject(quote.discount),
		asObject(review.discount),
		...(Array.isArray(review.reservations)
			? review.reservations.map((reservation) => asObject(reservation?.discount))
			: []),
	].filter((discount) => discount.displayTotalLine);
	if (!discounts.length) return false;
	const text = String(reply || "");
	return (
		!/<s\b[^>]*class=["'][^"']*\bmessage-price-old\b/i.test(text) ||
		!/<strong\b[^>]*class=["'][^"']*\bmessage-price-new\b/i.test(text) ||
		discounts.some((discount) => !replyPreservesVisibleNumbers(discount.displayTotalLine, text))
	);
}

function reviewReplyMissingConfirmationAsk(reply = "", toolResult = {}) {
	if (toolResult?.tool !== "send_review" || toolResult?.code !== "review_ready") return false;
	const text = normalizeIntentSearchText(reply)
		.replace(/[.!?\u061f\u060c,]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!text) return true;
	const compact = text.replace(/\s+/g, "");
	return !(
		/\b(?:confirm|complete|correct|continue|go\s+ahead|place\s+reservation|create\s+(?:the\s+)?booking)\b/i.test(
			text
		) ||
		/(?:\u0625\u062a\u0645\u0627\u0645|\u0627\u062a\u0645\u0627\u0645|\u0623\u0643\u0645\u0644|\u0627\u0643\u0645\u0644|\u0623\u0624\u0643\u062f|\u0627\u0624\u0643\u062f|\u062a\u0623\u0643\u064a\u062f|\u062a\u0627\u0643\u064a\u062f|\u0635\u062d\u064a\u062d|\u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a)/iu.test(
			compact
		)
	);
}

function formatNightsLabel(value = 0, languageCode = "en") {
	const nights = Math.max(0, Number(value || 0) || 0);
	if (/^ar\b/i.test(languageCode)) {
		if (nights === 1) return "ليلة واحدة";
		if (nights === 2) return "ليلتين";
		return `${formatNumber(nights, languageCode)} ليال`;
	}
	return `${nights} night${nights === 1 ? "" : "s"}`;
}

function roomDisplayLabel(room = {}, roomTypeKey = "", languageCode = "en") {
	const ar = /^ar\b/i.test(languageCode);
	const english = cleanDisplayString(room.displayName, 160);
	const localized = cleanDisplayString(room.displayName_OtherLanguage, 160);
	if (ar) {
		if (localized && english && localized !== english) return `${localized} (${english})`;
		return localized || english || roomTypeLabel(roomTypeKey, languageCode);
	}
	return english || localized || roomTypeLabel(roomTypeKey, languageCode);
}

function quoteRoomLinesText(quote = {}, fallbackRoomTypeKey = "", languageCode = "en") {
	const lines = Array.isArray(quote.rooms) ? quote.rooms : [];
	if (lines.length) {
		return lines
			.map((line) => {
				const label = roomDisplayLabel(
					line.room || line.quote?.room || {},
					line.roomTypeKey || line.roomType || fallbackRoomTypeKey,
					languageCode
				);
				return `${formatNumber(normalizeRoomCount(line.count, 1), languageCode)} x ${label}`;
			})
			.join(" + ");
	}
	return roomDisplayLabel(quote.room, fallbackRoomTypeKey, languageCode);
}

function roomSelectionsDisplayText(selections = [], languageCode = "en") {
	return normalizeRoomSelections(selections)
		.map((selection) => {
			const label =
				cleanDisplayString(selection.roomDisplayName, 160) ||
				roomTypeLabel(selection.roomTypeKey, languageCode);
			return `${formatNumber(selection.count, languageCode)} x ${label}`;
		})
		.join(" + ");
}

function roomComparisonTextAsksBoth(value = "") {
	const text = normalizeIntentSearchText(value).toLowerCase();
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:both|compare|comparison|options?|either)\b/i.test(text) ||
		/(?:\u0643\u0644\u0627\u0647\u0645\u0627|\u0627\u0644\u0627\u062b\u0646\u064a\u0646|\u0627\u0644\u0625\u062b\u0646\u064a\u0646|\u0627\u0644\u062e\u064a\u0627\u0631\u064a\u0646|\u0645\u0642\u0627\u0631\u0646\u0629|\u0627\u0644\u0627\u062e\u062a\u064a\u0627\u0631\u064a\u0646)/u.test(
			compact
		)
	);
}

function roomComparisonTextHasAlternativeConnector(value = "") {
	const text = normalizeIntentSearchText(value).toLowerCase();
	return (
		/\b(?:or|either)\b/i.test(text) ||
		/(?:\u0623\u0648|\u0627\u0648|\u0623\u0645|\u0627\u0645)/u.test(text)
	);
}

function previousAiAskedRoomComparisonChoice(entry = {}) {
	const text = normalizeIntentSearchText(entry?.message || "").toLowerCase();
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:which|prefer|choose).{0,80}\b(?:option|room)\b/i.test(text) ||
		/(?:\u0623\u064a\u0647\u0645\u0627|\u0623\u064a\u0647\u0645|\u0627\u064a\u0647\u0645\u0627|\u0627\u064a\u0647\u0645|\u062a\u0641\u0636\u0644|\u0627\u062e\u062a\u0631|\u062a\u062e\u062a\u0627\u0631)/u.test(
			compact
		)
	);
}

function roomComparisonAlternativeSegments(value = "") {
	const text = normalizeRoomCountMarkers(
		normalizeNumberWordsForParsing(normalizeDigits(repairMojibakeText(String(value || ""))))
	)
		.replace(/\r/g, "\n")
		.replace(/[\u060c\u061b;,]+/g, "\n");
	return text
		.split(/\n+|\s+(?:or|either|\u0623\u0648|\u0627\u0648|\u0623\u0645|\u0627\u0645)\s+/iu)
		.map((part) => part.trim())
		.filter(Boolean);
}

function uniqueRoomComparisonOptions(options = []) {
	const seen = new Set();
	const unique = [];
	for (const option of Array.isArray(options) ? options : []) {
		const selections = normalizeRoomSelections(option);
		const key = roomSelectionKey(selections);
		if (!key || seen.has(key)) continue;
		seen.add(key);
		unique.push(selections);
	}
	return unique;
}

function roomPriceComparisonOptionsFromText(value = "", known = {}, previousAi = {}) {
	const hasAlternativeConnector = roomComparisonTextHasAlternativeConnector(value);
	const asksBoth = roomComparisonTextAsksBoth(value);
	if (known?.sameDateRoomSelectionLocked && !hasAlternativeConnector && !asksBoth) {
		return [];
	}
	const latestHasPriceIntent = guestAsksPriceAvailabilityOrBooking(value, "");
	const priorPriceContext = previousAiLooksLikePriceCollection(previousAi);
	const options = [];
	if (hasAlternativeConnector) {
		for (const segment of roomComparisonAlternativeSegments(value)) {
			const selections = extractRoomSelectionsFromText(segment);
			if (selections.length) options.push(selections);
		}
	}
	const unique = uniqueRoomComparisonOptions(options);
	if (
		unique.length >= 2 &&
		(asksBoth || latestHasPriceIntent || priorPriceContext || quoteMatchesKnown(known))
	) {
		return unique.slice(0, 3);
	}
	const knownSelections = normalizeRoomSelections(known.roomSelections);
	if (
		asksBoth &&
		knownSelections.length >= 2 &&
		(previousAiAskedRoomComparisonChoice(previousAi) ||
			priorPriceContext ||
			Array.isArray(known.sameDateRoomOptions))
	) {
		return knownSelections.map((selection) => [selection]).slice(0, 3);
	}
	return [];
}

function comparisonOptionKnown(known = {}, selections = []) {
	const normalized = normalizeRoomSelections(selections);
	const next = { ...dropConflictingQuoteFromKnown(known) };
	delete next.quote;
	next.roomSelections = normalized;
	next.rooms = roomSelectionsTotal(normalized);
	if (normalized.length === 1) next.roomTypeKey = normalized[0].roomTypeKey;
	else delete next.roomTypeKey;
	return syncKnownFromQuote(next);
}

function sameDateOptionFromComparisonQuote(optionKnown = {}, result = {}, languageCode = "en") {
	const quote = asObject(result.quote);
	const selections = selectionsFromKnown(optionKnown);
	const requestedRooms = roomSelectionsTotal(selections) || normalizeRoomCount(optionKnown.rooms, 1);
	const roomTypeKey =
		quote.roomTypeKey ||
		optionKnown.roomTypeKey ||
		(selections.length === 1 ? selections[0].roomTypeKey : "");
	const roomLabel = quoteRoomLinesText(
		quoteHasContent(quote) ? quote : { rooms: selections },
		roomTypeKey,
		languageCode
	);
	return {
		roomTypeKey,
		roomLabel,
		requestedRooms,
		availableRooms: result.available ? requestedRooms : 0,
		requestedRoomsAvailable: Boolean(result.available),
		quotedRooms: quoteRoomCount(quote) || requestedRooms,
		checkinISO: result.checkinISO || optionKnown.checkinISO || "",
		checkoutISO: result.checkoutISO || optionKnown.checkoutISO || "",
		nights: Number(quote.nights || nightsBetween(optionKnown.checkinISO, optionKnown.checkoutISO) || 0) || 0,
		total: Number(quote.total || 0) || 0,
		currency: quote.currency || result.currency || optionKnown.currency || "SAR",
		roomSelections: selections,
	};
}

function buildRoomComparisonQuoteMessage(sc = {}, known = {}, items = [], hotel = {}, latestGuest = null) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const dateLines = reviewDateLines(known, languageCode);
	const availableItems = items.filter((item) => item?.result?.available && quoteHasContent(item.result.quote));
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "\u0627\u0644\u0641\u0646\u062f\u0642"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "the hotel";
	const lines = [];
	if (ar) {
		lines.push(
			`${arabicGuestAddress(sc, known, latestGuest?.message || "")}\u060c \u0642\u0627\u0631\u0646\u062a \u0644\u0643 \u0627\u0644\u062e\u064a\u0627\u0631\u064a\u0646 \u0641\u064a ${hotelName} \u062d\u0633\u0628 \u0627\u0644\u062a\u0648\u0627\u0631\u064a\u062e \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629 \u0645\u0639 \u062e\u0635\u0645 \u0627\u0644\u062d\u062c\u0632 \u0627\u0644\u0645\u0628\u0627\u0634\u0631:`
		);
		lines.push(...dateLines);
		items.forEach((item, index) => {
			const option = sameDateOptionFromComparisonQuote(item.known, item.result, languageCode);
			const quote = asObject(item.result.quote);
			const label = option.roomLabel || quoteRoomLinesText({ rooms: item.selections }, item.known.roomTypeKey, languageCode);
			const discount = quoteDiscountDisplay(quote, languageCode);
			lines.push(`${formatNumber(index + 1, languageCode)}. \u0627\u0644\u062e\u064a\u0627\u0631: ${label}`);
			if (item.result.available && quoteHasContent(quote)) {
				if (discount?.displayAveragePerNightLine) lines.push(discount.displayAveragePerNightLine);
				if (discount?.displayTotalLine) lines.push(discount.displayTotalLine);
			} else {
				lines.push(
					"\u0647\u0630\u0627 \u0627\u0644\u062e\u064a\u0627\u0631 \u0644\u0627 \u064a\u0638\u0647\u0631 \u062a\u0648\u0641\u0631\u0627 \u0645\u0624\u0643\u062f\u0627 \u0644\u0646\u0641\u0633 \u0627\u0644\u0641\u062a\u0631\u0629 \u0627\u0644\u0622\u0646."
				);
			}
		});
		lines.push(
			availableItems.length
				? "\u0627\u062e\u062a\u0631 \u0627\u0644\u0623\u0646\u0633\u0628 \u0644\u0643\u060c \u0648\u0623\u0643\u0645\u0644 \u0644\u0643 \u0627\u0644\u062d\u062c\u0632 \u0645\u0628\u0627\u0634\u0631\u0629."
				: "\u0644\u0648 \u062a\u062d\u0628\u060c \u0623\u0642\u062f\u0631 \u0623\u0631\u0627\u062c\u0639 \u0644\u0643 \u062a\u0648\u0627\u0631\u064a\u062e \u0623\u0648 \u062a\u0631\u062a\u064a\u0628 \u063a\u0631\u0641 \u0628\u062f\u064a\u0644."
		);
		return lines.filter(Boolean).join("\n");
	}
	lines.push(
		`${guestDisplayName(sc)}, I checked both options at ${hotelName} for the requested dates with the direct-booking discount:`
	);
	lines.push(...dateLines);
	items.forEach((item, index) => {
		const option = sameDateOptionFromComparisonQuote(item.known, item.result, languageCode);
		const quote = asObject(item.result.quote);
		const label = option.roomLabel || quoteRoomLinesText({ rooms: item.selections }, item.known.roomTypeKey, languageCode);
		const discount = quoteDiscountDisplay(quote, languageCode);
		lines.push(`${index + 1}. Option: ${label}`);
		if (item.result.available && quoteHasContent(quote)) {
			if (discount?.displayAveragePerNightLine) lines.push(discount.displayAveragePerNightLine);
			if (discount?.displayTotalLine) lines.push(discount.displayTotalLine);
		} else {
			lines.push("This option is not showing confirmed availability for the same dates right now.");
		}
	});
	lines.push(
		availableItems.length
			? "Choose the option that works best and I will continue the booking for you."
			: "I can check alternative dates or a different room setup if you like."
	);
	return lines.filter(Boolean).join("\n");
}

async function handleBrainRoomComparisonQuote(
	io,
	sc = {},
	hotel = {},
	known = {},
	latestGuest = null,
	options = [],
	typingStartedAt = 0
) {
	const caseId = caseIdText(sc);
	const languageCode = activeLanguageCode(sc, known);
	const items = [];
	for (const selections of uniqueRoomComparisonOptions(options).slice(0, 3)) {
		let optionKnown = comparisonOptionKnown(known, selections);
		optionKnown = filterInactiveRoomSelectionsForHotel(hotel, optionKnown, {
			fallbackKnown: known,
		}).known;
		const result = await quoteTool(sc, optionKnown);
		items.push({ selections: normalizeRoomSelections(selections), known: optionKnown, result });
	}
	const sameDateRoomOptions = items
		.map((item) => sameDateOptionFromComparisonQuote(item.known, item.result, languageCode))
		.filter((option) => option.roomTypeKey)
		.slice(0, 3);
	const nextKnown = {
		...dropConflictingQuoteFromKnown(known),
		sameDateRoomOptions,
	};
	delete nextKnown.quote;
	await saveKnownFacts(caseId, nextKnown);
	const reply = buildRoomComparisonQuoteMessage(sc, nextKnown, items, hotel, latestGuest);
	await waitForTypingMinimum(typingStartedAt);
	return sendAiMessage(io, sc, reply, {
		latestGuest,
		known: nextKnown,
		clientAction: sameDateRoomOptions.length
			? "same_date_room_options_ready"
			: "same_date_room_options_unavailable",
		quickReplies: roomOptionQuickReplies(sameDateRoomOptions, languageCode),
	});
}

function hijriRangeText(known = {}) {
	const checkinHijri = cleanDisplayString(known.checkinHijriText, 120);
	const checkoutHijri = cleanDisplayString(known.checkoutHijriText, 120);
	if (checkinHijri && checkoutHijri) return `${checkinHijri} - ${checkoutHijri}`;
	const calendar = String(known.dateCalendar || "").toLowerCase();
	if (!["hijri", "mixed"].includes(calendar)) return "";
	return cleanDisplayString(known.dateRangeOriginalText, 220);
}

function reviewDateLines(known = {}, languageCode = "en") {
	const ar = /^ar\b/i.test(languageCode);
	const gregorianRange = `${formatDate(known.checkinISO, languageCode)} - ${formatDate(
		known.checkoutISO,
		languageCode
	)}`;
	const hijriRange = hijriRangeText(known);
	if (!hijriRange) {
		return [ar ? `التواريخ: ${gregorianRange}` : `Dates: ${gregorianRange}`];
	}
	return ar
		? [
				`التواريخ الهجرية: ${hijriRange}`,
				`التواريخ الميلادية: ${gregorianRange}`,
		  ]
		: [
				`Dates (Hijri): ${hijriRange}`,
				`Dates (Gregorian): ${gregorianRange}`,
		  ];
}

function buildReviewMessage(sc = {}, known = {}, hotel = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const quote = asObject(known.quote);
	const nights = quote.nights || nightsBetween(known.checkinISO, known.checkoutISO);
	const roomLabel = quoteRoomLinesText(quote, known.roomTypeKey, languageCode);
	const totalRooms = quoteRoomCount(quote) || known.rooms || 1;
	const discountDisplay = quoteDiscountDisplay(quote, languageCode);
	const averagePriceLine =
		discountDisplay?.displayAveragePerNightLine ||
		(ar
			? `\u0627\u0644\u0633\u0639\u0631 \u0644\u0644\u064a\u0644\u0629: ${formatMoney(
					quote.averagePerNight || 0,
					quote.currency || "SAR",
					languageCode
			  )}`
			: `Rate per night: ${formatMoney(
					quote.averagePerNight || 0,
					quote.currency || "SAR",
					languageCode
			  )}`);
	const totalPriceLine =
		discountDisplay?.displayTotalLine ||
		(ar
			? `\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a: ${formatMoney(
					quote.total || 0,
					quote.currency || "SAR",
					languageCode
			  )}`
			: `Total: ${formatMoney(quote.total || 0, quote.currency || "SAR", languageCode)}`);
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "الفندق"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "Hotel";
	if (ar) {
		const roomLineLabel = Number(totalRooms || 1) > 1 ? "الغرف" : "الغرفة";
		return [
			`${arabicReviewAddress(sc, known)}، هذه مراجعة نهائية مختصرة قبل إنشاء الحجز:`,
			`الفندق: ${hotelName}`,
			`${roomLineLabel}: ${roomLabel}`,
			...reviewDateLines(known, languageCode),
			`عدد الليالي: ${formatNumber(nights, languageCode)}`,
			`عدد الغرف: ${formatNumber(totalRooms, languageCode)}`,
			`الضيوف: ${arabicGuestCountText(known.adults || 1, known.children || 0, languageCode)}`,
			`اسم الضيف: ${known.fullName || guestDisplayName(sc)}`,
			`الجنسية: ${known.nationality || "غير مضافة"}`,
			`الهاتف: ${known.phone || "غير مضاف"}`,
			`البريد: ${known.email || "غير مضاف"}`,
			`الإجمالي: ${formatMoney(quote.total || 0, quote.currency || "SAR", languageCode)}`,
			`إذا كل شيء صحيح، اختر "إتمام الحجز". وإذا هناك تعديل، اختر "هناك شيء غير صحيح".`,
		].join("\n");
	}
	const roomLineLabel = Number(totalRooms || 1) > 1 ? "Rooms" : "Room";
	return [
		`${guestDisplayName(sc)}, here is the final review before I create the booking:`,
		`Hotel: ${hotelName}`,
		`${roomLineLabel}: ${roomLabel}`,
		...reviewDateLines(known, languageCode),
		`Nights: ${nights}`,
		`Rooms: ${totalRooms}`,
		`Guests: ${englishGuestCountText(known.adults || 1, known.children || 0)}`,
		`Guest name: ${known.fullName || guestDisplayName(sc)}`,
		`Nationality: ${known.nationality || "Not added"}`,
		`Phone: ${known.phone || "Not added"}`,
		`Email: ${known.email || "Not added"}`,
		`Total: ${formatMoney(quote.total || 0, quote.currency || "SAR", languageCode)}`,
		`If everything is correct, choose "Complete booking". If something needs fixing, choose "Something is wrong".`,
	].join("\n");
}

function buildReviewMessage(sc = {}, known = {}, hotel = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const quote = asObject(known.quote);
	const nights = quote.nights || nightsBetween(known.checkinISO, known.checkoutISO);
	const roomLabel = quoteRoomLinesText(quote, known.roomTypeKey, languageCode);
	const totalRooms = quoteRoomCount(quote) || known.rooms || 1;
	const discountDisplay = quoteDiscountDisplay(quote, languageCode);
	const averagePriceLine =
		discountDisplay?.displayAveragePerNightLine ||
		(ar
			? `\u0627\u0644\u0633\u0639\u0631 \u0644\u0644\u064a\u0644\u0629: ${formatMoney(
					quote.averagePerNight || 0,
					quote.currency || "SAR",
					languageCode
			  )}`
			: `Rate per night: ${formatMoney(
					quote.averagePerNight || 0,
					quote.currency || "SAR",
					languageCode
			  )}`);
	const totalPriceLine =
		discountDisplay?.displayTotalLine ||
		(ar
			? `\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a: ${formatMoney(
					quote.total || 0,
					quote.currency || "SAR",
					languageCode
			  )}`
			: `Total: ${formatMoney(quote.total || 0, quote.currency || "SAR", languageCode)}`);
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "\u0627\u0644\u0641\u0646\u062f\u0642"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "Hotel";
	if (ar) {
		const roomLineLabel =
			Number(totalRooms || 1) > 1
				? "\u0627\u0644\u063a\u0631\u0641"
				: "\u0627\u0644\u063a\u0631\u0641\u0629";
		return [
			`${arabicReviewAddress(sc, known)}\u060c \u0647\u0630\u0647 \u0645\u0631\u0627\u062c\u0639\u0629 \u0646\u0647\u0627\u0626\u064a\u0629 \u0645\u062e\u062a\u0635\u0631\u0629 \u0642\u0628\u0644 \u0625\u0646\u0634\u0627\u0621 \u0627\u0644\u062d\u062c\u0632:`,
			`\u0627\u0644\u0641\u0646\u062f\u0642: ${hotelName}`,
			`${roomLineLabel}: ${roomLabel}`,
			...reviewDateLines(known, languageCode),
			`\u0639\u062f\u062f \u0627\u0644\u0644\u064a\u0627\u0644\u064a: ${formatNumber(nights, languageCode)}`,
			`\u0639\u062f\u062f \u0627\u0644\u063a\u0631\u0641: ${formatNumber(totalRooms, languageCode)}`,
			`\u0627\u0644\u0636\u064a\u0648\u0641: ${arabicGuestCountText(
				known.adults || 1,
				known.children || 0,
				languageCode
			)}`,
			`\u0627\u0633\u0645 \u0627\u0644\u0636\u064a\u0641: ${known.fullName || guestDisplayName(sc)}`,
			`\u0627\u0644\u062c\u0646\u0633\u064a\u0629: ${known.nationality || "\u063a\u064a\u0631 \u0645\u0636\u0627\u0641\u0629"}`,
			`\u0627\u0644\u0647\u0627\u062a\u0641: ${known.phone || "\u063a\u064a\u0631 \u0645\u0636\u0627\u0641"}`,
			`\u0627\u0644\u0628\u0631\u064a\u062f: ${known.email || "\u063a\u064a\u0631 \u0645\u0636\u0627\u0641"}`,
			averagePriceLine,
			totalPriceLine,
			`\u0625\u0630\u0627 \u0643\u0644 \u0634\u064a\u0621 \u0635\u062d\u064a\u062d\u060c \u0627\u062e\u062a\u0631 "\u0625\u062a\u0645\u0627\u0645 \u0627\u0644\u062d\u062c\u0632". \u0648\u0625\u0630\u0627 \u0647\u0646\u0627\u0643 \u062a\u0639\u062f\u064a\u0644\u060c \u0627\u062e\u062a\u0631 "\u0647\u0646\u0627\u0643 \u0634\u064a\u0621 \u063a\u064a\u0631 \u0635\u062d\u064a\u062d".`,
		].join("\n");
	}
	const roomLineLabel = Number(totalRooms || 1) > 1 ? "Rooms" : "Room";
	return [
		`${guestDisplayName(sc)}, here is the final review before I create the booking:`,
		`Hotel: ${hotelName}`,
		`${roomLineLabel}: ${roomLabel}`,
		...reviewDateLines(known, languageCode),
		`Nights: ${nights}`,
		`Rooms: ${totalRooms}`,
		`Guests: ${englishGuestCountText(known.adults || 1, known.children || 0)}`,
		`Guest name: ${known.fullName || guestDisplayName(sc)}`,
		`Nationality: ${known.nationality || "Not added"}`,
		`Phone: ${known.phone || "Not added"}`,
		`Email: ${known.email || "Not added"}`,
		averagePriceLine,
		totalPriceLine,
		`If everything is correct, choose "Complete booking". If something needs fixing, choose "Something is wrong".`,
	].join("\n");
}

function buildRepeatedReviewMessage(sc = {}, known = {}, hotel = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const quote = asObject(known.quote);
	const nights = quote.nights || nightsBetween(known.checkinISO, known.checkoutISO);
	const roomLabel = quoteRoomLinesText(quote, known.roomTypeKey, languageCode);
	const totalRooms = quoteRoomCount(quote) || known.rooms || 1;
	const discountDisplay = quoteDiscountDisplay(quote, languageCode);
	const averagePriceLine =
		discountDisplay?.displayAveragePerNightLine ||
		(ar
			? `\u0627\u0644\u0645\u062a\u0648\u0633\u0637 \u0644\u0643\u0644 \u0644\u064a\u0644\u0629: ${formatMoney(
					quote.averagePerNight || 0,
					quote.currency || "SAR",
					languageCode
			  )}`
			: `Nightly average: ${formatMoney(
					quote.averagePerNight || 0,
					quote.currency || "SAR",
					languageCode
			  )}`);
	const totalPriceLine =
		discountDisplay?.displayTotalLine ||
		(ar
			? `\u0627\u0644\u0642\u064a\u0645\u0629 \u0627\u0644\u0643\u0644\u064a\u0629: ${formatMoney(
					quote.total || 0,
					quote.currency || "SAR",
					languageCode
			  )}`
			: `Complete stay price: ${formatMoney(
					quote.total || 0,
					quote.currency || "SAR",
					languageCode
			  )}`);
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "\u0627\u0644\u0641\u0646\u062f\u0642"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "Hotel";
	const dates = reviewDateLines(known, languageCode);
	if (ar) {
		return [
			`${arabicReviewAddress(sc, known)}\u060c \u062d\u0627\u0636\u0631. \u0633\u0623\u0639\u064a\u062f \u062a\u0631\u062a\u064a\u0628 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0628\u0635\u064a\u063a\u0629 \u0645\u062e\u062a\u0644\u0641\u0629 \u0644\u0644\u062a\u062d\u0642\u0642 \u0645\u0639\u0643:`,
			`\u0627\u062e\u062a\u064a\u0627\u0631 \u0627\u0644\u0625\u0642\u0627\u0645\u0629 \u2014 ${hotelName} / ${roomLabel}`,
			...dates.map((line) => line.replace(/^\s*\u0627\u0644\u062a\u0648\u0627\u0631\u064a\u062e\s*:/u, "\u0627\u0644\u0641\u062a\u0631\u0629 \u2014")),
			`\u0627\u0644\u0645\u062f\u0629 \u0648\u0627\u0644\u062a\u0648\u0632\u064a\u0639 \u2014 ${formatNumber(
				nights,
				languageCode
			)} \u0644\u064a\u0644\u0629\u060c ${formatNumber(totalRooms, languageCode)} \u063a\u0631\u0641\u0629`,
			`\u0627\u0644\u0645\u0633\u0627\u0641\u0631\u0648\u0646 \u2014 ${arabicGuestCountText(
				known.adults || 1,
				known.children || 0,
				languageCode
			)}`,
			`\u0635\u0627\u062d\u0628 \u0627\u0644\u0637\u0644\u0628 \u2014 ${known.fullName || guestDisplayName(sc)} / ${
				known.nationality || "\u063a\u064a\u0631 \u0645\u0636\u0627\u0641\u0629"
			}`,
			`\u0648\u0633\u064a\u0644\u0629 \u0627\u0644\u062a\u0648\u0627\u0635\u0644 \u2014 ${
				known.phone || "\u063a\u064a\u0631 \u0645\u0636\u0627\u0641"
			} / ${known.email || "\u0628\u062f\u0648\u0646 \u0628\u0631\u064a\u062f"}`,
			averagePriceLine,
			totalPriceLine,
			`\u0644\u0627\u0639\u062a\u0645\u0627\u062f \u0647\u0630\u0647 \u0627\u0644\u0646\u0633\u062e\u0629 \u0627\u062e\u062a\u0631 "\u0625\u062a\u0645\u0627\u0645 \u0627\u0644\u062d\u062c\u0632"\u060c \u0648\u0644\u062a\u063a\u064a\u064a\u0631 \u0623\u064a \u0646\u0642\u0637\u0629 \u0627\u062e\u062a\u0631 "\u0647\u0646\u0627\u0643 \u0634\u064a\u0621 \u063a\u064a\u0631 \u0635\u062d\u064a\u062d".`,
		].join("\n");
	}
	return [
		`${guestDisplayName(sc)}, certainly. I will lay the same verified data out differently so it is easy to check:`,
		`Stay choice — ${hotelName} / ${roomLabel}`,
		...dates.map((line) => line.replace(/^\s*Dates\s*:/i, "Stay period —")),
		`Length and allocation — ${nights} night${nights === 1 ? "" : "s"}; ${totalRooms} room${
			totalRooms === 1 ? "" : "s"
		}`,
		`Travellers — ${englishGuestCountText(known.adults || 1, known.children || 0)}`,
		`Booking holder — ${known.fullName || guestDisplayName(sc)} / ${
			known.nationality || "Not added"
		}`,
		`Contact kept for this request — ${known.phone || "Not added"} / ${
			known.email || "No email"
		}`,
		averagePriceLine,
		totalPriceLine,
		`To approve this version, choose "Complete booking". To change any point, choose "Something is wrong".`,
	].join("\n");
}

function buildQuoteFallbackMessage(sc = {}, known = {}, result = {}, hotel = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	if (result.code === "room_count_limit_exceeded") {
		return buildRoomCountLimitMessage(sc, known, null);
	}
	const quote = asObject(result.quote);
	const quoteRoomLabel = quoteRoomLinesText(quote, known.roomTypeKey, languageCode);
	const roomLabel =
		!result.available && result.roomLabel
			? cleanDisplayString(result.roomLabel, 160)
			: quoteRoomLabel;
	const totalRooms = quoteRoomCount(quote) || known.rooms || 1;
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "الفندق"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "the hotel";
	const resultSelections = normalizeRoomSelections(result.roomSelections);
	const requestedRoomLabel = resultSelections.length
		? quoteRoomLinesText({ rooms: resultSelections }, known.roomTypeKey, languageCode)
		: roomLabel;
	if (result.code === "capacity_exceeded") {
		const totalGuests = Number(result.totalGuests || totalGuestsFromKnown(known) || 0) || 0;
		const selectedCapacity =
			Number(result.selectedCapacity || roomSelectionsGuestCapacity(selectionsFromKnown(known)) || 0) || 0;
		return ar
			? [
					`${arabicGuestAddress(sc, known)}\u060c \u0627\u0644\u062a\u0631\u062a\u064a\u0628 \u0627\u0644\u0645\u062d\u062f\u062f \u0644\u0644\u063a\u0631\u0641 \u0644\u0627 \u064a\u0643\u0641\u064a \u0639\u062f\u062f \u0627\u0644\u0636\u064a\u0648\u0641.`,
					requestedRoomLabel ? `\u0627\u0644\u0627\u062e\u062a\u064a\u0627\u0631 \u0627\u0644\u062d\u0627\u0644\u064a: ${requestedRoomLabel}.` : "",
					totalGuests && selectedCapacity
						? `\u0639\u062f\u062f \u0627\u0644\u0636\u064a\u0648\u0641 ${formatNumber(totalGuests, languageCode)} \u0648\u0627\u0644\u0633\u0639\u0629 \u0627\u0644\u0645\u0646\u0627\u0633\u0628\u0629 \u0644\u0644\u063a\u0631\u0641 \u0627\u0644\u0645\u062d\u062f\u062f\u0629 ${formatNumber(selectedCapacity, languageCode)}.`
						: "",
					`\u0623\u062d\u062a\u0627\u062c \u0623\u0639\u062f\u0644 \u062a\u0648\u0632\u064a\u0639 \u0627\u0644\u063a\u0631\u0641 \u0623\u0648 \u0623\u0636\u064a\u0641 \u063a\u0631\u0641\u0629 \u0645\u0646\u0627\u0633\u0628\u0629 \u0642\u0628\u0644 \u0623\u0646 \u0623\u0639\u0637\u064a\u0643 \u0633\u0639\u0631\u0627 \u0646\u0647\u0627\u0626\u064a\u0627.`,
			  ]
					.filter(Boolean)
					.join("\n")
			: [
					`${guestDisplayName(sc)}, the selected room setup does not fit the guest count.`,
					requestedRoomLabel ? `Current selection: ${requestedRoomLabel}.` : "",
					totalGuests && selectedCapacity
						? `Guests: ${totalGuests}; selected capacity: ${selectedCapacity}.`
						: "",
					`I need to adjust the room distribution or add a suitable room before giving a final price.`,
			  ]
					.filter(Boolean)
					.join("\n");
	}
	if (result.code === "same_day_checkin_not_supported") {
		const requestedDate = formatDate(
			result.checkinISO || known.checkinISO,
			languageCode
		);
		return ar
			? [
					`${arabicGuestAddress(sc, known)}، تاريخ الوصول المطلوب ${requestedDate} غير متاح للحجز عبر المحادثة لأنه يقع في نفس يوم الفندق.`,
					requestedRoomLabel ? `الغرف المطلوبة: ${requestedRoomLabel}.` : "",
					`اختر "تواريخ بديلة" وسأعرض لك أقرب تواريخ متاحة مؤكدة من التوفر، أو اختر "أعدل التفاصيل".`,
			  ]
					.filter(Boolean)
					.join("\n")
			: [
					`${guestDisplayName(sc)}, the requested check-in date ${requestedDate} is not bookable through chat because it is the hotel's same business day.`,
					requestedRoomLabel ? `Requested room(s): ${requestedRoomLabel}.` : "",
					`Choose "Alternative dates" and I will show the nearest verified available dates from inventory, or choose "Change details".`,
			  ]
					.filter(Boolean)
					.join("\n");
	}
	if (!result.available && result.code === "inventory_overbook") {
		return ar
			? [
					`${arabicGuestAddress(sc, known)}، لا يمكن تقديم ترتيب الغرف المطلوب بنفس الصورة لهذه الفترة.`,
					roomLabel ? `نوع الغرفة المطلوب: ${roomLabel}.` : "",
					"أقدر أجهز لك ترتيبًا مختلطًا مناسبًا يغطي الطلب، أو أحول نفس الترتيب للاستقبال للمراجعة. أيهما تفضل؟",
			  ]
					.filter(Boolean)
					.join("\n")
			: [
					`${guestDisplayName(sc)}, the exact requested room arrangement cannot be offered for the full stay.`,
					roomLabel ? `Requested room type: ${roomLabel}.` : "",
					"I can prepare a suitable mixed room plan for the full request, or pass the exact setup to reception for review. Which would you prefer?",
			  ]
					.filter(Boolean)
					.join("\n");
	}
	if (!result.available || !quote.total) {
		const unavailableItems = Array.isArray(result.unavailableSelections)
			? result.unavailableSelections
					.map((item) => {
						const label =
							item.roomLabel || roomTypeLabel(item.roomTypeKey, languageCode);
						const firstDate = validISODate(item.firstUnavailableDate);
						return firstDate
							? `${label} (${formatDate(firstDate, languageCode)})`
							: label;
					})
					.filter(Boolean)
			: [];
		if (unavailableItems.length || resultSelections.length > 1 || result.firstUnavailableDate) {
			const firstDate = validISODate(result.firstUnavailableDate);
			const blockedHint = firstDate
				? ar
					? `أول تاريخ غير متاح داخل الفترة هو ${formatDate(firstDate, languageCode)}.`
					: `The first unavailable date inside the range is ${formatDate(firstDate, languageCode)}.`
				: "";
			return ar
				? [
						`${arabicGuestAddress(sc, known)}، راجعت التوفر للفترة المطلوبة.`,
						`الغرف المطلوبة: ${requestedRoomLabel}`,
						`التواريخ: ${formatDate(known.checkinISO, languageCode)} - ${formatDate(known.checkoutISO, languageCode)}`,
						unavailableItems.length
							? `غير المتاح حاليًا: ${unavailableItems.join("، ")}.`
							: `لا يظهر توفر مؤكد لهذه التركيبة كاملة في الفترة المطلوبة.`,
						blockedHint,
						`أقدر أبحث لك عن أقرب تواريخ بديلة أو نعدّل نوع الغرف.`,
				  ]
						.filter(Boolean)
						.join("\n")
				: [
						`${guestDisplayName(sc)}, I checked the requested stay.`,
						`Requested rooms: ${requestedRoomLabel}`,
						`Dates: ${formatDate(known.checkinISO, languageCode)} - ${formatDate(known.checkoutISO, languageCode)}`,
						unavailableItems.length
							? `Currently unavailable: ${unavailableItems.join(", ")}.`
							: `This full room combination is not showing confirmed availability for the requested dates.`,
						blockedHint,
						`I can check the closest alternative dates or adjust the room selection.`,
				  ]
						.filter(Boolean)
						.join("\n");
		}
		return ar
			? `${arabicGuestAddress(sc, known)}، أعتذر لك، لا يظهر توفر مؤكد لهذا الخيار في ${hotelName} للتواريخ المطلوبة. أقدر أراجع لك أقرب تواريخ متاحة أو غرفة أخرى؟`
			: `${guestDisplayName(sc)}, I am sorry, this option does not show confirmed availability at ${hotelName} for those dates. Would you like me to check another room or dates?`;
	}
	const dateLines = reviewDateLines(known, languageCode);
	const discountDisplay = quoteDiscountDisplay(quote, languageCode);
	if (quote.roomPlanAdjusted || result.roomPlanAdjusted) {
		const requestedMix = roomSelectionsDisplayText(
			quote.requestedRoomSelections || result.requestedRoomSelections,
			languageCode
		);
		const recommendedMix = roomSelectionsDisplayText(
			quote.recommendedRoomSelections || quote.roomSelections,
			languageCode
		);
		const nightlyLine =
			discountDisplay?.displayAveragePerNightLine ||
			(ar
				? `\u0627\u0644\u0645\u062a\u0648\u0633\u0637 \u0644\u0644\u064a\u0644\u0629: ${formatMoney(
						quote.averagePerNight || 0,
						quote.currency || "SAR",
						languageCode
				  )}`
				: `Average per night: ${formatMoney(
						quote.averagePerNight || 0,
						quote.currency || "SAR",
						languageCode
				  )}`);
		const totalLine =
			discountDisplay?.displayTotalLine ||
			(ar
				? `\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a: ${formatMoney(
						quote.total || 0,
						quote.currency || "SAR",
						languageCode
				  )}`
				: `Total: ${formatMoney(
						quote.total || 0,
						quote.currency || "SAR",
						languageCode
				  )}`);
		if (quote.singleRoomMappedToDouble) {
			return ar
				? [
						`${arabicGuestAddress(sc, known)}\u060c \u0623\u0646\u0633\u0628 \u062e\u064a\u0627\u0631 \u0644\u0634\u062e\u0635 \u0648\u0627\u062d\u062f \u0647\u0648 \u063a\u0631\u0641\u0629 \u062f\u0628\u0644 \u0645\u0631\u064a\u062d\u0629 \u0644\u0644\u0625\u0642\u0627\u0645\u0629 \u0627\u0644\u0645\u0641\u0631\u062f\u0629.`,
						`\u0627\u0644\u063a\u0631\u0641\u0629: ${recommendedMix || roomLabel}`,
						...dateLines,
						`\u0639\u062f\u062f \u0627\u0644\u0644\u064a\u0627\u0644\u064a: ${formatNumber(
							quote.nights || result.nights || 0,
							languageCode
						)}`,
						nightlyLine,
						totalLine,
						`\u0623\u0643\u0645\u0644 \u0644\u0643 \u0627\u0644\u062d\u062c\u0632\u061f`,
				  ].join("\n")
				: [
						`${guestDisplayName(sc)}, the best option for one guest is a comfortable double room for single occupancy.`,
						`Room: ${recommendedMix || roomLabel}`,
						...dateLines,
						`Nights: ${quote.nights || result.nights || 0}`,
						nightlyLine,
						totalLine,
						`Shall I continue the booking for you?`,
				  ].join("\n");
		}
		const adjustmentIntro = ar
			? `${arabicGuestAddress(sc, known)}\u060c \u0644\u062a\u062c\u0647\u064a\u0632 \u0627\u0644\u0639\u062f\u062f \u0627\u0644\u0645\u0637\u0644\u0648\u0628 \u0628\u0634\u0643\u0644 \u0645\u0631\u064a\u062d\u060c \u062c\u0647\u0632\u062a \u0644\u0643 \u0627\u0644\u062a\u0631\u062a\u064a\u0628 \u0627\u0644\u0645\u0646\u0627\u0633\u0628 \u0627\u0644\u062a\u0627\u0644\u064a.`
			: `${guestDisplayName(sc)}, to accommodate the full request comfortably, I prepared the following suitable room mix.`;
		return ar
			? [
					adjustmentIntro,
					requestedMix ? `\u0627\u0644\u0637\u0644\u0628 \u0627\u0644\u0623\u0635\u0644\u064a: ${requestedMix}` : "",
					`\u0627\u0644\u062a\u0631\u062a\u064a\u0628 \u0627\u0644\u0645\u0642\u062a\u0631\u062d: ${recommendedMix || roomLabel}`,
					...dateLines,
					`\u0639\u062f\u062f \u0627\u0644\u0644\u064a\u0627\u0644\u064a: ${formatNumber(
						quote.nights || result.nights || 0,
						languageCode
					)}`,
					nightlyLine,
					totalLine,
					`\u0647\u0630\u0627 \u062a\u063a\u064a\u064a\u0631 \u0639\u0646 \u0627\u0644\u0637\u0644\u0628 \u0627\u0644\u0623\u0635\u0644\u064a\u061b \u0647\u0644 \u062a\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u0647\u0630\u0627 \u0627\u0644\u062a\u0631\u062a\u064a\u0628 \u0643\u064a \u0623\u0643\u0645\u0644\u061f`,
			  ]
					.filter(Boolean)
					.join("\n")
			: [
					adjustmentIntro,
					requestedMix ? `Original request: ${requestedMix}` : "",
					`Recommended mix: ${recommendedMix || roomLabel}`,
					...dateLines,
					`Nights: ${quote.nights || result.nights || 0}`,
					nightlyLine,
					totalLine,
					`This changes the original room mix. Do you agree to this exact recommended mix so I can continue?`,
			  ]
					.filter(Boolean)
					.join("\n");
	}
	if (ar) {
		const roomLineLabel = Number(totalRooms || 1) > 1 ? "الغرف" : "الغرفة";
		return [
			`تمام ${arabicGuestAddress(sc, known)}، متاح بإذن الله.`,
			`${roomLineLabel}: ${roomLabel}`,
			...dateLines,
			`عدد الليالي: ${formatNumber(quote.nights || result.nights || 0, languageCode)}`,
			discountDisplay?.displayAveragePerNightLine ||
				`السعر: ${formatMoney(quote.averagePerNight || 0, quote.currency || "SAR", languageCode)} لليلة`,
			discountDisplay?.displayTotalLine ||
				`الإجمالي: ${formatMoney(quote.total || 0, quote.currency || "SAR", languageCode)}`,
			`تحب أكمل لك الحجز؟`,
		].join("\n");
	}
	const roomLineLabel = Number(totalRooms || 1) > 1 ? "Rooms" : "Room";
	return [
		`Yes ${guestDisplayName(sc)}, this is available.`,
		`${roomLineLabel}: ${roomLabel}`,
		...dateLines,
		`Nights: ${quote.nights || result.nights || 0}`,
		discountDisplay?.displayAveragePerNightLine ||
			`Rate: ${formatMoney(quote.averagePerNight || 0, quote.currency || "SAR", languageCode)} per night`,
		discountDisplay?.displayTotalLine ||
			`Total: ${formatMoney(quote.total || 0, quote.currency || "SAR", languageCode)}`,
		`Would you like me to continue the booking?`,
	].join("\n");
}

function buildConfirmationMessage(sc = {}, known = {}, hotel = {}, reservation = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const links = reservationPublicLinks(reservation);
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "الفندق"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "the hotel";
	const total = reservation.total_amount || known.quote?.total || 0;
	if (ar) {
		return [
			`تم تأكيد الحجز بنجاح. رقم التأكيد: ${reservation.confirmation_number}.`,
			`شكرا لاختيارك ${hotelName}. سعداء بحجزك معنا ونتطلع لاستقبالك يوم ${formatDate(known.checkinISO, languageCode)}.`,
			`الإجمالي: ${formatMoney(total, known.quote?.currency || "SAR", languageCode)}.`,
			links.reservationConfirmation ? `[اضغط هنا لمعرفة المزيد من التفاصيل](${links.reservationConfirmation})` : "",
			links.payment ? `[رابط الدفع](${links.payment})` : "",
			`هل أقدر أساعدك بأي شيء آخر؟`,
		]
			.filter(Boolean)
			.join("\n");
	}
	return [
		`Your booking is confirmed. Confirmation number: ${reservation.confirmation_number}.`,
		`Thank you for choosing ${hotelName}. We look forward to welcoming you on ${formatDate(known.checkinISO, languageCode)}.`,
		`Total: ${formatMoney(total, known.quote?.currency || "SAR", languageCode)}.`,
		links.reservationConfirmation ? `[View reservation details](${links.reservationConfirmation})` : "",
		links.payment ? `[Payment link](${links.payment})` : "",
		`Can I help you with anything else?`,
	]
		.filter(Boolean)
		.join("\n");
}

function confirmationNumberFromText(value = "") {
	const text = normalizeDigits(String(value || ""));
	const matches = Array.from(text.matchAll(/\b\d{8,12}\b/g));
	for (const match of matches) {
		const item = match[0];
		const index = match.index || 0;
		const before = text.slice(Math.max(0, index - 42), index);
		const after = text.slice(index + item.length, index + item.length + 20);
		const nearby = `${before} ${after}`.toLowerCase();
		const previousChar = text[index - 1] || "";
		const phoneContext =
			/\+$/.test(before) ||
			previousChar === "+" ||
			/(?:phone|mobile|whatsapp|whats\s*app|telephone|tel|contact|call|\u0631\u0642\u0645 \u0627\u0644\u0647\u0627\u062a\u0641|\u0627\u0644\u0647\u0627\u062a\u0641|\u0647\u0627\u062a\u0641|\u0631\u0642\u0645 \u0627\u0644\u062c\u0648\u0627\u0644|\u0627\u0644\u062c\u0648\u0627\u0644|\u062c\u0648\u0627\u0644|\u0645\u0648\u0628\u0627\u064a\u0644|\u0648\u0627\u062a\u0633|\u0648\u0627\u062a\u0633\u0627\u0628|\u062a\u0648\u0627\u0635\u0644)/i.test(
				nearby
			);
		if (phoneContext) continue;
		if (/^20\d{6,}$/.test(item)) continue;
		return item;
	}
	return "";
}

function latestGuestAsksSupportContactNumber(value = "") {
	const raw = String(value || "");
	const text = normalizeIntentSearchText(raw).toLowerCase();
	const compact = text.replace(/\s+/g, "");
	if (!text) return false;
	if (/^\+?\d[\d\s().-]{6,24}$/.test(normalizeDigits(raw).trim())) return false;
	if (
		/(?:confirmation|booking\s*(?:number|no|#)|reservation\s*(?:number|no|#)|reference\s*(?:number|no|#))/i.test(
			text
		) ||
		/(?:\u0631\u0642\u0645|\u0646\u0645\u0631\u0629|\u0646\u0645\u0631\u0647)(?:\u0627\u0644)?(?:\u062a\u0623\u0643\u064a\u062f|\u062a\u0627\u0643\u064a\u062f|\u062d\u062c\u0632)|(?:\u0631\u0642\u0645)(?:\s+)?(?:\u0627\u0644)?(?:\u062a\u0623\u0643\u064a\u062f|\u062a\u0627\u0643\u064a\u062f|\u062d\u062c\u0632)/iu.test(
			compact
		)
	) {
		return false;
	}
	const arabicAskEscaped =
		/(?:\u0631\u0642\u0645\u0643\u0645|\u0631\u0642\u0645\u0643|\u0631\u0642\u0645\s*(?:\u0627\u0644)?(?:\u0648\u0627\u062a\u0633|\u0648\u0627\u062a\u0633\u0627\u0628|\u0648\u0627\u062a\u0633\s*\u0627\u0628|\u0647\u0627\u062a\u0641|\u062c\u0648\u0627\u0644|\u062a\u0648\u0627\u0635\u0644)|\u0648\u0627\u062a\u0633\u0627\u0628\u0643\u0645|\u0648\u0627\u062a\u0633\u0627\u0628\u0643|\u0648\u0627\u062a\u0633\u0643\u0645|\u0643\u064a\u0641\s*(?:\u0627\u062a\u0648\u0627\u0635\u0644|\u0623\u062a\u0648\u0627\u0635\u0644)|\u0627\u0631\u064a\u062f\s*\u0631\u0642\u0645|\u0639\u0627\u064a\u0632\s*\u0631\u0642\u0645|\u0645\u062d\u062a\u0627\u062c\s*\u0631\u0642\u0645|\u0627\u0628\u0639\u062a\s*(?:\u0644\u064a\s*)?(?:\u0627\u0644)?\u0631\u0642\u0645|\u0627\u0631\u0633\u0644\s*(?:\u0644\u064a\s*)?(?:\u0627\u0644)?\u0631\u0642\u0645|\u0645\u0645\u0643\u0646\s*(?:\u0627\u0644)?\u0631\u0642\u0645)/iu.test(
			compact
		);
	const englishAsk =
		/\b(?:whatsapp|whats\s*app|phone|mobile|contact\s*(?:number)?|call\s*(?:number)?|telephone|tel)\b/i.test(
			text
		) &&
		/\b(?:what|which|send|give|share|provide|need|want|can|could|how|contact|call)\b/i.test(
			text
		);
	return arabicAskEscaped || englishAsk;
}

function latestGuestAsksRoomPhotos(value = "") {
	const text = normalizeIntentSearchText(value).toLowerCase();
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:photo|photos|picture|pictures|image|images|room\s*(?:photo|photos|picture|pictures|image|images))\b/i.test(
			text
		) ||
		/(?:\u0635\u0648\u0631|\u0635\u0648\u0631\u0629|\u0635\u0648\u0631\u0647|\u0627\u0644\u0635\u0648\u0631|\u0635\u0648\u0631\u0627\u0644\u063a\u0631\u0641|\u0635\u0648\u0631\u0627\u0644\u0641\u0646\u062f\u0642|\u0635\u0648\u0631\u0647\u0627|\u0635\u0648\u0631\u062a\u0647\u0627)/iu.test(
			compact
		)
	);
}

function buildSupportContactNumberMessage(sc = {}, known = {}, latestGuest = null, hotel = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const wantsPhotos = latestGuestAsksRoomPhotos(latestGuest?.message || "");
	const ar =
		/^ar\b/i.test(languageCode) ||
		/[\u0600-\u06FF]/.test(String(latestGuest?.message || ""));
	const extraLines = [];
	if (latestGuestMentionsBus(latestGuest)) {
		const busDetails = serviceFactDetailsForReply(hotel?.busDetails, { allowArabic: ar });
		if (hotel?.hasBusService === true || busDetails) {
			extraLines.push(
				ar
					? `\u0648\u0628\u0627\u0644\u0646\u0633\u0628\u0629 \u0644\u0644\u0628\u0627\u0635 \u0623\u0648 \u0627\u0644\u0645\u0648\u0627\u0635\u0644\u0627\u062a: ${busDetails || "\u0627\u0644\u0641\u0646\u062f\u0642 \u064a\u0648\u0641\u0631 \u062f\u0639\u0645 \u0646\u0642\u0644 \u0644\u0644\u0636\u064a\u0648\u0641 \u062d\u0633\u0628 \u062a\u0646\u0633\u064a\u0642 \u0627\u0644\u0641\u0646\u062f\u0642."}`
					: `For bus/transport: ${busDetails || "the hotel provides guest transport support according to hotel coordination."}`
			);
		}
	}
	if (ar) {
		return [
			`\u0623\u0643\u064a\u062f\u060c \u0644\u0644\u062a\u0648\u0627\u0635\u0644 \u0645\u0639\u0646\u0627 \u0639\u0644\u0649 \u0648\u0627\u062a\u0633\u0627\u0628 \u0644\u0623\u064a \u0627\u0633\u062a\u0641\u0633\u0627\u0631: ${RESERVATION_CHANGE_CONTACT_PHONE}`,
			`\u0631\u0627\u0628\u0637 \u0627\u0644\u0648\u0627\u062a\u0633\u0627\u0628: ${RESERVATION_CHANGE_CONTACT_WHATSAPP}`,
			...extraLines,
			wantsPhotos
				? "\u0648\u0644\u0635\u0648\u0631 \u0627\u0644\u063a\u0631\u0641\u060c \u064a\u0645\u0643\u0646\u0643 \u0625\u0631\u0633\u0627\u0644 \u0627\u0633\u0645 \u0627\u0644\u0641\u0646\u062f\u0642 \u0639\u0644\u0649 \u0648\u0627\u062a\u0633\u0627\u0628 \u0648\u0633\u0646\u0631\u0633\u0644 \u0644\u0643 \u0627\u0644\u0635\u0648\u0631 \u0627\u0644\u0645\u062a\u0627\u062d\u0629\u060c \u0648\u0623\u0642\u062f\u0631 \u0623\u0633\u0627\u0639\u062f\u0643 \u0647\u0646\u0627 \u0623\u064a\u0636\u0627."
				: "\u0648\u0623\u0642\u062f\u0631 \u0623\u0633\u0627\u0639\u062f\u0643 \u0647\u0646\u0627 \u0641\u064a \u0627\u0644\u0634\u0627\u062a \u0623\u064a\u0636\u0627.",
		].join("\n");
	}
	return [
		`Sure, you can WhatsApp us for any inquiry at ${RESERVATION_CHANGE_CONTACT_PHONE}.`,
		`WhatsApp link: ${RESERVATION_CHANGE_CONTACT_WHATSAPP}`,
		...extraLines,
		wantsPhotos
			? "For room photos, send us the hotel name on WhatsApp and we will share the available photos. I can also help you here in chat."
			: "I can also help you here in chat.",
	].join("\n");
}

function humanEscalationContactToolResult(reason = "", draftReply = "") {
	return {
		tool: "human_escalation_contact",
		ok: true,
		code: "human_contact_required",
		reason: cleanDisplayString(reason, 160),
		contactPhone: RESERVATION_CHANGE_CONTACT_PHONE,
		whatsapp: RESERVATION_CHANGE_CONTACT_WHATSAPP,
		brainDraftReply: cleanDisplayString(draftReply, 1000),
		instruction:
			"The guest needs human/reception follow-up. Write the final customer-facing reply from OpenAI only. Be warm and professional, say the team will help or review the issue, and include the exact contactPhone and whatsapp link. Do not invent another contact method.",
	};
}

function buildHumanEscalationContactMessage(sc = {}, known = {}, latestGuest = null, reason = "") {
	const languageCode = activeLanguageCode(sc, known);
	const latestText = String(latestGuest?.message || "");
	const ar = /^ar\b/i.test(languageCode) || /[\u0600-\u06FF]/.test(latestText);
	if (ar) {
		return [
			`\u0623\u0641\u0647\u0645\u0643 ${arabicGuestAddress(sc, known, latestText)}\u060c \u0633\u0623\u062d\u0648\u0644 \u0627\u0644\u0645\u062d\u0627\u062f\u062b\u0629 \u0644\u0623\u062d\u062f \u0623\u0639\u0636\u0627\u0621 \u0627\u0644\u0641\u0631\u064a\u0642 \u0644\u0645\u0631\u0627\u062c\u0639\u062a\u0647\u0627 \u0645\u0639\u0643 \u0628\u062f\u0642\u0629.`,
			`\u0644\u0644\u0645\u062a\u0627\u0628\u0639\u0629 \u0627\u0644\u0623\u0633\u0631\u0639\u060c \u064a\u0645\u0643\u0646\u0643 \u0645\u0631\u0627\u0633\u0644\u062a\u0646\u0627 \u0648\u0627\u062a\u0633\u0627\u0628 \u0623\u0648 \u0627\u0644\u0627\u062a\u0635\u0627\u0644 \u0639\u0644\u0649: ${RESERVATION_CHANGE_CONTACT_PHONE}`,
			`\u0631\u0627\u0628\u0637 \u0627\u0644\u0648\u0627\u062a\u0633\u0627\u0628: ${RESERVATION_CHANGE_CONTACT_WHATSAPP}`,
		].join("\n");
	}
	return [
		`${guestDisplayName(sc)}, I understand. I will pass this conversation to a team member so they can help you properly.`,
		`For the fastest follow-up, please WhatsApp or call us at ${RESERVATION_CHANGE_CONTACT_PHONE}.`,
		`WhatsApp link: ${RESERVATION_CHANGE_CONTACT_WHATSAPP}`,
	].join("\n");
}

function latestGuestAsksPayAtHotel(value = "") {
	const raw = String(value || "");
	const text = normalizeIntentSearchText(raw).toLowerCase();
	const compact = text.replace(/\s+/g, "");
	if (!text) return false;
	const englishPay =
		/\b(?:pay|payment|settle|cash|card)\b/i.test(text) &&
		/\b(?:hotel|arrival|arrive|front\s*desk|reception|check\s*in|check-in)\b/i.test(text);
	const arabicPay =
		/(?:\u064a\u0646\u0641\u0639|\u0645\u0645\u0643\u0646|\u0627\u0642\u062f\u0631|\u0623\u0642\u062f\u0631|\u0647\u0644|\u062d\u0627\u0633\u0628|\u0627\u062d\u0627\u0633\u0628|)\s*(?:\u0627\u062f\u0641\u0639|\u0623\u062f\u0641\u0639|\u0627\u0644\u062f\u0641\u0639|\u062f\u0641\u0639|\u0627\u0633\u062f\u062f|\u0633\u062f\u0627\u062f|\u0627\u062d\u0627\u0633\u0628|\u0623\u062d\u0627\u0633\u0628|\u0643\u0627\u0634)/iu.test(
			text
		) &&
		/(?:\u0627\u0644\u0641\u0646\u062f\u0642|\u0627\u0644\u0648\u0635\u0648\u0644|\u0639\u0646\u062f\u0627\u0644\u0648\u0635\u0648\u0644|\u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644|\u0627\u0644\u062a\u0633\u0643\u064a\u0646|\u0627\u0644\u0631\u064a\u0633\u0628\u0634\u0646)/iu.test(
			compact
		);
	return englishPay || arabicPay;
}

function latestReservationConfirmationFromConversation(sc = {}) {
	let confirmation = "";
	for (const entry of Array.isArray(sc.conversation) ? sc.conversation : []) {
		if (
			isAiSupportEntry(entry) &&
			String(entry.clientAction || "").toLowerCase() === "reservation_confirmed"
		) {
			const found = confirmationNumberFromText(entry.message);
			if (found) confirmation = found;
		}
	}
	return confirmation;
}

function buildPostConfirmationPayAtHotelMessage(sc = {}, known = {}, latestGuest = null) {
	const languageCode = activeLanguageCode(sc, known);
	const ar =
		/^ar\b/i.test(languageCode) ||
		/[\u0600-\u06FF]/.test(String(latestGuest?.message || ""));
	const confirmation =
		cleanString(known.confirmation, 40) || latestReservationConfirmationFromConversation(sc);
	if (ar) {
		const address = arabicGuestAddress(sc, known, latestGuest?.message || "");
		const confirmationText = confirmation
			? ` \u0631\u0642\u0645 \u0627\u0644\u062a\u0623\u0643\u064a\u062f: ${confirmation}.`
			: "";
		return [
			`\u0646\u0639\u0645 \u064a\u0627 ${address}\u060c \u064a\u0645\u0643\u0646 \u0627\u0644\u062f\u0641\u0639 \u0641\u064a \u0627\u0644\u0641\u0646\u062f\u0642 \u0639\u0646\u062f \u0627\u0644\u0648\u0635\u0648\u0644.${confirmationText}`,
			"\u064a\u0631\u062c\u0649 \u0641\u0642\u0637 \u0625\u0628\u0631\u0627\u0632 \u0631\u0642\u0645 \u0627\u0644\u062a\u0623\u0643\u064a\u062f \u0644\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644\u060c \u0648\u0631\u0627\u0628\u0637 \u0627\u0644\u062f\u0641\u0639 \u0641\u064a \u0631\u0633\u0627\u0644\u0629 \u0627\u0644\u062a\u0623\u0643\u064a\u062f \u0645\u062a\u0627\u062d \u0623\u064a\u0636\u0627 \u0625\u0630\u0627 \u0643\u0627\u0646 \u0627\u0644\u062f\u0641\u0639 \u0623\u0648\u0646\u0644\u0627\u064a\u0646 \u0623\u0646\u0633\u0628 \u0644\u0643.",
			"\u0648\u0646\u0646\u0635\u062d \u0628\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0631\u0627\u0628\u0637 \u0627\u0644\u062f\u0641\u0639\u060c \u062d\u062a\u0649 \u0644\u062f\u0641\u0639 \u062c\u0632\u0621 \u0623\u0648 \u0639\u0631\u0628\u0648\u0646 \u0625\u0630\u0627 \u0643\u0627\u0646 \u0645\u062a\u0627\u062d\u0627\u064b\u060c \u0644\u0623\u0646\u0647 \u064a\u062b\u0628\u062a \u062c\u062f\u064a\u0629 \u0627\u0644\u062d\u0636\u0648\u0631 \u0648\u064a\u062b\u0628\u062a \u0627\u0644\u063a\u0631\u0641\u0629 \u0628\u0634\u0643\u0644 \u0623\u0641\u0636\u0644. \u0648\u0625\u0630\u0627 \u0644\u0645 \u064a\u062a\u0645 \u0627\u0644\u062f\u0641\u0639 \u0627\u0644\u0622\u0646 \u0641\u0627\u0644\u062d\u062c\u0632 \u064a\u0638\u0644 \u0642\u0627\u0626\u0645\u0627\u064b\u060c \u0648\u0642\u062f \u064a\u062a\u0648\u0627\u0635\u0644 \u0627\u0644\u0641\u0646\u062f\u0642 \u0641\u0642\u0637 \u0644\u062a\u0623\u0643\u064a\u062f \u0627\u0644\u0648\u0635\u0648\u0644.",
		].join("\n");
	}
	const confirmationText = confirmation ? ` Confirmation number: ${confirmation}.` : "";
	return [
		`Yes, you can pay at the hotel on arrival.${confirmationText}`,
		"Please show the confirmation number at reception. The payment link in the confirmation message is also available if you prefer to pay online.",
		"We recommend using the payment link, even for a partial payment/deposit when available, because it best secures the room and confirms arrival seriousness. If you do not pay online now, your confirmed reservation remains valid, and the hotel may contact you only to confirm arrival.",
	].join("\n");
}

function buildReviewedBookingPendingSuffix(sc = {}, known = {}, latestGuest = null) {
	const languageCode = activeLanguageCode(sc, known);
	const ar =
		/^ar\b/i.test(languageCode) ||
		/[\u0600-\u06FF]/.test(String(latestGuest?.message || ""));
	return ar
		? "\u0644\u0645 \u0623\u0646\u0634\u0626 \u0627\u0644\u062d\u062c\u0632 \u0628\u0639\u062f\u060c \u0648\u062a\u0641\u0627\u0635\u064a\u0644 \u0627\u0644\u0645\u0631\u0627\u062c\u0639\u0629 \u0645\u0627 \u0632\u0627\u0644\u062a \u062c\u0627\u0647\u0632\u0629 \u0643\u0645\u0627 \u0647\u064a. \u0639\u0646\u062f\u0645\u0627 \u062a\u0643\u0648\u0646 \u0645\u0633\u062a\u0639\u062f\u0627\u064b\u060c \u0627\u0643\u062a\u0628 \"\u0625\u062a\u0645\u0627\u0645 \u0627\u0644\u062d\u062c\u0632\" \u0644\u0623\u0639\u064a\u062f \u0627\u0644\u062a\u062d\u0642\u0642 \u0645\u0646 \u0627\u0644\u0633\u0639\u0631 \u0648\u062a\u0648\u0632\u064a\u0639 \u0627\u0644\u063a\u0631\u0641 \u062b\u0645 \u0623\u0646\u0634\u0626\u0647."
		: 'I have not created the reservation yet, and the reviewed details remain ready as shown. When you are ready, say "Complete booking" so I can revalidate the exact price and room mix before creating it.';
}

function buildReviewedBookingDeferredMessage(sc = {}, known = {}, latestGuest = null) {
	const languageCode = activeLanguageCode(sc, known);
	const ar =
		/^ar\b/i.test(languageCode) ||
		/[\u0600-\u06FF]/.test(String(latestGuest?.message || ""));
	const opening = ar
		? `\u0644\u0627 \u0645\u0634\u0643\u0644\u0629 \u064a\u0627 ${arabicGuestAddress(sc, known, latestGuest?.message || "")}\u060c \u062e\u0630 \u0648\u0642\u062a\u0643.`
		: `${guestDisplayName(sc)}, no problem—take your time.`;
	return [opening, buildReviewedBookingPendingSuffix(sc, known, latestGuest)].join("\n");
}

function buildPreBookingPayAtHotelMessage(sc = {}, known = {}, latestGuest = null) {
	const languageCode = activeLanguageCode(sc, known);
	const ar =
		/^ar\b/i.test(languageCode) ||
		/[\u0600-\u06FF]/.test(String(latestGuest?.message || ""));
	const policy = ar
		? [
				"\u0646\u0639\u0645\u060c \u064a\u0645\u0643\u0646\u0643 \u0627\u0644\u062f\u0641\u0639 \u0641\u064a \u0627\u0644\u0641\u0646\u062f\u0642 \u0639\u0646\u062f \u0627\u0644\u0648\u0635\u0648\u0644\u060c \u0648\u0627\u0644\u062f\u0641\u0639 \u0623\u0648\u0646\u0644\u0627\u064a\u0646 \u0644\u064a\u0633 \u0625\u0644\u0632\u0627\u0645\u064a\u0627\u064b.",
				"\u0648\u0646\u0646\u0635\u062d \u0628\u0631\u0627\u0628\u0637 \u0627\u0644\u062f\u0641\u0639\u060c \u062d\u062a\u0649 \u0644\u062f\u0641\u0639 \u062c\u0632\u0621 \u0625\u0630\u0627 \u0643\u0627\u0646 \u0645\u062a\u0627\u062d\u0627\u064b\u060c \u0644\u0623\u0646 \u0627\u0644\u062f\u0641\u0639 \u064a\u062b\u0628\u062a \u0627\u0644\u063a\u0631\u0641\u0629 \u0628\u0634\u0643\u0644 \u0623\u0641\u0636\u0644.",
		  ].join("\n")
		: [
				"Yes, you can pay at the hotel on arrival; online payment is not mandatory.",
				"We still recommend the payment link, including a partial payment when available, because completed payment secures the room more firmly.",
		  ].join("\n");
	return [policy, buildReviewedBookingPendingSuffix(sc, known, latestGuest)].join("\n");
}

function buildReviewedBookingQuestionFallback(sc = {}, known = {}, latestGuest = null) {
	const languageCode = activeLanguageCode(sc, known);
	const ar =
		/^ar\b/i.test(languageCode) ||
		/[\u0600-\u06FF]/.test(String(latestGuest?.message || ""));
	const answer = ar
		? "\u0623\u0631\u064a\u062f \u0623\u0646 \u0623\u062c\u064a\u0628 \u0639\u0646 \u0633\u0624\u0627\u0644\u0643 \u0642\u0628\u0644 \u0625\u0646\u0634\u0627\u0621 \u0627\u0644\u062d\u062c\u0632\u060c \u0644\u0643\u0646\u0646\u064a \u0644\u0645 \u0623\u062a\u0645\u0643\u0646 \u0645\u0646 \u0627\u0644\u062a\u062d\u0642\u0642 \u0645\u0646 \u0627\u0644\u062a\u0641\u0635\u064a\u0644 \u0627\u0644\u0645\u0637\u0644\u0648\u0628 \u0628\u0623\u0645\u0627\u0646. \u0641\u0636\u0644\u0627\u064b \u0623\u0639\u062f \u0625\u0631\u0633\u0627\u0644 \u0627\u0644\u0633\u0624\u0627\u0644 \u0648\u0633\u0623\u062c\u064a\u0628\u0643 \u0639\u0644\u064a\u0647 \u0645\u0628\u0627\u0634\u0631\u0629."
		: "I want to answer your question before creating the reservation, but I could not verify that detail safely. Please repeat the question and I will answer it directly.";
	return [answer, buildReviewedBookingPendingSuffix(sc, known, latestGuest)].join("\n");
}

function buildRoomCountLimitMessage(sc = {}, known = {}, latestGuest = null) {
	const languageCode = activeLanguageCode(sc, known);
	const ar =
		/^ar\b/i.test(languageCode) ||
		/[\u0600-\u06FF]/.test(String(latestGuest?.message || ""));
	if (ar) {
		return [
			`\u0637\u0644\u0628\u0643 \u0623\u0643\u0628\u0631 \u0645\u0646 \u062d\u062f \u0627\u0644\u062d\u062c\u0632 \u0627\u0644\u0622\u0645\u0646 \u0639\u0628\u0631 \u0627\u0644\u0645\u062d\u0627\u062f\u062b\u0629 (${formatNumber(MAX_AI_ROOM_COUNT, languageCode)} \u063a\u0631\u0641\u0629). \u0644\u0645 \u0623\u062e\u0641\u0636 \u0627\u0644\u0639\u062f\u062f \u0648\u0644\u0645 \u0623\u0646\u0634\u0626 \u062d\u062c\u0632\u0627\u064b.`,
			`\u0644\u062a\u0631\u062a\u064a\u0628 \u0647\u0630\u0627 \u0627\u0644\u0637\u0644\u0628 \u0627\u0644\u0643\u0628\u064a\u0631 \u0628\u062f\u0642\u0629\u060c \u062a\u0648\u0627\u0635\u0644 \u0645\u0639 \u0641\u0631\u064a\u0642 \u0627\u0644\u062d\u062c\u0648\u0632\u0627\u062a \u0648\u0627\u062a\u0633\u0627\u0628 \u0623\u0648 \u0627\u062a\u0635\u0644 \u0639\u0644\u0649 ${RESERVATION_CHANGE_CONTACT_PHONE}.`,
			`\u0631\u0627\u0628\u0637 \u0627\u0644\u0648\u0627\u062a\u0633\u0627\u0628: ${RESERVATION_CHANGE_CONTACT_WHATSAPP}`,
		].join("\n");
	}
	return [
		`Your request exceeds the safe chat-booking limit of ${MAX_AI_ROOM_COUNT} rooms. I have not reduced the requested count and have not created a reservation.`,
		`Please arrange this large request with our reservations team by WhatsApp or phone at ${RESERVATION_CHANGE_CONTACT_PHONE}.`,
		`WhatsApp: ${RESERVATION_CHANGE_CONTACT_WHATSAPP}`,
	].join("\n");
}

function replyContradictsPayAtHotelPolicy(reply = "") {
	const text = normalizeIntentSearchTextRepaired(reply);
	const compact = text.replace(/\s+/g, "");
	if (!text) return false;
	const payContext =
		/\b(?:pay|payment|settle|cash|card)\b/i.test(text) ||
		/(?:\u0627\u0644\u062f\u0641\u0639|\u062f\u0641\u0639|\u0627\u062f\u0641\u0639|\u0623\u062f\u0641\u0639|\u0627\u0633\u062f\u062f|\u0633\u062f\u0627\u062f|\u0627\u062d\u0627\u0633\u0628|\u0623\u062d\u0627\u0633\u0628|\u0643\u0627\u0634)/iu.test(text);
	const arrivalContext =
		/\b(?:hotel|arrival|arrive|front\s*desk|reception|check\s*in|check-in)\b/i.test(text) ||
		/(?:\u0627\u0644\u0641\u0646\u062f\u0642|\u0627\u0644\u0648\u0635\u0648\u0644|\u0639\u0646\u062f\u0627\u0644\u0648\u0635\u0648\u0644|\u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644|\u0627\u0644\u062a\u0633\u0643\u064a\u0646|\u0627\u0644\u0631\u064a\u0633\u0628\u0634\u0646)/iu.test(compact);
	const cannotConfirm =
		/\b(?:cannot|can't|cant|unable|not\s+able)\b.{0,90}\b(?:confirm|verify|guarantee)\b.{0,120}\b(?:pay|payment)\b/i.test(text) ||
		/(?:\u0644\u0627|\u0645\u0627|\u0645\u0634)\s*(?:\u0623\u0633\u062a\u0637\u064a\u0639|\u0627\u0633\u062a\u0637\u064a\u0639|\u0623\u0642\u062f\u0631|\u0627\u0642\u062f\u0631|\u0646\u0633\u062a\u0637\u064a\u0639|\u064a\u0645\u0643\u0646\u0646\u064a)\s*(?:\u0623\u0646|\u0627\u0646)?\s*(?:\u0623\u0624\u0643\u062f|\u0627\u0624\u0643\u062f|\u062a\u0623\u0643\u064a\u062f)?/iu.test(text);
	const impossible =
		/\b(?:not\s+possible|not\s+available|not\s+accepted|must\s+pay\s+online|online\s+payment\s+is\s+required)\b/i.test(text) ||
		/(?:\u0644\u0627|\u063a\u064a\u0631)\s*(?:\u064a\u0645\u0643\u0646|\u0645\u0645\u0643\u0646|\u0645\u062a\u0627\u062d|\u0645\u0633\u0645\u0648\u062d).{0,90}(?:\u0627\u0644\u062f\u0641\u0639|\u062f\u0641\u0639|\u0627\u0633\u062f\u062f|\u0633\u062f\u0627\u062f).{0,90}(?:\u0627\u0644\u0648\u0635\u0648\u0644|\u0627\u0644\u0641\u0646\u062f\u0642|\u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644)/iu.test(text);
	const onlineOnly =
		/\b(?:only|currently)\b.{0,80}\b(?:payment\s+link|online\s+payment|pay\s+online)\b/i.test(text) ||
		/(?:\u0627\u0644\u0645\u062a\u0627\u062d|\u0627\u0644\u0645\u062a\u0648\u0641\u0631).{0,80}(?:\u0631\u0627\u0628\u0637\s*\u0627\u0644\u062f\u0641\u0639|\u0627\u0644\u062f\u0641\u0639\s*(?:\u0639\u0628\u0631|\u0645\u0646\s*\u062e\u0644\u0627\u0644)\s*\u0631\u0627\u0628\u0637|\u0627\u0644\u062f\u0641\u0639\s*(?:\u0627\u0648\u0646\u0644\u0627\u064a\u0646|\u0623\u0648\u0646\u0644\u0627\u064a\u0646))/iu.test(text);
	return (payContext && arrivalContext && (cannotConfirm || impossible)) || onlineOnly;
}

function replyAffirmsPayAtHotelPolicy(reply = "") {
	const text = normalizeIntentSearchTextRepaired(reply);
	if (!text) return false;
	const english =
		/\b(?:yes|you\s+can|can\s+pay|may\s+pay|pay\s+at\s+the\s+hotel|pay\s+on\s+arrival|payment\s+(?:is\s+)?(?:accepted|available))\b/i.test(text) &&
		/\b(?:hotel|arrival|reception|front\s*desk|check\s*in|check-in)\b/i.test(text);
	const arabic =
		/(?:\u0646\u0639\u0645|\u064a\u0645\u0643\u0646|\u062a\u0642\u062f\u0631|\u062a\u0633\u062a\u0637\u064a\u0639|\u064a\u0646\u0641\u0639|\u0645\u0645\u0643\u0646|\u0645\u062a\u0627\u062d|\u0645\u0633\u0645\u0648\u062d).{0,90}(?:\u0627\u0644\u062f\u0641\u0639|\u062a\u062f\u0641\u0639|\u0627\u062f\u0641\u0639|\u0623\u062f\u0641\u0639|\u0627\u0644\u0633\u062f\u0627\u062f|\u062a\u062d\u0627\u0633\u0628|\u0643\u0627\u0634).{0,120}(?:\u0627\u0644\u0641\u0646\u062f\u0642|\u0627\u0644\u0648\u0635\u0648\u0644|\u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644|\u0627\u0644\u0631\u064a\u0633\u0628\u0634\u0646)/iu.test(text) ||
		/(?:\u0627\u0644\u062f\u0641\u0639|\u0627\u0644\u0633\u062f\u0627\u062f).{0,90}(?:\u0627\u0644\u0641\u0646\u062f\u0642|\u0627\u0644\u0648\u0635\u0648\u0644|\u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644|\u0627\u0644\u0631\u064a\u0633\u0628\u0634\u0646).{0,90}(?:\u0645\u062a\u0627\u062d|\u0645\u0645\u0643\u0646|\u0645\u0633\u0645\u0648\u062d|\u064a\u0645\u0643\u0646|\u064a\u0646\u0641\u0639)/iu.test(text);
	return english || arabic;
}

function replyMentionsConfirmedPaymentContext(reply = "", context = {}) {
	const text = normalizeIntentSearchTextRepaired(reply);
	if (!text) return false;
	const normalizedText = normalizeDigits(text);
	const confirmation = normalizeDigits(cleanString(context.confirmation || "", 60)).replace(/\D/g, "");
	if (confirmation && normalizedText.includes(confirmation)) return true;
	return (
		/\b(?:confirmation|reservation|booking|reference)\b.{0,80}\b(?:number|no\.?|#|reception|front\s*desk)\b/i.test(text) ||
		/\b(?:reception|front\s*desk)\b.{0,80}\b(?:confirmation|reservation|booking|reference)\b/i.test(text) ||
		/(?:\u0631\u0642\u0645\s*(?:\u0627\u0644)?(?:\u062a\u0623\u0643\u064a\u062f|\u0627\u0644\u062d\u062c\u0632)|(?:\u0627\u0644)?(?:\u062a\u0623\u0643\u064a\u062f|\u0627\u0644\u062d\u062c\u0632).{0,80}(?:\u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644|\u0627\u0644\u0631\u064a\u0633\u0628\u0634\u0646)|(?:\u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644|\u0627\u0644\u0631\u064a\u0633\u0628\u0634\u0646).{0,80}(?:\u0627\u0644)?(?:\u062a\u0623\u0643\u064a\u062f|\u0627\u0644\u062d\u062c\u0632))/iu.test(
			text
		)
	);
}

function replyMentionsPaymentLinkDepositGuidance(reply = "") {
	const text = normalizeIntentSearchTextRepaired(reply);
	if (!text) return false;
	return (
		/\b(?:payment\s+link|pay\s+link|online\s+payment|deposit|partial\s+payment|pay\s+online)\b/i.test(text) ||
		/(?:\u0631\u0627\u0628\u0637\s*\u0627\u0644\u062f\u0641\u0639|\u0631\u0627\u0628\u0637\s*\u0627\u0644\u0633\u062f\u0627\u062f|\u0627\u0644\u062f\u0641\u0639\s*(?:\u0627\u0648\u0646\u0644\u0627\u064a\u0646|\u0623\u0648\u0646\u0644\u0627\u064a\u0646)|\u0639\u0631\u0628\u0648\u0646|\u062f\u0641\u0639\s*(?:\u062c\u0632\u0621|\u062c\u0632\u0626\u064a|\u062c\u0632\u0626\u064a\u0627|\u062c\u0632\u0626\u064a\u064b\u0627)|\u062c\u062f\u064a\u0629\s*(?:\u0627\u0644)?\u062d\u0636\u0648\u0631|\u064a\u062b\u0628\u062a\s*(?:\u0627\u0644)?\u063a\u0631\u0641\u0629|\u064a\u0624\u0643\u062f\s*(?:\u0627\u0644)?\u062d\u0636\u0648\u0631)/iu.test(
			text
		)
	);
}

function paymentAtHotelReplyNeedsCorrection(decision = {}, latestGuest = {}, context = {}) {
	if (!latestGuestAsksPayAtHotel(latestGuest?.message || "")) return false;
	const action = String(decision?.action || "").trim().toLowerCase();
	if (["escalate", "close_case"].includes(action)) return false;
	if (action !== "reply") return true;
	const reply = cleanDisplayString(decision?.reply || "", 2200);
	if (!reply) return true;
	if (replyContradictsPayAtHotelPolicy(reply) || !replyAffirmsPayAtHotelPolicy(reply)) return true;
	if (!replyMentionsPaymentLinkDepositGuidance(reply)) return true;
	const confirmedContext = Boolean(context?.reservationAlreadyConfirmed || cleanString(context?.confirmation || "", 60));
	return confirmedContext && !replyMentionsConfirmedPaymentContext(reply, context);
}

function mentionsExplicitReservationIdentifier(value = "") {
	const text = normalizeDigits(String(value || "")).toLowerCase();
	const compact = normalizeIntentSearchText(value).replace(/\s+/g, "");
	return (
		/\b(?:confirmation|confirm(?:ation)?\s*(?:number|no|#)?|reservation\s*(?:number|no|#)?|booking\s*(?:number|no|#)?|reference\s*(?:number|no|#)?|ref\s*(?:number|no|#)?)\b/i.test(
			text
		) ||
		/(?:\u0631\u0642\u0645|\u0643\u0648\u062f|\u0646\u0645\u0631\u0629|\u0646\u0645\u0631\u0647)(?:\u0627\u0644)?(?:\u062d\u062c\u0632|\u062a\u0623\u0643\u064a\u062f|\u062a\u0627\u0643\u064a\u062f)/iu.test(
			compact
		) ||
		/(?:\u062a\u0623\u0643\u064a\u062f|\u062a\u0627\u0643\u064a\u062f)(?:\u0627\u0644)?\u062d\u062c\u0632/iu.test(
			compact
		)
	);
}

function latestGuestLooksLikeBookingIdentityAnswer(value = "") {
	const lines = String(value || "")
		.split(/\r?\n|\\n|[|]/)
		.map((line) => cleanDisplayString(line, 240))
		.filter(Boolean);
	if (!lines.length) return false;
	let matched = 0;
	for (const line of lines) {
		if (
			phoneFromIdentityText(line) ||
			phoneFromText(line) ||
			simplePhoneFromLine(line) ||
			nationalityFromIdentityText(line) ||
			nationalityFromText(line) ||
			normalizeNationalityHint(line) ||
			bookingNameFromLine(line) ||
			bookingNameFromIdentityText(line)
		) {
			matched += 1;
			continue;
		}
		if (/^[\p{L}\s-]{2,40}$/u.test(stripChatMarkup(line))) {
			matched += 1;
			continue;
		}
		return false;
	}
	return matched > 0;
}

function bookingIdentityCollectionContext(sc = {}, previousAi = null, known = {}) {
	const action = cleanString(previousAi?.clientAction, 80).toLowerCase();
	if (["required_details_needed", "review_reservation"].includes(action)) return true;
	if (previousAiAskedForIdentityConfirmation(previousAi)) return true;
	const text = normalizeDigits(String(previousAi?.message || "")).toLowerCase();
	if (
		/(?:full name|guest name|booking name|phone number|phone|mobile|nationality)/i.test(
			text
		) ||
		/(?:\u0627\u0633\u0645\s+(?:\u0635\u0627\u062d\u0628\s+)?\u0627\u0644\u062d\u062c\u0632|\u0627\u0644\u0627\u0633\u0645|\u0631\u0642\u0645\s+\u0627\u0644\u0647\u0627\u062a\u0641|\u0627\u0644\u0647\u0627\u062a\u0641|\u0627\u0644\u062c\u0648\u0627\u0644|\u0627\u0644\u062c\u0646\u0633\u064a\u0629|\u062c\u0646\u0633\u064a\u062a)/iu.test(
			text
		)
	) {
		return true;
	}
	const missing = requiredBookingMissing(known).filter((item) =>
		["fullName", "phone", "nationality"].includes(item)
	);
	return quoteMatchesKnown(known) && missing.length > 0;
}

function conversationHasReservationLookupContext(sc = {}) {
	const conversation = Array.isArray(sc.conversation) ? sc.conversation : [];
	return conversation.slice(-6).some((entry) => {
		const text = normalizeDigits(String(entry?.message || "")).toLowerCase();
		return /(reservation|booking|confirmation|confirm number|payment|pay|details|حجز|الحجز|تأكيد|تاكيد|دفع|ادفع|تفاصيل)/i.test(
			text
		);
	});
}

function previousAiAskedForReservationConfirmation(previousAi = null) {
	if (!previousAi || !isAiSupportEntry(previousAi)) return false;
	const action = cleanString(previousAi.clientAction, 80).toLowerCase();
	if (["reservation_lookup_not_found", "reservation_lookup_found"].includes(action)) return true;
	return mentionsExplicitReservationIdentifier(previousAi.message || "");
}

function latestGuestRequestsReservationLookup(
	sc = {},
	latestText = "",
	known = {},
	previousAi = null
) {
	const text = normalizeDigits(String(latestText || "")).toLowerCase();
	if (!text.trim()) return false;
	const explicitConfirmation = confirmationNumberFromText(text);
	const confirmation = explicitConfirmation || cleanString(known.confirmation, 40);
	if (!confirmation) return false;
	const updateOrCancel =
		/(update|change|modify|edit|cancel|تعديل|غير|تغيير|الغاء|إلغاء|إلغي|الغِ)/i.test(text);
	if (updateOrCancel) return false;
	const lookupIntent =
		/(reservation|booking|confirmation|confirm number|payment|pay|details|invoice|receipt|حجز|الحجز|تأكيد|تاكيد|دفع|ادفع|تفاصيل|فاتورة|ايصال|إيصال)/i.test(
			text
		);
	if (explicitConfirmation) {
		if (/^\s*\d{8,12}\s*$/.test(text) && previousAiAskedForReservationConfirmation(previousAi)) {
			return true;
		}
		if (
			bookingIdentityCollectionContext(sc, previousAi, known) &&
			latestGuestLooksLikeBookingIdentityAnswer(latestText) &&
			!mentionsExplicitReservationIdentifier(latestText)
		) {
			return false;
		}
		return (
			mentionsExplicitReservationIdentifier(latestText) ||
			lookupIntent ||
			(/^\s*\d{8,12}\s*$/.test(text) && conversationHasReservationLookupContext(sc))
		);
	}
	return lookupIntent;
}

function latestGuestRequestsReservationDateUpdate(latestText = "", known = {}) {
	const text = normalizeIntentSearchText(latestText)
		.replace(/[.!?\u061f\u060c,]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!text.trim()) return false;
	if (/\b(cancel|cancelation|cancellation)\b/i.test(text)) return false;
	const confirmation = confirmationNumberFromText(text) || cleanString(known.confirmation, 40);
	if (!confirmation) return false;
	const compact = text.replace(/\s+/g, "");
	const updateIntent =
		/\b(update|change|modify|edit|move|reschedule|shift)\b/i.test(text) ||
		/(?:\u0627\u0639\u062f\u0644|\u062a\u0639\u062f\u064a\u0644|\u063a\u064a\u0631|\u062a\u063a\u064a\u064a\u0631|\u0627\u0646\u0642\u0644|\u0646\u0642\u0644|\u0646\u062e\u0644\u064a|\u062e\u0644\u064a|\u0628\u062f\u0644)/i.test(
			compact
		);
	if (!updateIntent) return false;
	return (
		/(?:check.?in|check.?out|arrival|departure|date|dates|\d{4}-\d{2}-\d{2})/i.test(
			text
		) ||
		/(?:\u0648\u0635\u0648\u0644|\u0627\u0644\u0648\u0635\u0648\u0644|\u0645\u063a\u0627\u062f\u0631\u0629|\u0627\u0644\u0645\u063a\u0627\u062f\u0631\u0629|\u0645\u063a\u0627\u062f\u0631\u0647|\u0627\u0644\u0645\u063a\u0627\u062f\u0631\u0647|\u062a\u0627\u0631\u064a\u062e|\u062a\u0648\u0627\u0631\u064a\u062e)/i.test(
			compact
		) ||
		Boolean(quickDateRange(text)?.checkinISO)
	);
}

function latestGuestRequestsReservationCancel(latestText = "", known = {}) {
	const text = normalizeIntentSearchText(latestText)
		.replace(/[.!?\u061f\u060c,]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	if (!text) return false;
	const compact = text.replace(/\s+/g, "");
	const tokens = text.split(/[^A-Za-z\u0600-\u06FF]+/u).filter(Boolean);
	const arabicCancelWords = new Set([
		"\u0627\u0644\u063a\u0627\u0621",
		"\u0625\u0644\u063a\u0627\u0621",
		"\u0623\u0644\u063a\u0627\u0621",
		"\u0627\u0644\u063a\u064a",
		"\u0625\u0644\u063a\u064a",
		"\u0623\u0644\u063a\u064a",
		"\u0627\u0644\u063a\u0649",
		"\u0625\u0644\u063a\u0649",
		"\u0623\u0644\u063a\u0649",
		"\u0627\u0644\u063a\u064a\u0647",
		"\u0623\u0644\u063a\u064a\u0647",
		"\u0627\u0644\u063a\u064a\u0647\u0627",
		"\u0623\u0644\u063a\u064a\u0647\u0627",
		"\u0627\u0644\u063a\u0649\u0647",
		"\u0623\u0644\u063a\u0649\u0647",
		"\u0627\u0644\u063a\u0649\u0647\u0627",
		"\u0623\u0644\u063a\u0649\u0647\u0627",
		"\u0645\u0644\u063a\u064a",
		"\u0645\u0644\u063a\u0649",
		"\u0643\u0646\u0633\u0644",
	]);
	const cancelIntent =
		tokens.some((token) =>
			/^(?:cancel|cancelation|cancellation|canceled|cancelled)$/i.test(token)
		) ||
		tokens.some((token) => arabicCancelWords.has(token));
	if (!cancelIntent) return false;
	const confirmation = confirmationNumberFromText(text) || cleanString(known.confirmation, 40);
	if (confirmation) return true;
	return (
		/\b(reservation|booking|confirmation|status)\b/i.test(text) ||
		/(?:\u062d\u062c\u0632|\u0627\u0644\u062d\u062c\u0632|\u062a\u0627\u0643\u064a\u062f|\u062a\u0623\u0643\u064a\u062f|\u062d\u0627\u0644\u0629|\u062d\u0627\u0644\u0647|\u0631\u0642\u0645)/i.test(
			compact
		)
	);
}

function toReservationMoney(value = 0) {
	const number = Number(value);
	if (!Number.isFinite(number)) return 0;
	return Math.max(0, Math.round(number * 100) / 100);
}

function reservationNotCapturedPaymentStatus(reservation = {}) {
	const payment = normalizeIntentSearchText(reservation.payment || "")
		.replace(/[^\p{L}\d]+/gu, " ")
		.replace(/\s+/g, " ")
		.trim();
	return (
		payment === "credit debit" ||
		payment === "not captured" ||
		payment === "paypal pending review"
	);
}

function reservationBreakdownPaidFallback(reservation = {}) {
	const breakdown = asObject(reservation.paid_amount_breakdown);
	return Object.entries(breakdown).reduce((total, [key, value]) => {
		if (!/^paid_/i.test(key)) return total;
		return total + toReservationMoney(value);
	}, 0);
}

function reservationPendingReviewAmountSar(reservation = {}) {
	const captures = Array.isArray(reservation?.paypal_details?.pending_review_captures)
		? reservation.paypal_details.pending_review_captures
		: [];
	const captureSar = captures.reduce((total, capture) => {
		const status = normalizeIntentSearchText(
			capture?.capture_status || capture?.status || ""
		);
		if (status && !/pending|review/.test(status)) return total;
		return total + toReservationMoney(capture?.amount_sar);
	}, 0);
	if (captureSar > 0) return toReservationMoney(captureSar);
	if (
		toReservationMoney(reservation?.paypal_details?.pending_total_usd) > 0 ||
		reservation?.payment_details?.paypalReviewPending
	) {
		return toReservationMoney(reservation?.payment_details?.triggeredAmountSAR);
	}
	return 0;
}

function reservationPaymentSummary(reservation = {}) {
	const total = toReservationMoney(reservation.total_amount);
	const rawPaid = toReservationMoney(reservation.paid_amount);
	const onlinePaid = reservationNotCapturedPaymentStatus(reservation) ? 0 : rawPaid;
	const fallbackPaid = onlinePaid > 0 ? 0 : reservationBreakdownPaidFallback(reservation);
	const onsitePaid = toReservationMoney(reservation?.payment_details?.onsite_paid_amount);
	const confirmedPaid = toReservationMoney(onlinePaid + fallbackPaid + onsitePaid);
	const pendingReview = reservationPendingReviewAmountSar(reservation);
	const remaining = total > 0 ? toReservationMoney(Math.max(0, total - confirmedPaid)) : 0;
	return {
		total,
		confirmedPaid,
		pendingReview,
		remaining,
		currency: reservation.currency || "SAR",
		hasConfirmedPayment: confirmedPaid > 0,
		fullyPaid: total > 0 && confirmedPaid >= total,
	};
}

function latestGuestAsksReservationPayment(value = "") {
	const text = normalizeIntentSearchText(value);
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:paid|payment|deposit|remaining|balance|due|checkout|check\s*out|receipt|invoice|pay|paypal)\b/i.test(
			text
		) ||
		/(?:\u062f\u0641\u0639|\u062f\u0641\u0639\u062a|\u0627\u0644\u062f\u0641\u0639|\u0639\u0631\u0628\u0648\u0646|\u0628\u0627\u0642\u064a|\u0628\u0627\u0642\u0649|\u0627\u0644\u0628\u0627\u0642\u064a|\u0627\u0644\u0628\u0627\u0642\u0649|\u0645\u062a\u0628\u0642\u064a|\u0645\u062a\u0628\u0642\u0649|\u0641\u0627\u062a\u0648\u0631\u0629|\u0627\u064a\u0635\u0627\u0644|\u0625\u064a\u0635\u0627\u0644|\u0628\u0627\u064a\u0628\u0627\u0644)/iu.test(
			compact
		)
	);
}

function latestGuestIsBareReservationConfirmation(value = "") {
	const text = normalizeDigits(String(value || "")).trim();
	return /^\d{8,12}$/.test(text) && Boolean(confirmationNumberFromText(text));
}

function recentGuestAskedReservationPaymentBeforeLatest(sc = {}, latestGuest = null) {
	const conversation = Array.isArray(sc.conversation) ? sc.conversation : [];
	const latestTime = latestGuest?.date ? new Date(latestGuest.date).getTime() : 0;
	let skippedLatest = !latestGuest;
	let inspected = 0;
	for (let index = conversation.length - 1; index >= 0 && inspected < 8; index -= 1) {
		const entry = conversation[index];
		if (!skippedLatest && isGuestEntry(entry)) {
			const sameMessage = String(entry.message || "") === String(latestGuest?.message || "");
			const entryTime = entry.date ? new Date(entry.date).getTime() : 0;
			if (sameMessage && (!latestTime || !entryTime || Math.abs(entryTime - latestTime) < 2000)) {
				skippedLatest = true;
				continue;
			}
		}
		inspected += 1;
		if (isAiSupportEntry(entry) && String(entry.clientAction || "") === "reservation_lookup_found") {
			break;
		}
		if (isGuestEntry(entry) && latestGuestAsksReservationPayment(entry.message || "")) {
			return true;
		}
	}
	return false;
}

function reservationLookupTurnAsksPayment(sc = {}, latestGuest = null) {
	const latestText = String(latestGuest?.message || "");
	if (latestGuestAsksReservationPayment(latestText)) return true;
	return (
		latestGuestIsBareReservationConfirmation(latestText) &&
		recentGuestAskedReservationPaymentBeforeLatest(sc, latestGuest)
	);
}

function latestGuestAsksRemainingBalance(value = "") {
	const text = normalizeIntentSearchText(value);
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:remaining|balance|due|left|owed|rest)\b/i.test(text) ||
		/(?:\u0628\u0627\u0642\u064a|\u0628\u0627\u0642\u0649|\u0627\u0644\u0628\u0627\u0642\u064a|\u0627\u0644\u0628\u0627\u0642\u0649|\u0645\u062a\u0628\u0642\u064a|\u0645\u062a\u0628\u0642\u0649)/iu.test(
			compact
		)
	);
}

function latestGuestAsksPaymentLink(value = "") {
	const text = normalizeIntentSearchText(value);
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:payment\s*link|pay\s*online|checkout\s*link|link\s*to\s*pay)\b/i.test(
			text
		) ||
		/(?:\u0631\u0627\u0628\u0637\u0627\u0644\u062f\u0641\u0639|\u0631\u0627\u0628\u0637\s*\u0627\u0644\u062f\u0641\u0639|\u0627\u062f\u0641\u0639\s*\u0627\u0648\u0646\u0644\u0627\u064a\u0646|\u0627\u062f\u0641\u0639\s*\u0627\u0648\u0646\s*\u0644\u0627\u064a\u0646)/iu.test(
			compact
		)
	);
}

function latestGuestAsksReservationReceiptLink(value = "") {
	const text = normalizeIntentSearchText(value);
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:receipt|invoice|reservation\s*(?:details|link)|booking\s*(?:details|link)|confirmation\s*(?:details|link)|details\s*link)\b/i.test(
			text
		) ||
		/(?:\u0631\u0627\u0628\u0637(?:\u0627\u0644)?(?:\u062a\u0641\u0627\u0635\u064a\u0644|\u0627\u0644\u062a\u0641\u0627\u0635\u064a\u0644|\u062d\u062c\u0632|\u0627\u0644\u062d\u062c\u0632|\u062a\u0623\u0643\u064a\u062f|\u062a\u0627\u0643\u064a\u062f|\u0627\u0644\u062a\u0623\u0643\u064a\u062f|\u0627\u0644\u062a\u0627\u0643\u064a\u062f|\u0641\u0627\u062a\u0648\u0631\u0629|\u0641\u0627\u062a\u0648\u0631\u0647|\u0627\u0644\u0641\u0627\u062a\u0648\u0631\u0629|\u0627\u0644\u0641\u0627\u062a\u0648\u0631\u0647|\u0625\u064a\u0635\u0627\u0644|\u0627\u064a\u0635\u0627\u0644|\u0627\u0644\u0625\u064a\u0635\u0627\u0644|\u0627\u0644\u0627\u064a\u0635\u0627\u0644)|\u062a\u0641\u0627\u0635\u064a\u0644\u0627\u0644\u062d\u062c\u0632|\u0641\u0627\u062a\u0648\u0631\u0629|\u0641\u0627\u062a\u0648\u0631\u0647|\u0625\u064a\u0635\u0627\u0644|\u0627\u064a\u0635\u0627\u0644)/iu.test(
			compact
		)
	);
}

function latestGuestClaimsExistingReservationPayment(value = "") {
	const text = normalizeIntentSearchText(value);
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:already\s+paid|i\s+paid|paid\s+(?:a\s+)?deposit|made\s+(?:a\s+)?payment|deposit\s+for\s+(?:my\s+)?(?:booking|reservation))\b/i.test(
			text
		) ||
		/(?:\u062f\u0641\u0639\u062a|\u0633\u062f\u062f\u062a|\u062d\u0648\u0644\u062a|\u0639\u0631\u0628\u0648\u0646|\u062f\u0641\u0639\u062a\u0639\u0631\u0628\u0648\u0646|\u0639\u0631\u0628\u0648\u0646\u062d\u062c\u0632)/iu.test(
			compact
		)
	);
}

function latestGuestRequestsExistingReservationService(value = "") {
	const text = normalizeIntentSearchText(value);
	const compact = text.replace(/\s+/g, "");
	return (
		latestGuestClaimsExistingReservationPayment(value) ||
		/\b(?:existing|already\s+(?:booked|reserved|paid)|my\s+(?:reservation|booking)|reservation\s+(?:number|confirmation|details|status)|booking\s+(?:number|confirmation|details|status)|confirmation|confirmed|booked|extend|extension|change\s+(?:my\s+)?(?:date|stay|reservation|booking)|modify\s+(?:my\s+)?(?:date|stay|reservation|booking))\b/i.test(
			text
		) ||
		/(?:\u062d\u062c\u0632\u064a|\u062d\u062c\u0632\u062a|\u062d\u062c\u0632\u0646\u0627|\u0631\u0642\u0645\u0627\u0644\u062d\u062c\u0632|\u0631\u0642\u0645\u0627\u0644\u062a\u0623\u0643\u064a\u062f|\u062a\u0623\u0643\u064a\u062f|\u062a\u0627\u0643\u064a\u062f|\u0645\u0624\u0643\u062f|\u0645\u0648\u0643\u062f|\u062a\u0645\u062f\u064a\u062f|\u062a\u063a\u064a\u064a\u0631\u0627\u0644\u062a\u0627\u0631\u064a\u062e|\u062a\u063a\u064a\u064a\u0631\u0627\u0644\u062d\u062c\u0632|\u062a\u0639\u062f\u064a\u0644\u0627\u0644\u062d\u062c\u0632|\u062a\u0639\u062f\u064a\u0644\u0627\u0644\u062a\u0627\u0631\u064a\u062e)/iu.test(
			compact
		)
	);
}

function buildMissingReservationConfirmationMessage(sc = {}, known = {}, latestGuest = null, reason = "") {
	const languageCode = activeLanguageCode(sc, known);
	const ar =
		/^ar\b/i.test(languageCode) ||
		/[\u0600-\u06FF]/.test(String(latestGuest?.message || ""));
	if (ar) {
		if (reason === "multiple_matches") {
			return "\u0622\u0633\u0641\u064a\u0646\u060c \u0648\u062c\u062f\u0646\u0627 \u0623\u0643\u062b\u0631 \u0645\u0646 \u062d\u062c\u0632 \u0642\u0631\u064a\u0628 \u0645\u0646 \u0647\u0630\u0647 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a. \u0644\u062d\u0645\u0627\u064a\u0629 \u062e\u0635\u0648\u0635\u064a\u062a\u0643 \u0648\u0625\u0631\u062c\u0627\u0639 \u0627\u0644\u0633\u062c\u0644 \u0627\u0644\u0635\u062d\u064a\u062d\u060c \u0641\u0636\u0644\u0627 \u0623\u0631\u0633\u0644 \u0631\u0642\u0645 \u062a\u0623\u0643\u064a\u062f \u0627\u0644\u062d\u062c\u0632.";
		}
		if (reason === "no_match") {
			return "\u0644\u0645 \u0623\u062a\u0645\u0643\u0646 \u0645\u0646 \u062a\u062d\u062f\u064a\u062f \u0627\u0644\u062d\u062c\u0632 \u0628\u0627\u0644\u0627\u0633\u0645 \u0648\u0627\u0644\u062a\u0648\u0627\u0631\u064a\u062e \u0641\u0642\u0637. \u0641\u0636\u0644\u0627 \u0623\u0631\u0633\u0644 \u0631\u0642\u0645 \u062a\u0623\u0643\u064a\u062f \u0627\u0644\u062d\u062c\u0632 \u0644\u0623\u0631\u0627\u062c\u0639\u0647 \u0644\u0643 \u0628\u062f\u0642\u0629.";
		}
		return "\u0623\u0643\u064a\u062f\u060c \u0641\u0636\u0644\u0627 \u0623\u0631\u0633\u0644 \u0631\u0642\u0645 \u062a\u0623\u0643\u064a\u062f \u0627\u0644\u062d\u062c\u0632. \u0648\u0625\u0630\u0627 \u0644\u064a\u0633 \u0645\u0639\u0643 \u0627\u0644\u0631\u0642\u0645\u060c \u0623\u0631\u0633\u0644 \u0627\u0633\u0645 \u0627\u0644\u062d\u062c\u0632 \u0627\u0644\u062f\u0642\u064a\u0642 \u0645\u0639 \u062a\u0627\u0631\u064a\u062e \u0627\u0644\u062f\u062e\u0648\u0644 \u0648\u0627\u0644\u062e\u0631\u0648\u062c \u0648\u0633\u0623\u062d\u0627\u0648\u0644 \u0645\u0637\u0627\u0628\u0642\u0629 \u0627\u0644\u062d\u062c\u0632.";
	}
	if (reason === "multiple_matches") {
		return "I found more than one reservation close to those details. To protect the guest record and return the correct booking, please send the confirmation number.";
	}
	if (reason === "no_match") {
		return "I could not identify one exact reservation from the name and dates alone. Please send the confirmation number so I can check it accurately.";
	}
	return "Sure. Please send the reservation confirmation number. If you do not have it, send the exact reservation name plus check-in and checkout dates, and I will try to match the booking safely.";
}

function reservationLookupIdentity(sc = {}, known = {}, latestText = "") {
	return cleanDisplayString(
		known.fullName ||
			known.name ||
			bookingNameFromIdentityText(latestText) ||
			profileNameForBooking(sc),
		140
	);
}

function reservationServiceDateRange(known = {}, latestText = "") {
	const latestDates = quickDateRange(latestText);
	return {
		checkinISO: validISODate(latestDates?.checkinISO) || validISODate(known.checkinISO),
		checkoutISO:
			validISODate(latestDates?.checkoutISO) || validISODate(known.checkoutISO),
	};
}

function reservationServiceNameMatches(inputName = "", reservationName = "") {
	const input = duplicateNameForCompare(inputName);
	const stored = duplicateNameForCompare(reservationName);
	if (!input || !stored) return false;
	return input === stored || stored.includes(input) || input.includes(stored);
}

async function findReservationServiceMatches(sc = {}, hotel = {}, known = {}, latestGuest = null) {
	const latestText = String(latestGuest?.message || "");
	const name = reservationLookupIdentity(sc, known, latestText);
	const { checkinISO, checkoutISO } = reservationServiceDateRange(known, latestText);
	const hotelId = String(hotel?._id || sc.hotelId || "").trim();
	if (!hotelId || !name || !checkinISO || !checkoutISO) {
		return { status: "missing_details", name, checkinISO, checkoutISO, matches: [] };
	}
	const candidates = await listHotelReservationsByExactStay({
		hotelId,
		checkinISO,
		checkoutISO,
		limit: 25,
	});
	const matches = candidates.filter((reservation) =>
		reservationServiceNameMatches(name, reservation?.customer_details?.name || "")
	);
	return {
		status:
			matches.length === 1
				? "one_match"
				: matches.length > 1
				? "multiple_matches"
				: "no_match",
		name,
		checkinISO,
		checkoutISO,
		matches,
	};
}

function replyContainsPaidGuestReceptionPhone(value = "") {
	const digits = normalizeDigits(value).replace(/[^\d]/g, "");
	return (
		digits.includes(PAID_GUEST_RECEPTION_PHONE_DIGITS) ||
		digits.includes(PAID_GUEST_RECEPTION_PHONE_DIGITS.replace(/^966/, "0"))
	);
}

function previousAiSharedAdminContact(sc = {}, latestGuest = null) {
	const conversation = Array.isArray(sc.conversation) ? sc.conversation : [];
	const latestIndex = latestGuest
		? conversation.findIndex((entry) => entry === latestGuest)
		: conversation.length;
	const end = latestIndex >= 0 ? latestIndex : conversation.length;
	return conversation
		.slice(Math.max(0, end - 8), end)
		.some((entry) => {
			if (!entry?.isAi) return false;
			const message = String(entry.message || "");
			return (
				message.includes(RESERVATION_CHANGE_CONTACT_PHONE) ||
				message.includes(RESERVATION_CHANGE_CONTACT_WHATSAPP)
			);
		});
}

function latestGuestInsistsOnPaidReceptionPhone(value = "") {
	const text = normalizeIntentSearchText(value);
	const compact = text.replace(/\s+/g, "");
	const receptionSignal =
		/\b(?:reception|front\s*desk|arrival|hotel\s*number|direct\s*number|saudi\s*number)\b/i.test(
			text
		) ||
		/(?:\u0631\u064a\u0633\u064a\u0628\u0634\u0646|\u0627\u0633\u062a\u0642\u0628\u0627\u0644|\u0648\u0635\u0648\u0644|\u0627\u0644\u0641\u0646\u062f\u0642|\u0631\u0642\u0645\u0633\u0639\u0648\u062f\u064a|\u0633\u0639\u0648\u062f\u064a)/iu.test(
			compact
		);
	const asksContact =
		latestGuestAsksSupportContactNumber(value) ||
		(receptionSignal &&
			(/\b(?:number|phone|mobile|contact)\b/i.test(text) ||
				/(?:\u0631\u0642\u0645|\u062c\u0648\u0627\u0644|\u0647\u0627\u062a\u0641|\u062a\u0648\u0627\u0635\u0644)/iu.test(
					compact
				)));
	const insistSignal =
		/\b(?:direct|specific|reception|front\s*desk|insist|must|need\s+the\s+hotel|not\s+whatsapp)\b/i.test(
			text
		) ||
		/(?:\u0636\u0631\u0648\u0631\u064a|\u0644\u0627|\u0645\u0634|\u0627\u0644\u0633\u0639\u0648\u062f\u064a|\u0627\u0644\u0631\u064a\u0633\u064a\u0628\u0634\u0646|\u0646\u0641\u0633\u0647|\u0645\u0628\u0627\u0634\u0631)/iu.test(
			compact
		);
	return asksContact && receptionSignal && insistSignal;
}

function paidReceptionPhoneAllowed({
	reservation = null,
	sc = {},
	latestGuest = null,
} = {}) {
	if (!reservation) return false;
	const payment = reservationPaymentSummary(reservation);
	return (
		payment.hasConfirmedPayment &&
		latestGuestInsistsOnPaidReceptionPhone(latestGuest?.message || "") &&
		previousAiSharedAdminContact(sc, latestGuest)
	);
}

function compactReservationPaymentSummary(reservation = {}) {
	const payment = reservationPaymentSummary(reservation);
	return {
		total: payment.total,
		confirmedPaid: payment.confirmedPaid,
		pendingReview: payment.pendingReview,
		remaining: payment.remaining,
		currency: payment.currency,
		hasConfirmedPayment: payment.hasConfirmedPayment,
		fullyPaid: payment.fullyPaid,
	};
}

function reservationLookupToolResult(reservation = null, extra = {}) {
	const paymentSummary = reservation ? compactReservationPaymentSummary(reservation) : null;
	const paidReceptionContactAllowed = Boolean(extra.paidReceptionContactAllowed);
	const paymentRequested = Boolean(extra.paymentRequested);
	return {
		tool: "lookup_reservation",
		ok: Boolean(reservation),
		code: extra.code || (reservation ? "found" : "not_found"),
		confirmation:
			reservation?.confirmation_number || cleanDisplayString(extra.confirmation || "", 40),
		reservation: compactReservationForBrain(reservation),
		paymentSummary,
		paymentRequested,
		...(extra.lookupBy ? { lookupBy: extra.lookupBy } : {}),
		...(extra.lookupName ? { lookupName: extra.lookupName } : {}),
		...(extra.checkinISO ? { checkinISO: extra.checkinISO } : {}),
		...(extra.checkoutISO ? { checkoutISO: extra.checkoutISO } : {}),
		paidReceptionContact: {
			allowed: paidReceptionContactAllowed,
			contactPhone: paidReceptionContactAllowed ? PAID_GUEST_RECEPTION_PHONE : "",
			rule:
				"Only include contactPhone when allowed=true. Otherwise use the administration WhatsApp contact only.",
		},
		adminContact: {
			contactPhone: RESERVATION_CHANGE_CONTACT_PHONE,
			whatsapp: RESERVATION_CHANGE_CONTACT_WHATSAPP,
		},
		instruction: paymentRequested
			? "The guest asked about a paid deposit/payment in this lookup context. Answer only from paymentSummary: confirmedPaid is captured/confirmed, pendingReview is only mentioned if greater than 0, and remaining is the amount left. Do not mention double payment or pending review when pendingReview is 0."
			: "Answer only the guest's current reservation question from the reservation facts. Do not volunteer payment details unless paymentRequested=true or the latest message asks about payment/balance.",
	};
}

function buildReservationLookupMessage(
	sc = {},
	known = {},
	reservation = null,
	latestGuest = null,
	{ missingReason = "" } = {}
) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const confirmation = cleanString(known.confirmation, 40);
	if (!reservation) {
		if (missingReason) {
			return buildMissingReservationConfirmationMessage(
				sc,
				known,
				latestGuest,
				missingReason
			);
		}
		return ar
			? `لم أجد حجزا برقم التأكيد ${confirmation || ""} في النظام الحالي. فضلا راجع الرقم، أو ارسل نص التأكيد وسأحولها للاستقبال للتأكد.`
			: `I could not find a reservation with confirmation number ${confirmation || ""} in the current system. Please recheck the number, or send the confirmation text and I will pass it to reception to verify.`;
	}
	const links = reservationPublicLinks(reservation);
	const status = cleanDisplayString(
		reservation.reservation_status || reservation.state || "",
		80
	);
	const total = reservation.total_amount || 0;
	const currency = reservation.currency || known.quote?.currency || "SAR";
	const dateLine = `${formatDate(reservation.checkin_date, languageCode)} - ${formatDate(
		reservation.checkout_date,
		languageCode
	)}`;
	const latestText = String(latestGuest?.message || "");
	const asksPayment = reservationLookupTurnAsksPayment(sc, latestGuest);
	const asksRemaining = latestGuestAsksRemainingBalance(latestText);
	const asksPaymentLink = latestGuestAsksPaymentLink(latestText);
	const asksReceiptLink = latestGuestAsksReservationReceiptLink(latestText);
	const asksRestrictedReception = latestGuestInsistsOnPaidReceptionPhone(latestText);
	const payment = reservationPaymentSummary(reservation);
	const paidReceptionAllowed = paidReceptionPhoneAllowed({ reservation, sc, latestGuest });
	const includeReservationDetailsLink =
		links.reservationConfirmation && (!asksPayment || asksReceiptLink);
	const paymentLines = [];
	if (asksPayment || asksRemaining) {
		paymentLines.push(
			ar
				? `\u0627\u0644\u0645\u062f\u0641\u0648\u0639 \u0627\u0644\u0645\u0624\u0643\u062f: ${formatMoney(
						payment.confirmedPaid,
						currency,
						languageCode
				  )}`
				: `Confirmed paid: ${formatMoney(payment.confirmedPaid, currency, languageCode)}`
		);
		if (payment.pendingReview > 0) {
			paymentLines.push(
				ar
					? `\u064a\u0648\u062c\u062f \u0645\u0628\u0644\u063a ${formatMoney(
							payment.pendingReview,
							currency,
							languageCode
					  )} \u0642\u064a\u062f \u0645\u0631\u0627\u062c\u0639\u0629 \u0628\u0627\u064a\u0628\u0627\u0644\u060c \u0648\u0644\u0646 \u0646\u0639\u062a\u0628\u0631\u0647 \u0645\u062f\u0641\u0648\u0639\u0627 \u0645\u0624\u0643\u062f\u0627 \u0625\u0644\u0627 \u0628\u0639\u062f \u0627\u0643\u062a\u0645\u0627\u0644\u0647.`
					: `${formatMoney(
							payment.pendingReview,
							currency,
							languageCode
					  )} is still under PayPal review, so it is not counted as confirmed paid until PayPal completes it.`
			);
		}
		paymentLines.push(
			ar
				? `\u0627\u0644\u0645\u062a\u0628\u0642\u064a: ${formatMoney(
						payment.remaining,
						currency,
						languageCode
				  )}`
				: `Remaining balance: ${formatMoney(payment.remaining, currency, languageCode)}`
		);
	}
	const contactLines = [];
	if (asksRestrictedReception) {
		if (paidReceptionAllowed) {
			contactLines.push(
				ar
					? `\u0631\u0642\u0645 \u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644 \u0644\u0644\u0636\u064a\u0648\u0641 \u0627\u0644\u0645\u0624\u0643\u062f\u064a\u0646: ${PAID_GUEST_RECEPTION_PHONE}`
					: `Reception number for confirmed paid guests: ${PAID_GUEST_RECEPTION_PHONE}`
			);
		} else {
			contactLines.push(
				ar
					? `\u0644\u0644\u062a\u0646\u0633\u064a\u0642 \u0627\u0644\u0623\u0633\u0631\u0639\u060c \u0641\u0636\u0644\u0627 \u062a\u0648\u0627\u0635\u0644 \u0648\u0627\u062a\u0633\u0627\u0628 \u0645\u0639 \u0627\u0644\u0625\u062f\u0627\u0631\u0629 \u0639\u0644\u0649 ${RESERVATION_CHANGE_CONTACT_PHONE} \u0648\u0633\u064a\u0633\u0627\u0639\u062f\u0648\u0646\u0643 \u0641\u064a \u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644 \u0648\u0643\u0644 \u0627\u0644\u062a\u0641\u0627\u0635\u064a\u0644.`
					: `For the fastest coordination, please WhatsApp the administration team at ${RESERVATION_CHANGE_CONTACT_PHONE}. They will help with reception and all arrival details.`
			);
			contactLines.push(
				ar
					? `\u0631\u0627\u0628\u0637 \u0627\u0644\u0648\u0627\u062a\u0633\u0627\u0628: ${RESERVATION_CHANGE_CONTACT_WHATSAPP}`
					: `WhatsApp link: ${RESERVATION_CHANGE_CONTACT_WHATSAPP}`
			);
		}
	}
	if (asksRestrictedReception) {
		return contactLines.join("\n");
	}
	if (ar) {
		return [
			`\u0648\u062c\u062f\u062a \u0627\u0644\u062d\u062c\u0632 \u0631\u0642\u0645 ${reservation.confirmation_number || confirmation}.`,
			`\u0627\u0644\u062d\u0627\u0644\u0629: ${status || "\u063a\u064a\u0631 \u0645\u062d\u062f\u062f\u0629"}`,
			`\u0627\u0644\u062a\u0648\u0627\u0631\u064a\u062e: ${dateLine}`,
			`\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a: ${formatMoney(total, currency, languageCode)}`,
			...paymentLines,
			...contactLines,
			includeReservationDetailsLink
				? `[\u0631\u0627\u0628\u0637 \u062a\u0641\u0627\u0635\u064a\u0644 \u0627\u0644\u062d\u062c\u0632](${links.reservationConfirmation})`
				: "",
			links.payment && asksPaymentLink
				? `[\u0631\u0627\u0628\u0637 \u0627\u0644\u062f\u0641\u0639](${links.payment})`
				: "",
		]
			.filter(Boolean)
			.join("\n");
	}
	if (ar) {
		return [
			`وجدت الحجز رقم ${reservation.confirmation_number || confirmation}.`,
			`الحالة: ${status || "غير محددة"}`,
			`التواريخ: ${dateLine}`,
			`الإجمالي: ${formatMoney(total, currency, languageCode)}`,
			links.reservationConfirmation ? `[رابط تفاصيل الحجز](${links.reservationConfirmation})` : "",
			links.payment ? `[رابط الدفع](${links.payment})` : "",
			`إذا أردت تعديل التواريخ، ارسل تاريخ الوصول والمغادرة الجديدين.`,
		]
			.filter(Boolean)
			.join("\n");
	}
	return [
		`I found reservation ${reservation.confirmation_number || confirmation}.`,
		`Status: ${status || "Not specified"}`,
		`Dates: ${dateLine}`,
		`Total: ${formatMoney(total, currency, languageCode)}`,
		...paymentLines,
		...contactLines,
		includeReservationDetailsLink
			? `[Reservation details](${links.reservationConfirmation})`
			: "",
		links.payment && asksPaymentLink ? `[Payment link](${links.payment})` : "",
	]
		.filter(Boolean)
		.join("\n");
}

async function handleReservationLookup(io, sc = {}, hotel = {}, known = {}, latestGuest = null) {
	let confirmation =
		confirmationNumberFromText(latestGuest?.message || "") ||
		cleanString(known.confirmation, 40);
	const nextKnown = { ...known, confirmation };
	let reservation = null;
	let missingReason = "";
	if (confirmation) {
		reservation = await getReservationByConfirmation(confirmation).catch(() => null);
	} else if (latestGuestRequestsExistingReservationService(latestGuest?.message || "")) {
		const serviceMatches = await findReservationServiceMatches(sc, hotel, nextKnown, latestGuest);
		if (serviceMatches.status === "one_match") {
			reservation = serviceMatches.matches[0];
			confirmation = cleanString(reservation?.confirmation_number || "", 40);
			nextKnown.confirmation = confirmation;
		} else if (serviceMatches.status === "multiple_matches") {
			missingReason = "multiple_matches";
		} else if (serviceMatches.status === "no_match") {
			missingReason = "no_match";
		} else {
			missingReason = "missing_details";
		}
	}
	const activeHotelId = String(hotel?._id || "");
	const reservationHotelId = String(reservation?.hotelId || "");
	if (reservation && activeHotelId && reservationHotelId && activeHotelId !== reservationHotelId) {
		reservation = null;
	}
	await saveKnownFacts(caseIdText(sc), nextKnown);
	return sendAiMessage(io, sc, buildReservationLookupMessage(sc, nextKnown, reservation, latestGuest, { missingReason }), {
		latestGuest,
		known: nextKnown,
		clientAction: reservation ? "reservation_lookup_found" : "reservation_lookup_not_found",
	});
}

function duplicateReservationLookupSinceDate() {
	return new Date(Date.now() - Math.max(1, AI_EXISTING_RESERVATION_LOOKUP_DAYS) * DAY_MS);
}

function duplicateNameForCompare(value = "") {
	let text = cleanDisplayString(value, 140);
	for (let index = 0; index < 3; index += 1) {
		const next = text
			.replace(
				/^(?:dr\.?|doctor|prof\.?|mr\.?|mrs\.?|ms\.?)\s*[/.-]?\s+/i,
				""
			)
			.replace(
				/^(?:د\.?|د\/|دكتور|الدكتور|أستاذ|استاذ|الأستاذ|استاذة|أستاذة|السيد|السيدة|الحاج)\s*[/.-]?\s*/iu,
				""
			)
			.trim();
		if (!next || next === text) break;
		text = next;
	}
	const compact = compactNameForCompare(text);
	if (!compact || compact.length < 6) return "";
	if (/^(?:guest|customer|client|visitor|unknown|test)$/i.test(compact)) return "";
	return compact;
}

function duplicatePhoneDigits(value = "") {
	return cleanPhone(value).replace(/[^\d]/g, "");
}

function duplicatePhonesMatch(left = "", right = "") {
	const a = duplicatePhoneDigits(left);
	const b = duplicatePhoneDigits(right);
	if (!a || !b || a.length < 7 || b.length < 7) return false;
	if (a === b) return true;
	return a.length >= 9 && b.length >= 9 && (a.endsWith(b) || b.endsWith(a));
}

function roomTypeKeyForDuplicate(value = "") {
	const raw = String(value || "").trim();
	if (!raw) return "";
	if (ROOM_TYPE_KEYS.includes(raw)) return raw;
	return mapRoomToKey(raw) || "";
}

function canonicalDuplicateRoomSelections(selections = [], fallbackRoomTypeKey = "", fallbackRooms = 1) {
	const normalized = normalizeRoomSelections(selections);
	const source = normalized.length
		? normalized
		: roomTypeKeyForDuplicate(fallbackRoomTypeKey)
		? [
				{
					roomTypeKey: roomTypeKeyForDuplicate(fallbackRoomTypeKey),
					count: normalizeRoomCount(fallbackRooms, 1),
				},
		  ]
		: [];
	const merged = new Map();
	for (const item of source) {
		const key = roomTypeKeyForDuplicate(item.roomTypeKey || item.roomType || item.type);
		if (!key) continue;
		merged.set(key, (merged.get(key) || 0) + normalizeRoomCount(item.count, 1));
	}
	return Array.from(merged.entries())
		.sort(([left], [right]) => left.localeCompare(right))
		.map(([roomTypeKey, count]) => ({ roomTypeKey, count }));
}

function duplicateRoomSelectionKey(selections = []) {
	return (Array.isArray(selections) ? selections : [])
		.map((item) => `${item.roomTypeKey}:${normalizeRoomCount(item.count, 1)}`)
		.join("+");
}

function duplicateKnownRoomSelections(known = {}) {
	const quote = asObject(known.quote);
	const quoteSelections = normalizeRoomSelections(quote.roomSelections);
	if (quoteSelections.length) return canonicalDuplicateRoomSelections(quoteSelections);
	const lineSelections = Array.isArray(quote.rooms)
		? quote.rooms
				.map((line) => ({
					roomTypeKey: line?.roomTypeKey || line?.room?.roomType || line?.quote?.roomTypeKey || "",
					count: line?.count || line?.rooms || 1,
				}))
				.filter((line) => line.roomTypeKey)
		: [];
	if (lineSelections.length) return canonicalDuplicateRoomSelections(lineSelections);
	return canonicalDuplicateRoomSelections(
		known.roomSelections,
		known.roomTypeKey || quote.roomTypeKey,
		known.rooms || quote.rooms || 1
	);
}

function duplicateReservationRoomSelections(reservation = {}) {
	const picked = Array.isArray(reservation.pickedRoomsType)
		? reservation.pickedRoomsType
		: Array.isArray(reservation.pickedRoomsPricing)
		? reservation.pickedRoomsPricing
		: [];
	const selections = picked
		.map((row) => ({
			roomTypeKey: roomTypeKeyForDuplicate(
				row?.room_type || row?.roomType || row?.roomTypeKey || row?.displayName
			),
			count: normalizeRoomCount(row?.count, 1),
		}))
		.filter((row) => row.roomTypeKey);
	return canonicalDuplicateRoomSelections(selections);
}

function activeReservationForDuplicateCheck(reservation = {}) {
	const status = normalizeIntentSearchText(
		[
			reservation.reservation_status,
			reservation.state,
			reservation.pendingConfirmation?.status,
			reservation.pendingConfirmation?.operationalStatus,
			reservation.pendingConfirmation?.clientVisibleStatus,
		]
			.filter(Boolean)
			.join(" ")
	);
	if (!status) return true;
	return !/(?:cancel|cancell|void|delete|deleted|failed|reject|rejected|expired|no\s*show|noshow|archiv|removed|ملغ|الغاء|إلغاء)/i.test(
		status
	);
}

function duplicateKnownVariants(sc = {}, known = {}, hotel = {}) {
	const periods = normalizeSplitStayPeriods(known.splitStayPeriods);
	const base = {
		...known,
		hotelId: String(hotel?._id || sc.hotelId || ""),
	};
	if (periods.length >= 2) {
		return periods.map((period, index) => ({
			label: `period_${index + 1}`,
			known: {
				...base,
				checkinISO: period.checkinISO,
				checkoutISO: period.checkoutISO,
				quote: {},
			},
		}));
	}
	return [{ label: "single", known: base }];
}

function duplicateKeyForKnown(sc = {}, known = {}, hotel = {}) {
	const checkinISO = validISODate(known.checkinISO);
	const checkoutISO = validISODate(known.checkoutISO);
	const hotelId = String(hotel?._id || sc.hotelId || known.hotelId || "").trim();
	const name = duplicateNameForCompare(known.fullName || profileNameForBooking(sc));
	const phone = duplicatePhoneDigits(known.phone || profilePhoneForBooking(sc));
	const roomSelections = duplicateKnownRoomSelections(known);
	const roomKey = duplicateRoomSelectionKey(roomSelections);
	if (!hotelId || !checkinISO || !checkoutISO || !name || !phone || !roomKey) return "";
	return [hotelId, checkinISO, checkoutISO, roomKey, name, phone].join("|");
}

function duplicateKeyForKnownSet(sc = {}, known = {}, hotel = {}) {
	const keys = duplicateKnownVariants(sc, known, hotel)
		.map((variant) => duplicateKeyForKnown(sc, variant.known, hotel))
		.filter(Boolean);
	if (!keys.length) return "";
	return keys.sort().join("||");
}

function duplicateReservationMatchesKnown(reservation = {}, sc = {}, known = {}, hotel = {}) {
	if (!activeReservationForDuplicateCheck(reservation)) return false;
	const hotelId = String(hotel?._id || sc.hotelId || "").trim();
	if (hotelId && String(reservation.hotelId || "").trim() !== hotelId) return false;
	const checkinISO = validISODate(known.checkinISO);
	const checkoutISO = validISODate(known.checkoutISO);
	if (!checkinISO || !checkoutISO) return false;
	if (validISODate(reservation.checkin_date) !== checkinISO) return false;
	if (validISODate(reservation.checkout_date) !== checkoutISO) return false;
	const expectedName = duplicateNameForCompare(known.fullName || profileNameForBooking(sc));
	const reservationName = duplicateNameForCompare(reservation.customer_details?.name);
	if (!expectedName || !reservationName || expectedName !== reservationName) return false;
	if (!duplicatePhonesMatch(known.phone || profilePhoneForBooking(sc), reservation.customer_details?.phone)) {
		return false;
	}
	const expectedRoomKey = duplicateRoomSelectionKey(duplicateKnownRoomSelections(known));
	const reservationRoomKey = duplicateRoomSelectionKey(
		duplicateReservationRoomSelections(reservation)
	);
	return Boolean(expectedRoomKey && reservationRoomKey && expectedRoomKey === reservationRoomKey);
}

function compactExistingReservationForCase(reservation = {}, match = {}) {
	const links = reservationPublicLinks(reservation);
	return {
		reservationId: String(reservation._id || ""),
		confirmationNumber: cleanDisplayString(reservation.confirmation_number || "", 40),
		hotelId: String(reservation.hotelId || ""),
		hotelName: cleanDisplayString(reservation.hotelName || "", 120),
		customerName: cleanDisplayString(reservation.customer_details?.name || "", 120),
		phone: cleanDisplayString(reservation.customer_details?.phone || "", 40),
		email: cleanEmail(reservation.customer_details?.email || ""),
		checkinISO: validISODate(reservation.checkin_date),
		checkoutISO: validISODate(reservation.checkout_date),
		roomSelectionKey: duplicateRoomSelectionKey(duplicateReservationRoomSelections(reservation)),
		totalAmount: Number(reservation.total_amount || 0) || 0,
		currency: reservation.currency || "SAR",
		status: cleanDisplayString(reservation.reservation_status || reservation.state || "", 60),
		links,
		matchLabel: match.label || "",
	};
}

function existingReservationSnapshotForCase({
	status = "found",
	hotelId = "",
	matchKey = "",
	matchReason = "",
	matches = [],
} = {}) {
	return {
		status,
		lookupWindowDays: AI_EXISTING_RESERVATION_LOOKUP_DAYS,
		matchedAt: new Date(),
		hotelId: hotelId || null,
		matchKey,
		matchReason,
		reservations: matches
			.map((match) => compactExistingReservationForCase(match.reservation || match, match))
			.slice(0, 6),
	};
}

async function findExistingReservationDuplicateContext(sc = {}, hotel = {}, known = {}) {
	if (knownHasReservationConfirmation(known)) {
		return { complete: false, key: "", matches: [], reason: "current_case_already_confirmed" };
	}
	const variants = duplicateKnownVariants(sc, known, hotel)
		.map((variant) => ({
			...variant,
			key: duplicateKeyForKnown(sc, variant.known, hotel),
		}))
		.filter((variant) => variant.key);
	if (!variants.length) return { complete: false, key: "", matches: [], reason: "missing_key" };
	if (variants.length !== duplicateKnownVariants(sc, known, hotel).length) {
		return { complete: false, key: "", matches: [], reason: "missing_split_key" };
	}
	const hotelId = String(hotel?._id || sc.hotelId || "").trim();
	const reservations = await listRecentHotelReservationsForExistingGuest({
		hotelId,
		since: duplicateReservationLookupSinceDate(),
		limit: AI_EXISTING_RESERVATION_LOOKUP_LIMIT,
	});
	const byId = new Map();
	for (const variant of variants) {
		for (const reservation of reservations) {
			if (!duplicateReservationMatchesKnown(reservation, sc, variant.known, hotel)) continue;
			const id = String(reservation._id || "");
			if (!id || byId.has(id)) continue;
			byId.set(id, {
				label: variant.label,
				key: variant.key,
				reservation,
			});
		}
	}
	return {
		complete: true,
		key: variants.map((variant) => variant.key).sort().join("||"),
		matches: Array.from(byId.values()).sort(
			(a, b) =>
				new Date(b.reservation.createdAt || b.reservation.booked_at || 0) -
				new Date(a.reservation.createdAt || a.reservation.booked_at || 0)
		),
		reason: "same_hotel_name_phone_dates_room",
	};
}

function duplicateReservationAcknowledgedForKnown(known = {}, key = "") {
	return Boolean(
		key &&
			cleanString(known.existingReservationDuplicateAcknowledgedKey, 500) === key
	);
}

function guestAcknowledgesDuplicateReservationWarning(
	value = "",
	action = "",
	previousAiAction = ""
) {
	if (String(previousAiAction || "").toLowerCase() !== "existing_reservation_warning") {
		return false;
	}
	const cleanAction = cleanString(action, 80).toLowerCase();
	if (["duplicate_create_anyway", "duplicate_not_mine"].includes(cleanAction)) return true;
	const text = normalizeIntentSearchText(value)
		.replace(/[.!?\u061f\u060c,]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	const compact = text.replace(/\s+/g, "");
	return (
		guestConfirms(value, action) ||
		/\b(?:new|separate|another)\s+(?:booking|reservation)\b/i.test(text) ||
		/\b(?:not\s+mine|not\s+my\s+reservation|not\s+my\s+booking|create\s+anyway|book\s+anyway|continue\s+anyway)\b/i.test(
			text
		) ||
		/(?:حجزجديد|حجزاخر|حجزآخر|ليسهذاحجزي|مشحجزي|ليسحجزي|اكملرغمذلك|كملرغمذلك|نعمكمل|تمامكمل|اكيدكمل|أكيدكمل|اكمل|أكمل|تابع|استمر)/iu.test(
			compact
		)
	);
}

function applyDuplicateReservationAcknowledgement(sc = {}, known = {}, hotel = {}, latestGuest = null, previousAi = null) {
	const key = duplicateKeyForKnownSet(sc, known, hotel);
	if (
		key &&
		guestAcknowledgesDuplicateReservationWarning(
			latestGuest?.message || "",
			latestGuest?.clientAction || "",
			previousAi?.clientAction || ""
		)
	) {
		return {
			...known,
			existingReservationDuplicateAcknowledgedKey: key,
			existingReservationDuplicateAcknowledgedAt: new Date().toISOString(),
		};
	}
	return known;
}

function existingReservationDuplicateQuickReplies(languageCode = "en") {
	if (/^ar\b/i.test(languageCode)) {
		return [
			{ label: "أريد حجزًا جديدًا", value: "أريد حجزًا جديدًا", action: "duplicate_create_anyway" },
			{ label: "هذا ليس حجزي", value: "هذا ليس حجزي", action: "duplicate_not_mine" },
			{ label: "أحتاج مساعدة", value: "أحتاج مساعدة", action: "need_help" },
		];
	}
	return [
		{ label: "New booking", value: "I want a new separate booking", action: "duplicate_create_anyway" },
		{ label: "Not mine", value: "This is not my reservation", action: "duplicate_not_mine" },
		{ label: "Need help", value: "I need help", action: "need_help" },
	];
}

function existingReservationRowsForMessage(matches = [], languageCode = "en") {
	return matches
		.map((match, index) => {
			const reservation = match.reservation || match;
			const compact = compactExistingReservationForCase(reservation, match);
			const dateLine =
				compact.checkinISO && compact.checkoutISO
					? `${formatDate(compact.checkinISO, languageCode)} - ${formatDate(
							compact.checkoutISO,
							languageCode
					  )}`
					: "";
			const total = compact.totalAmount
				? formatMoney(compact.totalAmount, compact.currency || "SAR", languageCode)
				: "";
			if (/^ar\b/i.test(languageCode)) {
				return [
					`الحجز ${formatNumber(index + 1, languageCode)}:`,
					`رقم التأكيد: ${compact.confirmationNumber || ""}`,
					dateLine ? `الفترة: ${dateLine}` : "",
					total ? `الإجمالي: ${total}` : "",
					compact.links.reservationConfirmation
						? `رابط التفاصيل: ${compact.links.reservationConfirmation}`
						: "",
					compact.links.payment ? `رابط الدفع: ${compact.links.payment}` : "",
				]
					.filter(Boolean)
					.join("\n");
			}
			return [
				`Reservation ${index + 1}:`,
				`Confirmation number: ${compact.confirmationNumber || ""}`,
				dateLine ? `Dates: ${dateLine}` : "",
				total ? `Total: ${total}` : "",
				compact.links.reservationConfirmation
					? `Details: ${compact.links.reservationConfirmation}`
					: "",
				compact.links.payment ? `Payment link: ${compact.links.payment}` : "",
			]
				.filter(Boolean)
				.join("\n");
		})
		.join("\n\n");
}

function buildExistingReservationDuplicateWarningMessage(sc = {}, known = {}, hotel = {}, matches = []) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "الفندق"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "the hotel";
	const rows = existingReservationRowsForMessage(matches, languageCode);
	if (ar) {
		return [
			`${arabicGuestAddress(sc, known)}، وجدت حجزًا سابقًا بنفس بيانات الطلب في ${hotelName}: الاسم، رقم الجوال، التواريخ، ونوع الغرفة.`,
			rows,
			`حتى لا ننشئ حجزًا مكررًا بدون قصد، هل تريد حجزًا جديدًا منفصلًا رغم وجود هذا الحجز، أم أن هذا الحجز ليس لك؟`,
		]
			.filter(Boolean)
			.join("\n\n");
	}
	return [
		`${guestDisplayName(sc)}, I found an existing reservation at ${hotelName} with the same name, phone, dates, and room type.`,
		rows,
		`To avoid creating an unintended duplicate, please confirm whether you want a new separate booking anyway, or whether this reservation is not yours.`,
	]
		.filter(Boolean)
		.join("\n\n");
}

function buildExistingReservationHardCutMessage(sc = {}, known = {}, hotel = {}, matches = []) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "الفندق"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "the hotel";
	const rows = existingReservationRowsForMessage(matches, languageCode);
	const whatsapp = `[${RESERVATION_CHANGE_CONTACT_PHONE}](${RESERVATION_CHANGE_CONTACT_WHATSAPP})`;
	if (ar) {
		return [
			`${arabicGuestAddress(sc, known)}، وجدت أكثر من حجز سابق بنفس بيانات الطلب في ${hotelName}.`,
			rows,
			`حرصًا على منع أي حجوزات مكررة، أوقفت إنشاء أي حجز جديد من المحادثة الآلية لهذا الطلب.`,
			`للمراجعة أو التعديل، تواصل معنا عبر واتساب: ${whatsapp}.`,
			`سيتم إغلاق هذه المحادثة بعد قليل، ونحن بخدمتك عبر واتساب.`,
		]
			.filter(Boolean)
			.join("\n\n");
	}
	return [
		`${guestDisplayName(sc)}, I found more than one existing reservation at ${hotelName} with the same booking details.`,
		rows,
		`To prevent duplicate bookings, I have stopped automatic booking creation for this request.`,
		`Please contact us on WhatsApp for review or changes: ${whatsapp}.`,
		`This chat will close shortly, and we will help you there.`,
	]
		.filter(Boolean)
		.join("\n\n");
}

async function handleExistingReservationDuplicateGuard({
	io,
	sc = {},
	hotel = {},
	known = {},
	latestGuest = null,
	typingStartedAt = 0,
	stage = "review",
} = {}) {
	if (!latestGuest || knownHasReservationConfirmation(known)) return null;
	if (mentionsExplicitReservationIdentifier(latestGuest.message || "")) return null;
	const context = await findExistingReservationDuplicateContext(sc, hotel, known);
	if (!context.complete || !context.matches.length) return null;
	const matchCount = context.matches.length;
	const snapshot = existingReservationSnapshotForCase({
		status: matchCount >= 2 ? "hard_cut" : "warning",
		hotelId: hotel?._id || sc.hotelId || "",
		matchKey: context.key,
		matchReason: context.reason,
		matches: context.matches,
	});
	if (matchCount >= 2) {
		const nextKnown = {
			...known,
			existingReservationDuplicateKey: context.key,
			existingReservationDuplicateMatchCount: matchCount,
			existingReservationDuplicateHardCutAt: new Date().toISOString(),
		};
		await saveKnownFacts(caseIdText(sc), nextKnown);
		await waitForTypingMinimum(typingStartedAt);
		return sendAiMessage(io, sc, buildExistingReservationHardCutMessage(sc, nextKnown, hotel, context.matches), {
			latestGuest,
			known: nextKnown,
			clientAction: "existing_reservations_hard_cut",
			keepAiEnabled: false,
			closeCaseAfterMs: AI_EXISTING_RESERVATION_HARD_CLOSE_MS,
			closeReason: "ai_existing_reservation_hard_cut",
			caseFields: {
				aiExistingReservations: snapshot,
			},
		});
	}
	if (duplicateReservationAcknowledgedForKnown(known, context.key)) {
		return null;
	}
	const nextKnown = {
		...known,
		existingReservationDuplicateKey: context.key,
		existingReservationDuplicateMatchCount: matchCount,
		existingReservationDuplicateWarnedAt: new Date().toISOString(),
		existingReservationDuplicateStage: stage,
	};
	await saveKnownFacts(caseIdText(sc), nextKnown);
	await waitForTypingMinimum(typingStartedAt);
	return sendAiMessage(
		io,
		sc,
		buildExistingReservationDuplicateWarningMessage(sc, nextKnown, hotel, context.matches),
		{
			latestGuest,
			known: nextKnown,
			clientAction: "existing_reservation_warning",
			quickReplies: existingReservationDuplicateQuickReplies(
				activeLanguageCode(sc, nextKnown)
			),
			caseFields: {
				aiExistingReservations: snapshot,
			},
		}
	);
}

async function emitTyping(io, sc = {}, isTyping = true, details = {}) {
	const caseId = caseIdText(sc);
	if (!io || !caseId) return;
	const payload = {
		caseId,
		name: localizedAgentName(sc),
		isAi: true,
		...(isTyping && details?.progressKey
			? {
					progressKey: cleanString(details.progressKey, 80),
					statusText: cleanDisplayString(details.statusText, 500),
					expiresInMs: Math.max(
						5000,
						Math.min(90000, Number(details.expiresInMs || 60000) || 60000)
					),
			  }
			: {}),
	};
	io.to(caseId).emit(isTyping ? "typing" : "stopTyping", payload);
}

function reservationProcessingStatusText(sc = {}, known = {}) {
	const ar = /^ar\b/i.test(activeLanguageCode(sc, known));
	return ar
		? "\u062c\u0627\u0631\u064a \u0627\u0644\u0622\u0646 \u0645\u0631\u0627\u062c\u0639\u0629 \u0627\u0644\u0633\u0639\u0631 \u0648\u0627\u0644\u062a\u0641\u0627\u0635\u064a\u0644 \u0627\u0644\u0646\u0647\u0627\u0626\u064a\u0629 \u0648\u0625\u062a\u0645\u0627\u0645 \u0627\u0644\u062d\u062c\u0632. \u0642\u062f \u064a\u0633\u062a\u063a\u0631\u0642 \u0630\u0644\u0643 \u062d\u062a\u0649 \u062f\u0642\u064a\u0642\u0629\u061b \u0641\u0636\u0644\u064b\u0627 \u0627\u0646\u062a\u0638\u0631 \u0647\u0646\u0627 \u0648\u0633\u0623\u0631\u0633\u0644 \u0631\u0642\u0645 \u0627\u0644\u062a\u0623\u0643\u064a\u062f \u0641\u0648\u0631 \u0627\u0643\u062a\u0645\u0627\u0644\u0647."
		: "I am reviewing the final price and details and completing the reservation now. This may take up to one minute; please wait here and I will send the confirmation number as soon as it is complete.";
}

async function emitReservationProcessing(io, sc = {}, known = {}) {
	return emitTyping(io, sc, true, {
		progressKey: "reservation_confirmation",
		statusText: reservationProcessingStatusText(sc, known),
		expiresInMs: 60000,
	});
}

function clearIdleCloseTimer(caseId = "") {
	const key = caseIdText(caseId);
	const existing = idleCloseTimers.get(key);
	if (existing) clearTimeout(existing);
	idleCloseTimers.delete(key);
}

function clearDelayedCloseTimer(caseId = "") {
	const key = caseIdText(caseId);
	const existing = delayedCloseTimers.get(key);
	if (existing) clearTimeout(existing);
	delayedCloseTimers.delete(key);
}

function emitClosedCase(io, updatedCase = {}, reason = "ai_idle_timeout") {
	const caseId = caseIdText(updatedCase);
	if (!io || !caseId) return;
	const payload = {
		case: updatedCase,
		caseId,
		caseStatus: "closed",
		closedAt: updatedCase.closedAt || new Date(),
		closedBy: updatedCase.closedBy || "csr",
		reason,
	};
	io.emit("supportCaseUpdated", updatedCase);
	io.to(caseId).emit("supportCaseUpdated", updatedCase);
	io.emit("closeCase", payload);
	io.to(caseId).emit("aiPaused", { caseId, reason });
}

function scheduleDelayedCaseClose(
	io,
	sc = {},
	aiMessageDate = new Date(),
	{ delayMs = AI_EXISTING_RESERVATION_HARD_CLOSE_MS, reason = "ai_existing_reservation_hard_cut" } = {}
) {
	const caseId = caseIdText(sc);
	const aiMessageAt = entryTime({ date: aiMessageDate });
	if (!caseId || !aiMessageAt || delayMs <= 0) return;
	clearDelayedCloseTimer(caseId);
	const timer = setTimeout(async () => {
		delayedCloseTimers.delete(caseId);
		const latest = await getSupportCaseById(caseId).catch(() => null);
		if (!latest || latest.caseStatus !== "open") return;
		const latestEntry = latestConversationEntry(latest);
		const latestAt = entryTime(latestEntry);
		const latestAction = String(latestEntry?.clientAction || "").toLowerCase();
		const humanTakeoverAt = entryTime({ date: latest.humanTakeoverAt });
		if (humanTakeoverAt && humanTakeoverAt > aiMessageAt) return;
		if (
			!latestEntry?.isAi ||
			latestAt !== aiMessageAt ||
			latestAction !== "existing_reservations_hard_cut"
		) {
			return;
		}
		const nowDate = new Date();
		const updated = await setCaseStatus(caseId, {
			caseStatus: "closed",
			closedAt: nowDate,
			closedBy: "csr",
			aiToRespond: false,
			aiPausedAt: nowDate,
			aiHandoffReason: reason,
		}).catch((error) => {
			console.error("[aiagent] delayed close failed:", error?.message || error);
			return null;
		});
		if (updated) emitClosedCase(io, updated, reason);
	}, Math.max(1000, Number(delayMs) || 0));
	timer.unref?.();
	delayedCloseTimers.set(caseId, timer);
}

function scheduleIdleClose(io, sc = {}, aiMessageDate = new Date()) {
	const caseId = caseIdText(sc);
	const aiMessageAt = entryTime({ date: aiMessageDate });
	if (!io || !caseId || !aiMessageAt || AI_IDLE_AUTO_CLOSE_MS <= 0) return;
	clearIdleCloseTimer(caseId);

	const runAt = aiMessageAt + AI_IDLE_AUTO_CLOSE_MS;
	const delay = Math.max(1000, runAt - now());
	const timer = setTimeout(async () => {
		idleCloseTimers.delete(caseId);
		const latestGuestActivityAt = Number(guestActivityAtByCase.get(caseId) || 0);
		if (latestGuestActivityAt > aiMessageAt) {
			const waitMs = latestGuestActivityAt + AI_IDLE_AUTO_CLOSE_MS - now();
			if (waitMs > 0) {
				const rescheduleTimer = setTimeout(() => {
					scheduleIdleClose(io, sc, aiMessageDate);
				}, Math.max(1000, waitMs));
				rescheduleTimer.unref?.();
				idleCloseTimers.set(caseId, rescheduleTimer);
				return;
			}
		}
		if (activeTurns.has(caseId)) {
			scheduleIdleClose(io, sc, new Date(aiMessageAt));
			return;
		}
		const updated = await closeSupportCaseForAiIdle(caseId, {
			now: new Date(),
			reason: "ai_idle_timeout",
			latestAiDate: new Date(aiMessageAt),
		}).catch((error) => {
			console.error("[aiagent] idle close failed:", error?.message || error);
			return null;
		});
		if (updated) {
			emitClosedCase(io, updated, "ai_idle_timeout");
		}
	}, delay);
	timer.unref?.();
	idleCloseTimers.set(caseId, timer);
}

async function recoverIdleCloseTimers(io) {
	if (!io || AI_IDLE_AUTO_CLOSE_MS <= 0) return;
	try {
		const cases = await listOpenClientAiCasesForIdleSweep({ limit: 75 });
		const nowMs = now();
		let scheduled = 0;
		let closed = 0;
		for (const supportCase of cases) {
			const latestEntry = latestConversationEntry(supportCase);
			if (!latestEntry?.isAi || latestEntry?.isSystem) continue;
			const latestAt = entryTime(latestEntry);
			if (!latestAt) continue;
			if (nowMs - latestAt >= AI_IDLE_AUTO_CLOSE_MS) {
				const updated = await closeSupportCaseForAiIdle(caseIdText(supportCase), {
					now: new Date(),
					reason: "ai_idle_timeout",
					latestAiDate: new Date(latestAt),
				}).catch((error) => {
					console.error("[aiagent] idle recovery close failed:", error?.message || error);
					return null;
				});
				if (updated) {
					closed += 1;
					emitClosedCase(io, updated, "ai_idle_timeout");
				}
			} else {
				scheduled += 1;
				scheduleIdleClose(io, supportCase, new Date(latestAt));
			}
		}
		if (closed || scheduled) {
			console.log("[aiagent] idle close recovery", { closed, scheduled });
		}
	} catch (error) {
		console.error("[aiagent] idle close recovery failed:", error?.message || error);
	}
}

async function waitForGuestQuiet(caseId = "") {
	const key = caseIdText(caseId);
	for (let i = 0; i < 20; i += 1) {
		const until = Number(guestTypingUntilByCase.get(key) || 0);
		const remaining = until - now();
		if (remaining <= 0) return true;
		await sleep(Math.min(remaining, 800));
	}
	return Number(guestTypingUntilByCase.get(key) || 0) <= now();
}

async function sendAiMessage(io, sc = {}, text = "", options = {}) {
	const caseId = caseIdText(sc);
	let message = String(text || "").trim();
	const stockPrivacyContext = {
		known: options.known || {},
		clientAction: options.clientAction || "",
	};
	const protocolGuard = sanitizeCustomerFacingProtocolText(message);
	if (protocolGuard.blocked) {
		console.error("[aiagent] blocked protocol-shaped customer reply", {
			caseId,
			reason: protocolGuard.reason,
			length: message.length,
		});
		message = safeProtocolBlockedCustomerReply(
			sc,
			options.known || {},
			options.latestGuest,
			options.clientAction || "ai_reply",
			options.validatedFallback || ""
		);
	} else if (protocolGuard.changed && protocolGuard.text) {
		message = protocolGuard.text.trim();
	}
	if (replyDisclosesInternalStock(message, stockPrivacyContext)) {
		console.error("[aiagent] replaced customer reply containing private hotel stock", {
			caseId,
			clientAction: cleanString(options.clientAction, 80),
		});
		const fallback = String(options.validatedFallback || "").trim();
		message =
			fallback &&
			!sanitizeCustomerFacingProtocolText(fallback).blocked &&
			!replyDisclosesInternalStock(fallback, stockPrivacyContext)
				? fallback
				: stockPrivacyRecoveryReply(sc, options.known || {});
	}
	const repetitionCriticalAction = new Set([
		"reservation_confirmed",
		"review_reservation",
		"reservation_lookup_found",
		"reservation_lookup_not_found",
		"reservation_update_success",
		"reservation_cancel_contact",
		"reservation_finalize_failed",
		"human_escalation_contact",
	]);
	if (
		!repetitionCriticalAction.has(cleanString(options.clientAction, 80).toLowerCase()) &&
		replyTooSimilarToRecentAi(
			sc,
			message,
			options.latestGuest,
			options.clientAction || "ai_reply"
		)
	) {
		console.warn("[aiagent] replaced repetitive customer reply", {
			caseId,
			clientAction: cleanString(options.clientAction, 80),
		});
		message = selectNonRepeatedCustomerReplyRecovery(
			sc,
			options.known || {},
			options.latestGuest,
			options.clientAction || "ai_reply"
		);
	}
	if (!caseId || !message) return null;
	const workerNoDirectEmit = Boolean(io?.__aiWorkerNoDirectEmit);
	const quiet = await waitForGuestQuiet(caseId);
	if (!quiet) {
		if (io && !workerNoDirectEmit) {
			schedulePlanTurn(io, caseId, {
				delayMs: AI_GUEST_REPLY_QUIET_MS,
				reason: "guest_still_typing_before_send",
			});
		}
		return await getSupportCaseById(caseId).catch(() => sc);
	}
	const latestBeforeSend = await getSupportCaseById(caseId).catch(() => null);
	const reservationWaitAcknowledgementsOnly = Boolean(
		options.allowReservationWaitAcknowledgements &&
			latestBeforeSend &&
			onlyReservationProcessingAcknowledgementsAfter(latestBeforeSend, options.latestGuest)
	);
	const successfulMutationMayBypassStale = Boolean(options.allowAfterSuccessfulMutation);
	if (
		options.latestGuest &&
		(!latestBeforeSend ||
			(!latestGuestStillCurrent(latestBeforeSend, options.latestGuest) &&
				!reservationWaitAcknowledgementsOnly &&
				!successfulMutationMayBypassStale))
	) {
		if (io && !workerNoDirectEmit) {
			schedulePlanTurn(io, caseId, {
				delayMs: AI_GUEST_REPLY_QUIET_MS,
				reason: "new_guest_message_before_send",
			});
		}
		return latestBeforeSend;
	}
	const languageCode = activeLanguageCode(sc, options.known || {});
	const firstReplyLooksArabic =
		/^ar\b/i.test(languageCode) ||
		/[\u0600-\u06FF]/.test(`${message || ""} ${options.latestGuest?.message || ""}`);
	if (
		!hasAnyAiEntry(latestBeforeSend || sc) &&
		firstReplyLooksArabic
	) {
		message = withFirstArabicIslamicGreeting(message);
	}
	const customerSafeQuickReplies = (Array.isArray(options.quickReplies)
		? options.quickReplies.slice(0, 3)
		: []
	).filter((item) => {
		const values =
			typeof item === "string"
				? [item]
				: Object.values(asObject(item)).filter(
						(value) => ["string", "number"].includes(typeof value)
				  );
		return values.every(
			(value) =>
				!replyDisclosesInternalStock(String(value)) &&
				!sanitizeCustomerFacingProtocolText(String(value)).blocked
		);
	});
	const messageData = {
		messageBy: {
			customerName: localizedAgentName(sc),
			customerEmail: "support@jannatbooking.com",
			userId: "jannat-ai-support",
		},
		message,
		date: new Date(),
		inquiryAbout: "support",
		inquiryDetails: message.slice(0, 300),
		seenByAdmin: false,
		seenByHotel: false,
		seenByCustomer: false,
		isAi: true,
		isSystem: false,
		clientTag: `${workerNoDirectEmit ? "ai_worker" : "ai_slim"}_${Date.now()}_${Math.random()
			.toString(36)
			.slice(2, 8)}`,
		clientAction: options.clientAction || "ai_reply",
		preferredLanguage: sc.preferredLanguage || "",
		preferredLanguageCode: languageCode,
		quickReplies: customerSafeQuickReplies,
	};
	const fields = {
		conversation: messageData,
		aiRelated: true,
		aiToRespond: options.keepAiEnabled === false ? false : true,
	};
	const extraCaseFields = asObject(options.caseFields);
	if (Object.keys(extraCaseFields).length) {
		Object.assign(fields, extraCaseFields);
	}
	if (options.handoff) {
		fields.aiToRespond = false;
		fields.aiPausedAt = new Date();
		fields.aiHandoffReason = options.handoffReason || "human_review_needed";
		fields.escalationStatus = "active";
		fields.escalationReason = options.handoffReason || "human_review_needed";
		fields.escalationSource = "ai";
		fields.escalatedAt = new Date();
	}
	if (options.closeCase) {
		fields.caseStatus = "closed";
		fields.closedAt = new Date();
		fields.closedBy = "csr";
		fields.aiToRespond = false;
		fields.aiPausedAt = new Date();
		fields.aiHandoffReason = options.closeReason || "ai_closed_case";
	}
	const latestGuestForAppend =
		reservationWaitAcknowledgementsOnly || successfulMutationMayBypassStale
		? latestGuestEntry(latestBeforeSend)
		: options.latestGuest;
	const aiAfterLatestGuest = latestNonSystemAiAfterGuest(
		latestBeforeSend,
		latestGuestForAppend
	);
	const answeringGuestQueuedBehindSuccessfulMutation = Boolean(
		aiAfterLatestGuest &&
			String(aiAfterLatestGuest.clientAction || "").toLowerCase() === "reservation_confirmed"
	);
	const saved = await updateSupportCaseAppendIfNoRecentAiDuplicate(caseId, fields, {
		requireOpenClientAi: !options.closeCase && !options.handoff,
		requireLatestGuestText: latestGuestForAppend?.message || "",
		requireNoAiAfter: answeringGuestQueuedBehindSuccessfulMutation
			? null
			: latestGuestForAppend?.date || null,
		duplicateWindowMs: 30000,
	});
	const updatedCase = saved?.updatedCase || (await getSupportCaseById(caseId).catch(() => null));
	if (saved?.skipped) {
		console.warn("[aiagent] customer reply append skipped; socket message suppressed", {
			caseId,
			clientAction: cleanString(options.clientAction, 80),
		});
		if (io && updatedCase && !workerNoDirectEmit) {
			io.to(caseId).emit("supportCaseUpdated", updatedCase);
			io.emit("supportCaseUpdated", updatedCase);
			await emitTyping(io, updatedCase, false);
		}
		const newestGuest = latestGuestEntry(updatedCase || {});
		if (
			io &&
			newestGuest &&
			!latestNonSystemAiAfterGuest(updatedCase || {}, newestGuest)
		) {
			schedulePlanTurn(io, caseId, {
				delayMs: 25,
				reason: "reply_append_skipped_for_current_guest",
				skipMinimumQuiet: true,
			});
		}
		return updatedCase;
	}
	if (io && updatedCase && !workerNoDirectEmit) {
		io.to(caseId).emit("receiveMessage", { ...messageData, caseId });
		io.to(caseId).emit("supportCaseUpdated", updatedCase);
		io.emit("supportCaseUpdated", updatedCase);
		await emitTyping(io, sc, false);
		if (options.closeCase) {
			const payload = {
				case: updatedCase,
				caseId,
				caseStatus: "closed",
				closedAt: updatedCase.closedAt || new Date(),
				closedBy: updatedCase.closedBy || "csr",
				reason: options.closeReason || "ai_closed_case",
			};
			io.emit("closeCase", payload);
			io.to(caseId).emit("aiPaused", { caseId, reason: payload.reason });
		}
		if (options.handoff) {
			io.to(caseId).emit("aiPaused", {
				caseId,
				reason: options.handoffReason || "human_review_needed",
			});
		}
	}
	if (updatedCase && !options.closeCase && !options.handoff) {
		if (options.closeCaseAfterMs) {
			scheduleDelayedCaseClose(io, updatedCase, messageData.date, {
				delayMs: options.closeCaseAfterMs,
				reason: options.closeReason || "ai_delayed_close",
			});
		} else {
			clearDelayedCloseTimer(caseId);
			scheduleIdleClose(io, updatedCase, messageData.date);
		}
	} else if (options.closeCase || options.handoff) {
		clearIdleCloseTimer(caseId);
		clearDelayedCloseTimer(caseId);
	}
	return updatedCase;
}

async function saveKnownFacts(caseId = "", known = {}) {
	if (!caseId) return;
	const nextKnown = applySelectedSameDateRoomOptionLock({ ...asObject(known) });
	const currentCase = await getSupportCaseById(caseId).catch(() => null);
	const previousSnapshot = asObject(currentCase?.aiStateSnapshot);
	if (!quoteHasContent(nextKnown.quote)) {
		const previousQuote = previousSnapshot?.known?.quote;
		if (quoteCanBePreservedForKnown(previousQuote, nextKnown)) {
			nextKnown.quote = previousQuote;
		} else {
			delete nextKnown.quote;
		}
	}
	await updateSupportCaseAiStateSnapshot(caseId, {
		...previousSnapshot,
		version: 3,
		updatedAt: new Date(),
		known: nextKnown,
	}).catch((error) => {
		console.error("[aiagent] save known facts failed:", error?.message || error);
	});
}

async function sendReview(io, sc = {}, known = {}, hotel = {}, latestGuest = null) {
	let reviewKnown = applySelectedSameDateRoomOptionLock(
		syncKnownFromQuote({ ...known, quote: asObject(known.quote) })
	);
	reviewKnown = applyAdjustedRoomPlanGuestConfirmation(
		reviewKnown,
		latestGuest,
		previousAiEntryBeforeLatestGuest(sc, latestGuest)
	);
	reviewKnown = ensureRoomPlanForGuestCapacity(hotel, reviewKnown).known;
	if (!quoteMatchesKnown(reviewKnown) && quoteInputsKnown(reviewKnown)) {
		const quoteResult = await quoteTool(sc, reviewKnown);
		if (quoteResult.available && quoteResult.quote) {
			reviewKnown = syncKnownFromQuote({ ...reviewKnown, quote: quoteResult.quote });
			await saveKnownFacts(caseIdText(sc), reviewKnown);
		} else {
			reviewKnown.quote = {
				available: false,
				roomTypeKey: quoteResult.roomTypeKey || reviewKnown.roomTypeKey,
				checkinISO: quoteResult.checkinISO || reviewKnown.checkinISO,
				checkoutISO: quoteResult.checkoutISO || reviewKnown.checkoutISO,
				rooms: Math.max(1, Number(reviewKnown.rooms || 1) || 1),
				roomSelections: normalizeRoomSelections(quoteResult.roomSelections || reviewKnown.roomSelections),
				currency: quoteResult.currency || "SAR",
				code: quoteResult.code || "not_available",
				roomLabel: quoteResult.roomLabel || roomTypeLabel(reviewKnown.roomTypeKey, reviewKnown.languageCode),
				firstUnavailableDate: quoteResult.firstUnavailableDate || "",
			};
			reviewKnown = syncKnownFromQuote(reviewKnown);
			if (shouldRecoverHotelUnavailableToJannat(sc, reviewKnown, quoteResult)) {
				return recoverHotelUnavailableToJannatSupport({
					io,
					sc,
					hotel,
					known: reviewKnown,
					quoteResult,
					latestGuest,
				});
			}
			return sendAiMessage(io, sc, buildQuoteFallbackMessage(sc, reviewKnown, quoteResult, hotel), {
				latestGuest,
				known: reviewKnown,
				clientAction: "quote_unavailable",
			});
		}
	}
	if (adjustedRoomPlanConfirmationPending(reviewKnown)) {
		await saveKnownFacts(caseIdText(sc), reviewKnown);
		return sendAiMessage(
			io,
			sc,
			buildAdjustedRoomPlanConfirmationMessage(sc, reviewKnown),
			{
				latestGuest,
				known: reviewKnown,
				clientAction: "room_plan_confirmation_required",
				quickReplies: proceedQuickReplies(activeLanguageCode(sc, reviewKnown)),
			}
		);
	}
	const missing = requiredBookingMissing(reviewKnown);
	if (missing.length) {
		return sendAiMessage(io, sc, buildMandatoryDetailsMessage(sc, reviewKnown, missing), {
			latestGuest,
			known: reviewKnown,
		});
		/*
		const languageCode = activeLanguageCode(sc, reviewKnown);
		const ar = /^ar\b/i.test(languageCode);
		const readable = missing
			.filter((item) => item !== "quote")
			.map((item) => {
				const labels = ar
					? {
							checkinISO: "تاريخ الوصول",
							checkoutISO: "تاريخ المغادرة",
							roomTypeKey: "نوع الغرفة",
							fullName: "الاسم الكامل",
							phone: "رقم الهاتف",
							nationality: "الجنسية",
							adults: "\u0639\u062f\u062f \u0627\u0644\u0628\u0627\u0644\u063a\u064a\u0646 \u0648\u0627\u0644\u0623\u0637\u0641\u0627\u0644 \u0625\u0646 \u0648\u062c\u062f",
					  }
					: {
							checkinISO: "check-in date",
							checkoutISO: "checkout date",
							roomTypeKey: "room type",
							fullName: "full name",
							phone: "phone number",
							nationality: "nationality",
							adults: "number of adults and children, if any",
					  };
				return labels[item] || item;
			});
		const text = ar
			? `تمام، بقي فقط ${readable.join("، ")} حتى أجهز مراجعة الحجز بشكل صحيح.`
			: `Almost ready. I still need ${readable.join(", ")} so I can prepare the booking review correctly.`;
		return sendAiMessage(io, sc, text, { latestGuest, known: reviewKnown });
		*/
	}
	await saveKnownFacts(caseIdText(sc), reviewKnown);
	if (shouldOfferOptionalEmail(sc, reviewKnown)) {
		return sendOptionalEmailOffer(io, sc, reviewKnown, latestGuest);
	}
	const text = buildReviewMessage(sc, reviewKnown, hotel);
	const updated = await sendAiMessage(io, sc, text, {
		latestGuest,
		known: reviewKnown,
		clientAction: "review_reservation",
		quickReplies: reviewQuickReplies(activeLanguageCode(sc, reviewKnown)),
	});
	if (latestConversationEntry(updated)?.clientAction === "review_reservation") {
		reviewKnown.reviewSentAt = new Date().toISOString();
		reviewKnown.officialReviewSnapshot = officialReviewSnapshotFromKnown(reviewKnown);
		await saveKnownFacts(caseIdText(sc), reviewKnown);
	}
	return updated;
}

async function handleQuote(io, sc = {}, hotel = {}, known = {}, latestGuest = null) {
	const caseId = caseIdText(sc);
	const latestText = String(latestGuest?.message || "");
	const previousAi = previousAiEntryBeforeLatestGuest(sc, latestGuest);
	if (
		latestGuest &&
		latestGuestRaisesBudgetConcern(latestText) &&
		!latestGuestHasExplicitStayChangeForBudget(latestText) &&
		aiMessageLooksLikeDisplayedQuote(previousAi)
	) {
		const budgetKnown = restoreKnownFromDisplayedQuoteForBudget(known, previousAi);
		await saveKnownFacts(caseId, budgetKnown);
		await waitForTypingMinimum(now());
		return sendAiMessage(io, sc, buildValueObjectionFallbackReply(sc, hotel, budgetKnown, latestGuest), {
			latestGuest,
			known: budgetKnown,
			clientAction: "value_objection",
			quickReplies: valueObjectionQuickReplies(activeLanguageCode(sc, budgetKnown)),
		});
	}
	known = filterInactiveRoomSelectionsForHotel(hotel, known).known;
	known = ensureRoomPlanForGuestCapacity(hotel, known).known;
	logTurnStage(caseId, "quote_tool_start", {
		checkinISO: known.checkinISO || "",
		checkoutISO: known.checkoutISO || "",
		roomTypeKey: known.roomTypeKey || "",
	});
	const result = await quoteTool(sc, known);
	logTurnStage(caseId, "quote_tool_done", {
		available: Boolean(result?.available),
		hasQuote: Boolean(result?.quote),
		code: result?.code || "",
	});
	let nextKnown = { ...known };
	if (result.available && result.quote) nextKnown.quote = result.quote;
	else {
		nextKnown.quote = {
			available: false,
			roomTypeKey: result.roomTypeKey || known.roomTypeKey,
			checkinISO: result.checkinISO || known.checkinISO,
			checkoutISO: result.checkoutISO || known.checkoutISO,
			rooms: Math.max(1, Number(known.rooms || 1) || 1),
			roomSelections: normalizeRoomSelections(result.roomSelections || known.roomSelections),
			currency: result.currency || "SAR",
			code: result.code || "not_available",
			roomLabel: result.roomLabel || roomTypeLabel(known.roomTypeKey, known.languageCode),
			firstUnavailableDate: result.firstUnavailableDate || "",
			minCheckinISO: result.minCheckinISO || "",
			unavailableSelections: Array.isArray(result.unavailableSelections)
				? result.unavailableSelections.slice(0, 5)
				: [],
		};
	}
	nextKnown = syncKnownFromQuote(nextKnown);
	await saveKnownFacts(caseIdText(sc), nextKnown);
	if (!result.available && shouldRecoverHotelUnavailableToJannat(sc, nextKnown, result)) {
		return recoverHotelUnavailableToJannatSupport({
			io,
			sc,
			hotel,
			known: nextKnown,
			quoteResult: result,
			latestGuest,
		});
	}
	const reply = buildQuoteFallbackMessage(sc, nextKnown, result, hotel);
	const quickReplies = result.available
		? proceedQuickReplies(activeLanguageCode(sc, nextKnown))
		: quoteUnavailableQuickRepliesForCase(sc, nextKnown);
	return sendAiMessage(io, sc, reply, {
		latestGuest,
		known: nextKnown,
		clientAction: result.available ? "quote_ready" : "quote_unavailable",
		quickReplies,
	});
}

async function unusedHandoffToHumanBeforeContactPolicy(io, sc = {}, known = {}, latestGuest = null, reason = "") {
	const languageCode = activeLanguageCode(sc, known);
	const text = /^ar\b/i.test(languageCode)
		? "أفهمك، سأحول المحادثة الآن لأحد أعضاء الفريق حتى يساعدك بشكل أدق."
		: "I understand. I will pass this conversation to a team member so they can help you properly.";
	return sendAiMessage(io, sc, text, {
		latestGuest,
		known,
		handoff: true,
		handoffReason: reason || "ai_escalated",
	});
}

async function handoffToHuman(io, sc = {}, known = {}, latestGuest = null, reason = "") {
	const text = buildHumanEscalationContactMessage(sc, known, latestGuest, reason);
	return sendAiMessage(io, sc, text, {
		latestGuest,
		known,
		clientAction: "human_escalation_contact",
		handoff: true,
		handoffReason: reason || "ai_escalated",
	});
}

function caseOutroImpliesPendingBooking(reply = "") {
	const text = normalizeIntentSearchText(reply).toLowerCase();
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:continue|finish|complete|resume)\s+(?:the\s+)?(?:booking|reservation)\s+later\b/i.test(text) ||
		/\b(?:book|booking|reserve|reservation)\s+later\b/i.test(text) ||
		/(?:\u062a\u0643\u0645\u0644\u0627\u0644\u062d\u062c\u0632|\u0646\u0643\u0645\u0644\u0627\u0644\u062d\u062c\u0632|\u0625\u0643\u0645\u0627\u0644\u0627\u0644\u062d\u062c\u0632|\u0627\u0643\u0645\u0627\u0644\u0627\u0644\u062d\u062c\u0632|\u0627\u0644\u062d\u062c\u0632\u0644\u0627\u062d\u0642)/u.test(compact)
	);
}

function buildCaseOutroText(sc = {}, known = {}, hasConfirmedReservation = false) {
	const languageCode = activeLanguageCode(sc, known);
	if (hasConfirmedReservation) {
		return /^ar\b/i.test(languageCode)
			? "\u0639\u0644\u0649 \u0627\u0644\u0631\u062d\u0628 \u0648\u0627\u0644\u0633\u0639\u0629\u060c \u062d\u062c\u0632\u0643\u0645 \u0645\u0624\u0643\u062f \u0648\u0646\u062a\u0637\u0644\u0639 \u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644\u0643\u0645 \u0628\u0625\u0630\u0646 \u0627\u0644\u0644\u0647. \u0646\u062d\u0646 \u0641\u064a \u062e\u062f\u0645\u062a\u0643\u0645 \u0641\u064a \u0623\u064a \u0648\u0642\u062a."
			: "You are very welcome. Your booking is confirmed, and we look forward to welcoming you. We are here anytime if you need anything else.";
	}
	return /^ar\b/i.test(languageCode)
		? "\u0639\u0644\u0649 \u0627\u0644\u0631\u062d\u0628 \u0648\u0627\u0644\u0633\u0639\u0629\u060c \u0633\u0639\u062f\u062a \u0628\u062e\u062f\u0645\u062a\u0643. \u0646\u062d\u0646 \u0641\u064a \u062e\u062f\u0645\u062a\u0643 \u0641\u064a \u0623\u064a \u0648\u0642\u062a\u060c \u0648\u0625\u0630\u0627 \u0623\u062d\u0628\u0628\u062a \u062a\u0643\u0645\u0644 \u0627\u0644\u062d\u062c\u0632 \u0644\u0627\u062d\u0642\u064b\u0627 \u0641\u0623\u0646\u0627 \u062a\u062d\u062a \u0623\u0645\u0631\u0643."
		: "It was my pleasure helping you. We are here anytime, and if you would like to continue later I will be happy to help.";
}

async function closeCaseWithOutro(io, sc = {}, known = {}, latestGuest = null, reply = "") {
	const hasConfirmedReservation =
		knownHasReservationConfirmation(known) || conversationHasAiAction(sc, "reservation_confirmed");
	const suppliedReply = String(reply || "").trim();
	const text =
		suppliedReply && !(hasConfirmedReservation && caseOutroImpliesPendingBooking(suppliedReply))
			? suppliedReply
			: buildCaseOutroText(sc, known, hasConfirmedReservation);
	const updatedAfterOutro = await sendAiMessage(io, sc, text, {
		latestGuest,
		known,
		clientAction: "case_outro",
		source: suppliedReply && text === suppliedReply ? "openai" : "",
	});
	const caseId = caseIdText(updatedAfterOutro || sc);
	if (!caseId || !updatedAfterOutro) return updatedAfterOutro;
	await sleep(AI_OUTRO_CLOSE_DELAY_MS);
	const latestCase = await getSupportCaseById(caseId).catch(() => null);
	if (!latestCase || latestCase.caseStatus !== "open" || latestCase.aiToRespond === false) {
		return latestCase || updatedAfterOutro;
	}
	const latestEntry = latestConversationEntry(latestCase);
	if (
		!isAiSupportEntry(latestEntry) ||
		latestEntry?.isSystem ||
		String(latestEntry?.clientAction || "") !== "case_outro"
	) {
		return latestCase;
	}
	const closed = await closeSupportCaseForAiIdle(caseId, {
		now: new Date(),
		reason: "ai_guest_finished",
		latestAiDate: latestEntry.date,
	}).catch((error) => {
		console.error("[aiagent] outro close failed:", error?.message || error);
		return null;
	});
	if (closed) {
		clearIdleCloseTimer(caseId);
		emitClosedCase(io, closed, "ai_guest_finished");
		return closed;
	}
	return latestCase;
}

function buildCancelReservationContactMessage(sc = {}, hotel = {}, known = {}, latestGuest = null) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const latestText = String(latestGuest?.message || "");
	const confirmation = cleanDisplayString(known.confirmation, 40);
	const policy = localizedCancellationPolicyLine(hotel, languageCode);
	if (ar) {
		const agentName = localizedAgentName(sc);
		const name = firstArabicNameForAddress(sc, known, latestText);
		const address = name ? ` \u064a\u0627 \u0623\u0633\u062a\u0627\u0630 ${name}` : "";
		const intro = `\u0623\u0643\u064a\u062f${address}\u060c \u0645\u0639\u0643 ${agentName}.`;
		const body = `\u0644\u0625\u0644\u063a\u0627\u0621 \u0627\u0644\u062d\u062c\u0632 \u0623\u0648 \u062a\u063a\u064a\u064a\u0631 \u062d\u0627\u0644\u062a\u0647 \u0625\u0644\u0649 \u0645\u0644\u063a\u064a\u060c \u0641\u0636\u0644\u0627 \u062a\u0648\u0627\u0635\u0644 \u0645\u0639\u0646\u0627 \u0648\u0627\u062a\u0633\u0627\u0628 \u0623\u0648 \u0627\u062a\u0635\u0627\u0644 \u0639\u0644\u0649 ${RESERVATION_CHANGE_CONTACT_PHONE}.`;
		const link = `\u0631\u0627\u0628\u0637 \u0627\u0644\u0648\u0627\u062a\u0633\u0627\u0628: ${RESERVATION_CHANGE_CONTACT_WHATSAPP}`;
		const ref = confirmation
			? `\u0627\u0630\u0643\u0631 \u0631\u0642\u0645 \u0627\u0644\u062d\u062c\u0632 ${confirmation} \u0641\u064a \u0627\u0644\u0631\u0633\u0627\u0644\u0629 \u0648\u0633\u064a\u062a\u0645 \u0645\u0631\u0627\u062c\u0639\u062a\u0647 \u0645\u0639\u0643.`
			: `\u0648\u0644\u0648 \u0645\u0639\u0643 \u0631\u0642\u0645 \u0627\u0644\u062d\u062c\u0632\u060c \u0627\u0630\u0643\u0631\u0647 \u0641\u064a \u0631\u0633\u0627\u0644\u0629 \u0627\u0644\u0648\u0627\u062a\u0633\u0627\u0628 \u062d\u062a\u0649 \u062a\u0643\u0648\u0646 \u0627\u0644\u0645\u0631\u0627\u062c\u0639\u0629 \u0623\u0633\u0631\u0639.`;
		return withWarmPrefix([intro, policy, body, link, ref].filter(Boolean).join("\n"), sc, known, latestText);
	}
	const guestName = guestDisplayName(sc);
	const intro = `Absolutely ${guestName}, this is ${localizedAgentName(sc)}.`;
	const body = `To cancel a reservation or change its status to canceled, please WhatsApp or call us at ${RESERVATION_CHANGE_CONTACT_PHONE}.`;
	const ref = confirmation
		? `Mention reservation ${confirmation} so the team can review it with you.`
		: `If you have the confirmation number, include it in the WhatsApp message so the team can review it faster.`;
	return withWarmPrefix(
		[intro, policy, body, `WhatsApp: ${RESERVATION_CHANGE_CONTACT_WHATSAPP}`, ref]
			.filter(Boolean)
			.join("\n"),
		sc,
		known,
		latestText
	);
}

async function handleCancelReservation(io, sc = {}, hotel = {}, known = {}, latestGuest = null) {
	const text = buildCancelReservationContactMessage(sc, hotel, known, latestGuest);
	return sendAiMessage(io, sc, text, {
		latestGuest,
		known,
		clientAction: "reservation_cancel_contact",
	});
}

function buildReservationUpdateFallbackMessage(sc = {}, known = {}, result = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const confirmation = result.reservation?.confirmation_number || known.confirmation || "";
	const checkinISO = result.checkinISO || known.checkinISO || "";
	const checkoutISO = result.checkoutISO || known.checkoutISO || "";
	if (result.ok) {
		const total =
			result.reservation?.total_amount || result.quote?.totals?.totalPriceWithCommission || 0;
		return ar
			? [
					`تم تحديث الحجز ${confirmation} بنجاح.`,
					`التواريخ الجديدة: ${formatDate(checkinISO, languageCode)} - ${formatDate(checkoutISO, languageCode)}.`,
					total ? `الإجمالي الجديد: ${formatMoney(total, "SAR", languageCode)}.` : "",
					`عاد الحجز إلى انتظار تأكيد الإدارة بعد فحص التوفر.`,
			  ]
					.filter(Boolean)
					.join("\n")
			: [
					`Reservation ${confirmation} has been updated successfully.`,
					`New dates: ${formatDate(checkinISO, languageCode)} - ${formatDate(checkoutISO, languageCode)}.`,
					total ? `New total: ${formatMoney(total, "SAR", languageCode)}.` : "",
					`The reservation is pending management confirmation again after the availability check.`,
			  ]
					.filter(Boolean)
					.join("\n");
	}
	if (result.code === "requote_required") {
		const total = Number(result.quote?.totals?.totalPriceWithCommission || 0) || 0;
		return ar
			? [
					`تغيّر السعر أو إعداد الغرفة أثناء الفحص النهائي، لذلك لم أعدّل الحجز ${confirmation || ""}.`,
					`التواريخ المطلوبة: ${formatDate(checkinISO, languageCode)} - ${formatDate(checkoutISO, languageCode)}.`,
					total ? `الإجمالي المحدّث: ${formatMoney(total, "SAR", languageCode)}.` : "",
					"إذا كان السعر والتفاصيل المحدّثة مناسبة، أكّد لي وسأعيد تنفيذ التعديل بالفحص النهائي.",
			  ]
					.filter(Boolean)
					.join("\n")
			: [
					`The price or room configuration changed during the final check, so reservation ${confirmation || ""} was not updated.`,
					`Requested dates: ${formatDate(checkinISO, languageCode)} - ${formatDate(checkoutISO, languageCode)}.`,
					total ? `Updated total: ${formatMoney(total, "SAR", languageCode)}.` : "",
					"If the refreshed price and details work for you, confirm and I will run the update again with a final check.",
			  ]
					.filter(Boolean)
					.join("\n");
	}
	if (result.code === "unavailable") {
		return ar
			? `عذرا، لا يظهر توفر مؤكد لهذه التواريخ للحجز ${confirmation}. أرسل تواريخ أخرى وسأفحصها لك.`
			: `I am sorry, reservation ${confirmation} cannot be moved to those dates because confirmed availability is not showing. Send another date range and I will check it.`;
	}
	return ar
		? `لم أتمكن من تحديث الحجز ${confirmation || ""} الآن. سأحتاج مراجعة البيانات أو تحويلها للاستقبال.`
		: `I could not update reservation ${confirmation || ""} right now. Please recheck the details, or I can pass it to reception.`;
}

function buildReservationUpdateIntro(sc = {}, known = {}, latestGuest = null) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const latestText = String(latestGuest?.message || "");
	const prefix = warmBookingPrefix(sc, known, latestText);
	if (ar) {
		const agentName = localizedAgentName(sc);
		const name = firstArabicNameForAddress(sc, known, latestText);
		const address = name ? ` \u064a\u0627 \u0623\u0633\u062a\u0627\u0630 ${name}` : "";
		const intro = `\u0623\u0647\u0644\u0627${address}\u060c \u0645\u0639\u0643 ${agentName}. \u0648\u0644\u0627 \u064a\u0647\u0645\u0643\u060c \u0631\u0627\u062c\u0639\u062a \u0627\u0644\u062a\u0648\u0641\u0631 \u0644\u0644\u062a\u0648\u0627\u0631\u064a\u062e \u0627\u0644\u062c\u062f\u064a\u062f\u0629.`;
		return prefix ? `${intro}\n${prefix}` : intro;
	}
	const guestName = guestDisplayName(sc);
	const intro = `Hi ${guestName}, this is ${localizedAgentName(sc)}. No problem, I checked availability for the new dates.`;
	return prefix ? `${intro}\n${prefix}` : intro;
}

function buildFriendlyReservationUpdateMessage(sc = {}, known = {}, result = {}, latestGuest = null) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const intro = buildReservationUpdateIntro(sc, known, latestGuest);
	const confirmation = result.reservation?.confirmation_number || known.confirmation || "";
	const checkinISO = result.checkinISO || known.checkinISO || "";
	const checkoutISO = result.checkoutISO || known.checkoutISO || "";
	if (result.code === "requote_required") {
		return [intro, buildReservationUpdateFallbackMessage(sc, known, result)]
			.filter(Boolean)
			.join("\n");
	}
	if (result.ok) {
		const total =
			result.reservation?.total_amount || result.quote?.totals?.totalPriceWithCommission || 0;
		return ar
			? [
					intro,
					`\u062a\u0645 \u062a\u062d\u062f\u064a\u062b \u0627\u0644\u062d\u062c\u0632 ${confirmation} \u0628\u0646\u062c\u0627\u062d.`,
					`\u0627\u0644\u062a\u0648\u0627\u0631\u064a\u062e \u0627\u0644\u062c\u062f\u064a\u062f\u0629: ${formatDate(checkinISO, languageCode)} - ${formatDate(checkoutISO, languageCode)}.`,
					total ? `\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a \u0627\u0644\u062c\u062f\u064a\u062f: ${formatMoney(total, "SAR", languageCode)}.` : "",
					`\u0639\u0627\u062f \u0627\u0644\u062d\u062c\u0632 \u0625\u0644\u0649 \u0627\u0646\u062a\u0638\u0627\u0631 \u062a\u0623\u0643\u064a\u062f \u0627\u0644\u0625\u062f\u0627\u0631\u0629 \u0628\u0639\u062f \u0641\u062d\u0635 \u0627\u0644\u062a\u0648\u0641\u0631.`,
			  ]
					.filter(Boolean)
					.join("\n")
			: [
					intro,
					`Reservation ${confirmation} has been updated successfully.`,
					`New dates: ${formatDate(checkinISO, languageCode)} - ${formatDate(checkoutISO, languageCode)}.`,
					total ? `New total: ${formatMoney(total, "SAR", languageCode)}.` : "",
					`The reservation is pending management confirmation again after the availability check.`,
			  ]
					.filter(Boolean)
					.join("\n");
	}
	if (result.code === "unavailable") {
		return ar
			? `${intro}\n\u0623\u0639\u062a\u0630\u0631\u060c \u0644\u0627 \u064a\u0638\u0647\u0631 \u062a\u0648\u0641\u0631 \u0645\u0624\u0643\u062f \u0644\u0647\u0630\u0647 \u0627\u0644\u062a\u0648\u0627\u0631\u064a\u062e \u0644\u0644\u062d\u062c\u0632 ${confirmation}. \u0623\u0631\u0633\u0644 \u0644\u064a \u062a\u0648\u0627\u0631\u064a\u062e \u0623\u062e\u0631\u0649 \u0648\u0623\u0631\u0627\u062c\u0639\u0647\u0627 \u0644\u0643.`
			: `${intro}\nI am sorry, reservation ${confirmation} cannot be moved to those dates because confirmed availability is not showing. Send another date range and I will check it.`;
	}
	return ar
		? `${intro}\n\u0644\u0645 \u0623\u062a\u0645\u0643\u0646 \u0645\u0646 \u062a\u062d\u062f\u064a\u062b \u0627\u0644\u062d\u062c\u0632 ${confirmation || ""} \u0627\u0644\u0622\u0646. \u0633\u0623\u062d\u062a\u0627\u062c \u0645\u0631\u0627\u062c\u0639\u0629 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0623\u0648 \u062a\u062d\u0648\u064a\u0644\u0647\u0627 \u0644\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644.`
		: `${intro}\nI could not update reservation ${confirmation || ""} right now. Please recheck the details, or I can pass it to reception.`;
}

async function handleUpdateReservation(io, sc = {}, hotel = {}, known = {}, latestGuest = null) {
	if (!known.confirmation || !known.checkinISO || !known.checkoutISO) {
		const decision = await askOpenAI({
			sc,
			hotel,
			known,
			latestGuest,
			toolResult: { tool: "update_reservation", ok: false, code: "missing_required_details" },
		});
		return sendAiMessage(io, sc, decision.reply, { latestGuest, known });
	}
	const result = await updateReservationDatesForCase({
		caseId: caseIdText(sc),
		hotel,
		confirmation: known.confirmation,
		checkinISO: known.checkinISO,
		checkoutISO: known.checkoutISO,
		roomTypeOverride: known.roomTypeKey || "",
		io,
	});
	if (result.ok) {
		return sendAiMessage(io, sc, buildFriendlyReservationUpdateMessage(sc, known, result, latestGuest), {
			latestGuest,
			known,
			clientAction: "reservation_update_success",
		});
	}
	const decision = await askOpenAI({
		sc,
		hotel,
		known,
		latestGuest,
		toolResult: {
			tool: "update_reservation",
			...result,
			instruction: result.requiresRequote
				? "The reservation was not updated. Present the refreshed exact dates/room/price from the tool result, clearly say the PMS changed during final verification, and ask the guest to confirm the refreshed update. Never claim the update succeeded."
				: "Explain the update result accurately and do not claim success when ok=false.",
		},
	}).catch((error) => {
		console.warn("[aiagent] update reservation reply fallback:", error?.message || error);
		return { reply: buildFriendlyReservationUpdateMessage(sc, known, result, latestGuest) };
	});
	return sendAiMessage(io, sc, decision.reply, {
		latestGuest,
		known,
		clientAction: result.requiresRequote
			? "reservation_update_requote_required"
			: "reservation_update_failed",
	});
}

async function waitForTypingMinimum(typingStartedAt = 0) {
	await sleep(Math.max(0, AI_TYPING_MIN_VISIBLE_MS - (now() - Number(typingStartedAt || 0))));
}

function compactQuoteToolResult(result = {}, known = {}) {
	const quote = asObject(result.quote);
	const partialQuote = asObject(result.partialQuote);
	const resultSelections = normalizeRoomSelections(result.roomSelections);
	const unavailableSelections = Array.isArray(result.unavailableSelections)
		? result.unavailableSelections
				.map((item) => ({
					roomTypeKey: item.roomTypeKey || "",
					count: normalizeRoomCount(item.count, 1),
					roomLabel:
						item.roomLabel || roomTypeLabel(item.roomTypeKey || "", known.languageCode),
					code: String(item.code || ""),
					firstUnavailableDate: validISODate(item.firstUnavailableDate),
				}))
				.filter((item) => item.roomTypeKey)
		: [];
	const total = Number(quote.total || quote.totals?.totalPriceWithCommission || 0) || 0;
	const averagePerNight = Number(quote.averagePerNight || 0) || 0;
	const currency = quote.currency || result.currency || known.currency || "SAR";
	const roomLines = (Array.isArray(quote.roomLines) ? quote.roomLines : [])
		.slice(0, 12)
		.map((line) => ({
			roomTypeKey: cleanString(line.roomTypeKey, 40),
			roomLabel: cleanDisplayString(line.roomLabel, 160),
			count: normalizeRoomCount(line.count, 1),
			capacityGuests: Number(line.capacityGuests || 0) || 0,
			perRoomAverageNightly: Number(line.perRoomAverageNightly || 0) || 0,
			perRoomStayTotal: Number(line.perRoomStayTotal || 0) || 0,
			lineTotal: Number(line.lineTotal || 0) || 0,
			perNightPerRoom: Array.isArray(line.perNightPerRoom)
				? line.perNightPerRoom.slice(0, 20).map((value) => Number(value || 0))
				: [],
		}));
	const discount = quoteDiscountDisplay(
		{ total, averagePerNight, currency },
		known.languageCode || "en"
	);
	return {
		tool: "get_quote",
		ok: result.ok !== false,
		available: Boolean(result.available && quoteHasContent(quote)),
		code: String(result.code || ""),
		checkinISO: quote.checkinISO || result.checkinISO || known.checkinISO || "",
		checkoutISO: quote.checkoutISO || result.checkoutISO || known.checkoutISO || "",
		nights:
			Number(quote.nights || 0) ||
			nightsBetween(
				quote.checkinISO || result.checkinISO || known.checkinISO,
				quote.checkoutISO || result.checkoutISO || known.checkoutISO
			),
		roomTypeKey: quote.roomTypeKey || result.roomTypeKey || known.roomTypeKey || "",
		roomLabel:
			quote.roomLabel ||
			result.roomLabel ||
			roomTypeLabel(result.roomTypeKey || known.roomTypeKey, known.languageCode),
		totalRooms:
			Number(quote.totalRooms || quote.roomCount || 0) ||
			normalizeRoomCount(known.rooms, 1),
		roomSelections:
			Array.isArray(quote.roomSelections) && quote.roomSelections.length
				? normalizeRoomSelections(quote.roomSelections)
				: resultSelections.length
				? resultSelections
				: normalizeRoomSelections(known.roomSelections),
		roomPlanAdjusted: Boolean(quote.roomPlanAdjusted),
		singleRoomMappedToDouble: Boolean(quote.singleRoomMappedToDouble),
		roomPlanRequiresGuestConfirmation: Boolean(quote.roomPlanRequiresGuestConfirmation),
		requestedRoomSelections: normalizeRoomSelections(quote.requestedRoomSelections),
		recommendedRoomSelections: normalizeRoomSelections(
			quote.recommendedRoomSelections || quote.roomSelections
		),
		roomLines,
		unavailableSelections,
		firstUnavailableDate: validISODate(result.firstUnavailableDate),
		minCheckinISO: validISODate(result.minCheckinISO),
		total,
		averagePerNight,
		currency,
		discount,
		perNight: Array.isArray(quote.perNight) ? quote.perNight.slice(0, 20) : [],
		partialQuote: Object.keys(partialQuote).length
			? {
					rooms: Number(partialQuote.rooms || 0) || 0,
					nights: Number(partialQuote.nights || 0) || 0,
					total: Number(partialQuote.total || 0) || 0,
					currency: partialQuote.currency || result.currency || "SAR",
			  }
			: null,
	};
}

function quoteReplyFormattingInstruction() {
	return [
		"Write the quote in the guest language with clean formatting.",
		"Use separate short lines or simple bullets for room(s), dates, nights, total, and the next question.",
		"Do not compress the quote into one paragraph.",
		"Do not add reference numbers, date references, IDs, or unexplained numeric lines.",
		"Do not say the booking or reservation is confirmed, created, completed, finalized, or booked from a quote.",
		"Do not call an availability quote a final review, official review, final booking summary, or say you will raise/submit the booking for review before required guest details are collected.",
		"Always show the exact toolResult.checkinISO and toolResult.checkoutISO values in the quote date line, even if you also add a localized date phrase.",
		"For available quotes with toolResult.discount, show price lines using toolResult.discount.displayAveragePerNightLine and toolResult.discount.displayTotalLine exactly. Preserve the <s class=\"message-price-old\"> original price and <strong class=\"message-price-new\"> discounted price on the same row.",
		"If the guest asks why there is a discount, explain briefly that direct booking through reception has no middleman commission.",
		"If available, ask whether the guest wants to continue; do not ask for name, phone, nationality, or email before this quote has been shown.",
		"Use toolResult.totalRooms and toolResult.roomSelections as the authoritative room count. Do not copy raw guest shorthand like 03 rooms if the toolResult says one room.",
		"For a mixed-room or multi-configuration quote, use toolResult.roomLines to show each exact room/configuration count, its per-room average nightly price, its per-room stay total, and its line total before the grand total. Do not apply one room's nightly price to another room type.",
		"If toolResult.roomPlanAdjusted is true, say the exact original mix cannot be offered as requested, list only the requested mix and the exact recommended mix, and ask the guest to confirm it. Never disclose the hotel's configured, remaining, total, or available stock.",
		"If toolResult.singleRoomMappedToDouble is true, explain naturally that a double room can be reserved for one guest/single occupancy; do not claim a separate single room exists.",
		"If unavailable, clearly say the requested stay/room count is not available or there are not enough rooms, mention every requested room selection from toolResult.roomSelections and any firstUnavailableDate, and offer alternatives, different dates, or room-count adjustment; do not collapse a mixed-room request into one room type, and do not show total/price as 0.",
		"If toolResult.code is same_day_checkin_not_supported, explicitly say the requested check-in is unavailable/not bookable through chat. toolResult.minCheckinISO is only the earliest date the chat can start checking; do not invite the guest to book/search from that date as the solution, and do not call it available or recommended unless an alternatives/availability tool result proves availability. Offer the Alternative dates button or changing details.",
	].join(" ");
}

function splitStayQuoteInputsKnown(known = {}) {
	return Boolean(
		normalizeSplitStayPeriods(known.splitStayPeriods).length >= 2 &&
			(known.roomTypeKey || normalizeRoomSelections(known.roomSelections).length)
	);
}

function splitStayQuoteMatchesKnown(known = {}) {
	const periods = normalizeSplitStayPeriods(known.splitStayPeriods);
	if (periods.length < 2 || known.splitStayQuoteAvailable !== true) return false;
	const total =
		Number(known.splitStayTotal || 0) ||
		periods.reduce((sum, period) => sum + (Number(period.total || 0) || 0), 0);
	if (!Number.isFinite(total) || total <= 0) {
		return false;
	}
	return periods.every(
		(period) =>
			validISODate(period.checkinISO) &&
			validISODate(period.checkoutISO) &&
			period.checkoutISO > period.checkinISO &&
			Number(period.nights || 0) > 0 &&
			Number(period.total || 0) > 0
	);
}

function splitStayReservationMissing(known = {}) {
	const facts = asObject(known);
	const missing = [];
	if (normalizeSplitStayPeriods(facts.splitStayPeriods).length < 2) {
		missing.push("checkinISO", "checkoutISO");
	}
	if (!facts.roomTypeKey && !normalizeRoomSelections(facts.roomSelections).length) {
		missing.push("roomTypeKey");
	}
	if (!splitStayQuoteMatchesKnown(facts)) missing.push("quote");
	if (
		!cleanString(facts.fullName) ||
		!isPlausibleBookingName(facts.fullName) ||
		facts.fullNameNeedsConfirmation
	) {
		missing.push("fullName");
	}
	if (!cleanPhone(facts.phone) || facts.phoneNeedsConfirmation) missing.push("phone");
	if (!cleanString(facts.nationality) || facts.nationalityNeedsConfirmation) {
		missing.push("nationality");
	}
	if (!Number.isFinite(Number(facts.adults)) || Number(facts.adults) < 1) {
		missing.push("adults");
	}
	return missing;
}

async function handleBrainSplitStayQuote(
	io,
	sc = {},
	hotel = {},
	known = {},
	latestGuest = null,
	typingStartedAt = 0
) {
	const caseId = caseIdText(sc);
	const periods = normalizeSplitStayPeriods(known.splitStayPeriods);
	if (!periods.length) return null;
	if (!splitStayQuoteInputsKnown(known)) {
		await saveKnownFacts(caseId, known);
		return sendBrainToolReplyFromOpenAI({
			io,
			sc,
			hotel,
			known,
			latestGuest,
			toolResult: {
				tool: "get_quote",
				quoteMode: "split_stay",
				ok: false,
				code: "missing_split_stay_inputs",
				missing: [
					...(!known.roomTypeKey && !normalizeRoomSelections(known.roomSelections).length
						? ["roomTypeKey"]
						: []),
				],
				splitStayPeriods: periods,
				instruction:
					"The guest has multiple separate stay periods for the same hotel. Do not merge the date ranges. Ask only for the missing room selection or guest detail needed to check the quote.",
			},
			clientAction: "required_stay_details_needed",
			typingStartedAt,
			preserveFallbackNumbers: false,
		});
	}
	const quoteResults = [];
	for (const period of periods) {
		const quoteKnown = {
			...known,
			checkinISO: period.checkinISO,
			checkoutISO: period.checkoutISO,
			quote: null,
		};
		delete quoteKnown.splitStayPeriods;
		delete quoteKnown.splitStayTotal;
		delete quoteKnown.splitStayQuoteAvailable;
		delete quoteKnown.splitStayQuotedAt;
		const result = await quoteTool(sc, quoteKnown).catch((error) => ({
			ok: false,
			available: false,
			code: "quote_failed",
			message: cleanDisplayString(error?.message || String(error), 260),
			checkinISO: period.checkinISO,
			checkoutISO: period.checkoutISO,
		}));
		quoteResults.push({
			period,
			result,
			summary: compactQuoteToolResult(result, {
				...quoteKnown,
				quote: asObject(result.quote),
			}),
		});
	}
	const allAvailable = quoteResults.every((item) => item.result.available && item.result.quote);
	const quotedPeriods = quoteResults.map((item) => {
		const quote = asObject(item.result.quote);
		return {
			checkinISO: item.period.checkinISO,
			checkoutISO: item.period.checkoutISO,
			nights:
				Number(quote.nights || 0) ||
				nightsBetween(item.period.checkinISO, item.period.checkoutISO),
			total: Number(quote.total || quote.totals?.totalPriceWithCommission || 0) || 0,
			currency: quote.currency || item.result.currency || "SAR",
			selectionKey:
				cleanString(quote.selectionKey, 500) || roomSelectionKey(quote.roomSelections),
			roomSelections: normalizeRoomSelections(quote.roomSelections),
			quoteFingerprint: splitStayPeriodQuoteFingerprint(quote, item.period),
		};
	});
	const total = quotedPeriods.reduce((sum, period) => sum + Number(period.total || 0), 0);
	const currency =
		quotedPeriods.find((period) => period.currency)?.currency ||
		quoteResults.find((item) => item.summary.currency)?.summary.currency ||
		"SAR";
	const nextKnown = {
		...known,
		splitStayPeriods: quotedPeriods,
		splitStayTotal: total,
		splitStayQuoteAvailable: allAvailable,
		splitStayQuotedAt: new Date().toISOString(),
	};
	delete nextKnown.checkinISO;
	delete nextKnown.checkoutISO;
	delete nextKnown.quote;
	await saveKnownFacts(caseId, nextKnown);
	const toolResult = splitStayQuoteToolResultFromResults({
		known: nextKnown,
		quoteResults,
		quotedPeriods,
		allAvailable,
		total,
		currency,
		instruction:
			"This is one customer request with multiple separate stay periods at the same hotel. Do not merge the gaps into one continuous reservation. Quote each available period and the combined total from toolResult only. If all periods are available, ask whether to continue and mention that the next step is a review before creating separate reservations, one per period. Use neutral, natural wording; do not use combined gender slash forms such as رغبتِ/رغبتَ. If any period is unavailable, explain which period is unavailable and offer to check alternatives. Do not say the reservation is confirmed or created.",
	});
	if (allAvailable) {
		const reply = buildSplitStayQuoteMessage(sc, nextKnown, hotel, toolResult);
		await waitForTypingMinimum(typingStartedAt);
		return sendAiMessage(io, sc, reply, {
			latestGuest,
			known: nextKnown,
			clientAction: "split_stay_quote_ready",
			quickReplies: splitStayQuickReplies(activeLanguageCode(sc, nextKnown)),
		});
	}
	return sendBrainToolReplyFromOpenAI({
		io,
		sc,
		hotel,
		known: nextKnown,
		latestGuest,
		toolResult: {
			tool: "get_quote",
			quoteMode: "split_stay",
			ok: quoteResults.every((item) => item.result.ok !== false),
			available: allAvailable,
			code: allAvailable ? "split_stay_quote_ready" : "split_stay_quote_unavailable",
			roomTypeKey: nextKnown.roomTypeKey || "",
			rooms: normalizeRoomCount(nextKnown.rooms, 1),
			roomSelections: normalizeRoomSelections(nextKnown.roomSelections),
			splitStayPeriods: quotedPeriods.map((period, index) => ({
				...period,
				available: Boolean(quoteResults[index]?.result?.available),
				code: quoteResults[index]?.result?.code || "",
				roomLabel: quoteResults[index]?.summary?.roomLabel || "",
				perNight: quoteResults[index]?.summary?.perNight || [],
			})),
			total,
			currency,
			instruction:
				"This is one customer request with multiple separate stay periods at the same hotel. Do not merge the gaps into one continuous reservation. Quote each available period and the combined total from toolResult only. If all periods are available, ask whether to continue and mention that the next step is a review before creating separate reservations, one per period. Use neutral, natural wording; do not use combined gender slash forms such as رغبتِ/رغبتَ. If any period is unavailable, explain which period is unavailable and offer to check alternatives. Do not say the reservation is confirmed or created.",
		},
		clientAction: allAvailable ? "split_stay_quote_ready" : "split_stay_quote_unavailable",
		quickReplies: allAvailable
			? splitStayQuickReplies(activeLanguageCode(sc, nextKnown))
			: quoteUnavailableQuickRepliesForCase(sc, nextKnown),
		typingStartedAt,
		preserveFallbackNumbers: false,
	});
}

function splitStayReservationKey(caseId = "", index = 0) {
	const key = cleanString(caseId, 80);
	return key ? `${key}:split:${Number(index || 0) + 1}` : "";
}

function splitStayRoomSummary(known = {}, languageCode = "en") {
	const selections = normalizeRoomSelections(known.roomSelections);
	if (selections.length) {
		return selections
			.map(
				(selection) =>
					`${formatNumber(selection.count || 1, languageCode)} x ${roomTypeLabel(
						selection.roomTypeKey,
						languageCode
					)}`
			)
			.join(", ");
	}
	return `${formatNumber(normalizeRoomCount(known.rooms, 1), languageCode)} x ${roomTypeLabel(
		known.roomTypeKey,
		languageCode
	)}`;
}

function compactSplitStayReviewForBrain(known = {}, hotel = {}, sc = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const periods = normalizeSplitStayPeriods(known.splitStayPeriods);
	const periodTotal = periods.reduce((sum, period) => sum + Number(period.total || 0), 0);
	const total =
		periods.every((period) => Number(period.total || 0) > 0) && periodTotal > 0
			? periodTotal
			: Number(known.splitStayTotal || 0) || periodTotal;
	const currency = periods.find((period) => period.currency)?.currency || "SAR";
	const discount = quoteDiscountDisplay({ total, averagePerNight: 0, currency }, languageCode);
	return {
		hotelName: hotel?.hotelName || hotel?.hotelName_OtherLanguage || "",
		mode: "separate_reservations",
		reservationCount: periods.length,
		roomTypeKey: known.roomTypeKey || "",
		roomSummary: splitStayRoomSummary(known, languageCode),
		roomSelections: normalizeRoomSelections(known.roomSelections),
		rooms: normalizeRoomCount(known.rooms, 1),
		adults: Number(known.adults || 0) || 0,
		children: Number(known.children || 0) || 0,
		fullName: known.fullName || "",
		phone: known.phone || "",
		nationality: known.nationality || "",
		email: cleanEmail(known.email),
		reservations: periods.map((period, index) => ({
			number: index + 1,
			checkinISO: period.checkinISO,
			checkoutISO: period.checkoutISO,
			nights: Number(period.nights || nightsBetween(period.checkinISO, period.checkoutISO)),
			total: Number(period.total || 0) || 0,
			currency: period.currency || "SAR",
			discount: quoteDiscountDisplay(
				{
					total: Number(period.total || 0) || 0,
					averagePerNight: 0,
					currency: period.currency || currency,
				},
				languageCode
			),
		})),
		total,
		currency,
		discount,
	};
}

function buildSplitStayReviewMessage(sc = {}, known = {}, hotel = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const periods = normalizeSplitStayPeriods(known.splitStayPeriods);
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "الفندق"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "the hotel";
	const roomSummary = splitStayRoomSummary(known, languageCode);
	const periodTotal = periods.reduce((sum, period) => sum + Number(period.total || 0), 0);
	const total =
		periods.every((period) => Number(period.total || 0) > 0) && periodTotal > 0
			? periodTotal
			: Number(known.splitStayTotal || 0) || periodTotal;
	const currency = periods.find((period) => period.currency)?.currency || "SAR";
	if (ar) {
		return [
			`${arabicReviewAddress(sc, known)}، هذه مراجعة نهائية قبل إنشاء الحجز:`,
			`سيتم إنشاء ${formatNumber(periods.length, languageCode)} حجوزات منفصلة، حجز مستقل لكل فترة، حتى لا ندمج الفاصل بين الفترات.`,
			`الفندق: ${hotelName}`,
			`الغرفة: ${roomSummary}`,
			`الضيوف: ${arabicGuestCountText(known.adults || 1, known.children || 0, languageCode)}`,
			`اسم الضيف: ${known.fullName || guestDisplayName(sc)}`,
			`الجنسية: ${known.nationality || "غير مضافة"}`,
			`الهاتف: ${known.phone || "غير مضاف"}`,
			...periods.map((period, index) => {
				const nights =
					Number(period.nights || 0) ||
					nightsBetween(period.checkinISO, period.checkoutISO);
				return `الحجز ${formatNumber(index + 1, languageCode)}: من ${formatDate(
					period.checkinISO,
					languageCode
				)} إلى ${formatDate(period.checkoutISO, languageCode)}، ${formatNumber(
					nights,
					languageCode
				)} ليال، الإجمالي ${formatMoney(period.total || 0, period.currency || currency, languageCode)}`;
			}),
			`الإجمالي لكل الحجوزات: ${formatMoney(total, currency, languageCode)}`,
			`إذا كل شيء صحيح، اختر "إتمام الحجز". وإذا هناك تعديل، اختر "هناك شيء غير صحيح".`,
		].join("\n");
	}
	return [
		`${guestDisplayName(sc)}, here is the final review before I create the booking:`,
		`I will create ${periods.length} separate reservations, one for each stay period, so the gap is not merged into one reservation.`,
		`Hotel: ${hotelName}`,
		`Room: ${roomSummary}`,
		`Guests: ${englishGuestCountText(known.adults || 1, known.children || 0)}`,
		`Guest name: ${known.fullName || guestDisplayName(sc)}`,
		`Nationality: ${known.nationality || "Not added"}`,
		`Phone: ${known.phone || "Not added"}`,
		...periods.map((period, index) => {
			const nights =
				Number(period.nights || 0) || nightsBetween(period.checkinISO, period.checkoutISO);
			return `Reservation ${index + 1}: ${formatDate(
				period.checkinISO,
				languageCode
			)} to ${formatDate(period.checkoutISO, languageCode)}, ${nights} nights, total ${formatMoney(
				period.total || 0,
				period.currency || currency,
				languageCode
			)}`;
		}),
		`Total for all reservations: ${formatMoney(total, currency, languageCode)}`,
		`If everything is correct, choose "Complete booking". If something needs fixing, choose "Something is wrong".`,
	].join("\n");
}

function buildSplitStayReviewMessage(sc = {}, known = {}, hotel = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const periods = normalizeSplitStayPeriods(known.splitStayPeriods);
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "\u0627\u0644\u0641\u0646\u062f\u0642"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "the hotel";
	const roomSummary = splitStayRoomSummary(known, languageCode);
	const periodTotal = periods.reduce((sum, period) => sum + Number(period.total || 0), 0);
	const total =
		periods.every((period) => Number(period.total || 0) > 0) && periodTotal > 0
			? periodTotal
			: Number(known.splitStayTotal || 0) || periodTotal;
	const currency = periods.find((period) => period.currency)?.currency || "SAR";
	if (ar) {
		const reservationCountLine =
			periods.length === 2
				? "\u0633\u064a\u062a\u0645 \u0625\u0646\u0634\u0627\u0621 \u062d\u062c\u0632\u064a\u0646 \u0645\u0646\u0641\u0635\u0644\u064a\u0646\u060c \u062d\u062c\u0632 \u0645\u0633\u062a\u0642\u0644 \u0644\u0643\u0644 \u0641\u062a\u0631\u0629\u060c \u062d\u062a\u0649 \u0644\u0627 \u0646\u062f\u0645\u062c \u0627\u0644\u0641\u0627\u0635\u0644 \u0628\u064a\u0646 \u0627\u0644\u0641\u062a\u0631\u0627\u062a."
				: `\u0633\u064a\u062a\u0645 \u0625\u0646\u0634\u0627\u0621 ${formatNumber(periods.length, languageCode)} \u062d\u062c\u0648\u0632\u0627\u062a \u0645\u0646\u0641\u0635\u0644\u0629\u060c \u062d\u062c\u0632 \u0645\u0633\u062a\u0642\u0644 \u0644\u0643\u0644 \u0641\u062a\u0631\u0629\u060c \u062d\u062a\u0649 \u0644\u0627 \u0646\u062f\u0645\u062c \u0627\u0644\u0641\u0627\u0635\u0644 \u0628\u064a\u0646 \u0627\u0644\u0641\u062a\u0631\u0627\u062a.`;
		return [
			`${arabicReviewAddress(sc, known)}\u060c \u0647\u0630\u0647 \u0645\u0631\u0627\u062c\u0639\u0629 \u0646\u0647\u0627\u0626\u064a\u0629 \u0642\u0628\u0644 \u0625\u0646\u0634\u0627\u0621 \u0627\u0644\u062d\u062c\u0632:`,
			reservationCountLine,
			`\u0627\u0644\u0641\u0646\u062f\u0642: ${hotelName}`,
			`\u0627\u0644\u063a\u0631\u0641\u0629: ${roomSummary}`,
			`\u0627\u0644\u0636\u064a\u0648\u0641: ${arabicGuestCountText(known.adults || 1, known.children || 0, languageCode)}`,
			`\u0627\u0633\u0645 \u0627\u0644\u0636\u064a\u0641: ${known.fullName || guestDisplayName(sc)}`,
			`\u0627\u0644\u062c\u0646\u0633\u064a\u0629: ${known.nationality || "\u063a\u064a\u0631 \u0645\u0636\u0627\u0641\u0629"}`,
			`\u0627\u0644\u0647\u0627\u062a\u0641: ${known.phone || "\u063a\u064a\u0631 \u0645\u0636\u0627\u0641"}`,
			...periods.map((period, index) => {
				const nights =
					Number(period.nights || 0) ||
					nightsBetween(period.checkinISO, period.checkoutISO);
				const periodPriceLine = quoteDiscountDisplay(
					{
						total: Number(period.total || 0) || 0,
						averagePerNight: 0,
						currency: period.currency || currency,
					},
					languageCode
				)?.displayTotalLine || `\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a: ${formatMoney(
					period.total || 0,
					period.currency || currency,
					languageCode
				)}`;
				return `\u0627\u0644\u062d\u062c\u0632 ${formatNumber(index + 1, languageCode)}: \u0645\u0646 ${formatDate(
					period.checkinISO,
					languageCode
				)} \u0625\u0644\u0649 ${formatDate(period.checkoutISO, languageCode)}\u060c ${formatNumber(
					nights,
					languageCode
				)} \u0644\u064a\u0627\u0644\u060c ${periodPriceLine}`;
			}),
			quoteDiscountDisplay({ total, averagePerNight: 0, currency }, languageCode)
				?.displayTotalLine?.replace(
					/^\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a:/u,
					"\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a \u0644\u0643\u0644 \u0627\u0644\u062d\u062c\u0648\u0632\u0627\u062a:"
				) ||
				`\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a \u0644\u0643\u0644 \u0627\u0644\u062d\u062c\u0648\u0632\u0627\u062a: ${formatMoney(total, currency, languageCode)}`,
			`\u0625\u0630\u0627 \u0643\u0644 \u0634\u064a\u0621 \u0635\u062d\u064a\u062d\u060c \u0627\u062e\u062a\u0631 "\u0625\u062a\u0645\u0627\u0645 \u0627\u0644\u062d\u062c\u0632". \u0648\u0625\u0630\u0627 \u0647\u0646\u0627\u0643 \u062a\u0639\u062f\u064a\u0644\u060c \u0627\u062e\u062a\u0631 "\u0647\u0646\u0627\u0643 \u0634\u064a\u0621 \u063a\u064a\u0631 \u0635\u062d\u064a\u062d".`,
		].join("\n");
	}
	return [
		`${guestDisplayName(sc)}, here is the final review before I create the booking:`,
		`I will create ${periods.length} separate reservations, one for each stay period, so the gap is not merged into one reservation.`,
		`Hotel: ${hotelName}`,
		`Room: ${roomSummary}`,
		`Guests: ${englishGuestCountText(known.adults || 1, known.children || 0)}`,
		`Guest name: ${known.fullName || guestDisplayName(sc)}`,
		`Nationality: ${known.nationality || "Not added"}`,
		`Phone: ${known.phone || "Not added"}`,
		...periods.map((period, index) => {
			const nights =
				Number(period.nights || 0) || nightsBetween(period.checkinISO, period.checkoutISO);
			return `Reservation ${index + 1}: ${formatDate(
				period.checkinISO,
				languageCode
			)} to ${formatDate(period.checkoutISO, languageCode)}, ${nights} nights, total ${formatMoney(
				period.total || 0,
				period.currency || currency,
				languageCode
			)}`;
		}),
		`Total for all reservations: ${formatMoney(total, currency, languageCode)}`,
		`If everything is correct, choose "Complete booking". If something needs fixing, choose "Something is wrong".`,
	].join("\n");
}

function buildSplitStayConfirmationMessage(sc = {}, known = {}, hotel = {}, reservations = []) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const hotelName = ar
		? hotel.hotelName_OtherLanguage || hotel.hotelName || "الفندق"
		: hotel.hotelName || hotel.hotelName_OtherLanguage || "the hotel";
	const rows = reservations.map((reservation, index) => {
		const links = reservationPublicLinks(reservation);
		const total = reservation.total_amount || 0;
		const checkinISO = validISODate(reservation.checkin_date);
		const checkoutISO = validISODate(reservation.checkout_date);
		if (ar) {
			return [
				`الحجز ${formatNumber(index + 1, languageCode)}:`,
				`رقم التأكيد: ${reservation.confirmation_number || ""}`,
				`الفترة: ${formatDate(checkinISO, languageCode)} إلى ${formatDate(
					checkoutISO,
					languageCode
				)}`,
				`الإجمالي: ${formatMoney(total, reservation.currency || "SAR", languageCode)}`,
				links.reservationConfirmation ? `تفاصيل الحجز: ${links.reservationConfirmation}` : "",
				links.payment ? `رابط الدفع: ${links.payment}` : "",
			]
				.filter(Boolean)
				.join("\n");
		}
		return [
			`Reservation ${index + 1}:`,
			`Confirmation number: ${reservation.confirmation_number || ""}`,
			`Dates: ${formatDate(checkinISO, languageCode)} to ${formatDate(
				checkoutISO,
				languageCode
			)}`,
			`Total: ${formatMoney(total, reservation.currency || "SAR", languageCode)}`,
			links.reservationConfirmation ? `Details: ${links.reservationConfirmation}` : "",
			links.payment ? `Payment link: ${links.payment}` : "",
		]
			.filter(Boolean)
			.join("\n");
	});
	if (ar) {
		return [
			`تم إنشاء الحجوزات بنجاح كحجوزات منفصلة في ${hotelName}.`,
			...rows,
			`هل أقدر أساعدك بأي شيء آخر؟`,
		].join("\n\n");
	}
	return [
		`The reservations have been created successfully as separate bookings at ${hotelName}.`,
		...rows,
		`Can I help you with anything else?`,
	].join("\n\n");
}

function buildSplitStayPartialFailureMessage(
	sc = {},
	known = {},
	hotel = {},
	reservations = [],
	error = null
) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const created = reservations.map((reservation) => reservation.confirmation_number).filter(Boolean);
	if (ar) {
		return [
			created.length
				? `تم إنشاء بعض الحجوزات بالفعل: ${created.join(", ")}.`
				: `${arabicReviewAddress(sc, known)}، لم أتمكن من إنشاء الحجوزات الآن بشكل آمن.`,
			`سأحولها للفريق لمراجعة الفترات المنفصلة بدون دمجها في حجز واحد.`,
		].join("\n");
	}
	return [
		created.length
			? `Some reservations were already created: ${created.join(", ")}.`
			: `${guestDisplayName(sc)}, I could not safely create the reservations right now.`,
		`I will pass this to the team so the separate stay periods are reviewed without merging them into one booking.`,
	].join("\n");
}

function splitStayQuoteTotalsMatchKnown(known = {}, quotedPeriods = [], total = 0) {
	const currentPeriods = normalizeSplitStayPeriods(known.splitStayPeriods);
	const nextPeriods = normalizeSplitStayPeriods(quotedPeriods);
	if (currentPeriods.length < 2 || currentPeriods.length !== nextPeriods.length) return false;
	const moneyMatches = (a, b) => Math.abs((Number(a) || 0) - (Number(b) || 0)) < 0.01;
	const currentPeriodTotal = currentPeriods.reduce(
		(sum, period) => sum + Number(period.total || 0),
		0
	);
	const currentTotal =
		currentPeriods.every((period) => Number(period.total || 0) > 0) && currentPeriodTotal > 0
			? currentPeriodTotal
			: Number(known.splitStayTotal || 0) || currentPeriodTotal;
	if (!moneyMatches(currentTotal, total)) return false;
	return currentPeriods.every((period, index) => {
		const next = nextPeriods[index] || {};
		return (
			period.checkinISO === next.checkinISO &&
			period.checkoutISO === next.checkoutISO &&
			moneyMatches(period.total, next.total) &&
			Boolean(period.quoteFingerprint) &&
			period.quoteFingerprint === next.quoteFingerprint
		);
	});
}

async function quoteSplitStayPeriodsForKnown(sc = {}, known = {}, periods = []) {
	const quoteResults = [];
	for (const period of periods) {
		const quoteKnown = {
			...known,
			checkinISO: period.checkinISO,
			checkoutISO: period.checkoutISO,
			quote: null,
		};
		delete quoteKnown.splitStayPeriods;
		delete quoteKnown.splitStayTotal;
		delete quoteKnown.splitStayQuoteAvailable;
		delete quoteKnown.splitStayQuotedAt;
		const result = await quoteTool(sc, quoteKnown).catch((error) => ({
			ok: false,
			available: false,
			code: "quote_failed",
			message: cleanDisplayString(error?.message || String(error), 260),
			checkinISO: period.checkinISO,
			checkoutISO: period.checkoutISO,
		}));
		quoteResults.push({
			period,
			result,
			summary: compactQuoteToolResult(result, {
				...quoteKnown,
				quote: asObject(result.quote),
			}),
		});
	}
	const allAvailable = quoteResults.every((item) => item.result.available && item.result.quote);
	const quotedPeriods = quoteResults.map((item) => {
		const quote = asObject(item.result.quote);
		return {
			checkinISO: item.period.checkinISO,
			checkoutISO: item.period.checkoutISO,
			nights:
				Number(quote.nights || 0) ||
				nightsBetween(item.period.checkinISO, item.period.checkoutISO),
			total: Number(quote.total || quote.totals?.totalPriceWithCommission || 0) || 0,
			currency: quote.currency || item.result.currency || "SAR",
			selectionKey:
				cleanString(quote.selectionKey, 500) || roomSelectionKey(quote.roomSelections),
			roomSelections: normalizeRoomSelections(quote.roomSelections),
			quoteFingerprint: splitStayPeriodQuoteFingerprint(quote, item.period),
		};
	});
	const total = quotedPeriods.reduce((sum, period) => sum + Number(period.total || 0), 0);
	const currency =
		quotedPeriods.find((period) => period.currency)?.currency ||
		quoteResults.find((item) => item.summary.currency)?.summary.currency ||
		"SAR";
	return {
		quoteResults,
		quotedPeriods,
		allAvailable,
		total,
		currency,
		ok: quoteResults.every((item) => item.result.ok !== false),
	};
}

function splitStayQuoteToolResultFromResults({
	known = {},
	quoteResults = [],
	quotedPeriods = [],
	allAvailable = false,
	total = 0,
	currency = "SAR",
	instruction = "",
} = {}) {
	const languageCode = known.languageCode || "en";
	const totalDiscount = quoteDiscountDisplay(
		{ total, averagePerNight: 0, currency },
		languageCode
	);
	return {
		tool: "get_quote",
		quoteMode: "split_stay",
		ok: quoteResults.every((item) => item.result.ok !== false),
		available: allAvailable,
		code: allAvailable ? "split_stay_quote_ready" : "split_stay_quote_unavailable",
		roomTypeKey: known.roomTypeKey || "",
		rooms: normalizeRoomCount(known.rooms, 1),
		roomSelections: normalizeRoomSelections(known.roomSelections),
		splitStayPeriods: quotedPeriods.map((period, index) => ({
			...period,
			available: Boolean(quoteResults[index]?.result?.available),
			code: quoteResults[index]?.result?.code || "",
			roomLabel: quoteResults[index]?.summary?.roomLabel || "",
			perNight: quoteResults[index]?.summary?.perNight || [],
			discount: quoteDiscountDisplay(
				{
					total: Number(period.total || 0) || 0,
					averagePerNight: 0,
					currency: period.currency || currency,
				},
				languageCode
			),
		})),
		total,
		currency,
		discount: totalDiscount,
		instruction:
			instruction ||
			"This is one customer request with multiple separate stay periods at the same hotel. Quote each period separately and explain that continuing will lead to separate reservations for the separate periods. Do not merge the gaps into one reservation. For every period price, use splitStayPeriods[].discount.displayTotalLine exactly. For the combined total, use toolResult.discount.displayTotalLine exactly. Use neutral, natural wording; do not use combined gender slash forms such as رغبتِ/رغبتَ. Do not say the reservation is confirmed or created.",
	};
}

function relabelDiscountLine(line = "", label = "") {
	const value = String(line || "").trim();
	const nextLabel = String(label || "").trim();
	if (!value || !nextLabel) return value;
	return value
		.replace(/^Total\s*:/i, `${nextLabel}:`)
		.replace(/^\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a\s*:/u, `${nextLabel}:`);
}

function splitStayDiscountLine(label = "", total = 0, currency = "SAR", languageCode = "en", discount = null) {
	const displayLine = asObject(discount)?.displayTotalLine;
	if (displayLine) return relabelDiscountLine(displayLine, label);
	const generated = quoteDiscountDisplay({ total, averagePerNight: 0, currency }, languageCode)
		?.displayTotalLine;
	if (generated) return relabelDiscountLine(generated, label);
	return `${label}: ${formatMoney(total, currency, languageCode)}`;
}

function buildSplitStayQuoteMessage(sc = {}, known = {}, hotel = {}, toolResult = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const resultPeriods = Array.isArray(toolResult.splitStayPeriods)
		? toolResult.splitStayPeriods
		: [];
	const knownPeriods = normalizeSplitStayPeriods(known.splitStayPeriods);
	const periods = (resultPeriods.length ? resultPeriods : knownPeriods)
		.map((period, index) => ({
			...asObject(period),
			checkinISO: validISODate(period.checkinISO),
			checkoutISO: validISODate(period.checkoutISO),
			nights:
				Number(period.nights || 0) ||
				nightsBetween(period.checkinISO, period.checkoutISO),
			total: Number(period.total || 0) || 0,
			currency: period.currency || toolResult.currency || "SAR",
			roomLabel:
				cleanDisplayString(period.roomLabel, 160) ||
				splitStayRoomSummary(known, languageCode),
			number: index + 1,
		}))
		.filter((period) => period.checkinISO && period.checkoutISO);
	const total =
		Number(toolResult.total || 0) ||
		Number(known.splitStayTotal || 0) ||
		periods.reduce((sum, period) => sum + Number(period.total || 0), 0);
	const currency =
		toolResult.currency ||
		periods.find((period) => period.currency)?.currency ||
		"SAR";
	const hotelName = hotelDisplayNameForLanguage(hotel, languageCode);
	const roomSummary = splitStayRoomSummary(known, languageCode);
	if (ar) {
		const periodRows = periods.flatMap((period) => {
			const priceLine = splitStayDiscountLine(
				"\u0633\u0639\u0631 \u0647\u0630\u0647 \u0627\u0644\u0641\u062a\u0631\u0629",
				period.total,
				period.currency || currency,
				languageCode,
				period.discount
			);
			return [
				`\u0627\u0644\u0641\u062a\u0631\u0629 ${formatNumber(period.number, languageCode)}: ${formatDate(
					period.checkinISO,
					languageCode
				)} \u0625\u0644\u0649 ${formatDate(period.checkoutISO, languageCode)}\u060c ${formatNumber(
					period.nights,
					languageCode
				)} \u0644\u064a\u0627\u0644\u060c ${period.roomLabel}`,
				priceLine,
			];
		});
		return [
			`\u062a\u0645\u0627\u0645 ${arabicGuestAddress(sc, known)}\u060c \u0631\u0627\u062c\u0639\u062a \u0627\u0644\u0641\u062a\u0631\u0627\u062a \u0643\u062d\u062c\u0648\u0632\u0627\u062a \u0645\u0646\u0641\u0635\u0644\u0629 \u062d\u062a\u0649 \u0644\u0627 \u0646\u062f\u0645\u062c \u0627\u0644\u0641\u0627\u0635\u0644 \u0628\u064a\u0646\u0647\u0627.`,
			`\u0627\u0644\u0641\u0646\u062f\u0642: ${hotelName}`,
			`\u0627\u0644\u063a\u0631\u0641\u0629: ${roomSummary}`,
			...periodRows,
			splitStayDiscountLine(
				"\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a \u0644\u0643\u0644 \u0627\u0644\u062d\u062c\u0648\u0632\u0627\u062a",
				total,
				currency,
				languageCode,
				toolResult.discount
			),
			"\u0625\u0630\u0627 \u064a\u0646\u0627\u0633\u0628\u0643 \u0627\u0644\u0639\u0631\u0636\u060c \u0623\u062a\u0627\u0628\u0639 \u0645\u0639\u0643 \u0644\u0644\u0645\u0631\u0627\u062c\u0639\u0629 \u0642\u0628\u0644 \u0625\u0646\u0634\u0627\u0621 \u062d\u062c\u0632 \u0645\u0633\u062a\u0642\u0644 \u0644\u0643\u0644 \u0641\u062a\u0631\u0629.",
		].join("\n");
	}
	const periodRows = periods.flatMap((period) => {
		const priceLine = splitStayDiscountLine(
			"This period",
			period.total,
			period.currency || currency,
			languageCode,
			period.discount
		);
		return [
			`Period ${period.number}: ${formatDate(period.checkinISO, languageCode)} to ${formatDate(
				period.checkoutISO,
				languageCode
			)}, ${period.nights} night${Number(period.nights) === 1 ? "" : "s"}, ${period.roomLabel}`,
			priceLine,
		];
	});
	return [
		`${guestDisplayName(sc)}, I checked these as separate stay periods so the gap is not merged into one reservation.`,
		`Hotel: ${hotelName}`,
		`Room: ${roomSummary}`,
		...periodRows,
		splitStayDiscountLine("Total for all reservations", total, currency, languageCode, toolResult.discount),
		`If this works for you, I can continue to the review before creating one separate reservation for each period.`,
	].join("\n");
}

async function reservationSubmissionAuthorizationBarrier({
	io,
	sc = {},
	latestGuest = null,
	stage = "submit",
} = {}) {
	const caseId = caseIdText(sc);
	const current = caseId ? await getSupportCaseById(caseId).catch(() => null) : null;
	const allowed = Boolean(
		current &&
			latestGuest &&
			(latestGuestStillCurrent(current, latestGuest) ||
				onlyReservationProcessingAcknowledgementsAfter(current, latestGuest))
	);
	if (allowed) return { allowed: true, current };
	logTurnStage(caseId, "reservation_submit_stopped_for_new_guest", { stage });
	await emitTyping(io, sc, false);
	if (io && caseId) {
		schedulePlanTurn(io, caseId, {
			delayMs: 25,
			reason: "new_guest_before_reservation_create",
			skipMinimumQuiet: true,
		});
	}
	return { allowed: false, current: current || sc };
}

function reservationGuestRevisionGuard({ io, sc = {}, latestGuest = null, stage = "insert" } = {}) {
	return async () => {
		const barrier = await reservationSubmissionAuthorizationBarrier({
			io,
			sc,
			latestGuest,
			stage: `${stage}_immediately_before_insert`,
		});
		if (barrier.allowed) return true;
		const error = new Error(
			"The guest sent a new instruction before the reservation was inserted."
		);
		error.code = "AI_RESERVATION_GUEST_CHANGED_BEFORE_INSERT";
		error.currentSupportCase = barrier.current || null;
		throw error;
	};
}

async function handleBrainSplitStayReservationSubmit({
	io,
	sc = {},
	hotel = {},
	known = {},
	latestGuest = null,
	typingStartedAt = 0,
} = {}) {
	const caseId = caseIdText(sc);
	const nextKnown = {
		...known,
		splitStayPeriods: normalizeSplitStayPeriods(known.splitStayPeriods),
	};
	delete nextKnown.checkinISO;
	delete nextKnown.checkoutISO;
	delete nextKnown.quote;
	const refreshed = await quoteSplitStayPeriodsForKnown(
		sc,
		nextKnown,
		nextKnown.splitStayPeriods
	);
	if (
		!refreshed.allAvailable ||
		!splitStayQuoteTotalsMatchKnown(nextKnown, refreshed.quotedPeriods, refreshed.total)
	) {
		const refreshedKnown = {
			...nextKnown,
			splitStayPeriods: refreshed.quotedPeriods,
			splitStayTotal: refreshed.total,
			splitStayQuoteAvailable: refreshed.allAvailable,
			splitStayQuotedAt: new Date().toISOString(),
		};
		await saveKnownFacts(caseId, refreshedKnown);
		return sendBrainToolReplyFromOpenAI({
			io,
			sc,
			hotel,
			known: refreshedKnown,
			latestGuest,
			toolResult: splitStayQuoteToolResultFromResults({
				known: refreshedKnown,
				...refreshed,
				instruction: refreshed.allAvailable
					? "The final availability/price check changed before reservation creation. Show the refreshed quote for each separate period and ask the guest to continue again before creating separate reservations."
					: "The final availability check found that one or more separate periods is no longer available. Explain the unavailable period and offer alternatives.",
			}),
			clientAction: refreshed.allAvailable
				? "split_stay_quote_ready"
				: "split_stay_quote_unavailable",
			quickReplies: refreshed.allAvailable
				? splitStayQuickReplies(activeLanguageCode(sc, refreshedKnown))
				: quoteUnavailableQuickRepliesForCase(sc, refreshedKnown),
			typingStartedAt,
			preserveFallbackNumbers: false,
		});
	}
	const duplicateGuard = await handleExistingReservationDuplicateGuard({
		io,
		sc,
		hotel,
		known: nextKnown,
		latestGuest,
		typingStartedAt,
		stage: "split_submit_final",
	});
	if (duplicateGuard) return duplicateGuard;
	const submitBarrier = await reservationSubmissionAuthorizationBarrier({
		io,
		sc,
		latestGuest,
		stage: "split_submit_before_create",
	});
	if (!submitBarrier.allowed) return submitBarrier.current;
	const reservations = [];
	try {
		for (let index = 0; index < refreshed.quoteResults.length; index += 1) {
			const periodBarrier = await reservationSubmissionAuthorizationBarrier({
				io,
				sc,
				latestGuest,
				stage: `split_submit_before_create_${index + 1}`,
			});
			if (!periodBarrier.allowed) {
				if (!reservations.length) return periodBarrier.current;
				const interrupted = new Error(
					"The guest sent a new instruction while separate reservations were being created."
				);
				interrupted.code = "AI_SPLIT_STAY_GUEST_INTERRUPTED_AFTER_PARTIAL_CREATE";
				throw interrupted;
			}
			const item = refreshed.quoteResults[index];
			const quote = asObject(item.result.quote);
			let periodKnown = syncKnownFromQuote({
				...nextKnown,
				checkinISO: item.period.checkinISO,
				checkoutISO: item.period.checkoutISO,
				quote,
			});
			delete periodKnown.splitStayPeriods;
			delete periodKnown.splitStayTotal;
			delete periodKnown.splitStayQuoteAvailable;
			delete periodKnown.splitStayQuotedAt;
			const room =
				quote.room ||
				resolveRoomForStay(
					hotel,
					normalizeRoomSelections(periodKnown.roomSelections)[0] || {
						roomType: periodKnown.roomTypeKey,
					}
				);
			const reservation = await createReservationForCase({
				caseId,
				reservationCaseId: splitStayReservationKey(caseId, index),
				useSupportCaseReservationLock: false,
				markSupportCaseReservation: false,
				hotel,
				slots: {
					...periodKnown,
					children: Number.isFinite(Number(periodKnown.children))
						? Number(periodKnown.children)
						: 0,
					rooms: Math.max(1, Number(periodKnown.rooms || nextKnown.rooms || 1) || 1),
				},
				quoteData: quote,
				room,
				beforeInsertGuard: reservationGuestRevisionGuard({
					io,
					sc,
					latestGuest,
					stage: `split_submit_period_${index + 1}`,
				}),
			});
			reservations.push(reservation);
			if (!shouldSkipReservationConfirmationDispatch()) {
				dispatchAiReservationConfirmation({
					caseId,
					reservation,
					mode: "initial",
					includeGuestEmail: Boolean(cleanEmail(nextKnown.email)),
					guestEmail: cleanEmail(nextKnown.email),
				}).catch((error) => {
					console.error("[aiagent] confirmation dispatch failed:", error?.message || error);
				});
			}
		}
		nextKnown.splitStayReservations = reservations.map(compactReservationForBrain);
		nextKnown.splitStayConfirmations = reservations
			.map((reservation) => reservation.confirmation_number)
			.filter(Boolean);
		nextKnown.reservationIds = reservations.map((reservation) => String(reservation._id || ""));
		nextKnown.confirmation = nextKnown.splitStayConfirmations.join(", ");
		await saveKnownFacts(caseId, nextKnown);
		const fallback = buildSplitStayConfirmationMessage(sc, nextKnown, hotel, reservations);
		return sendBrainToolReplyFromOpenAI({
			io,
			sc,
			hotel,
			known: nextKnown,
			latestGuest,
			toolResult: {
				tool: "submit_reservation",
				ok: true,
				code: "split_stay_reservations_created",
				quoteMode: "split_stay",
				mode: "separate_reservations",
				reservations: reservations.map(compactReservationForBrain),
				confirmations: nextKnown.splitStayConfirmations,
				review: compactSplitStayReviewForBrain(nextKnown, hotel, sc),
				instruction:
					"Write the final reservation-created confirmation in the guest language. Explain that the separate stay periods were created as separate reservations. Include every confirmation number, every reservation details link, and every payment link exactly from toolResult. Politely recommend using the payment link, even for a partial payment/deposit when available, because it better secures the room and shows seriousness. Also make clear online payment is recommended but not mandatory and the confirmed reservation remains valid if they do not pay online now. Ask if anything else is needed.",
			},
			clientAction: "reservation_confirmed",
			fallback,
			typingStartedAt,
		});
	} catch (error) {
		console.error("[aiagent] split-stay reservation finalize failed:", error?.message || error);
		if (
			error?.code === "AI_RESERVATION_GUEST_CHANGED_BEFORE_INSERT" &&
			reservations.length === 0
		) {
			return error.currentSupportCase || (await getSupportCaseById(caseId).catch(() => sc));
		}
		if (
			error?.code === "AI_RESERVATION_REQUOTE_REQUIRED" &&
			reservations.length === 0
		) {
			return handleBrainSplitStayQuote(
				io,
				sc,
				hotel,
				nextKnown,
				latestGuest,
				typingStartedAt
			);
		}
		nextKnown.splitStayReservations = reservations.map(compactReservationForBrain);
		nextKnown.splitStayConfirmations = reservations
			.map((reservation) => reservation.confirmation_number)
			.filter(Boolean);
		await saveKnownFacts(caseId, nextKnown);
		const fallback = buildSplitStayPartialFailureMessage(
			sc,
			nextKnown,
			hotel,
			reservations,
			error
		);
		return sendBrainToolReplyFromOpenAI({
			io,
			sc,
			hotel,
			known: nextKnown,
			latestGuest,
			toolResult: {
				tool: "submit_reservation",
				ok: false,
				code: reservations.length
					? "split_stay_partial_create_failed"
					: "reservation_finalize_failed",
				quoteMode: "split_stay",
				mode: "separate_reservations",
				reservations: reservations.map(compactReservationForBrain),
				error: cleanDisplayString(error?.message || String(error), 240),
				instruction:
					"Apologize briefly and explain that the separate reservations need a team member to review them. If any reservation was created, include its confirmation number. Do not claim missing reservations were created.",
			},
			clientAction: "reservation_finalize_failed",
			fallback,
			typingStartedAt,
			preserveFallbackNumbers: false,
		});
	}
}

async function sendBrainSplitStayReviewReply({
	io,
	sc = {},
	hotel = {},
	known = {},
	latestGuest = null,
	typingStartedAt = 0,
	tool = "send_review",
} = {}) {
	const caseId = caseIdText(sc);
	const nextKnown = {
		...known,
		splitStayPeriods: normalizeSplitStayPeriods(known.splitStayPeriods),
	};
	delete nextKnown.checkinISO;
	delete nextKnown.checkoutISO;
	delete nextKnown.quote;
	const missing = splitStayReservationMissing(nextKnown).filter(
		(field) => field !== "quote" || !splitStayQuoteMatchesKnown(nextKnown)
	);
	await saveKnownFacts(caseId, nextKnown);
	if (missing.length) {
		return sendBrainToolReplyFromOpenAI({
			io,
			sc,
			hotel,
			known: nextKnown,
			latestGuest,
			toolResult: {
				tool,
				quoteMode: "split_stay",
				ok: false,
				code: "split_stay_missing_required_details",
				missing,
				splitStayPeriods: nextKnown.splitStayPeriods,
				splitStayTotal: Number(nextKnown.splitStayTotal || 0) || 0,
				currency:
					nextKnown.splitStayPeriods.find((period) => period.currency)?.currency ||
					"SAR",
				instruction:
					"Ask only for the missing required booking details in the guest language. Keep the split stay periods separate and do not ask again for dates already in toolResult.",
			},
			clientAction: "required_details_needed",
			typingStartedAt,
			preserveFallbackNumbers: false,
		});
	}
	if (tool !== "submit_reservation" && shouldOfferOptionalEmail(sc, nextKnown)) {
		await waitForTypingMinimum(typingStartedAt);
		return sendOptionalEmailOffer(io, sc, nextKnown, latestGuest);
	}
	const duplicateGuard = await handleExistingReservationDuplicateGuard({
		io,
		sc,
		hotel,
		known: nextKnown,
		latestGuest,
		typingStartedAt,
		stage: tool === "submit_reservation" ? "split_submit" : "split_review",
	});
	if (duplicateGuard) return duplicateGuard;
	if (tool === "submit_reservation") {
		return handleBrainSplitStayReservationSubmit({
			io,
			sc,
			hotel,
			known: nextKnown,
			latestGuest,
			typingStartedAt,
		});
	}
	const fallback = buildSplitStayReviewMessage(sc, nextKnown, hotel);
	const reviewChatKnown = { ...nextKnown, fullName: "" };
	const reviewChatGuestProfile = guestDisplayName(sc);
	const reviewChatGuestAddressName = shortGuestAddressName(
		sc,
		reviewChatKnown,
		latestGuest?.message || ""
	);
	const reviewChatGuestAddress = guestAddressForPrompt(
		sc,
		reviewChatKnown,
		latestGuest?.message || ""
	);
	const reviewChatGuestNames = [
		reviewChatGuestAddress,
		reviewChatGuestAddressName,
		reviewChatGuestProfile,
	]
		.map((item) => cleanDisplayString(item, 120))
		.filter((item) => item && !/^(guest|customer|client|visitor|unknown)$/i.test(item));
	const reviewBookingName = cleanDisplayString(nextKnown.fullName, 160);
	const reviewChatDiffersFromBooking =
		Boolean(reviewBookingName && reviewChatGuestNames.length) &&
		!reviewChatGuestNames.some((item) => sameBookingName(item, reviewBookingName));
	return sendBrainToolReplyFromOpenAI({
		io,
		sc,
		hotel,
		known: nextKnown,
		latestGuest,
		toolResult: {
			tool: "send_review",
			quoteMode: "split_stay",
			ok: true,
			code: "review_ready",
			review: compactSplitStayReviewForBrain(nextKnown, hotel, sc),
			chatGuest: {
				address: reviewChatGuestAddress,
				addressName: reviewChatGuestAddressName,
				profileName: reviewChatGuestProfile,
				differsFromBookingHolder: reviewChatDiffersFromBooking,
			},
			instruction:
				"Write the official pre-submission booking review in the guest language using these exact split-stay facts. Explain that the separate date ranges will be created as separate reservations only after confirmation. Open by addressing the chat guest using toolResult.chatGuest.address, chatGuest.addressName, guestAddress, or guestProfileName. If toolResult.chatGuest.differsFromBookingHolder is true, do not greet or address toolResult.review.fullName/known.fullName as the guest; list that fullName only as the booking name/holder in the review details. This is not a confirmed booking yet: do not say confirmed, created, completed, finalized, or booked. Keep each stay period, date range, nights, room summary, guests, booking name, phone, nationality, and total clear. For each stay period with toolResult.review.reservations[].discount.displayTotalLine, include that displayTotalLine exactly. For the combined total with toolResult.review.discount.displayTotalLine, include it exactly. Preserve the <s class=\"message-price-old\"> and <strong class=\"message-price-new\"> markup. Then ask the chat guest to confirm before creating the reservations.",
		},
		clientAction: "review_reservation",
		quickReplies: reviewQuickReplies(activeLanguageCode(sc, nextKnown)),
		fallback,
		typingStartedAt,
	});
}

function quoteReplyHasUnexplainedReference(reply = "") {
	const text = normalizeDigits(String(reply || ""));
	if (!text.trim()) return false;
	if (/(?:date\s*reference|reference\s*(?:date|number|id)?|ref(?:erence)?\s*[:#-]|\u0645\u0631\u062c\u0639\s*(?:\u0627\u0644\u062a\u0648\u0627\u0631\u064a\u062e|\u0627\u0644\u062a\u0627\u0631\u064a\u062e|\u0627\u0644\u062d\u062c\u0632|\u0631\u0642\u0645)?|\u0631\u0642\u0645\s*(?:\u0645\u0631\u062c\u0639\u064a|\u0627\u0644\u0645\u0631\u062c\u0639))/iu.test(text)) {
		return true;
	}
	return text.split(/\r?\n/).some((line) => {
		const clean = line.replace(/^[\s\-*•]+/, "").trim();
		return /^\d{5,8}$/.test(clean);
	});
}

function sameDayReplyClaimsMinimumDateAvailable(reply = "", toolResult = {}) {
	if (String(toolResult?.code || "") !== "same_day_checkin_not_supported") return false;
	const minDate = validISODate(toolResult.minCheckinISO);
	if (!minDate) return false;
	const text = normalizeIntentSearchText(reply);
	const compact = text.replace(/\s+/g, "");
	if (!text.includes(minDate)) return false;
	const minIndex = text.indexOf(minDate);
	const nearby = text.slice(Math.max(0, minIndex - 90), minIndex + minDate.length + 90);
	const compactNearby = compact.slice(Math.max(0, compact.indexOf(minDate) - 90), compact.indexOf(minDate) + minDate.length + 90);
	return (
		/\b(?:available|bookable|recommended|confirmed|can\s+book|reserve\s+from|arrange\s+from|search\s+from|check\s+from|look\s+from|start\s+from|begin\s+from)\b/i.test(nearby) ||
		/(?:\u0645\u062a\u0627\u062d|\u0645\u062a\u0627\u062d\u0629|\u0645\u062a\u0627\u062d\u0647|\u0627\u0644\u062d\u062c\u0632\u0644\u0647|\u064a\u0645\u0643\u0646\u0627\u0644\u062d\u062c\u0632|\u0623\u0631\u062a\u0628\u0644\u0643|\u0627\u0631\u062a\u0628\u0644\u0643|\u0645\u0624\u0643\u062f|\u0627\u0644\u062e\u064a\u0627\u0631\u0627\u0644\u0623\u0642\u0631\u0628|\u0627\u0644\u062e\u064a\u0627\u0631\u0627\u0644\u0627\u0642\u0631\u0628|\u0627\u0628\u062d\u062b\u0645\u0646|\u0623\u0628\u062d\u062b\u0645\u0646|\u0627\u0628\u062d\u062b\u0644\u0643\u0645\u0646|\u0623\u0628\u062d\u062b\u0644\u0643\u0645\u0646|\u0646\u0628\u062f\u0623\u0645\u0646|\u0623\u0628\u062f\u0623\u0645\u0646|\u0627\u0628\u062f\u0623\u0645\u0646|\u0627\u0643\u0645\u0644\u0645\u0646|\u0623\u0643\u0645\u0644\u0645\u0646|\u0646\u0643\u0645\u0644\u0645\u0646)/iu.test(compactNearby)
	);
}

function sameDayReplyMissingUnavailableLanguage(reply = "", toolResult = {}) {
	if (String(toolResult?.code || "") !== "same_day_checkin_not_supported") return false;
	const text = normalizeIntentSearchText(reply);
	const compact = text.replace(/\s+/g, "");
	return !(
		/\b(?:unavailable|not\s+available|not\s+bookable|cannot\s+be\s+booked|can't\s+be\s+booked|same-?day)\b/i.test(
			text
		) ||
		/(?:\u063a\u064a\u0631\u0645\u062a\u0627\u062d|\u063a\u064a\u0631\u0645\u062a\u0627\u062d\u0629|\u063a\u064a\u0631\u0645\u062a\u0648\u0641\u0631|\u063a\u064a\u0631\u0645\u062a\u0648\u0641\u0631\u0629|\u0644\u0627\u064a\u0642\u0628\u0644|\u0644\u0627\u064a\u0645\u0643\u0646\u0627\u0644\u062d\u062c\u0632|\u0644\u0627\u064a\u0645\u0643\u0646\u062d\u062c\u0632|\u0646\u0641\u0633\u064a\u0648\u0645|\u0627\u0644\u064a\u0648\u0645)/iu.test(
			compact
		)
	);
}

function sameDayReplyMissingHotelDayContext(reply = "", toolResult = {}) {
	if (String(toolResult?.code || "") !== "same_day_checkin_not_supported") return false;
	const text = normalizeIntentSearchText(reply);
	const compact = text.replace(/\s+/g, "");
	return !(
		/\b(?:same-?day|today|hotel business day|hotel day|earliest|start checking|tomorrow)\b/i.test(
			text
		) ||
		/(?:\u0627\u0644\u064a\u0648\u0645|\u0646\u0641\u0633\u064a\u0648\u0645|\u064a\u0648\u0645\u0627\u0644\u0641\u0646\u062f\u0642|\u0623\u0642\u0631\u0628|\u0627\u0642\u0631\u0628|\u0628\u062f\u0621\u0627\u0644\u0628\u062d\u062b|\u064a\u0628\u062f\u0623\u0627\u0644\u0628\u062d\u062b|\u063a\u062f\u0627|\u063a\u062f\u0627\u064b|\u0628\u0643\u0631\u0629)/iu.test(
			compact
		)
	);
}

function quoteReplyClaimsFutureDatePast(reply = "", toolResult = {}, known = {}) {
	if (toolResult?.tool !== "get_quote") return false;
	const checkinISO = validISODate(toolResult?.checkinISO || known.checkinISO);
	if (!checkinISO || checkinISO <= businessTodayISO()) return false;
	const text = normalizeIntentSearchText(normalizeDigits(String(reply || ""))).toLowerCase();
	const compact = text.replace(/\s+/g, "");
	return (
		/\b(?:past|passed|already\s+passed|expired|old\s+dates?)\b/i.test(text) ||
		/(?:\u0641\u0627\u062a|\u0641\u0627\u0626\u062a|\u0645\u0627\u0636\u064a|\u0645\u0627\u0636\u064a\u0629|\u0642\u062f\u064a\u0645\u0629|\u0633\u0628\u0642)/iu.test(compact)
	);
}

function regexEscape(value = "") {
	return String(value).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function quoteReplyUsesRoomLabelAsHotelName(reply = "", toolResult = {}) {
	if (toolResult?.tool !== "get_quote") return false;
	const roomLabel = cleanDisplayString(
		toolResult.roomLabel || toolResult.quote?.roomLabel || "",
		160
	);
	if (!roomLabel || roomLabel.length < 4) return false;
	const text = String(reply || "")
		.replace(/<[^>]*>/g, " ")
		.replace(/\s+/g, " ")
		.trim();
	const intro = text.split(/(?<=[.!?\u061f])\s+|\n/).slice(0, 2).join(" ");
	if (!intro || !new RegExp(regexEscape(roomLabel), "i").test(intro)) return false;
	return /(?:\u0641\u0631\u064a\u0642|\u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644|\u0627\u0644\u062d\u062c\u0648\u0632\u0627\u062a|\u0645\u0639\u0643|\u0623\u0646\u0627|\bteam\b|\breception\b|\breservations\b).{0,80}(?:\u0641\u064a|\u0628|at|in|from)/iu.test(
		intro
	);
}

function unavailableQuoteShowsZeroTotal(reply = "", toolResult = {}) {
	if (toolResult?.tool !== "get_quote" || toolResult?.available) return false;
	const text = normalizeDigits(String(reply || ""));
	return /(?:total|الإجمالي|الاجمالي)[^\n]{0,60}(?:\b0(?:\.00)?\b|٠(?:[.,]٠٠)?)(?:\s*(?:sar|s\.?r\.?|ريال))?/iu.test(
		text
	);
}

function unavailableQuoteMissingClearLanguage(reply = "", toolResult = {}) {
	if (toolResult?.tool !== "get_quote" || toolResult?.available !== false) return false;
	if (String(toolResult?.code || "") === "same_day_checkin_not_supported") return false;
	const text = normalizeIntentSearchTextRepaired(reply);
	const compact = text.replace(/\s+/g, "");
	return !(
		/\b(?:not\s+available|unavailable|not\s+enough|cannot\s+confirm|can't\s+confirm|alternative|available\s+dates?|adjust\s+(?:dates?|rooms?)|different\s+(?:dates?|rooms?))\b/i.test(
			text
		) ||
		/(?:\u063a\u064a\u0631\u0645\u062a\u0627\u062d|\u063a\u064a\u0631\u0645\u062a\u0627\u062d\u0629|\u063a\u064a\u0631\u0645\u062a\u0648\u0641\u0631|\u063a\u064a\u0631\u0645\u062a\u0648\u0641\u0631\u0629|\u0628\u062f\u0627\u0626\u0644|\u0628\u062f\u064a\u0644|\u062a\u0648\u0627\u0631\u064a\u062e\u0645\u062a\u0627\u062d\u0629|\u062a\u0639\u062f\u064a\u0644\u0627\u0644\u062a\u0648\u0627\u0631\u064a\u062e|\u062a\u063a\u064a\u064a\u0631\u0627\u0644\u063a\u0631\u0641)/iu.test(
			compact
		)
	);
}

function requiredDetailsReplyListsKnownPhoneAsMissing(reply = "", known = {}, toolResult = {}) {
	if (toolResult?.tool !== "send_review" || toolResult?.code !== "missing_required_details") {
		return false;
	}
	const phone = cleanPhone(known.phone);
	if (!phone || !known.phoneNeedsConfirmation) return false;
	const text = normalizeDigits(String(reply || ""));
	const phoneIndex = text.indexOf(phone);
	if (phoneIndex < 0) return false;
	const nearby = text.slice(Math.max(0, phoneIndex - 40), phoneIndex + phone.length + 20);
	const compactNearby = normalizeIntentSearchText(nearby).replace(/\s+/g, "");
	const rawPhoneLabel =
		/(?:phone|mobile|whatsapp|رقم\s*(?:الهاتف|الجوال)|الهاتف|الجوال)\s*[:：-]/iu.test(nearby) ||
		/(?:رقمالهاتف|رقمالجوال|الهاتف|الجوال)[:：-]?/iu.test(compactNearby);
	const confirmationContext =
		/(?:confirm|confirmation|existing|current|shown|same number|تأكيد|الموجود|الظاهر|نفس\s+الرقم)/iu.test(
			nearby
		);
	return rawPhoneLabel && !confirmationContext;
}

function requiredDetailsReplyHasUnexplainedNumber(reply = "", toolResult = {}) {
	if (toolResult?.tool !== "send_review" || toolResult?.code !== "missing_required_details") {
		return false;
	}
	const text = normalizeDigits(stripChatMarkup(reply));
	if (!text.trim()) return false;
	return text.split(/\r?\n/).some((line) => {
		const clean = line.replace(/^[\s\-*â€¢]+/, "").trim();
		if (/^\d{1,2}$/.test(clean)) return true;
		if (/(?:^|[.!?\u061F])\s*\d{1,2}\s*$/.test(clean)) return true;
		return /(?:\b(?:booking|reservation)\b|\u0627\u0644\u062d\u062c\u0632)\s*#?\s*\d{1,2}\b/iu.test(clean);
	});
}

function compactReservationForBrain(reservation = null) {
	if (!reservation) return null;
	const links = reservationPublicLinks(reservation);
	return {
		confirmation: reservation.confirmation_number || "",
		status: reservation.reservation_status || reservation.state || "",
		checkinISO: validISODate(reservation.checkin_date),
		checkoutISO: validISODate(reservation.checkout_date),
		total: Number(reservation.total_amount || 0) || 0,
		currency: reservation.currency || "SAR",
		customerName: reservation.customer_details?.customer_name || "",
		phone: reservation.customer_details?.phone || "",
		totalRooms: Number(reservation.total_rooms || 0) || 0,
		totalGuests: Number(reservation.total_guests || reservation.adults || 0) || 0,
		paymentSummary: compactReservationPaymentSummary(reservation),
		links,
	};
}

function reservationConfirmationRequiredLines(toolResult = {}) {
	const source = asObject(toolResult);
	if (source.tool !== "submit_reservation" || source.ok !== true) return [];
	const reservations =
		source.code === "split_stay_reservations_created"
			? Array.isArray(source.reservations)
				? source.reservations
				: []
			: [source.reservation || source].filter(Boolean);
	const lines = [];
	reservations.forEach((reservation, index) => {
		const item = asObject(reservation);
		const links = {
			...asObject(item.links),
			...(source.code === "split_stay_reservations_created" ? {} : asObject(source.links)),
		};
		const prefix =
			reservations.length > 1 ? `Reservation ${index + 1}` : "Reservation";
		const confirmation = cleanString(
			item.confirmation || item.confirmation_number || source.confirmation,
			100
		);
		const detailsLink = cleanString(links.reservationConfirmation, 320);
		const paymentLink = cleanString(links.payment, 320);
		if (confirmation) lines.push(`${prefix} confirmation: ${confirmation}`);
		if (detailsLink) lines.push(`${prefix} details link: ${detailsLink}`);
		if (paymentLink) lines.push(`${prefix} payment link: ${paymentLink}`);
	});
	return lines;
}

function withReservationConfirmationRequiredLines(toolResult = {}) {
	const source = asObject(toolResult);
	const requiredConfirmationLines = reservationConfirmationRequiredLines(source);
	if (!requiredConfirmationLines.length) return source;
	return { ...source, requiredConfirmationLines };
}

function compactUpdateToolResult(result = {}, known = {}) {
	const reservation = result.reservation || null;
	return {
		tool: "update_reservation",
		ok: Boolean(result.ok),
		code: String(result.code || ""),
		confirmation: reservation?.confirmation_number || known.confirmation || "",
		checkinISO: result.checkinISO || known.checkinISO || "",
		checkoutISO: result.checkoutISO || known.checkoutISO || "",
		total:
			Number(
				reservation?.total_amount || result.quote?.totals?.totalPriceWithCommission || 0
			) || 0,
		currency: reservation?.currency || result.quote?.currency || "SAR",
		reservation: compactReservationForBrain(reservation),
	};
}


async function askCompactToolWriter({
	sc,
	known,
	latestGuest,
	toolResult,
	fallback = "",
	requireContact = false,
	requirePolicy = false,
	preserveFallbackNumbers = true,
} = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const safeToolResult = withReservationConfirmationRequiredLines(
		redactInternalStockForCustomer(toolResult)
	);
	const toolName = String(safeToolResult?.tool || "");
	const confirmationWriter = toolName === "submit_reservation";
	const reviewWriter = toolName === "send_review";
	const requiredVisibleNumbers = preserveFallbackNumbers
		? numericTokensForPolish(fallback).slice(0, 40)
		: [];
	const identityRepeatAllowed =
		!hasAnyAiEntry(sc) || guestAsksAgentIdentity(latestGuest?.message || "");
	const toolSpecificRules = [
		toolName === "get_quote"
			? "Write the exact quote result now. Use short separate lines for room mix, check-in, checkout, nights, per-room pricing when mixed, grand total, and one sales next step. This is not a confirmed reservation. If singleRoomMappedToDouble is true, sell one comfortable double as single occupancy. If roomPlanAdjusted is true, state only the original requested mix and exact offered mix, then ask for agreement."
			: "",
		toolName === "check_room_options"
			? "The guest explicitly asked for room choices. Present at most the two tool-backed choices supplied, concisely, without any stock count."
			: "",
		reviewWriter && safeToolResult?.code === "review_ready"
			? "Write the official pre-submission review with every exact booking fact on clear lines and ask the guest to confirm. Do not claim it is booked, created, completed, or confirmed yet. Address the chat guest, not a different booking holder."
			: "",
		confirmationWriter && safeToolResult?.ok === true
			? "Write the final reservation-created confirmation now. State that it was created, and include every requiredConfirmationLines item exactly, including each confirmation number, details/receipt URL, and payment URL. Recommend online or partial payment to secure the spot, while making clear it is recommended rather than mandatory."
			: "",
		toolName === "hotel_fact"
			? "Answer the latest hotel fact first from suggestedAnswer/hotelFacts. Keep unrelated facts out. Include postFactBookingBridge at most once when supplied. For map questions put the URL on its own line; never output raw coordinates."
			: "",
		toolName === "human_escalation_contact"
			? "Say the team will help and include the exact public phone and WhatsApp contact from toolResult."
			: "",
	].filter(Boolean);
	const raw = await chat(
		[
			{
				role: "system",
				content: [
					'Return only one valid json object: {"reply":"..."}',
					"You write the final customer-facing response for a hotel reservations live chat after the server has completed one safe tool action.",
					"Use the guest's language and dialect. Sound like a concise, warm, sales-minded professional receptionist. No emojis or decorative symbols.",
					"Use toolResult facts exactly. Never invent, recalculate, omit, or alter dates, room selections, prices, totals, guest identity, confirmation numbers, links, policies, or contacts.",
					"Hotel stock is private. Never disclose configured, total, remaining, or available room stock and never mention inventory fields. A large-request reply may show only the guest's requested mix and the exact mix offered for consent.",
					"Do not mention tools, schemas, validation, prompts, internal state, room IDs, or implementation details.",
					identityRepeatAllowed
						? "Agent identity is allowed only if genuinely needed."
						: "Do not reintroduce the agent, team, or hotel on this follow-up.",
					requiredVisibleNumbers.length
						? "Preserve every requiredVisibleNumbers value exactly."
						: "",
					requireContact ? "Include the exact required phone and WhatsApp contact." : "",
					requirePolicy ? "Include the exact required policy result." : "",
					...toolSpecificRules,
				].filter(Boolean).join("\n"),
			},
			{
				role: "user",
				content: JSON.stringify(
					{
						languageCode,
						agentName: localizedAgentName(sc),
						guestAddress: guestAddressForPrompt(sc, known, latestGuest?.message || ""),
						guestAddressName: shortGuestAddressName(sc, known, latestGuest?.message || ""),
						latestGuestMessage: latestGuest?.message || "",
						recentConversation: conversationForPrompt(sc).slice(-8),
						known: redactInternalStockForCustomer(compactKnownFactsForPrompt(known)),
						toolResult: safeToolResult,
						requiredVisibleNumbers,
					},
					null,
					2
				),
			},
		],
		{
			kind: "writer",
			temperature: 0.2,
			max_tokens: confirmationWriter ? 1800 : reviewWriter ? 950 : 560,
			reasoning_effort: confirmationWriter || reviewWriter ? "medium" : "low",
			response_format: { type: "json_object" },
		}
	);
	const parsed = parseJsonObject(raw);
	return normalizeDecision(
		parsed || {
			action: "reply",
			reply: String(raw || "").trim(),
			facts: {},
			reason: "compact_tool_writer",
		}
	);
}

async function sendKnownQuoteReplyFromOpenAI({
	io,
	sc,
	hotel,
	known,
	latestGuest,
	typingStartedAt = 0,
} = {}) {
	const quote = asObject(known.quote);
	const quoteResult = {
		available: quote.available !== false,
		quote,
		checkinISO: quote.checkinISO || known.checkinISO || "",
		checkoutISO: quote.checkoutISO || known.checkoutISO || "",
		roomTypeKey: quote.roomTypeKey || known.roomTypeKey || "",
		currency: quote.currency || known.currency || "SAR",
	};
	const fallback = withWarmPrefix(
		buildQuoteFallbackMessage(sc, known, quoteResult, hotel),
		sc,
		known,
		latestGuest?.message || ""
	);
	return sendBrainToolReplyFromOpenAI({
		io,
		sc,
		hotel,
		known,
		latestGuest,
		toolResult: {
			...compactQuoteToolResult(quoteResult, known),
			instruction: quoteReplyFormattingInstruction(),
		},
		clientAction: quoteResult.available ? "quote_ready" : "quote_unavailable",
		quickReplies: quoteResult.available
			? proceedQuickReplies(activeLanguageCode(sc, known))
			: quoteUnavailableQuickRepliesForCase(sc, known),
		fallback,
		typingStartedAt,
	});
}

async function sendBrainToolReply({
	io,
	sc,
	hotel,
	known,
	latestGuest,
	toolResult,
	clientAction = "ai_reply",
	quickReplies = [],
	fallback = "",
	typingStartedAt = 0,
	requireContact = false,
	requirePolicy = false,
	preserveFallbackNumbers = true,
} = {}) {
	let reply = String(fallback || "").trim();
	let decision = null;
	let usedToolWriterReply = false;
	try {
		decision = await askOpenAI({
			sc,
			hotel,
			known,
			latestGuest,
			toolResult,
			turnKind: "tool_result",
			kind: "writer",
			maxTokens: 420,
			reasoningEffort: "",
		});
		if (decision?.reply) {
			reply = decision.reply;
			usedToolWriterReply = true;
		}
	} catch (error) {
		console.warn("[aiagent] brain tool reply fallback:", error?.message || error);
	}
	if (!reply) reply = fallback || "";
	if (
		fallback &&
		preserveFallbackNumbers &&
		!replyPreservesVisibleNumbers(fallback, reply)
	) {
		reply = fallback;
	}
	if (
		requireContact &&
		(!reply.includes(RESERVATION_CHANGE_CONTACT_PHONE) ||
			!reply.includes(RESERVATION_CHANGE_CONTACT_WHATSAPP))
	) {
		reply = fallback;
	}
	if (
		requirePolicy &&
		toolResult?.policy &&
		!/(14|١٤|policy|refund|one\s+night|\u0633\u064a\u0627\u0633\u0629|\u0627\u0633\u062a\u0631\u062f\u0627\u062f|\u0644\u064a\u0644\u0629\s+\u0648\u0627\u062d\u062f\u0629)/i.test(reply)
	) {
		reply = fallback;
	}
	if (replyRequestsForbiddenBookingField(reply)) {
		reply = fallback || buildAllowedMissingBookingDetailsMessage(sc, known);
	}
	if (decision?.action === "escalate") {
		await waitForTypingMinimum(typingStartedAt);
		return handoffToHuman(io, sc, known, latestGuest, decision.reason || "ai_escalated");
	}
	if (decision?.action === "close_case") {
		await waitForTypingMinimum(typingStartedAt);
		return closeCaseWithOutro(io, sc, known, latestGuest, reply);
	}
	if (!usedToolWriterReply) {
		reply = await polishCustomerReply({
			sc,
			hotel,
			known,
			latestGuest,
			decision: { ...(decision || {}), action: "reply" },
			reply,
		});
	}
	await waitForTypingMinimum(typingStartedAt);
	return sendAiMessage(io, sc, reply, {
		latestGuest,
		known,
		clientAction,
		quickReplies,
	});
}

function emergencyToolResultReply(sc = {}, hotel = {}, known = {}, toolResult = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const tool = String(toolResult?.tool || "");
	if (tool === "get_quote") {
		const quote = toolResult.available
			? {
					...asObject(toolResult),
					total: Number(toolResult.total || 0) || 0,
					averagePerNight: Number(toolResult.averagePerNight || 0) || 0,
					currency: toolResult.currency || "SAR",
			  }
			: {};
		return buildQuoteFallbackMessage(
			sc,
			known,
			{
				...asObject(toolResult),
				quote,
				available: Boolean(toolResult.available),
				roomSelections: normalizeRoomSelections(toolResult.roomSelections),
			},
			hotel
		);
	}
	if (tool === "send_review" && toolResult?.code === "review_ready") {
		return buildReviewMessage(sc, known, hotel);
	}
	if (tool === "check_room_options") {
		return buildSameDateRoomOptionsMessage(sc, known, {
			options: Array.isArray(toolResult.options) ? toolResult.options.slice(0, 2) : [],
		});
	}
	if (toolResult?.suggestedAnswer) {
		return cleanDisplayString(toolResult.suggestedAnswer, 1800);
	}
	return ar
		? "\u0648\u0635\u0644\u062a\u0646\u064a \u0631\u0633\u0627\u0644\u062a\u0643. \u062a\u0639\u0630\u0631 \u0625\u0643\u0645\u0627\u0644 \u0627\u0644\u062e\u0637\u0648\u0629 \u0628\u0634\u0643\u0644 \u0646\u0647\u0627\u0626\u064a \u0627\u0644\u0622\u0646\u060c \u0648\u0633\u0623\u0628\u0642\u064a \u0645\u0639\u0643 \u0644\u0644\u0645\u0633\u0627\u0639\u062f\u0629 \u0628\u062f\u0648\u0646 \u062a\u0643\u0631\u0627\u0631 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a."
		: "I received your message. That step could not be completed safely just now, and I will keep helping without asking you to repeat the details.";
}

function stockPrivateFallbackReply(sc = {}, known = {}, toolResult = {}) {
	const languageCode = activeLanguageCode(sc, known);
	const ar = /^ar\b/i.test(languageCode);
	const offered = normalizeRoomSelections(
		toolResult.recommendedRoomSelections || toolResult.roomSelections
	);
	const mix = roomSelectionsDisplayText(offered, languageCode);
	const dates =
		toolResult.checkinISO && toolResult.checkoutISO
			? `${toolResult.checkinISO} - ${toolResult.checkoutISO}`
			: "";
	const total = Number(toolResult.total || 0) || 0;
	if (ar) {
		return [
			`${arabicGuestAddress(sc, known)}\u060c \u0644\u0627 \u064a\u0645\u0643\u0646 \u062a\u0646\u0641\u064a\u0630 \u0627\u0644\u062a\u0631\u062a\u064a\u0628 \u0627\u0644\u0623\u0635\u0644\u064a \u0628\u0646\u0641\u0633 \u0627\u0644\u0635\u0648\u0631\u0629.`,
			mix ? `\u0627\u0644\u062a\u0631\u062a\u064a\u0628 \u0627\u0644\u0630\u064a \u0623\u0642\u062f\u0631 \u0623\u0642\u062f\u0645\u0647 \u0644\u0643: ${mix}` : "",
			dates ? `\u0627\u0644\u062a\u0648\u0627\u0631\u064a\u062e: ${dates}` : "",
			total ? `\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a: ${formatMoney(total, toolResult.currency || "SAR", languageCode)}` : "",
			"\u0647\u0644 \u062a\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u0647\u0630\u0627 \u0627\u0644\u062a\u0631\u062a\u064a\u0628\u061f",
		]
			.filter(Boolean)
			.join("\n");
	}
	return [
		`${guestDisplayName(sc)}, the original room setup cannot be offered exactly as requested.`,
		mix ? `The room mix I can offer: ${mix}` : "",
		dates ? `Dates: ${dates}` : "",
		total ? `Total: ${formatMoney(total, toolResult.currency || "SAR", languageCode)}` : "",
		"Do you agree to this exact room mix?",
	]
		.filter(Boolean)
		.join("\n");
}

async function sendBrainToolReplyFromOpenAI({
	io,
	sc,
	hotel,
	known,
	latestGuest,
	toolResult,
	clientAction = "ai_reply",
	quickReplies = [],
	fallback = "",
	typingStartedAt = 0,
	requireContact = false,
	requirePolicy = false,
	preserveFallbackNumbers = true,
	replySuffix = "",
	handoff = false,
	handoffReason = "",
} = {}) {
	const caseId = caseIdText(sc);
	let decision = null;
	let reply = "";
	const readOnlyToolReply = new Set([
		"get_quote",
		"check_alternatives",
		"check_room_options",
		"hotel_fact",
		"split_city_itinerary",
		"official_review_question",
		"send_review",
	]).has(String(toolResult?.tool || ""));
	if (readOnlyToolReply && latestGuest) {
		const currentBeforeWriter = await getSupportCaseById(caseId).catch(() => null);
		if (!currentBeforeWriter || !latestGuestStillCurrent(currentBeforeWriter, latestGuest)) {
			logTurnStage(caseId, "tool_writer_skipped_for_new_guest", {
				tool: toolResult?.tool || "",
			});
			schedulePlanTurn(io, caseId, {
				delayMs: 25,
				reason: "new_guest_message_before_tool_writer",
				skipMinimumQuiet: true,
			});
			return currentBeforeWriter || sc;
		}
	}
	fallback = String(fallback || "").trim() || emergencyToolResultReply(sc, hotel, known, toolResult);
	const stockPrivacyContext = { known, clientAction, toolResult };
	if (replyDisclosesInternalStock(fallback, stockPrivacyContext)) {
		fallback = stockPrivateFallbackReply(sc, known, toolResult);
	}
	if (toolResult?.tool === "send_review" && toolResult?.code === "missing_required_details") {
		const missing = Array.isArray(toolResult.missing)
			? toolResult.missing
			: requiredBookingMissing(known);
		const requiredDetailsReply =
			String(fallback || "").trim() ||
			buildMandatoryDetailsMessage(sc, known, missing);
		await waitForTypingMinimum(typingStartedAt);
		return sendAiMessage(io, sc, requiredDetailsReply, {
			latestGuest,
			known,
			clientAction,
			quickReplies,
			source: "server",
		});
	}
	const invalidReplyReason = (candidate = "") => {
		const text = String(candidate || "").trim();
		if (!text) return "missing_openai_reply";
		const submitConfirmationHasSpecificValidation =
			toolResult?.tool === "submit_reservation" && toolResult?.ok === true;
		if (
			fallback &&
			preserveFallbackNumbers &&
			!submitConfirmationHasSpecificValidation &&
			!replyPreservesVisibleNumbers(fallback, text)
		) {
			return "visible_numbers_changed";
		}
		if (toolResult?.tool === "get_quote" && quoteReplyHasUnexplainedReference(text)) {
			return "unexplained_quote_reference";
		}
		if (
			toolResult?.tool === "get_quote" &&
			sameDayReplyClaimsMinimumDateAvailable(text, toolResult)
		) {
			return "same_day_minimum_date_claimed_available";
		}
		if (
			toolResult?.tool === "get_quote" &&
			sameDayReplyMissingUnavailableLanguage(text, toolResult)
		) {
			return "same_day_unavailable_language_missing";
		}
		if (
			toolResult?.tool === "get_quote" &&
			sameDayReplyMissingHotelDayContext(text, toolResult)
		) {
			return "same_day_hotel_day_context_missing";
		}
		if (quoteReplyClaimsFutureDatePast(text, toolResult, known)) {
			return "future_quote_called_past";
		}
		if (quoteReplyUsesRoomLabelAsHotelName(text, toolResult)) {
			return "quote_identity_used_room_as_hotel";
		}
		if (replyContainsEmoji(text)) {
			return "emoji_used";
		}
		if (replyDisclosesInternalStock(text, stockPrivacyContext)) {
			return "internal_stock_disclosure";
		}
		if (unavailableQuoteShowsZeroTotal(text, toolResult)) {
			return "unavailable_quote_zero_total";
		}
		if (unavailableQuoteMissingClearLanguage(text, toolResult)) {
			return "unavailable_quote_unclear";
		}
		if (quoteReplyMissingDiscountFormat(text, toolResult)) {
			return "quote_discount_format_missing";
		}
		if (quoteReplyMissingToolDates(text, toolResult)) {
			return "quote_tool_dates_missing";
		}
		if (quoteReplyHasExtraneousMoneyAmount(text, toolResult, fallback)) {
			return "quote_extra_money_amount";
		}
		if (quoteReplyMentionsUnbackedDeposit(text, toolResult)) {
			return "quote_unbacked_deposit";
		}
		if (quoteReplyRoomCountConflictsWithTool(text, toolResult)) {
			return "quote_room_count_conflict";
		}
		if (requiredDetailsReplyListsKnownPhoneAsMissing(text, known, toolResult)) {
			return "known_phone_listed_as_missing";
		}
		if (requiredDetailsReplyHasUnexplainedNumber(text, toolResult)) {
			return "unexplained_required_details_number";
		}
		if (
			toolResult?.tool === "check_alternatives" &&
			alternativeReplyDriftedToHotelFact(text)
		) {
			return "alternative_reply_drifted_to_hotel_fact";
		}
		if (
			toolResult?.tool === "hotel_fact" &&
			(hotelFactReplyHasUnwantedLocationDump(text, toolResult) ||
				hotelFactReplyHasRawLocationNumbers(text))
		) {
			return "hotel_fact_location_dump";
		}
		if (
			toolResult?.tool === "hotel_fact" &&
			hotelFactBranchReplyNeedsCorrection(text, toolResult)
		) {
			return "hotel_fact_branch_repeated_location";
		}
		if (
			toolResult?.tool === "hotel_fact" &&
			hotelFactPriceGuidanceReplyNeedsCorrection(text, toolResult)
		) {
			return "hotel_fact_price_guidance_unclear";
		}
		if (
			toolResult?.tool === "hotel_fact" &&
			hotelFactMapReplyNeedsCorrection(text, toolResult)
		) {
			return "hotel_fact_map_missing";
		}
		if (
			toolResult?.tool === "hotel_fact" &&
			hotelFactReplyHasRoboticSourceLabel(text)
		) {
			return "hotel_fact_robotic_source_label";
		}
		if (hotelFactReplyHasRawBookingNumberDump(text, toolResult)) {
			return "hotel_fact_raw_number_dump";
		}
		if (hotelFactReplyRepeatsRecentBookingBridge(text, sc, latestGuest, toolResult)) {
			return "hotel_fact_repeated_sales_bridge";
		}
		if (hotelFactLocationReplyNeedsLineBreaks(text, toolResult)) {
			return "hotel_fact_location_linebreaks";
		}
		if (closerHotelReplyNeedsSalesClose(text, toolResult)) {
			return "hotel_fact_closer_sales_close_missing";
		}
		if (toolResult?.tool === "get_quote" && reviewReplyClaimsBookingConfirmed(text)) {
			return "quote_claimed_confirmed_before_submit";
		}
		if (
			toolResult?.tool === "official_review_question" &&
			reviewReplyClaimsBookingConfirmed(text)
		) {
			return "official_review_question_claimed_created";
		}
		if (quoteReplyUsesPrematureReviewLanguage(text, toolResult)) {
			return "quote_premature_review_language";
		}
		if (
			["send_review", "submit_reservation"].includes(String(toolResult?.tool || "")) &&
			replyPromisesProgressWithoutAction(text) &&
			!reviewReplyHasOfficialToolFacts(text, toolResult)
		) {
			return "vague_progress_instead_of_tool_result";
		}
		if (
			toolResult?.tool === "submit_reservation" &&
			toolResult?.ok === true &&
			toolResult?.code === "reservation_created"
		) {
			const reservation = asObject(toolResult.reservation);
			const links = {
				...asObject(reservation.links),
				...asObject(toolResult.links),
			};
			const requiredParts = [
				cleanString(reservation.confirmation || toolResult.confirmation, 80),
				cleanString(links.reservationConfirmation, 260),
				cleanString(links.payment, 260),
			].filter(Boolean);
			if (requiredParts.some((item) => !text.includes(item))) {
				return "reservation_confirmation_links_missing";
			}
		}
		if (
			toolResult?.tool === "submit_reservation" &&
			toolResult?.ok === true &&
			toolResult?.code === "split_stay_reservations_created"
		) {
			const requiredParts = (Array.isArray(toolResult.reservations)
				? toolResult.reservations
				: []
			)
				.flatMap((reservation) => {
					const item = asObject(reservation);
					const links = asObject(item.links);
					return [
						cleanString(item.confirmation, 80),
						cleanString(links.reservationConfirmation, 260),
						cleanString(links.payment, 260),
					];
				})
				.filter(Boolean);
			if (requiredParts.some((item) => !text.includes(item))) {
				return "reservation_confirmation_links_missing";
			}
		}
		if (
			toolResult?.tool === "send_review" &&
			toolResult?.code === "review_ready" &&
			reviewReplyClaimsBookingConfirmed(text)
		) {
			return "review_claimed_confirmed_before_submit";
		}
		if (
			toolResult?.tool === "send_review" &&
			toolResult?.code === "review_ready" &&
			reviewReplyNeedsCleanFormatting(text)
		) {
			return "review_formatting_unclear";
		}
		if (reviewReplyChangesPhone(text, toolResult)) {
			return "review_phone_changed";
		}
		if (reviewReplyMissingBookingIdentity(text, toolResult)) {
			return "review_identity_missing";
		}
		if (reviewReplyNeedsChatGuestAddress(text, sc, known, toolResult, latestGuest)) {
			return "review_addressed_booking_holder";
		}
		if (reviewReplyHasMixedDateFormat(text, toolResult)) {
			return "review_mixed_date_format";
		}
		if (reviewReplyMissingConfirmationAsk(text, toolResult)) {
			return "review_confirmation_step_missing";
		}
		if (reviewReplyMissingDiscountFormat(text, toolResult)) {
			return "review_discount_format_missing";
		}
		if (
			!["reservation_created", "split_stay_reservations_created"].includes(
				String(toolResult?.code || "")
			) &&
			replyTooSimilarToRecentAi(sc, text, latestGuest, clientAction)
		) {
			return "repetitive_reply";
		}
		const replyMustIncludeContact =
			requireContact ||
			decision?.action === "escalate" ||
			toolResult?.tool === "human_escalation_contact";
		if (
			replyMustIncludeContact &&
			(!text.includes(RESERVATION_CHANGE_CONTACT_PHONE) ||
				!text.includes(RESERVATION_CHANGE_CONTACT_WHATSAPP))
		) {
			return "required_contact_missing";
		}
		if (
			replyContainsPaidGuestReceptionPhone(text) &&
			!toolResult?.paidReceptionContact?.allowed
		) {
			return "restricted_reception_phone_not_allowed";
		}
		if (
			requirePolicy &&
			toolResult?.policy &&
			!/(14|Ù¡Ù¤|policy|refund|one\s+night|\u0633\u064a\u0627\u0633\u0629|\u0627\u0633\u062a\u0631\u062f\u0627\u062f|\u0644\u064a\u0644\u0629\s+\u0648\u0627\u062d\u062f\u0629)/i.test(text)
		) {
			return "required_policy_missing";
		}
		if (replyRequestsForbiddenBookingField(text)) {
			return "forbidden_booking_field_requested";
		}
		return "";
	};
	try {
		decision = await askCompactToolWriter({
			sc,
			known,
			latestGuest,
			toolResult,
			fallback,
			requireContact,
			requirePolicy,
			preserveFallbackNumbers,
		});
		reply = sanitizeCustomerReplyHotelName({
			reply: decision?.reply || "",
			sc,
			hotel,
			known,
			latestGuest,
		});
	} catch (error) {
		console.warn("[aiagent] brain tool reply failed:", error?.message || error);
	}
	let invalidReason = invalidReplyReason(reply);
	if (
		invalidReason === "reservation_confirmation_links_missing" &&
		fallback &&
		toolResult?.tool === "submit_reservation" &&
		toolResult?.ok === true
	) {
		reply = fallback;
		invalidReason = "";
		console.warn("[aiagent] reservation confirmation fallback used", {
			caseId,
			tool: toolResult?.tool || "",
		});
	}
	if (invalidReason && fallback) {
		reply = fallback;
		const fallbackReason = invalidReason;
		invalidReason = "";
		console.warn("[aiagent] tool reply fallback used after validation", {
			caseId,
			tool: toolResult?.tool || "",
			reason: fallbackReason,
		});
	}
	if (invalidReason) {
		console.error("[aiagent] brain tool reply blocked: OpenAI reply required", {
			caseId,
			invalidReason,
			tool: toolResult?.tool || "",
		});
		await emitTyping(io, sc, false);
		return (await getSupportCaseById(caseId).catch(() => null)) || sc;
	}
	if (decision?.action === "escalate") {
		await waitForTypingMinimum(typingStartedAt);
		return sendAiMessage(io, sc, reply, {
			latestGuest,
			known,
			clientAction: "human_escalation_contact",
			handoff: true,
			handoffReason: decision.reason || "ai_escalated",
			source: "openai",
		});
	}
	if (decision?.action === "close_case") {
		await waitForTypingMinimum(typingStartedAt);
		return closeCaseWithOutro(io, sc, known, latestGuest, reply);
	}
	const suffix = String(replySuffix || "").trim();
	if (suffix && !reply.includes(suffix)) {
		const hotelFactBridgeSuffix =
			toolResult?.tool === "hotel_fact" &&
			toolResult?.postFactBookingBridge &&
			suffix === String(toolResult.postFactBookingBridge || "").trim();
		const hasEquivalentHotelFactBridge =
			toolResult?.tool === "hotel_fact" &&
			((hotelFactBridgeSuffix && hotelFactReplyHasConcreteBookingBridge(reply)) ||
				(toolResult?.bookingCheckpointWillBeAppended &&
					hotelFactReplyAlreadyHasBookingCheckpoint(reply, known)));
		if (!hasEquivalentHotelFactBridge) {
			reply = [String(reply || "").trim(), suffix].filter(Boolean).join("\n\n");
		}
	}
	reply = sanitizeCustomerReplyHotelName({ reply, sc, hotel, known, latestGuest });
	await waitForTypingMinimum(typingStartedAt);
	return sendAiMessage(io, sc, reply, {
		latestGuest,
		known,
		clientAction,
		quickReplies,
		source: "openai",
		allowReservationWaitAcknowledgements: Boolean(
			toolResult?.tool === "submit_reservation" &&
				toolResult?.ok === true &&
				["reservation_created", "split_stay_reservations_created"].includes(
					String(toolResult?.code || "")
				)
		),
		allowAfterSuccessfulMutation: Boolean(
			toolResult?.tool === "submit_reservation" &&
				toolResult?.ok === true &&
				["reservation_created", "split_stay_reservations_created"].includes(
					String(toolResult?.code || "")
				)
		),
		validatedFallback: fallback,
		handoff,
		handoffReason: handoff ? handoffReason || "ai_escalated" : undefined,
	});
}

async function handleBrainQuote(io, sc = {}, hotel = {}, known = {}, latestGuest = null, typingStartedAt = 0) {
	const caseId = caseIdText(sc);
	known = applySelectedSameDateRoomOptionLock(known);
	const latestText = String(latestGuest?.message || "");
	const previousAi = previousAiEntryBeforeLatestGuest(sc, latestGuest);
	if (
		latestGuest &&
		latestGuestRaisesBudgetConcern(latestText) &&
		!latestGuestHasExplicitStayChangeForBudget(latestText) &&
		aiMessageLooksLikeDisplayedQuote(previousAi)
	) {
		const budgetKnown = restoreKnownFromDisplayedQuoteForBudget(known, previousAi);
		await saveKnownFacts(caseId, budgetKnown);
		await waitForTypingMinimum(typingStartedAt);
		return sendAiMessage(io, sc, buildValueObjectionFallbackReply(sc, hotel, budgetKnown, latestGuest), {
			latestGuest,
			known: budgetKnown,
			clientAction: "value_objection",
			quickReplies: valueObjectionQuickReplies(activeLanguageCode(sc, budgetKnown)),
		});
	}
	known = filterInactiveRoomSelectionsForHotel(hotel, known).known;
	known = ensureRoomPlanForGuestCapacity(hotel, known).known;
	if (normalizeSplitStayPeriods(known.splitStayPeriods).length >= 2) {
		return handleBrainSplitStayQuote(io, sc, hotel, known, latestGuest, typingStartedAt);
	}
	if (!quoteInputsKnown(known)) {
		const fallback = buildQuoteGuardFallbackMessage(sc, known);
		await saveKnownFacts(caseId, known);
		return sendBrainToolReplyFromOpenAI({
			io,
			sc,
			hotel,
			known,
			latestGuest,
			toolResult: {
				tool: "get_quote",
				ok: false,
				code: "missing_quote_inputs",
				missing: requiredBookingMissing(known).filter((item) =>
					["checkinISO", "checkoutISO", "roomTypeKey"].includes(item)
				),
			},
			fallback,
			typingStartedAt,
			preserveFallbackNumbers: false,
		});
	}
	const result = await quoteTool(sc, known);
	let nextKnown = { ...known };
	if (result.available && result.quote) {
		nextKnown.quote = result.quote;
	} else {
		nextKnown.quote = {
			available: false,
			roomTypeKey: result.roomTypeKey || known.roomTypeKey,
			checkinISO: result.checkinISO || known.checkinISO,
			checkoutISO: result.checkoutISO || known.checkoutISO,
			rooms: Math.max(1, Number(known.rooms || 1) || 1),
			roomSelections: normalizeRoomSelections(result.roomSelections || known.roomSelections),
			currency: result.currency || "SAR",
			code: result.code || "not_available",
			roomLabel: result.roomLabel || roomTypeLabel(known.roomTypeKey, known.languageCode),
			firstUnavailableDate: result.firstUnavailableDate || "",
			minCheckinISO: result.minCheckinISO || "",
			unavailableSelections: Array.isArray(result.unavailableSelections)
				? result.unavailableSelections.slice(0, 5)
				: [],
		};
	}
	nextKnown = syncKnownFromQuote(nextKnown);
	await saveKnownFacts(caseId, nextKnown);
	if (!result.available && shouldRecoverHotelUnavailableToJannat(sc, nextKnown, result)) {
		return recoverHotelUnavailableToJannatSupport({
			io,
			sc,
			hotel,
			known: nextKnown,
			quoteResult: result,
			latestGuest,
			typingStartedAt,
		});
	}
	const fallback = withWarmPrefix(
		buildQuoteFallbackMessage(sc, nextKnown, result, hotel),
		sc,
		nextKnown,
		latestGuest?.message || ""
	);
	return sendBrainToolReplyFromOpenAI({
		io,
		sc,
		hotel,
		known: nextKnown,
		latestGuest,
		toolResult: {
			...compactQuoteToolResult(result, nextKnown),
			instruction: quoteReplyFormattingInstruction(),
		},
		clientAction: result.available ? "quote_ready" : "quote_unavailable",
		quickReplies: result.available
			? proceedQuickReplies(activeLanguageCode(sc, nextKnown))
			: quoteUnavailableQuickRepliesForCase(sc, nextKnown),
		fallback,
		typingStartedAt,
	});
}

async function handleBrainAlternatives(
	io,
	sc = {},
	hotel = {},
	known = {},
	latestGuest = null,
	typingStartedAt = 0
) {
	const caseId = caseIdText(sc);
	if (!quoteInputsKnown(known)) {
		const fallback = buildStayClarificationMessage(sc, known, latestGuest?.message || "");
		await saveKnownFacts(caseId, known);
		return sendBrainToolReplyFromOpenAI({
			io,
			sc,
			hotel,
			known,
			latestGuest,
			toolResult: {
				tool: "check_alternatives",
				ok: false,
				code: "missing_stay_selection",
			},
			fallback,
			typingStartedAt,
			preserveFallbackNumbers: false,
		});
	}
	const result = await suggestAlternativeStays(sc, known).catch((error) => {
		console.error("[aiagent] brain alternative availability failed:", error?.message || error);
		return { options: [], checkedDays: 0, validatedCandidates: 0 };
	});
	const nextKnown = {
		...known,
		alternativeStays: (Array.isArray(result.options) ? result.options : [])
			.map((option) => ({
				checkinISO: option.checkinISO,
				checkoutISO: option.checkoutISO,
				nights: option.nights,
				rooms: option.rooms,
				roomSelections: normalizeRoomSelections(option.roomSelections),
				roomTypeKey: option.roomTypeKey || "",
				roomLabel: option.roomLabel || "",
				total: option.total,
				currency: option.currency,
			}))
			.slice(0, 2),
	};
	await saveKnownFacts(caseId, nextKnown);
	const fallback = buildAlternativeAvailabilityMessage(sc, nextKnown, result);
	await waitForTypingMinimum(typingStartedAt);
	return sendAiMessage(io, sc, fallback, {
		latestGuest,
		known: nextKnown,
		clientAction: result.options?.length
			? "alternative_dates_ready"
			: "alternative_dates_unavailable",
		quickReplies: alternativeStayQuickReplies(
			nextKnown.alternativeStays,
			activeLanguageCode(sc, nextKnown)
		),
		source: "server",
	});
}

